 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYfRuleMgt 
SELECT
    REPR_CD_GP,
    CD_GP,
    ITEM,
    REPR_CD_CONTENTS,
    CASE REPR_CD_GP 
        WHEN 'YF0005' THEN (SELECT S.REPR_CD_CONTENTS FROM TB_YF_RULE S  WHERE S.REPR_CD_GP = 'YM6001' AND S.CD_GP = '1' AND S.ITEM = t.ITEM ) 
    ELSE ITEM
    END AS ITEM_NM,
    REGISTER,
    REG_DDTT,
    MODIFIER,
    TO_CHAR(MOD_DDTT, 'YYYY/MM/DD HH24:MI:SS') AS MOD_DDTT,
    DEL_YN,
    ITEM1,
    ITEM_VALUE1,
    ITEM2,
    ITEM_VALUE2,
    DTL_ITEM1,
    DTL_ITEM2,
    DTL_ITEM3,
    DTL_ITEM4,
    DTL_ITEM5,
    DTL_ITEM6,
    DTL_ITEM7,
    DTL_ITEM8,
    DTL_ITEM9,
    DTL_ITEM10
FROM TB_YF_RULE t
WHERE REPR_CD_GP = :V_REPR_CD_GP
AND CD_GP = NVL(:V_CD_GP, CD_GP)
AND DEL_YN = 'N'
ORDER BY CASE REPR_CD_GP  WHEN 'YF0005' THEN SUBSTR(CD_GP,2,1) ELSE CD_GP END,
         CASE REPR_CD_GP  WHEN 'YF0005' THEN SUBSTR(CD_GP,1,1) ELSE CD_GP END,
         ITEM
 </pre> */
public final static String getYfRuleMgt = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYfRuleMgt";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarDirectInfo
WITH PARAM AS (
SELECT :V_YD_GP AS YD_GP
      ,:V_FR_BAY_GP AS FR_BAY_GP
      ,:V_TO_BAY_GP AS TO_BAY_GP
  FROM DUAL
)

SELECT CASE
       WHEN FR_DIRECT = 'L' AND TO_DIRECT = 'R' THEN '1'
       WHEN FR_DIRECT = 'L' AND TO_DIRECT = 'L' THEN '2'
       WHEN FR_DIRECT = 'R' AND TO_DIRECT = 'L' THEN '3'
       WHEN FR_DIRECT = 'R' AND TO_DIRECT = 'R' THEN '4'
        END AS CD_VAL
      , DECODE(FR_DIRECT,'L','СТ','Пь') || '(' || FR_DIRECT || ')' || '->' || DECODE(TO_DIRECT,'L','СТ','Пь') || '(' || TO_DIRECT || ')' AS CD_NM
  FROM (SELECT DISTINCT
               CASE 
               WHEN SUBSTR(YD_CARPNT_CD,2,1) = '1' THEN 'L'
               WHEN SUBSTR(YD_CARPNT_CD,2,1) = '2' AND YD_BAY_GP = 'H' THEN 'L'
               ELSE 'R'
           END AS FR_DIRECT
          FROM TB_YD_CARPOINT A
              ,PARAM P
         WHERE A.DEL_YN     = 'N'
           AND A.YD_CAR_USETYPE_GP = 'MT'
           AND A.YD_GP      = P.YD_GP
           AND A.YD_BAY_GP  = P.FR_BAY_GP) A
      ,(SELECT DISTINCT
               CASE 
               WHEN SUBSTR(YD_CARPNT_CD,2,1) = '1' THEN 'L'
               WHEN SUBSTR(YD_CARPNT_CD,2,1) = '2' AND YD_BAY_GP = 'H' THEN 'L'
               ELSE 'R'
           END AS TO_DIRECT
          FROM TB_YD_CARPOINT A
              ,PARAM P
         WHERE A.DEL_YN     = 'N'
           AND A.YD_CAR_USETYPE_GP = 'MT'
           AND A.YD_GP      = P.YD_GP
           AND A.YD_BAY_GP != P.FR_BAY_GP
           AND A.YD_BAY_GP  = NVL(P.TO_BAY_GP,A.YD_BAY_GP)) B
 </pre> */
public final static String getCarDirectInfo = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarDirectInfo";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjlSub2  
SELECT
    ROWNUM AS SEQ 
    , TT.*
FROM
(
    SELECT DISTINCT T.STL_NO
        , T.STK_POS
        , T.CURR_PROG_CD
        , T.COIL_SIZE
        , T.NET_WEIGH_WT
        , T.COIL_OUTDIA
        , T.YD_STK_LYR_STAT
    FROM
    (
    --
        SELECT M2.STL_NO
            , SUBSTR(M2.YD_STK_COL_GP,2,5) ||SUBSTR(M2.YD_STK_LYR_NO,3,1)|| M2.YD_STK_BED_NO AS STK_POS 
            , B.CURR_PROG_CD
            , TO_CHAR(B.COIL_T,'99,999.00')  || ' X ' || TO_CHAR(B.COIL_W,'99,999')  AS COIL_SIZE
            , B.NET_WEIGH_WT
            , B.COIL_OUTDIA
            , 'S' AS YD_STK_LYR_STAT -- ЛѓТїДыБт
        FROM TB_YF_WRKBOOK M
            , TB_YF_WRKBOOKMTL M2
            , TB_PT_COILCOMM B  
        WHERE M.YD_WBOOK_ID = M2.YD_WBOOK_ID
        AND M2.STL_NO=B.COIL_NO  
        AND M2.DEL_YN = 'N'
        AND M.DEL_YN = 'N'
        AND M.YD_WRK_PLAN_TCAR = '1XTC03'
        AND NOT EXISTS (
            SELECT 1
            FROM TB_YF_CRNSCH S
                 , TB_YF_CRNWRKMTL S1
            WHERE S.YD_CRN_SCH_ID = S1.YD_CRN_SCH_ID
            AND S1.STL_NO = M2.STL_NO
            AND S.DEL_YN = 'N'
            AND S1.DEL_YN = 'N'
        )
        AND NOT EXISTS (
            SELECT 1
            FROM  TB_YF_TCARFTMVMTL T
            WHERE T.STL_NO = M2.STL_NO
            AND T.DEL_YN = 'N' 
        )
    
    UNION
    
        SELECT
           TCAR.STL_NO, TCAR.STK_POS, TCAR.CURR_PROG_CD, TCAR.COIL_SIZE, TCAR.NET_WEIGH_WT, TCAR.COIL_OUTDIA 
           , CASE 
                WHEN TCAR.YD_CURR_BAY_GP = SUBSTR(STK_POS,1,1) OR TCAR.YD_STK_LYR_STAT = 'M' THEN  TCAR.YD_STK_LYR_STAT 
            ELSE 'S' END AS  YD_STK_LYR_STAT
        FROM
        (
            SELECT T.STL_NO
                , SUBSTR(L.YD_STK_COL_GP,2,1) || 'TC' ||SUBSTR(T.YD_STK_LYR_NO,3,1)|| T.YD_STK_BED_NO AS STK_POS 
                , B.CURR_PROG_CD
                , TO_CHAR(B.COIL_T,'99,999.00')  || ' X ' || TO_CHAR(B.COIL_W,'99,999')  AS COIL_SIZE
                , B.NET_WEIGH_WT
                , B.COIL_OUTDIA
                , NVL(( 
                    SELECT S.YD_STK_LYR_STAT
                    FROM TB_YF_STKLYR S 
                    WHERE S.STL_NO = T.STL_NO
                    AND S.YD_STK_COL_GP LIKE '1_TC03%'
                   ),'M') AS YD_STK_LYR_STAT
                , E.YD_CURR_BAY_GP
            FROM   TB_YF_TCARSCH TS 
                , TB_YF_TCARFTMVMTL T
                , TB_PT_COILCOMM B
                , TB_YF_STKLYR L
                , TB_YF_EQP E
            WHERE TS.YD_TCAR_SCH_ID = T.YD_TCAR_SCH_ID 
            AND T.STL_NO = B.COIL_NO 
            AND TS.YD_EQP_ID = E.YD_EQP_ID
            AND T.STL_NO = L.STL_NO(+)
            AND T.YD_STK_BED_NO = L.YD_STK_BED_NO(+)
            AND T.YD_STK_LYR_NO = L.YD_STK_LYR_NO(+)
            AND TS.YD_TCAR_SCH_ID = :V_YD_TCAR_SCH_ID
            AND T.DEL_YN = 'N'
        ) TCAR
    ) T
    ORDER BY CASE WHEN ( SELECT YD_CURR_BAY_GP FROM TB_YF_EQP WHERE YD_EQP_ID = '1XTC03') = SUBSTR(T.STK_POS,1,1) THEN 1 ELSE 999 END, SUBSTR(T.STK_POS,2,4) ASC
) TT  
 </pre> */
public final static String getacoilTcarWrkStatInqjlSub2 = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilTcarWrkStatInqjlSub2";

