 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListPapWrapIn 
SELECT
    T.*
FROM
(
       WITH S_KEY AS (
            SELECT
                  SUBSTR(V_GF_LOC,0,6) AS V_YD_STK_COL_GP 
                , SUBSTR(V_GF_LOC,7,2) AS V_YD_STK_BED_NO 
                , NVL(SUBSTR(V_GF_LOC,9,2),'01') AS V_YD_STK_LYR_NO
                , V_GF_LOC
            FROM
            (
                SELECT
                 :V_GF_LOC AS V_GF_LOC
                FROM DUAL
            )
       )
       -- ЧиДч ЙјСіПЁ СіЦїРх ФкРЯРЬ РћФЁЕЧОю РжДТАЧСі
       SELECT DISTINCT 
            A.YD_STK_COL_GP,
            A.YD_STK_BED_NO,
            A.YD_STK_LYR_NO,
            A.YD_STK_LYR_STAT,
            A.STL_NO,
            '' AS YD_WBOOK_ID,
            'СіЦїРх ЙјСі [' || A.YD_STK_BED_NO ||  ']ПЁ ДйИЅ РчЗсАЁ РлОїСпРдДЯДй. [РлОїСпРЮ РчЗсЙјШЃ :' || A.STL_NO  ||' ]' AS MSG
       FROM TB_YF_STKLYR A, S_KEY S
       WHERE A.YD_STK_COL_GP = S.V_YD_STK_COL_GP
       AND A.YD_STK_BED_NO = S.V_YD_STK_BED_NO
       AND A.YD_STK_LYR_NO = S.V_YD_STK_LYR_NO
       AND A.STL_NO IS NOT NULL
       UNION ALL
       -- ЕПАЃРЬРћЛѓТї Йз CTSНКФЩСь
       SELECT
            SS.*
            ,'СіЦїРх ЙјСі [' || SS.YD_STK_BED_NO ||  ']ПЁ ДйИЅ РчЗсАЁ РлОїПЙОрСпРдДЯДй. [РлОїСпРЮ РчЗсЙјШЃ :' || SS.STL_NO  ||', CTSРлОїСіНУ :'|| SS.YD_CTS_SCH_ID ||' ]' AS MSG
       FROM
       (
           SELECT   SUBSTR(M.YD_TO_LOC_GUIDE,0,6) AS YD_STK_COL_GP 
                , SUBSTR(M.YD_TO_LOC_GUIDE,7,2) AS YD_STK_BED_NO 
                , NVL(SUBSTR(M.YD_TO_LOC_GUIDE,9,2),'01') AS YD_STK_LYR_NO
                , 'D'
                , M1.STL_NO
                , CTS.YD_CTS_SCH_ID
           FROM TB_YF_WRKBOOK M, TB_YF_WRKBOOKMTL M1, TB_YF_CTS_SCH CTS, S_KEY S
           WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
           AND M.YD_WBOOK_ID = CTS.YD_WBOOK_ID
           AND CTS.DEL_YN = 'N'
           AND M.YD_TO_LOC_GUIDE LIKE S.V_YD_STK_COL_GP || S.V_YD_STK_BED_NO ||'%'
       ) SS
       UNION ALL
       -- ЕПАЃРЬРћЛѓТї Йз CTSНКФЩСь
       SELECT
            SS.*
            ,'СіЦїРх ЙјСі [' || SS.YD_STK_BED_NO ||  ']ПЁ ДйИЅ РчЗсАЁ РлОїПЙОрСпРдДЯДй. [РлОїСпРЮ РчЗсЙјШЃ :' || SS.STL_NO  ||', РлОїПЙОрID :'|| SS.YD_WBOOK_ID ||' ]' AS MSG 
       FROM
       (
           SELECT   SUBSTR(M.YD_TO_LOC_GUIDE,0,6) AS YD_STK_COL_GP 
                , SUBSTR(M.YD_TO_LOC_GUIDE,7,2) AS YD_STK_BED_NO 
                , NVL(SUBSTR(M.YD_TO_LOC_GUIDE,9,2),'01') AS YD_STK_LYR_NO
                , 'D'
                , M1.STL_NO
                , M.YD_WBOOK_ID
           FROM TB_YF_WRKBOOK M, TB_YF_WRKBOOKMTL M1, S_KEY S
           WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
           AND M.DEL_YN = 'N'
           AND M1.DEL_YN = 'N'
           AND M.YD_TO_LOC_GUIDE LIKE S.V_YD_STK_COL_GP || S.V_YD_STK_BED_NO ||'%'
     ) SS
)  T
 </pre> */
public final static String getListPapWrapIn = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListPapWrapIn";

