 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.GetCTSSchHistory
WITH SEARCH_KEY AS (
     SELECT
         :V_YD_EQP_ID AS V_YD_EQP_ID
        , TO_DATE(:V_FROM_DATETIME,'YYYYMMDDHH24MI') AS V_FROM_DT
        , TO_DATE(:V_TO_DATETIME,'YYYYMMDDHH24MI') AS V_TO_DT
    FROM DUAL 
)
SELECT TT.*
  FROM (
            SELECT
                XX.*
            FROM
            (
                    SELECT T.*,
                           ROWNUM AS SEQ,
                           CASE CARLD_EQP
                           WHEN 'SR' THEN CARLD_BAY || 'ЕП ПьУј' || CARLD_POINT || 'П­'
                           WHEN 'SL' THEN CARLD_BAY || 'ЕП СТУј' || CARLD_POINT || 'П­'
                           ELSE ''
                            END||'('||T.YD_CARLD_WR_LOC ||')'  AS YD_CARLD_WR_LOC_NM
                          ,CASE CARUD_EQP
                           WHEN 'SR' THEN CARUD_BAY || 'ЕП ПьУј' || CARUD_POINT || 'П­'
                           WHEN 'SL' THEN CARUD_BAY || 'ЕП СТУј' || CARUD_POINT || 'П­'
                           ELSE ''
                            END ||'('||T.YD_CARUD_WR_LOC ||')' AS YD_CARUD_WR_LOC_NM
                    FROM
                    (
                        SELECT 
                                CT.YD_EQP_ID AS YD_CTS_EQP_ID
                               , EQ.YD_EQP_NAME  AS YD_EQP_ID_NM
                               , TO_CHAR(CT.YD_CARLD_WR_DT,'YYYY/MM/DD HH24:MI') AS YD_CARLD_WR_DT
                               , CT.YD_CARUD_WR_LOC
                               , CT.YD_CARLD_WR_LOC
                               , TO_CHAR(CT.YD_CARUD_WR_DT,'YYYY/MM/DD HH24:MI') AS YD_CARUD_WR_DT
                               , SUBSTR(CT.YD_CARLD_WR_LOC,2,1) AS CARLD_BAY
                               , SUBSTR(CT.YD_CARUD_WR_LOC,2,1) AS CARUD_BAY
                               , SUBSTR(CT.YD_CARLD_WR_LOC,3,2) AS CARLD_EQP
                               , SUBSTR(CT.YD_CARUD_WR_LOC,3,2) AS CARUD_EQP
                               , SUBSTR(CT.YD_CARLD_WR_LOC,5,2) AS CARLD_POINT
                               , SUBSTR(CT.YD_CARUD_WR_LOC,5,2) AS CARUD_POINT
                               , CT.STL_NO
                               , COUNT(*) OVER() AS TOTAL
                            FROM 
                                 TB_YF_WRKHIST WR
                                ,TB_YF_CTS_SCH CT
                                ,SEARCH_KEY P
                                ,TB_YF_EQP EQ
                         WHERE  WR.YD_WRK_HDS_DD  BETWEEN P.V_FROM_DT AND  P.V_TO_DT
                            AND WR.DEL_YN = 'N'
                            AND WR.YD_WBOOK_ID = CT.YD_WBOOK_ID
                            AND CT.YD_EQP_ID = EQ.YD_EQP_ID
                            AND CT.YD_EQP_ID LIKE P.V_YD_EQP_ID || '%'
                            AND CT.DEL_YN = 'Y'
                            AND CT.YD_WRK_PROG_STAT IN ('2', '4' ) 
                            ORDER BY YD_CARLD_WR_DT DESC
                    ) T
             ) XX
        WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE 
     ) TT
 WHERE SEQ >= (( :V_PAGE_NO -1)* :V_PAGE_SIZE ) + 1
 </pre> */
public final static String GetCTSSchHistory = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.GetCTSSchHistory";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCrnSchAxYML007Next
SELECT YD_CRN_SCH_ID ,YD_WRK_PROG_STAT,YD_UP_WO_LOC,YD_DN_WO_LOC,YD_SCH_CD,YD_AID_WRK_YN,YD_CTS_RELAY_YN,SEQ1,SEQ3,YD_SCH_PRIOR,CHK ,YD_WBOOK_ID
  FROM
       (
SELECT A.*
  ,(CASE WHEN CHK=1 THEN 1 ELSE SEQ2 END) AS SEQ3
  FROM
       ( SELECT CS.YD_CRN_SCH_ID
              , CS.YD_WRK_PROG_STAT
              , CS.YD_UP_WO_LOC 
              , CS.YD_DN_WO_LOC 
              , CS.YD_SCH_CD              
              , CM.YD_AID_WRK_YN
              , (SELECT YD_CTS_RELAY_YN FROM TB_YF_WRKBOOK  WHERE YD_WBOOK_ID=CS.YD_WBOOK_ID) AS YD_CTS_RELAY_YN
              , DECODE(CS.YD_WRK_PROG_STAT,'W','0','S','1', CS.YD_WRK_PROG_STAT) AS SEQ1
              , (CASE WHEN CS.YD_SCH_PRIOR = 0                                                    THEN 0 
                     WHEN CS.YD_CRN_GRAB_USE_RULE_ID = (SELECT YD_CRN_GRAB_USE_RULE_ID 
                                                          FROM TB_YF_CRNSCH 
                                                         WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
                                                           AND SUBSTR(YD_SCH_CD,3,2) = 'PT')     THEN 1  --ТїЗЎИИ ПЌМг РлОї ИёРћ
                     ELSE 2  END) AS SEQ2 -- РЬРќ
              , CS.YD_SCH_PRIOR
              
              , ( CASE WHEN CS.YD_SCH_PRIOR = 0                                                    THEN 0 
                       WHEN (SELECT YD_CTS_RELAY_YN FROM TB_YF_WRKBOOK  WHERE YD_WBOOK_ID=CS.YD_WBOOK_ID)='Y' 
                            AND CS.YD_SCH_CD LIKE '1_PT%' 
                       THEN 1 ELSE 2 END) AS CHK
              , cs.YD_WBOOK_ID
              ,CS.YD_UP_WO_LOC_XAXIS 
           FROM TB_YF_CRNSCH CS
              , TB_YF_CRNWRKMTL CM
          WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
            AND CS.DEL_YN = 'N'
            AND CM.DEL_YN = 'N'
            AND CS.YD_EQP_ID =  :V_YD_EQP_ID 
            AND CS.YD_SCH_CD <> :V_YD_SCH_CD
            AND CS.YD_UP_WO_LOC_XAXIS IS NOT NULL   --// ЙАИЎРћ СТЧЅАЁ ЕщОюАЃ АцПь 
       ) A     
          ORDER BY SEQ1 DESC   --РлОїЛѓХТ
                 , SEQ3        --ТїЗЎПЌМгРлОї ПЉКЮ
                 , YD_SCH_PRIOR
                 , CHK         --ТїЗЎЧќЛѓУјСЄПЉКЮ
                 , CASE WHEN SUBSTR(YD_SCH_CD,3,2) = 'PT' THEN YD_WBOOK_ID ELSE '0' END --ТїЗЎРЬ ПьМБ ЕЕТјЧб ДыЛѓ ПьМБ
                 , CASE WHEN YD_SCH_CD LIKE '1_DC01LM' THEN TO_NUMBER(YD_CRN_SCH_ID) * -1
                        ELSE TO_NUMBER(YD_CRN_SCH_ID) END 
       )    
WHERE ROWNUM = 1
 </pre> */
