 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilPapWrapInOutSdInqjl.getWrapCellNoStat
-- СіЦїРх ЙјСі ЧіШВСЖШИ

WITH PARAM AS(
SELECT :V_YD_GP AS YD_GP
      FROM DUAL
)
SELECT SR.COIL_NO AS STL_NO               --ФкРЯЙјШЃ
      ,SR.WORD_UNIT_NAME        --РлОїДмРЇ
      ,SR.STEP_NO               --ТїМі
      ,CC.COIL_T                --ЕЮВВ
      ,CC.COIL_W                --Цј
      ,CC.COIL_WT               --СпЗЎ
      ,CC.COIL_OUTDIA           --ПмАц
      ,CC.YD_STR_LOC            --РњРхРЇФЁ
      ,CC.YD_BAY_GP             --ЕПБИКа
      ,DECODE(TRIM(TRANSLATE(CC.YD_EQP_GP, '1234567890', '          ')), NULL, 'АЁДЩ', 'КвАЁДЩ') AS CHK_SUPPLY
      ,TO_CHAR(SR.SHEAR_WORK_DT ,'YYYY.MM.DD HH24:MI:SS') AS SHEAR_WORK_DT  --СЄСЄРлОїРЯНУ
      ,TO_CHAR(SR.G_WRAP_CMPL_DT,'YYYY.MM.DD HH24:MI:SS') AS G_WRAP_CMPL_DT--СіЦїРхПЯЗсРЯНУ
      ,SR.G_WRAP_CMPLER         --СіЦїРхПЯЗсРк
      ,SR.G_WRAP_CMPL_LINE      --СіЦїРхПЯЗсЖѓРЮ
      ,SR.G_WRAP_CMPL_YN        --СіЦїРхПЯЗсРЏЙЋ
      ,CC.ORD_YEOJAE_GP
FROM   USRHRA.TB_HR_C_SHEARWOWR SR
      ,USRPTA.TB_PT_COILCOMM CC
      ,USRPTA.TB_PT_OSCOMM OC
      ,PARAM P
WHERE  CC.ORD_NO    = OC.ORD_NO
AND    CC.ORD_DTL   = OC.ORD_DTL
AND    CC.COIL_NO   = SR.COIL_NO
AND    SR.HR_PLNT_GP in ('C', 'B', 'A')
AND    SR.SHEAR_INI_DATE >= TO_CHAR(SYSDATE - 60, 'YYYYMMDD') --УжДы АЫЛі 2ДоГЛЗЮ ЧбСЄ.
AND    OC.WRAP_METHOD_CD = 'EB'  --МіУтРч СіЦїРх
AND    OC.ITEMNAME_CD NOT IN ('HAP', 'HBP', 'HCP', 'HAS', 'HBS', 'HCS', 'HAT', 'HBT', 'HCT') --РгАЁАј ОїУМПыРИЗЮ СІПмЧЯАэ УпУт
AND    SR.RECEIPT_HOLD_SCRAP_CAUSE_GP IN ('I', 'B')
AND    SR.G_WRAP_CMPL_YN IS NULL
AND    CC.YD_GP =P.YD_GP
AND    CC.RECORD_PROG_STAT IN('1','2')
AND    CC.ORD_YEOJAE_GP ='1'
AND    CC.CURR_PROG_CD IN ('H','G','K','N','L') 
ORDER BY SR.SHEAR_WORK_DT, SR.COIL_NO
 </pre> */
public final static String getWrapCellNoStat = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilPapWrapInOutSdInqjl.getWrapCellNoStat";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L021
SELECT 'YFF1L021' AS JMS_TC_CD
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT 	--JMSTCЛ§МКРЯНУ
      ,'YFF1L021' 
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24-MI-SS')       				--Л§МКРЯНУ
     ||'I' 				                                            --РќЙЎБИКа
     ||'0026'                                        				--РќЙЎБцРЬ
     ||RPAD(' ',  29 , ' ')
     ||RPAD(NVL(P.YD_STK_COL_GP,' '),6,' ')
     ||RPAD(NVL(P.YD_ZONE_GP,' '),1,' ')
     ||RPAD(NVL(CASE P.YD_ZONE_GP
                WHEN 'AZ' THEN 'FF9DFF'
                WHEN 'BZ' THEN 'AFFFEE'
                WHEN 'CZ' THEN '82F987'
                WHEN 'DZ' THEN 'FF8C8C'
                WHEN 'EZ' THEN 'FFE846'
                WHEN 'GZ' THEN '74D190'
                WHEN 'HZ' THEN '64AAFF'
                ELSE 'BBBBBB' 
                END
                ,' ')
            ,10
            ,' ')    
     ||RPAD(' ',  9 , ' ') AS JMS_TC_MESSAGE
  FROM (SELECT SUBSTR(YD_STK_COL_GP,0,4) || '01' AS YD_STK_COL_GP
              ,MIN(YD_ZONE_GP) AS YD_ZONE_GP
          FROM TB_YF_STKCOL A
         WHERE SUBSTR(A.YD_STK_COL_GP,0,4) = SUBSTR(:V_YD_STK_COL_GP,0,4)
           AND YD_ZONE_GP IS NOT NULL
         GROUP BY SUBSTR(YD_STK_COL_GP,0,4)) P
 </pre> */
