 /** <pre> 
 --com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCraneChange1
--ХЉЗЙРЮРлОїАќИЎ ХЉЗЙРЮКЏАц СЖШИ 
SELECT CS.YD_WBOOK_ID
      ,CS.YD_WRK_PROG_STAT
      ,CS.YD_SCH_CD
      ,CS.YD_EQP_ID
      ,CS.CHG_YD_EQP_ID
      ,CS.CHG_YD_SCH_PRIOR
      ,(SELECT DECODE(YD_EQP_PROG_STAT, 'B', YD_EQP_PROG_STAT, 'W') FROM TB_YF_EQP EP WHERE EP.YD_EQP_ID = CS.CHG_YD_EQP_ID) AS CHG_YD_EQP_STAT
      ,EQ.YD_EQP_WRK_MODE AS CHG_YD_EQP_WRK_MODE
      ,EQ.YD_EQP_WRK_MODE2
      ,(SELECT YD_EQP_WRK_MODE2       FROM TB_YF_EQP WHERE YD_EQP_ID = CS.YD_EQP_ID) AS OLD_YD_EQP_WRK_MODE2
      ,(SELECT YD_EQP_WRK_MODE        FROM TB_YF_EQP WHERE YD_EQP_ID = CS.YD_EQP_ID) AS OLD_YD_EQP_WRK_MODE
      ,(SELECT YD_EQP_AUTO_CRN_MODE       FROM TB_YF_EQP WHERE YD_EQP_ID = CS.YD_EQP_ID) AS OLD_YD_EQP_AUTO_CRN_MODE
      ,(SELECT YD_EQP_PROG_STAT       FROM TB_YF_EQP WHERE YD_EQP_ID = CS.YD_EQP_ID) AS OLD_YD_EQP_PROG_STAT 
      ,EQ.YD_EQP_AUTO_CRN_MODE AS NEW_YD_EQP_AUTO_CRN_MODE
  FROM TB_YF_EQP EQ
      ,(
        SELECT CS.YD_WBOOK_ID
              ,CS.YD_WRK_PROG_STAT
              ,CS.YD_SCH_CD
              ,CS.YD_EQP_ID
              ,(CASE WHEN CS.YD_EQP_ID = SR.YD_WRK_CRN  THEN YD_ALT_CRN
                     WHEN CS.YD_EQP_ID = SR.YD_ALT_CRN  THEN YD_WRK_CRN
                     ELSE CS.YD_EQP_ID END) AS CHG_YD_EQP_ID
              , CS.YD_SCH_PRIOR  AS CHG_YD_SCH_PRIOR
          FROM TB_YF_CRNSCH  CS
              ,TB_YF_SCHRULE SR
         WHERE CS.YD_SCH_CD     = SR.YD_SCH_CD
           AND CS.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
           AND CS.DEL_YN = 'N'           
           ) CS
 WHERE CS.CHG_YD_EQP_ID = EQ.YD_EQP_ID
--   AND EQ.YD_WRK_PROG_STAT IN ('O', 'N', 'R','W')
 </pre> */
public final static String getCraneChange1 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCraneChange1";

