 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdStkColNo2
WITH PARAM AS
(
    SELECT
        :V_YD_STK_COL_GP AS P_YD_STK_COL_GP
    FROM
        DUAL
)
SELECT
    YD_STK_COL_GP AS CD_VAL,
    YD_STK_COL_GP AS CD_NM
FROM
    (
        SELECT DISTINCT
            SUBSTR(SC.YD_STK_COL_GP, 5, 2) AS YD_STK_COL_GP
        FROM
            TB_YF_STKCOL  SC,
            TB_YF_STKLYR  SL,
            PARAM
        WHERE 1=1
        AND SUBSTR(SC.YD_STK_COL_GP,1,4) = P_YD_STK_COL_GP
        AND SC.YD_STK_COL_GP = SL.YD_STK_COL_GP
        AND SL.YD_STK_LYR_STAT IN ('E','C')
        AND SUBSTR(P_YD_STK_COL_GP, 3, 2) != 'TC'

        UNION ALL

        SELECT DISTINCT
            SUBSTR(SC.YD_STK_COL_GP, 5, 2) AS YD_STK_COL_GP
        FROM
            TB_YF_STKCOL SC,
            TB_YF_STKLYR SL,
            PARAM
        WHERE 1=1
        AND SUBSTR(SC.YD_STK_COL_GP, 1, 4) = P_YD_STK_COL_GP
        AND SC.YD_STK_COL_GP = SL.YD_STK_COL_GP
        AND SUBSTR(P_YD_STK_COL_GP, 3, 2) = 'TC'
    )
ORDER BY YD_STK_COL_GP
 </pre> */
public final static String getCodeYdStkColNo2 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdStkColNo2";

