 /** <pre> 
 -- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfColInfo 
-- РћФЁП­col СЄКИ СЖШИ 
SELECT
    A.*
  , R.REPR_CD_CONTENTS AS YD_STK_COL_USAGE_CD_NM
  , R2.REPR_CD_CONTENTS AS YD_ZONE_GP_NM
FROM (
        SELECT A.YD_STK_COL_GP -- П­БИКа
             , A.YD_STK_COL_USAGE_CD -- П­ПыЕЕ
             ,(SELECT MAX(Z.COL_GP) 
                 FROM TB_YF_STKCOL Z
                WHERE Z.YD_GP = A.YD_GP
                  AND Z.BAY_GP = A.BAY_GP
                  AND Z.SECT_GP = A.SECT_GP ) AS COL_CNT
             , COUNT(DISTINCT B.YD_STK_BED_NO) AS BED_CNT --ЙшЕхМі
             , SUM(DECODE(B.YD_STK_LYR_ACTIVE_STAT, 'E', 1, 0)) AS TOTAL_CNT --УбИХМі
             , SUM(DECODE(B.YD_STK_LYR_STAT, 'C', 1, 'L', 1, 'U', 1, 'S', 1, 0)) AS STK_CNT --РћФЁИХМі
             , SUM(DECODE(B.YD_STK_LYR_ACTIVE_STAT, 'E', DECODE(B.YD_STK_LYR_STAT, 'C', 0, 'L', 0, 'U', 0, 'S', 0, 1), 0)) AS STK_ABLE_CNT--РћФЁАЁДЩИХМі
             , SUBSTR(A.YD_STK_COL_GP,5,2) AS COL_NO
             , 'C' || SUBSTR(A.YD_STK_COL_GP,5,2) AS COL_ID
             , MAX(B.YD_STK_LYR_NO) AS MAX_YD_STK_LYR_NO
             , MIN(A.YD_ZONE_GP) AS YD_ZONE_GP
          FROM TB_YF_STKCOL   A
             , TB_YF_STKLYR B
         WHERE A.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP||'%' -- ОпЕх+ЕП+НКЦЧ:(2A01 ...)
           AND B.YD_STK_BED_NO NOT IN ('00')
           AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
         GROUP BY A.YD_GP,A.BAY_GP,A.SECT_GP,A.YD_STK_COL_GP, A.YD_STK_COL_USAGE_CD
) A
, TB_YF_RULE R
, TB_YF_RULE R2
WHERE  A.YD_STK_COL_USAGE_CD = R.ITEM(+)
AND R.REPR_CD_GP(+) = 'YF0003'
AND R.CD_GP(+) = 'STACKUSAGE'
AND R2.REPR_CD_GP(+) = 'YM6001'
AND R2.CD_GP(+) = '1'
AND A.YD_ZONE_GP = R2.ITEM(+)
ORDER BY A.YD_STK_COL_GP
 </pre> */
public final static String getYfColInfo = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfColInfo";

