 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCtsWrkRstHist 
WITH   SEARCH_VAL AS  (
    SELECT
        NVL(:V_SORT,'X') AS V_SORT,
        TO_DATE( NVL(:V_FR_DATE, TO_CHAR(SYSDATE-500,'YYYYMMDD')) , 'YYYYMMDD') AS V_FR_DATE,
        TO_DATE( NVL(:V_TO_DATE, TO_CHAR(SYSDATE,'YYYYMMDD')) , 'YYYYMMDD' )+0.99999 AS V_TO_DATE
    FROM DUAL
) 
SELECT
      A.STL_NO
    , A.YD_EQP_ID
    , TO_CHAR(A.YD_WORD_DT,'YYYYMMDD') AS YD_WORD_DT
    , A.YD_CARLD_WR_DT
    , A.YD_CARUD_WR_DT
    , A.YD_CARLD_WR_LOC
    , FF.YD_EQP_NAME AS FR_SADDLE_NM
    , A.YD_CARUD_WO_LOC
    , TT.YD_EQP_NAME AS TO_SADDLE_NM
    , A.YD_CTS_SCH_ID
    , A.YD_WBOOK_ID
    , A.YD_CTS_RELAY_BAY_GP
    , A.YD_CTS_RELAY_YN
    , ROW_NUMBER() OVER( PARTITION BY TO_CHAR(A.YD_WORD_DT,'YYYYMMDD') ORDER BY A.STL_NO DESC ) AS SORT_1
    , ROW_NUMBER() OVER( PARTITION BY TO_CHAR(A.YD_WORD_DT,'YYYYMMDD'), A.STL_NO ORDER BY A.YD_WORD_DT ASC, A.YD_CARLD_WR_DT ASC) AS SORT_2
FROM TB_YF_CTS_SCH A
    , TB_YF_EQP FF
    , TB_YF_EQP TT
    , TB_YF_EQP CT
    , SEARCH_VAL SVAL
WHERE A.YD_WRK_PROG_STAT IN ('2','4')
AND A.YD_CARUD_WO_LOC = TT.YD_EQP_ID(+)
AND A.YD_CARLD_WR_LOC = FF.YD_EQP_ID(+)
AND A.YD_EQP_ID = CT.YD_EQP_ID
AND A.YD_WORD_DT BETWEEN SVAL.V_FR_DATE AND SVAL.V_TO_DATE
--AND A.STL_NO = 'HRS0294'
ORDER BY TO_CHAR(A.YD_WORD_DT,'YYYYMMDD'),
    CASE SVAL.V_SORT 
        WHEN 'STL_NO' THEN  SORT_1 || SORT_2
        WHEN 'LM' THEN TO_CHAR(A.YD_CARLD_WR_DT,'YYYYMMDDHH24MISS') 
        WHEN 'X' THEN  SORT_1 || SORT_2
    END
 </pre> */
public final static String getCtsWrkRstHist = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCtsWrkRstHist";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getZoneVerSeq
WITH PARAM AS(
        SELECT :V_YD_ZONE_GP AS YD_ZONE_GP
              ,:V_YD_STK_COL_GP AS YD_STK_COL_GP
              ,:V_RANKING AS RANKING
              ,:V_VER_ID AS VER_ID
          FROM DUAL)

,ZONE_RANK AS (
SELECT ROWNUM AS RN
      ,A.*
  FROM( SELECT A.YD_STK_COL_GP
              ,A.YD_ZONE_GP
              ,A.YD_LOC_SRCH_RNG_SEQ
          FROM TB_YF_SCHLOCSRCH_ZONE_V A
              ,PARAM P
         WHERE A.DEL_YN = 'N'
           AND A.VER_ID = P.VER_ID
           AND A.YD_ZONE_GP = P.YD_ZONE_GP
           AND SUBSTR(A.YD_STK_COL_GP,2,1) = SUBSTR(P.YD_STK_COL_GP,2,1)
         ORDER BY YD_LOC_SRCH_RNG_SEQ) A)
   
SELECT NVL(A.YD_LOC_SRCH_RNG_SEQ,NVL((SELECT MAX(Z.YD_LOC_SRCH_RNG_SEQ)
                                        FROM ZONE_RANK Z),0)+1) AS YD_LOC_SRCH_RNG_SEQ
  FROM ZONE_RANK A
      ,PARAM P
 WHERE P.RANKING = A.RN(+)
 </pre> */
public final static String getZoneVerSeq = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getZoneVerSeq";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectCTSLyr
SELECT *
FROM
(
SELECT A.STL_NO
      ,C.YD_WBOOK_ID
      ,A.YD_STK_COL_GP AS YD_CARLD_WO_LOC
      ,C.YD_AIM_BAY_GP
      ,C.YD_TO_LOC_GUIDE
      ,RANK() OVER(PARTITION BY A.STL_NO ORDER BY B.YD_WBOOK_ID DESC) AS RNK
FROM TB_YF_STKLYR A,
     TB_YF_WRKBOOKMTL B,
     TB_YF_WRKBOOK C
WHERE (A.YD_STK_COL_GP LIKE '%SR%'
       OR 
       A.YD_STK_COL_GP LIKE '%SL%'
      )
  AND A.STL_NO IS NOT NULL 
  AND C.YD_AIM_BAY_GP IS NOT NULL
  AND A.YD_STK_LYR_STAT = 'C'
  AND A.STL_NO      = B.STL_NO
  AND B.YD_WBOOK_ID = C.YD_WBOOK_ID
  AND C.YD_WRK_PLAN_TCAR = '1XTC01'
)
WHERE RNK = 1
 </pre> */
public final static String selectCTSLyr = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectCTSLyr";

