 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdSchCd2
--НКФЩСйФкЕхСЖШИ[ЕПГЛРЬРћСІПм]
WITH PARAM AS
(
    SELECT
        :V_YD_GP     AS P_YD_GP,
        :V_YD_BAY_GP AS P_YD_BAY_GP
    FROM
        DUAL    
)
SELECT
    CD_VAL,
    CD_NM
FROM
    (
        SELECT
            YD_SCH_CD   AS CD_VAL,
            CD_CONTENTS AS CD_NM,
            YD_BAY_GP
        FROM
            TB_YF_SCHRULE,
            PARAM
        WHERE 1=1
        AND YD_GP  = P_YD_GP
        AND YD_SCH_CD NOT LIKE YD_GP || YD_BAY_GP || 'YD01MM'
        AND YD_SCH_CD NOT LIKE YD_GP || YD_BAY_GP || 'YD02MM'
        AND YD_SCH_CD NOT LIKE YD_GP || YD_BAY_GP || 'YD21MM'
        AND YD_SCH_CD NOT LIKE YD_GP || YD_BAY_GP || 'YD22MM'
        AND DEL_YN = 'N'
        
        UNION ALL
        
        SELECT
            '1_PT02UM' AS CD_VAL,
            'РЬМлЛѓТї' AS CD_NM,
            '0' AS YD_BAY_GP
        FROM
            PARAM
        WHERE 1=1
        AND P_YD_GP = '1'
        
        UNION ALL
        
        SELECT
            '1_PT02LM' AS CD_VAL,
            'РЬМлЧЯТї' AS CD_NM,
            '0' AS YD_BAY_GP
        FROM
            PARAM
        WHERE 1=1
        AND P_YD_GP = '1'
    ),
    PARAM
WHERE 1=1
AND YD_BAY_GP LIKE P_YD_BAY_GP || '%' 
ORDER BY YD_BAY_GP, DECODE(SUBSTR(CD_VAL, 3, 6), 'DC01LM', 1, 'PT02LM', 1, 'EC01LM', 2, 'EC02LM', 3, 99), CD_NM

 </pre> */
