 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.checkDcCnvyrByStl 
WITH SEARCH_KEY AS (
    SELECT
        :V_STL_NO AS V_STL_NO
        , :V_BIZ_GP AS V_BIZ_GP
    FROM DUAL
)
SELECT
    T.MSG
FROM 
(
 -- Л§МКЕЧБт ЖЇЙЎПЁ ЗЮСї УМХЉДТ ЧЪПфЧЯСі ОЪРН 
    
    SELECT 'РњРхЧАСЄКИ(Stock)РЬ СИРчЧЯСі ОЪНРДЯДй.'  AS MSG
    FROM TB_YF_STOCK S, SEARCH_KEY K
    WHERE S.STL_NO = K.V_STL_NO
    AND S.DEL_YN = 'N'
    AND K.V_BIZ_GP = 'I' -- TAKE INРЬ ОЦДвЖЇИИ УМХЉЧЯРк
    UNION ALL
    SELECT
        'ОпЕхПЁ РћФЁЕШ ФкРЯИИ Take In УГИЎИІ Чв Мі РжНРДЯДй.' AS MSG
    FROM TB_YF_STKLYR A, TB_YF_STKCOL B, SEARCH_KEY K
    WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
    AND A.STL_NO = K.V_STL_NO
    AND B.SECT_GP BETWEEN '00' AND '99'
    AND K.V_BIZ_GP = 'I' -- TAKE INРЬ ОЦДвЖЇИИ УМХЉЧЯРк
    UNION ALL
    SELECT
        'ОпЕхПЁ РћФЁЕШ ФкРЯРдДЯДй. ФкРЯЙјШЃИІ ШЎРЮЧЯММПф' AS MSG
    FROM TB_YF_STKLYR A, TB_YF_STKCOL B, SEARCH_KEY K
    WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
    AND A.STL_NO = K.V_STL_NO
    AND B.SECT_GP BETWEEN '00' AND '99'
    AND K.V_BIZ_GP <> 'I' -- TAKE INРЬ ОЦДвЖЇИИ УМХЉЧЯРк
    UNION ALL
    SELECT
        'РлОїПЙОрРЬ ЕюЗЯЕЧОю РжДТ РчЗсРдДЯДй.'
    FROM TB_YF_WRKBOOKMTL M1, TB_YF_WRKBOOK M, SEARCH_KEY K
    WHERE M1.YD_WBOOK_ID = M.YD_WBOOK_ID 
    AND M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N'
    AND M.DEL_YN = 'N'
    AND NOT EXISTS (
        SELECT
            1
        FROM TB_YF_CRNSCH S
        WHERE S.YD_WBOOK_ID = M1.YD_WBOOK_ID
        AND S.DEL_YN = 'N'
        UNION ALL
        SELECT
            1
        FROM TB_YF_CTS_SCH S
        WHERE S.STL_NO = M1.STL_NO
        AND S.DEL_YN = 'N'
    )
    UNION ALL
    SELECT
        'ХЉЗЙРЮНКФЩСьРЬ ПЙОрЕЧОю РжДТ РчЗсРдДЯДй.'
    FROM TB_YF_CRNWRKMTL M1, TB_YF_CRNSCH M, SEARCH_KEY K
    WHERE M1.YD_CRN_SCH_ID = M.YD_CRN_SCH_ID 
    AND M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N'
    AND M.DEL_YN = 'N'
    UNION ALL
    SELECT
        'CTS РлОїРЬ ПЙОрЕЧОю РжДТ РчЗсРдДЯДй.'
    FROM TB_YF_CTS_SCH M1, SEARCH_KEY K
    WHERE  M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N'
    UNION ALL
    SELECT
        CASE M1.PROC_GP 
            WHEN 'F' THEN 'HFL'
            WHEN 'K' THEN 'SPM'
            WHEN 'Q' THEN 'EQL'
        END  || 'РЧ МГКёПЁ РжДТ РчЗсРдДЯДй.'
    FROM TB_YF_EQPTRACKING M1, SEARCH_KEY K
    WHERE  M1.STL_NO = K.V_STL_NO
    AND M1.DEL_YN = 'N' 
    AND M1.PROC_GP IN ('K', 'Q', 'F')
) T 
 </pre> */
public final static String checkDcCnvyrByStl = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.checkDcCnvyrByStl";

