 /** <pre> 
SELECT
  CD_NM  
 , CD_VAL
FROM
(
    SELECT
        CASE PROC_GP
            WHEN 'B' THEN 'DC'
            WHEN 'F' THEN 'HFL'
            WHEN 'K' THEN 'SPM'
            WHEN 'Q' THEN 'EQL'
        END ||' ' || YD_BAY_GP || 'ЕП' ||  ' [' || '1' || YD_BAY_GP || CASE PROC_GP WHEN 'B' THEN 'DC' ELSE PROC_GP||'E' END  || '01' || ']' AS CD_NM 
        ,'1' || YD_BAY_GP || CASE PROC_GP WHEN 'B' THEN 'DC' ELSE PROC_GP||'E' END  || '01' AS CD_VAL
    FROM TB_YF_EQPTRACKING
    WHERE PROC_GP IN ('B','F','K','Q')
    AND (
         (PROC_GP = 'B' AND YD_BAY_GP IN ( 'B', 'C' ))
        OR 
        (PROC_GP = 'F' AND YD_BAY_GP IN ( 'B'))
        OR 
        (PROC_GP = 'K' AND YD_BAY_GP IN ( 'D', 'E' ))    
        OR 
        (PROC_GP = 'Q' AND YD_BAY_GP IN ( 'E', 'F' ))
    )
    GROUP BY PROC_GP, YD_BAY_GP HAVING ( (:V_EQP_GP = 'D' AND PROC_GP = 'B') OR (:V_EQP_GP = 'J' AND PROC_GP <> 'B') )
    ORDER BY PROC_GP, CD_VAL
)
 </pre> */
