 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getLastCrnSchIdAuto
SELECT * 
  FROM (
        SELECT YD_CRN_SCH_ID 
          FROM TB_YF_CRNSCH  A
         WHERE YD_SCH_CD = :V_YD_SCH_CD
           AND YD_EQP_ID = :V_YD_EQP_ID
           AND DEL_YN = 'N'
           AND YD_WRK_PROG_STAT IN ('W','S','1')
           AND 1 = CASE WHEN (SELECT COUNT(*) 
                                FROM TB_YF_CRNSCH
                               WHERE YD_WRK_PROG_STAT IN ('S','1') 
                                 AND YD_SCH_CD <> A.YD_SCH_CD 
                                 AND YD_EQP_ID =  A.YD_EQP_ID
                                 AND DEL_YN = 'N' ) > 0 
                        THEN 0 
                        ELSE 1 END
         ORDER BY YD_CRN_SCH_ID DESC
) WHERE ROWNUM = 1 
 </pre> */
public final static String getLastCrnSchIdAuto = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getLastCrnSchIdAuto";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchAxYML007
WITH TMP_TBL AS 
(
SELECT YD_CRN_SCH_ID ,YD_WRK_PROG_STAT,YD_UP_WO_LOC,YD_DN_WO_LOC,YD_SCH_CD,YD_AID_WRK_YN,YD_CTS_RELAY_YN,SEQ1,SEQ3,YD_SCH_PRIOR,CHK ,YD_WBOOK_ID,MAX_YD_CRN_SCH_ID
  FROM
       (
SELECT A.*
  ,(CASE WHEN CHK=1 THEN 1 ELSE SEQ2 END) AS SEQ3
  FROM
       ( SELECT CS.YD_CRN_SCH_ID
              , CS.YD_EQP_ID 
              , CS.YD_WRK_PROG_STAT
              , CS.YD_UP_WO_LOC 
              , CS.YD_DN_WO_LOC 
              , CS.YD_SCH_CD
              , CM.YD_AID_WRK_YN
              , CS.YD_SCH_PRIOR
              , DECODE(CS.YD_WRK_PROG_STAT,'W','0','S','1', CS.YD_WRK_PROG_STAT) AS SEQ1
              , (SELECT YD_CTS_RELAY_YN FROM USRYFA.TB_YF_WRKBOOK  WHERE YD_WBOOK_ID=CS.YD_WBOOK_ID) AS YD_CTS_RELAY_YN
              , CASE WHEN CS.YD_SCH_PRIOR = 0                                                    THEN 0 
                     WHEN CS.YD_SCH_CD    = '1EKE05UM'                                           THEN 0 
                     WHEN CS.YD_CRN_GRAB_USE_RULE_ID = (SELECT YD_CRN_GRAB_USE_RULE_ID 
                                                          FROM TB_YF_CRNSCH 
                                                         WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
                                                           AND SUBSTR(YD_SCH_CD,3,2) = 'PT')     THEN 1  --ТїЗЎИИ
                     ELSE 2  END AS SEQ2 -- РЬРќ 
              , (SELECT MAX(C.YD_CRN_SCH_ID) 
                   FROM TB_YF_CRNSCH C
                      , TB_YF_CRNWRKMTL M
                  WHERE C.YD_CRN_SCH_ID    = M.YD_CRN_SCH_ID
                    AND C.DEL_YN    = 'N'
                    AND M.DEL_YN    = 'N'
                    AND C.YD_EQP_ID = CS.YD_EQP_ID
                    AND C.YD_SCH_CD = CS.YD_SCH_CD
                    AND C.YD_WRK_PROG_STAT = 'W' ) AS MAX_YD_CRN_SCH_ID     
              , ( CASE WHEN CS.YD_SCH_PRIOR = 0                                                    THEN 0 
                       WHEN (SELECT YD_CTS_RELAY_YN FROM USRYFA.TB_YF_WRKBOOK  WHERE YD_WBOOK_ID=CS.YD_WBOOK_ID)='Y' 
                            AND CS.YD_SCH_CD LIKE '1_PT%' 
                       THEN 1 ELSE 2 END) AS CHK      
              , cs.YD_WBOOK_ID         
           FROM TB_YF_CRNSCH CS
              , TB_YF_CRNWRKMTL CM
          WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
            AND CS.DEL_YN = 'N'
            AND CM.DEL_YN = 'N'
            AND CS.YD_EQP_ID =  :V_YD_EQP_ID 
       ) A    
 ORDER BY SEQ1 DESC   --РлОїЛѓХТ
         --, SEQ3        --ТїЗЎПЌМгРлОї ПЉКЮ
         , YD_SCH_PRIOR
         , CHK         --ТїЗЎЧќЛѓУјСЄПЉКЮ
         , CASE WHEN SUBSTR(YD_SCH_CD,3,2) = 'PT' THEN YD_WBOOK_ID ELSE '0' END --ТїЗЎРЬ ПьМБ ЕЕТјЧб ДыЛѓ ПьМБ
         , CASE WHEN YD_SCH_CD LIKE '1CEC02LM' THEN DECODE(SUBSTR(A.YD_UP_WO_LOC, 7, 2),'01',1,'02',2, 3) ELSE 1 END
         , CASE WHEN YD_SCH_CD LIKE '1_DC01LM' THEN TO_NUMBER(YD_CRN_SCH_ID) * -1
                ELSE TO_NUMBER(YD_CRN_SCH_ID) END 
   )      
 WHERE ROWNUM = 1  
)

SELECT YD_CRN_SCH_ID
     , YD_EQP_ID 
     , YD_WRK_PROG_STAT
     , YD_UP_WO_LOC 
     , YD_DN_WO_LOC 
     , YD_SCH_CD
     , YD_SCH_PRIOR      
  FROM TB_YF_CRNSCH 
 WHERE YD_CRN_SCH_ID IN (
                        SELECT CASE WHEN YD_SCH_CD LIKE '1_DC01LM' AND YD_WRK_PROG_STAT = 'W' THEN MAX_YD_CRN_SCH_ID  
                                    WHEN YD_SCH_CD    = '1EKD02LM' AND YD_WRK_PROG_STAT = 'W' THEN MAX_YD_CRN_SCH_ID  
                               ELSE YD_CRN_SCH_ID END AS YD_CRN_SCH_ID
                          FROM TMP_TBL TB
                        )  
 </pre> */
public final static String getCrnSchAxYML007 = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchAxYML007";

 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getCrnSchAxYML007A
SELECT * 
  FROM
       ( SELECT CS.YD_CRN_SCH_ID
              , CS.YD_WRK_PROG_STAT
              , CS.YD_UP_WO_LOC 
              , CS.YD_DN_WO_LOC 
              , CS.YD_SCH_CD
              , NVL(SR.ADV_CRN_PRIOR,CS.YD_SCH_PRIOR)  AS YD_SCH_PRIOR
              , DECODE(CS.YD_WRK_PROG_STAT,'W','0','S','1', CS.YD_WRK_PROG_STAT) AS SEQ1
              , CASE WHEN CS.YD_SCH_PRIOR = 0  OR SR.ADV_CRN_PRIOR = 0         THEN 0 
                     WHEN CS.YD_CRN_GRAB_USE_RULE_ID = (SELECT YD_CRN_GRAB_USE_RULE_ID 
                                                          FROM TB_YF_CRNSCH 
                                                         WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
                                                           AND SUBSTR(YD_SCH_CD,3,2) = 'PT')     THEN 1  --ТїЗЎИИ
                     ELSE 2  END AS SEQ2 -- РЬРќ 
           FROM TB_YF_CRNSCH CS
              , TB_YF_CRNWRKMTL CM
              , TB_YF_SCHEDULERULE SR
          WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
            AND CS.YD_SCH_CD = SR.YD_SCH_CD
            AND CS.DEL_YN = 'N'
            AND CM.DEL_YN = 'N'
            AND CS.YD_EQP_ID =  :V_YD_EQP_ID 
          ORDER BY SEQ1 DESC, SEQ2, NVL(SR.ADV_CRN_PRIOR,CS.YD_SCH_PRIOR)
                 , CASE WHEN YD_SCH_CD = '3ADC01LM' THEN TO_NUMBER(YD_CRN_SCH_ID) * -1
                        ELSE TO_NUMBER(YD_CRN_SCH_ID) END 
       )    
 WHERE ROWNUM = 1
 </pre> */
public final static String getCrnSchAxYML007A = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getCrnSchAxYML007A";

