 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCoilCommonInfo
SELECT
    (CASE WHEN YD_GP ='1' THEN 'A' ELSE HR_PLNT_GP END) AS PLNT_GP,
    HR_PLNT_GP,     --АјРхБИКа
    REPLACE(PASS_PROC1, '6R', '6K') AS PASS_PROC1,
    REPLACE(PASS_PROC2, '6R', '6K') AS PASS_PROC2,
    REPLACE(PASS_PROC3, '6R', '6K') AS PASS_PROC3,
    REPLACE(PASS_PROC4, '6R', '6K') AS PASS_PROC4,
    REPLACE(PASS_PROC5, '6R', '6K') AS PASS_PROC5,
    ORD_NO,         --СІРлЙјШЃ
    ORD_DTL,        --СІРлЧрЙј
    COIL_T,         --ФкРЯЕЮВВ
    COIL_W,         --ФкРЯЦј
    CURR_COIL_LEN,  --ФкРЯБцРЬ
    COIL_INDIA,     --ФкРЯГЛАц
    COIL_OUTDIA,    --ФкРЯПмАц
    DECODE(COIL_WT, 0, NET_CAL_WT, COIL_WT) AS COIL_WT, -- ФкРЯСпЗЎ
    NEXT_PROC,      --ТїАјСЄ
    PLAN_PROC1,     --АшШЙАјСЄ
    BRANCH_CD,      --КаБтРЇФЁФкЕх
    EXTEND_CONVEYOR_BRANCH_CD,  --ШЎРхКаБтРЇФЁФкЕх
    HYSCO_TRANS_GP, --HYSCOРЬМлМіДм
    COOL_METHOD,    --ГУАЂЙцЙ§
    DECODE(CURR_PROG_CD, '2', 'H', '3', 'D', '4', 'E', '6', 'L', '7', 'K', CURR_PROG_CD) AS CURR_PROG_CD,
    RETURN_GP,
    YD_EQP_GP
FROM
    TB_PT_COILCOMM
WHERE 1=1
AND COIL_NO = :V_COIL_NO    --РчЗсЙјШЃ
 </pre> */
public final static String getCoilCommonInfo = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCoilCommonInfo";

