 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCStkLyr
WITH CSM AS
(
    SELECT
        CM.STL_NO,
        SUBSTR(CS.YD_UP_WO_LOC, 1, 6) AS YD_STK_COL_GP_UP,
        SUBSTR(CS.YD_UP_WO_LOC, 7, 2) AS YD_STK_BED_NO_UP,
        SUBSTR(CS.YD_DN_WO_LOC, 1, 6) AS YD_STK_COL_GP_DN,
        SUBSTR(CS.YD_DN_WO_LOC, 7, 2) AS YD_STK_BED_NO_DN,
        CS.YD_UP_WO_LYR AS YD_STK_LYR_GP,
        CS.YD_CRN_SCH_ID,
        CS.YD_TO_LOC_DCSN_MTD,
        CM.RNUM
    FROM
        TB_YF_CRNSCH CS,
        (
            SELECT
                CS.YD_CRN_SCH_ID,
                CM.STL_NO,
                ROW_NUMBER() OVER(PARTITION BY CM.STL_NO ORDER BY CS.YD_CRN_SCH_ID) AS RNUM
            FROM
                TB_YF_CRNSCH    CS,
                TB_YF_CRNWRKMTL CM
            WHERE 1=1
            AND CM.YD_CRN_SCH_ID  = CS.YD_CRN_SCH_ID
            AND CS.DEL_YN         = 'N'
            AND CM.DEL_YN         = 'N'
            AND CM.STL_NO IN
            (
                SELECT
                    STL_NO
                FROM
                    TB_YF_CRNWRKMTL
                WHERE 1=1
                AND DEL_YN = 'N'
                AND YD_WBOOK_ID = :V_YD_WBOOK_ID
            )
        ) CM
    WHERE 1=1
    AND CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
    AND CS.DEL_YN = 'N'
)
SELECT
    YD_STK_COL_GP,
    YD_STK_BED_NO,
    YD_STK_LYR_NO,
    MAX(STL_NO) AS STL_NO,
    MIN(YD_STK_LYR_STAT) AS YD_STK_LYR_STAT
FROM
    (
        --ПјЗЁРЇФЁ
        SELECT
            SL.YD_STK_COL_GP,
            SL.YD_STK_BED_NO,
            SL.YD_STK_LYR_NO,
            SL.STL_NO,
            'C' AS YD_STK_LYR_STAT --РћФЁСп
        FROM
            TB_YF_STKLYR SL,
            CSM
        WHERE 1=1
        AND SL.STL_NO     = CSM.STL_NO
        AND SL.YD_STK_COL_GP = CSM.YD_STK_COL_GP_UP
        AND SL.YD_STK_LYR_STAT = 'U' --БЧЛѓДыБт

        UNION ALL

        --БЧЧЯСіНУРЇФЁ
        SELECT
            SL.YD_STK_COL_GP,
            SL.YD_STK_BED_NO,
            SL.YD_STK_LYR_NO,
            NULL AS STL_NO,
            'E'  AS YD_STK_LYR_STAT --РћФЁАЁДЩ
        FROM
            TB_YF_STKLYR SL,
            CSM
        WHERE 1=1
        AND SL.STL_NO     = CSM.STL_NO
        AND SL.YD_STK_COL_GP = CSM.YD_STK_COL_GP_DN
        AND SL.YD_STK_BED_NO = CSM.YD_STK_BED_NO_DN
    )
GROUP BY YD_STK_COL_GP, YD_STK_BED_NO, YD_STK_LYR_NO
 </pre> */
public final static String getCrnWrkMgtSCStkLyr = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCStkLyr";

