 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getMvCarSch  
WITH MVCAR_SCH AS (
    SELECT A.YD_CAR_SCH_ID
          ,A.TRN_EQP_CD
          ,A.YD_CAR_PROG_STAT
          ,A.SPOS_WLOC_CD
          ,A.YD_PNT_CD1
          ,A.YD_CARLD_STOP_LOC
          ,A.ARR_WLOC_CD
          ,A.YD_PNT_CD3
          ,A.YD_CARUD_STOP_LOC
          ,CASE WHEN A.YD_CAR_PROG_STAT BETWEEN '1' AND '4' THEN A.YD_CARLD_WRK_BOOK_ID 
                WHEN A.YD_CAR_PROG_STAT BETWEEN 'A' AND 'D' THEN A.YD_CARUD_WRK_BOOK_ID 
                ELSE '' END AS CARSCH_YD_WBOOK_ID
     FROM  TB_YD_CARSCH A
    WHERE  A.DEL_YN = 'N'
      AND  A.YD_CAR_USE_GP = 'L'
      AND  ((A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') AND A.SPOS_WLOC_CD IN ('D2Y44','D2Y45')) --ЙкЦЧП­ПЌ ФкРЯ ЛѓТї
             OR 
            (A.YD_CAR_PROG_STAT IN ('5','A','B','C','D','E') AND A.ARR_WLOC_CD IN ('D2Y44','D2Y45'))) --ЙкЦЧП­ПЌ ФкРЯ ЧЯТї
)
SELECT ROWNUM AS RNUM
      ,A.*
FROM   (
            SELECT MC.YD_CAR_SCH_ID
                  ,MC.TRN_EQP_CD
                  ,MC.YD_CAR_PROG_STAT
                  ,MC.SPOS_WLOC_CD
                  ,MC.YD_PNT_CD1
                  ,MC.YD_CARLD_STOP_LOC
                  ,MC.ARR_WLOC_CD
                  ,MC.YD_PNT_CD3
                  ,MC.YD_CARUD_STOP_LOC
                  ,WB.YD_WBOOK_ID
                  ,WB.YD_SCH_CD
                  ,(SELECT MAX(CD_CONTENTS)
                      FROM TB_YF_SCHRULE
                     WHERE YD_SCH_CD =  WB.YD_SCH_CD) AS YD_SCH_CD_NM
                  ,(SELECT YD_CRN_SCH_ID
                      FROM TB_YF_CRNSCH
                     WHERE YD_WBOOK_ID IN (
                                           SELECT YD_WBOOK_ID 
                                             FROM TB_YF_WRKBOOK
                                            WHERE TRN_EQP_CD = MC.TRN_EQP_CD
                                              AND DEL_YN = 'N'
                                          )
                       AND DEL_YN = 'N'
                       AND ROWNUM = 1 
                   ) AS YD_CRN_SCH_ID
                  ,ROWNUM AS NO
            FROM   MVCAR_SCH MC
                  ,TB_YF_WRKBOOK WB
            WHERE  MC.CARSCH_YD_WBOOK_ID = WB.YD_WBOOK_ID(+)
            AND    WB.DEL_YN(+) = 'N'
            ORDER BY MC.TRN_EQP_CD
       ) A
 </pre> */
public final static String getMvCarSch = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getMvCarSch";

