 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getUsableLyrList2
--ЛчПыАЁДЩЧб Дм LYR
WITH PARAM AS
(
    SELECT
        :V_YD_STK_COL_GP AS P_YD_STK_COL_GP,
        :V_YD_STK_BED_NO AS P_YD_STK_BED_NO,
        CASE WHEN :V_ADD_NON_ACTIVE_YN = 'Y' THEN 'C' ELSE '' END AS P_ADD_NON_ACTIVE_YN
    FROM
        DUAL
)
SELECT DISTINCT
    YD_STK_LYR_NO AS CD_VAL,
    YD_STK_LYR_NO AS CD_NM
FROM
    TB_YF_STKLYR,
    PARAM
WHERE YD_STK_COL_GP = P_YD_STK_COL_GP --ОпЕх,ЕП,НКЦЧ,П­
  AND YD_STK_BED_NO LIKE DECODE(P_YD_STK_BED_NO,'*','%',P_YD_STK_BED_NO)
  AND YD_STK_LYR_ACTIVE_STAT IN ('E', P_ADD_NON_ACTIVE_YN )
  AND YD_STK_LYR_STAT IN ('E','C')
  AND DEL_YN = 'N'
  AND YD_STK_COL_GP LIKE '1%'
ORDER BY CD_VAL ASC
 </pre> */
