 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchStat
--ХЉЗЙРЮНКФЩСй ЛѓХТСЄКИ СЖШИ 
SELECT DISTINCT A.*
FROM
(
    SELECT
         COUNT(*) OVER()                                    AS TT_MTL_SH
        ,COUNT(DISTINCT WM.STL_NO) OVER()                   AS WM_MTL_SH
        ,COUNT(DISTINCT ST.STL_NO) OVER()                   AS ST_MTL_SH
        
        ,CASE WHEN WB.YD_SCH_CD LIKE '1__D__LM' OR WB.YD_SCH_CD LIKE '%E10UM' --МГКёУпУтНУ LYRПЁДТ РчЗсСЄКИ ОјРН
              THEN COUNT(DISTINCT WM.STL_NO) OVER() 
              ELSE COUNT(DISTINCT SL.STL_NO) OVER() END               AS SL_MTL_SH
        
        ,CASE WHEN WB.YD_SCH_CD LIKE '1__D__LM' OR WB.YD_SCH_CD LIKE '%E10UM' --МГКёУпУтНУ LYRПЁДТ РчЗсСЄКИ ОјРН
              THEN COUNT(DISTINCT WM.STL_NO) OVER() 
              ELSE SUM(DECODE(SL.YD_STK_LYR_STAT,'C',1,'U',1)) OVER() END AS STAT_C_SH --РћФЁСпРЮ РчЗсИХМі
              
        ,MAX(WM.YD_UP_COLL_SEQ) OVER()                      AS YD_UP_COLL_SEQ
        ,COUNT(CASE WHEN SL.YD_STK_COL_GP NOT LIKE SUBSTR(WB.YD_SCH_CD,1,2)||'%' AND SL.YD_STK_LYR_STAT ='C' 
                    THEN SL.STL_NO END) OVER()              AS AB_LOC_SH       --РњРхРЇФЁРЬЛѓ РчЗсИХМі
                    
        ,(SELECT 'Y'
            FROM TB_YF_CRANE_TRAVL_PROH CTP
           WHERE CTP.YD_GP  =SUBSTR(SL.YD_STK_COL_GP,1,1)
             AND CTP.BAY_GP =SUBSTR(SL.YD_STK_COL_GP,2,1)
             AND SUBSTR(SL.YD_STK_COL_GP,3,4) BETWEEN SUBSTR(CTP.TRAVL_PROH_FROMLOC,3,4) AND SUBSTR(CTP.TRAVL_PROH_TOLOC,3,4) 
             AND CTP.DEL_YN ='N'
             AND ROWNUM = 1  
          ) AS YM_CRANE_TRAVL_PROH
                   
        ,WB.YD_GP                                                   --ОпЕхБИКа
        ,WB.YD_BAY_GP                                               --ОпЕхЕПБИКа
        ,WB.YD_SCH_CD                                               --ОпЕхНКФЩСьФкЕх
        ,WB.YD_SCH_PRIOR                                            --ОпЕхНКФЩСьПьМБМјРЇ
        ,WB.YD_TO_LOC_DCSN_MTD                                      --ОпЕхToРЇФЁАсСЄЙцЙ§
        ,WB.YD_TO_LOC_GUIDE                                         --ОпЕхToРЇФЁGuide
        ,WB.YD_CAR_USE_GP                                           --ОпЕхТїЗЎЛчПыБИКа
        ,WB.TRN_EQP_CD                                              --ПюМлРхКёФкЕх
        ,WB.CAR_NO                                                  --ТїЗЎЙјШЃ
        ,WB.CARD_NO                                                 --ФЋЕхЙјШЃ
        ,TO_CHAR(WB.REG_DDTT,'YYYYMMDDHH24MISS') AS YD_WBOOK_DT     --ОпЕхРлОїПЙОрРЯНУ

        ,SR.YD_SCH_PROH_EXN                                         --ОпЕхНКФЩСьБнСіРЏЙЋ
        ,SR.YD_WRK_CRN                                              --ОпЕхРлОїХЉЗЙРЮ
        ,SR.YD_WRK_CRN_PRIOR                                        --ОпЕхРлОїХЉЗЙРЮПьМБМјРЇ
        ,SR.YD_ALT_CRN                                              --ОпЕхДыУМХЉЗЙРЮ
        ,SR.YD_ALT_CRN_PRIOR                                        --ОпЕхДыУМХЉЗЙРЮПьМБМјРЇ

        ,E0.YD_EQP_PROG_STAT        AS YD_EQP_STAT_PLN              --РлОїАшШЙХЉЗЙРЮ ОпЕхМГКёЛѓХТ
        ,E0.YD_EQP_WRK_MODE         AS YD_EQP_WRK_MODE_PLN          --РлОїАшШЙХЉЗЙРЮ ОпЕхМГКёРлОїMode
        ,E1.YD_EQP_PROG_STAT        AS YD_EQP_STAT_WRK              --РлОїХЉЗЙРЮ ОпЕхМГКёЛѓХТ
        ,E1.YD_EQP_WRK_MODE         AS YD_EQP_WRK_MODE_WRK          --РлОїХЉЗЙРЮ ОпЕхМГКёРлОїMode
        ,E2.YD_EQP_PROG_STAT        AS YD_EQP_STAT_ALT              --ДыУМХЉЗЙРЮ ОпЕхМГКёЛѓХТ
        ,E2.YD_EQP_WRK_MODE         AS YD_EQP_WRK_MODE_ALT          --ДыУМХЉЗЙРЮ ОпЕхМГКёРлОїMode
        ,'N'                        AS CM_DUP_YN                    -- ХЉЗЙРЮНКФЩСй РчЗсСпКЙПЉКЮ
        ,'N'                        AS CL_DUP_GP                    -- ХЉЗЙРЮНКФЩСй РњРхРЇФЁСпКЙПЉКЮ

        ,CASE WHEN (WB.YD_SCH_CD LIKE '1_TC__UM' OR WB.YD_SCH_CD LIKE '1_YD__MM')  THEN WB.YD_WRK_PLAN_CRN 
              ELSE '' END AS YD_WRK_PLAN_CRN 
              
        ,CASE WHEN WB.YD_SCH_CD LIKE '__PT__U_' THEN 'C'  --ТїЗЎЛѓТї
              WHEN WB.YD_SCH_CD LIKE '__TC__U_' THEN 'T'  --ДыТїЛѓТї
              WHEN LENGTH(WB.YD_TO_LOC_GUIDE) >= 4 AND WB.YD_TO_LOC_GUIDE LIKE WB.YD_GP||WB.YD_BAY_GP||'%' THEN 'G' --SpanБИКа РЬЛѓРЬИщ
              ELSE 'Z' END AS TO_LOC_CHK_GP                            --ToРЇФЁСЁАЫБИКа

        ,CASE WHEN WB.REGISTER = 'AUTO_MV_A' THEN 'A'    -- ГУАЂДѕЙЬ
              WHEN WB.REGISTER = 'AUTO_MV_B' THEN 'B'    -- МГКёДѕЙЬ
              WHEN WB.REGISTER = 'AUTO_MV_C' THEN 'C' 
              ELSE ''
              END   AS WB_REGISTER 
         
        ,CASE WHEN SL.YD_STK_LYR_NO = '02' THEN 'N' 
              ELSE (SELECT CASE WHEN SUM(DECODE(S2.YD_STK_LYR_STAT,'D',1)) > 0 THEN 'Y' ELSE 'N' END
                      FROM TB_YF_STKLYR S2
                     WHERE S2.YD_STK_COL_GP = SL.YD_STK_COL_GP 
                       AND S2.YD_STK_LYR_NO = '02'
                       AND S2.YD_STK_BED_NO IN (SL.YD_STK_BED_NO, 
                                                CASE WHEN SL.YD_STK_LYR_NO = '01' THEN LPAD(TO_NUMBER(SL.YD_STK_BED_NO)-1,2,'0') END)
                    )
              END AS UP_DN_GP --ЛѓДм БЧЧЯ ДыЛѓ ПЉКЮ
    FROM TB_YF_WRKBOOK          WB
        ,TB_YF_WRKBOOKMTL       WM
        ,TB_YF_STOCK            ST
        ,TB_YF_SCHRULE          SR
        ,TB_YF_EQP              E0
        ,TB_YF_EQP              E1
        ,TB_YF_EQP              E2
        ,(SELECT * 
            FROM TB_YF_STKLYR 
           WHERE YD_STK_LYR_STAT IN ('C','U')
         ) SL --МГКёУпУтНУ LYRПЁДТ РчЗсСЄКИ ОјРН
    WHERE WB.YD_WBOOK_ID        = :V_YD_WBOOK_ID
      AND WB.YD_WBOOK_ID        = WM.YD_WBOOK_ID(+)
      AND WM.STL_NO             = ST.STL_NO(+)
      AND WM.STL_NO             = SL.STL_NO(+)
      AND WB.YD_SCH_CD          = SR.YD_SCH_CD
      AND WB.YD_WRK_PLAN_CRN    = E0.YD_EQP_ID(+)
      AND SR.YD_WRK_CRN         = E1.YD_EQP_ID(+)
      AND SR.YD_ALT_CRN         = E2.YD_EQP_ID(+)
      AND WB.DEL_YN             = 'N'
      AND WM.DEL_YN(+)          = 'N'
      AND SL.DEL_YN(+)          = 'N'
      AND SR.DEL_YN(+)          = 'N'
      AND E1.DEL_YN(+)          = 'N'
      AND E2.DEL_YN(+)          = 'N'
      AND E0.DEL_YN(+)          = 'N'
)  A
 </pre> */
public final static String getCrnSchStat = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnSchStat";

