 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilCarWrkMgtjm.getCoilYdGdsOutCarCoilNEW2 
WITH TEMP_TABLE AS (
    SELECT 'D2Y44'AS SPOS_WLOC_CD, '1' AS YD_GP FROM DUAL UNION ALL
    SELECT 'D2Y45'AS SPOS_WLOC_CD, '1' AS YD_GP FROM DUAL
),
PARAM AS (
    SELECT :V_YD_GP             AS V_YD_GP
          ,:V_YD_BAY_GP         AS V_YD_BAY_GP
          --,:V_YD_WLOC_CD        AS V_WLOC_CD
          ,:V_LDTRN_CAR_STAT_CD AS V_LDTRN_CAR_STAT_CD
          ,:V_ORDERBY           AS V_ORDERBY
      FROM DUAL
),
TEMP_TABLE_DM AS (
    --//ДыБтРх BACKUPУГИЎ ДыЛѓ                                                          
    SELECT NVL(SUBSTR(CMBN_CARLD_NO,1,8),TRANS_WORD_DATE) AS TRANS_WORD_DATE
          ,TO_NUMBER(NVL(SUBSTR(CMBN_CARLD_NO,9,7),TRANS_WORD_SEQNO)) AS  TRANS_WORD_SEQNO 
          ,YD_GP 
          ,TRANS_MEANS_GP
          ,DRIVER_TEL_NO 
          ,DRIVER_NAME 
          ,LDTRN_CAR_STAT_CD 
          ,CARD_NO 
          ,CAR_NO
     FROM TB_DM_TRANSWORDCOMM A 
         ,PARAM P
    WHERE A.TRANS_WORD_DATE >= TO_CHAR(SYSDATE-1,'YYYYFMDD')
      AND A.YD_GP = P.V_YD_GP
      AND A.DEL_YN='N'
      AND A.LDTRN_CAR_STAT_CD  IN('R2','R3' ,'R4','R5')  -- ЕЕТјДыБт 
    UNION
   SELECT NVL(SUBSTR(CMBN_CARLD_NO,1,8),FRTOMOVE_WORD_DATE) AS FRTOMOVE_WORD_DATE
         ,TO_NUMBER(NVL(SUBSTR(CMBN_CARLD_NO,9,7),FRTOMOVE_WORD_SEQNO)) AS  TRANS_WORD_SEQNO 
         ,YD_GP 
         ,TRANS_MEANS_GP
         ,DRIVER_TEL_NO 
         ,DRIVER_NAME 
         ,LDTRN_CAR_STAT_CD 
         ,CARD_NO 
         ,CAR_NO
     FROM TB_DM_COILFRTOMOVEWORDCOMM A 
         ,PARAM P
    WHERE A.FRTOMOVE_WORD_DATE >= TO_CHAR(SYSDATE-1,'YYYYFMDD')
      AND A.YD_GP = P.V_YD_GP
      AND A.DEL_YN='N'
      AND A.LDTRN_CAR_STAT_CD  IN('R2','R3' ,'R4','R5')  -- ЕЕТјДыБт  
)
SELECT A.*
      ,(SELECT Z.CD_MNNG
          FROM VW_CM_CODES Z
         WHERE Z.CD_EN_ID = 'YD_CAR_PROG_STAT'
           AND Z.CD_CAT_ID = 'HS0000'
           AND Z.CD_VAL = A.YD_CAR_PROG_STAT) AS YD_CAR_PROG_STAT_NM
      ,B.YD_STK_COL_GP
      ,B.WLOC_CD
      ,B.YD_PNT_CD
      ,NVL(( 
         SELECT 'N'
           FROM TB_YF_STKCOL CC
             , TB_YF_STKLYR DD
             , TB_YF_WRKBOOK EE
             , TB_YF_WRKBOOKMTL FF
          WHERE CC.YD_STK_COL_GP=DD.YD_STK_COL_GP
           AND EE.YD_WBOOK_ID =FF.YD_WBOOK_ID                         
           AND DD.STL_NO=FF.STL_NO
           AND NVL(EE.DEL_YN,'N') ='N'
           AND NVL(FF.DEL_YN,'N') ='N'
           AND (CC.CARD_NO=A.CARD_NO OR  CC.TRN_EQP_CD=A.TRN_EQP_CD)
           AND ROWNUM<=1),'Y') AS COLLOR_YN 
      ,SP.YD_WRK_ALW_SH
      ,SP.YD_WRK_ALW_WT
      ,A.YD_CARPNT_CD || CASE SUBSTR(A.YD_CARPNT_CD,2,1)
                            WHEN  '1' THEN '(L)'
                            WHEN  '2' THEN CASE WHEN A.YD_BAY = 'H' THEN '(L)' ELSE '(R)' END
                            WHEN  '3' THEN '(R)' END AS YD_CARPNT_CD_NM
  FROM (
        ---------------------------------------------------------------------
         SELECT '1' AS chk 
                ,SUBSTR(C.YD_CARPNT_CD,2,1) AS YD_ENTRY --ХыЗЮ
                ,SUBSTR(C.YD_CARPNT_CD,3,1) AS YD_BAY --ЕП
                ,C.YD_CARPNT_CD
                ,NVL(A.CAR_NO,A.TRN_EQP_CD) AS CAR_NO 
                ,A.CARD_NO
                ,A.TRN_EQP_CD                
                ,(CASE WHEN A.TRN_EQP_CD IS NULL 
                       THEN DECODE(A.YD_CAR_WRK_GP ,'1','ГЛМі','2','МіУт','3','ПЌОШЧиМл','9','ГУПЌНКФЩСй','ГЛМі')
                       ELSE 'БИГЛПюМл' END) AS YD_CAR_USE_NM
                ,A.YD_CAR_WRK_GP AS YD_CAR_USE_GP       
                ,D.LDTRN_CAR_STAT_CD --ТїЗЎSTS
                ,A.YD_CAR_PROG_STAT--СјЧрЛѓХТ
                ,A.ARR_WLOC_CD --ТјСіАГМв
                ,CASE WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN
                (
                      ( 
                      SELECT  COUNT(*)
                         FROM USRYFA.TB_YF_STOCK CC
                        WHERE (CC.TRANS_ORD_DATE = A.TRANS_ORD_DATE AND CC.TRANS_ORD_SEQNO = A.TRANS_ORD_SEQNO)
                           --OR (CC.FRTOMOVE_WORD_NO = B.FRTOMOVE_WORD_NO) 
                      )
                      + 
                      ( 
                      SELECT  COUNT(*)
                         FROM USRYFA.TB_YF_STOCK CC
                        WHERE   (CC.FRTOMOVE_WORD_NO = A.FRTOMOVE_WORD_NO) 
                      )
                      + 
                      --КЙМі УЂАэ     
                      ( SELECT COUNT(*)
                         FROM TB_YD_STOCK CC
                        WHERE (CC.TRANS_ORD_DATE = A.TRANS_ORD_DATE AND CC.TRANS_ORD_SEQNO = A.TRANS_ORD_SEQNO)
                        AND CC.CAR_NO = NVL(A.CAR_NO,A.TRN_EQP_CD)
                      )
--                     +
--                      (SELECT COUNT(*)
--                           FROM TB_YF_WRKBOOK M
--                               , TB_YF_WRKBOOKMTL M1
--                          WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
--                          AND  M.TRN_EQP_CD = A.TRN_EQP_CD
--                          AND M.DEL_YN = 'N'
--                          AND M1.DEL_YN = 'N'
--                      )
                 )
                  ELSE
                    (SELECT COUNT(*)  FROM TB_YD_CARFTMVMTL H  WHERE H.YD_CAR_SCH_ID = A.YD_CAR_SCH_ID)
                 END AS YD_PLN_WRK_SH   --РлОїАшШЙИХМі
                ,CASE WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN
                    (
                          ( 
                              SELECT  NVL(SUM(G.COIL_WT) ,0)
                                 FROM USRYFA.TB_YF_STOCK CC, TB_PT_COILCOMM G
                                WHERE (CC.TRANS_ORD_DATE = A.TRANS_ORD_DATE AND CC.TRANS_ORD_SEQNO = A.TRANS_ORD_SEQNO)
                                AND CC.STL_NO=G.COIL_NO
                                   --OR (CC.FRTOMOVE_WORD_NO = B.FRTOMOVE_WORD_NO) 
                          )
                          + 
                          ( 
                              SELECT  NVL(SUM(G.COIL_WT) ,0)
                                 FROM USRYFA.TB_YF_STOCK CC, TB_PT_COILCOMM G
                                WHERE   (CC.FRTOMOVE_WORD_NO = A.FRTOMOVE_WORD_NO) 
                                AND CC.STL_NO=G.COIL_NO
                          )
                          + 
                          --КЙМі УЂАэ     
                          (
                            SELECT NVL(SUM(G.COIL_WT) ,0)
                             FROM TB_YD_STOCK CC, TB_PT_COILCOMM G
                            WHERE (CC.TRANS_ORD_DATE = A.TRANS_ORD_DATE AND CC.TRANS_ORD_SEQNO = A.TRANS_ORD_SEQNO)
                            AND CC.STL_NO=G.COIL_NO
                          )
                         
--                         +
--                          (
--                               SELECT NVL(SUM(G.COIL_WT) ,0)
--                               FROM TB_YF_WRKBOOK M
--                                   , TB_YF_WRKBOOKMTL M1
--                                   , TB_PT_COILCOMM G
--                              WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
--                              AND  M.TRN_EQP_CD = A.TRN_EQP_CD
--                              AND M1.STL_NO=G.COIL_NO
--                              AND M.DEL_YN = 'N'
--                              AND M1.DEL_YN = 'N'
--                          )
                    )
                 ELSE
                    (SELECT NVL(SUM(G.COIL_WT) ,0)  FROM TB_YD_CARFTMVMTL H, TB_PT_COILCOMM G  WHERE H.YD_CAR_SCH_ID = A.YD_CAR_SCH_ID AND  H.STL_NO=G.COIL_NO  )
                 END  AS YD_PLN_MTL_WT_SUM --РлОїАшШЙСпЗЎ  
                ,( 
                    SELECT COUNT(*) 
                     FROM  TB_YD_CARFTMVMTL H 
                    WHERE H.DEL_YN = CASE WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN 'N' ELSE 'Y' END
                      AND H.YD_CAR_SCH_ID=A.YD_CAR_SCH_ID 
                      AND H.YD_STK_BED_NO IS NOT NULL
                 ) AS YD_WRK_SH --РлОїНЧРћИХМі
                ,(
                    NVL((SELECT SUM(COIL_WT) 
                           FROM TB_YD_CARFTMVMTL H
                              , TB_PT_COILCOMM G 
                              , PARAM P
                          WHERE H.DEL_YN = CASE WHEN A.YD_CAR_PROG_STAT IN ('1','2','3','4','5') THEN 'N' ELSE 'Y' END
                            AND H.YD_CAR_SCH_ID=A.YD_CAR_SCH_ID 
                            AND H.STL_NO=G.COIL_NO
                            AND H.YD_STK_BED_NO IS NOT NULL
                            AND B.YD_GP = P.V_YD_GP
                            ),0)
                 ) AS YD_MTL_WT_SUM --РлОїНЧРћСпЗЎ
                ,A.YD_CAR_SCH_ID
                ,A.TRANS_ORD_DATE AS TRANS_ORD_DT 
                ,A.TRANS_ORD_SEQNO
                ,NVL(E.DRIVER_NAME,' ')||'['||NVL(E.DRIVER_TEL_NO,' ')||']' AS TEL_NO
                ,NVL(A.TEL_NO,' ') AS  TEL_NUMBER
                ,A.DRIVER_NAME
                ,D.TRANS_MEANS_GP AS WORK_GP
                ,TO_CHAR(A.YD_CARLD_ARR_DT,'YYYY-MM-DD HH24:MI:SS')    as YD_CARLD_ARR_DT
                ,A.WAIT_ARR_DDTT
                ,A.WAIT_ARR_GP
                ,A.CMBN_CARLD_YN
                ,C.YD_GP
                ,F.YD_MSG_NM
           FROM TB_YD_CARSCH A
              , TEMP_TABLE B
              , TB_YD_CARPOINT C
              , TB_DM_TRANSWORDCOMM D
              , TEMP_TABLE_DM E
              ,( SELECT YD_CAR_SCH_ID,YD_MSG_NM
                    FROM 
                         (SELECT last_value(YD_MSG_NM) over(partition by YD_CAR_SCH_ID ORDER BY  YD_CAR_SCH_ID,YF_CARSCHLOG_SEQ
                                                     ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) YD_MSG_NM
                                ,YD_CAR_SCH_ID
                                ,COUNT(*) OVER(partition by YD_CAR_SCH_ID ORDER BY  YD_CAR_SCH_ID,YF_CARSCHLOG_SEQ) CNT
                           FROM TB_YF_CARSCHLOG 
                           WHERE  NVL(DEL_YN,'N') ='N'
                             AND YD_MSG_NM NOT LIKE '%РдЕПЦїРЮЦЎ%' ) TEMP
                    WHERE CNT =1) F    
               ,PARAM P
              
          WHERE --A.SPOS_WLOC_CD=B.SPOS_WLOC_CD
                (CASE WHEN A.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN A.SPOS_WLOC_CD ELSE A.ARR_WLOC_CD END) 
              = B.SPOS_WLOC_CD
          
            AND A.TRANS_ORD_DATE =E.TRANS_WORD_DATE(+)
            AND A.TRANS_ORD_SEQNO=E.TRANS_WORD_SEQNO(+)
            AND (CASE WHEN A.YD_CAR_PROG_STAT IN('1','2','3','4','5') THEN YD_CARLD_STOP_LOC ELSE YD_CARUD_STOP_LOC END) 
              = (CASE WHEN A.SPOS_WLOC_CD IN ('D2Y44','D2Y45') THEN REPLACE(C.YD_STK_COL_GP(+),'TR1','TR0') ELSE C.YD_STK_COL_GP(+) END)  
            AND A.TRANS_ORD_DATE =D.TRANS_WORD_DATE(+)
            AND A.TRANS_ORD_SEQNO=D.TRANS_WORD_SEQNO(+)
            AND A.YD_CAR_SCH_ID =F.YD_CAR_SCH_ID(+)
            AND B.YD_GP = P.V_YD_GP
            AND NVL(C.YD_BAY_GP,' ') LIKE P.V_YD_BAY_GP || '%'
            AND NVL(C.WLOC_CD,' ') IN ( SELECT SPOS_WLOC_CD FROM TEMP_TABLE)
            AND NVL(D.LDTRN_CAR_STAT_CD,' ') LIKE P.V_LDTRN_CAR_STAT_CD||'%'
            AND A.DEL_YN='N'

       ) A
      ,TB_YD_CARPOINT B
      ,PARAM P
      ,
       (
             SELECT
                *
             FROM
             (
                 SELECT 
                    ROW_NUMBER() OVER(PARTITION BY TRN_EQP_CD ORDER BY YD_CAR_REG_SEQ DESC) AS RN
                    , SP.TRN_EQP_CD
                    , SP.YD_WRK_ALW_SH
                    , SP.YD_WRK_ALW_WT
                 FROM TB_YD_CARSPEC SP
                 WHERE DEL_YN = 'N'
             )
             WHERE RN = 1
       ) SP
 WHERE A.YD_CARPNT_CD = B.YD_CARPNT_CD(+)   
 AND A.TRN_EQP_CD = SP.TRN_EQP_CD(+)
 </pre> */
public final static String getCoilYdGdsOutCarCoilNEW2 = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilCarWrkMgtjm.getCoilYdGdsOutCarCoilNEW2";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfStkcol
SELECT YD_STK_COL_GP                            AS YD_STK_COL_GP
	  ,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS')    AS REG_DDTT
	  ,REGISTER                                 AS REGISTER
	  ,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS')    AS MOD_DDTT
	  ,MODIFIER                                 AS MODIFIER
	  ,DEL_YN                                   AS DEL_YN
	  ,YD_GP                                    AS YD_GP
      ,(SELECT YD_STK_COL_ACT_STAT 
          FROM USRYDA.TB_YD_CARPOINT B
         WHERE B.YD_STK_COL_GP=A.YD_STK_COL_GP   
           AND ROWNUM<=1 )                      AS YD_STK_COL_ACT_STAT  
      ,YD_CAR_USE_GP                            AS YD_CAR_USE_GP
      ,TRN_EQP_CD                               AS TRN_EQP_CD
      ,CAR_NO                                   AS CAR_NO
      ,CARD_NO                                  AS CARD_NO       
      ,WLOC_CD                                  AS WLOC_CD
      ,YD_PNT_CD                                AS YD_PNT_CD
FROM TB_YF_STKCOL A
WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
  AND DEL_YN ='N'
 </pre> */
public final static String getYfStkcol = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfStkcol";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdCarsch
SELECT
    YD_CAR_SCH_ID                                   AS YD_CAR_SCH_ID,
    REGISTER                                        AS REGISTER,
    TO_CHAR(REG_DDTT,'YYYYMMDDHH24MISS')            AS REG_DDTT,
    MODIFIER                                        AS MODIFIER,
    TO_CHAR(MOD_DDTT,'YYYYMMDDHH24MISS')            AS MOD_DDTT,
    DEL_YN                                          AS DEL_YN,
    YD_EQP_ID                                       AS YD_EQP_ID,
    YD_CAR_USE_GP                                   AS YD_CAR_USE_GP,
    CAR_NO                                          AS CAR_NO,
    TRN_EQP_CD                                      AS TRN_EQP_CD,
    CAR_KIND                                        AS CAR_KIND,
    TRANS_EQUIPMENT_TYPE                            AS TRANS_EQUIPMENT_TYPE,
    YD_EQP_WRK_STAT                                 AS YD_EQP_WRK_STAT,
    YD_WRK_PROG_STAT                                AS YD_WRK_PROG_STAT,
    NVL(YD_EQP_WRK_SH, '0')                         AS YD_EQP_WRK_SH,
    YD_EQP_WRK_WT                                   AS YD_EQP_WRK_WT,
    YD_STK_BED_TP                                   AS YD_STK_BED_TP,
    SPOS_WLOC_CD                                    AS SPOS_WLOC_CD,
    (
        CASE
        WHEN ARR_WLOC_CD IS NULL THEN
        (
            SELECT
                (
                    SELECT --+ INDEX(D PK_PT_STLFRTOMOVE)
                        D.ARR_WLOC_CD
                    FROM
                        TB_PT_STLFRTOMOVE D
                    WHERE 1=1
                    AND D.TRANSWORD_SEQNO =
                    (
                        SELECT--+ INDEX_DESC(D PK_PT_STLFRTOMOVE)
                            MAX(TRANSWORD_SEQNO)
                        FROM
                            TB_PT_STLFRTOMOVE K
                        WHERE 1=1
                        AND D.STL_NO = K.STL_NO
                        AND ROWNUM <= 1
                    )
                    AND B.STL_NO = D.STL_NO
                ) AS ARR_WLOC_CD
            FROM
                TB_YD_STKLYR B
            WHERE 1=1
            AND C.YD_CARLD_STOP_LOC = B.YD_STK_COL_GP
            AND ROWNUM <= 1
        )
        ELSE ARR_WLOC_CD END
    )                                               AS ARR_WLOC_CD,
    YD_CARLD_LEV_LOC                                AS YD_CARLD_LEV_LOC,
    TO_CHAR(YD_CARLD_LEV_DT,'YYYYMMDDHH24MISS')     AS YD_CARLD_LEV_DT,
    TO_CHAR(YD_CARLD_PNT_WO_DT,'YYYYMMDDHH24MISS')  AS YD_CARLD_PNT_WO_DT,
    YD_PNT_CD1                                      AS YD_PNT_CD1,
    YD_PNT_CD2                                      AS YD_PNT_CD2,
    YD_CARLD_WRK_BOOK_ID                            AS YD_CARLD_WRK_BOOK_ID,
    YD_CARLD_SCH_REQ_GP                             AS YD_CARLD_SCH_REQ_GP,
    YD_CARLD_STOP_LOC                               AS YD_CARLD_STOP_LOC,
    TO_CHAR(YD_CARLD_ARR_DT,'YYYYMMDDHH24MISS')     AS YD_CARLD_ARR_DT,
    TO_CHAR(YD_CARLD_ST_DT,'YYYYMMDDHH24MISS')      AS YD_CARLD_ST_DT,
    TO_CHAR(YD_CARLD_CMPL_DT,'YYYYMMDDHH24MISS')    AS YD_CARLD_CMPL_DT,
    YD_CARLD_WRK_ACT_GP                             AS YD_CARLD_WRK_ACT_GP,
    TO_CHAR(YD_CARLD_CHK_DT,'YYYYMMDDHH24MISS')     AS YD_CARLD_CHK_DT,
    TO_CHAR(YD_CARUD_LEV_DT,'YYYYMMDDHH24MISS')     AS YD_CARUD_LEV_DT,
    TO_CHAR(YD_CARUD_PNT_WO_DT,'YYYYMMDDHH24MISS')  AS YD_CARUD_PNT_WO_DT,
    YD_PNT_CD3                                      AS YD_PNT_CD3,
    YD_PNT_CD4                                      AS YD_PNT_CD4,
    YD_CARUD_WRK_BOOK_ID                            AS YD_CARUD_WRK_BOOK_ID,
    YD_CARUD_STOP_LOC                               AS YD_CARUD_STOP_LOC,
    YD_CARUD_SCH_REQ_GP                             AS YD_CARUD_SCH_REQ_GP,
    TO_CHAR(YD_CARUD_ARR_DT,'YYYYMMDDHH24MISS')     AS YD_CARUD_ARR_DT,
    TO_CHAR(YD_CARUD_CHK_DT,'YYYYMMDDHH24MISS')     AS YD_CARUD_CHK_DT,
    TO_CHAR(YD_CARUD_ST_DT,'YYYYMMDDHH24MISS')      AS YD_CARUD_ST_DT,
    TO_CHAR(YD_CARUD_CMPL_DT,'YYYYMMDDHH24MISS')    AS YD_CARUD_CMPL_DT,
    YD_CARUD_WRK_ACT_GP                             AS YD_CARUD_WRK_ACT_GP,
    YD_TRN_WRK_DELY_CD                              AS YD_TRN_WRK_DELY_CD,
    CARD_NO                                         AS CARD_NO,
    YD_CAR_PROG_STAT                                AS YD_CAR_PROG_STAT,
    FRTOMOVE_PLANT_GP                               AS FRTOMOVE_PLANT_GP,
    PROC_TO                                         AS PROC_TO,
    RENTPROC_CD                                     AS RENTPROC_CD,
    YD_FRTOMOVE_YD_GP                               AS YD_FRTOMOVE_YD_GP,
    YD_FRTOMOVE_BAY_GP                              AS YD_FRTOMOVE_BAY_GP,
    URGENT_FRTOMOVE_WORD_GP                         AS URGENT_FRTOMOVE_WORD_GP,
    DEST_TEL_NO                                     AS DEST_TEL_NO,
    YD_DLVRDD_RULE_DD                               AS YD_DLVRDD_RULE_DD,
    SHIPASSIGN_WORD_DATE                            AS SHIPASSIGN_WORD_DATE,
    SHIPASSIGN_WORD_SEQNO                           AS SHIPASSIGN_WORD_SEQNO,
    SHIP_CD                                         AS SHIP_CD,
    SHIP_NAME                                       AS SHIP_NAME,
    RSHP_HOLD_NO                                    AS RSHP_HOLD_NO,
    BERTH_NO                                        AS BERTH_NO,
    SAILNO                                          AS SAILNO,
    YD_CAR_WRK_GP                                   AS YD_CAR_WRK_GP,
    TRANS_ORD_DATE                                  AS TRANS_ORD_DATE,
    TRANS_ORD_SEQNO                                 AS TRANS_ORD_SEQNO,
    YD_BAYIN_WO_SEQ,
    YD_CAR_RCPT_CHK_YN,
    YD_CAR_ISSUE_CHK_YN,
    YD_CAR_RCPT_CHECKER,
    YD_CAR_ISSUE_CHECKER,
    SUBSTR(YD_CARLD_STOP_LOC, 1, 1)                 AS YD_GP,
    (
        SELECT
            COUNT(*)
        FROM
            TB_YD_CRNSCH
        WHERE 1=1
        AND YD_WBOOK_ID = YD_CARLD_WRK_BOOK_ID
        AND DEL_YN = 'N'
    )                                               AS YD_CRN_SCH_ID,
    (
        SELECT
            E.CR_FRTOMOVE_GP
        FROM
            TB_YD_CARFTMVMTL D,
            TB_YF_STOCK E
        WHERE 1=1
        AND D.YD_CAR_SCH_ID = C.YD_CAR_SCH_ID
        AND D.STL_NO = E.STL_NO
        AND ROWNUM = 1
     )                                              AS CR_FRTOMOVE_GP
FROM
    TB_YD_CARSCH C
WHERE 1=1
AND YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String getYdCarsch = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdCarsch";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getRetnTrgtGds 
-- ЙнЧА/ШИМл ДыЛѓ СЖШИ 
WITH PARAM AS (
SELECT :V_CAR_NO          AS P_CAR_NO
     , :V_TRANS_ORD_DATE  AS P_TRANS_ORD_DATE
     , :V_TRANS_ORD_SEQNO AS P_TRANS_ORD_SEQNO
  FROM DUAL     
)
SELECT RNUM
     , LPAD(RNUM, 2, '0') AS YD_STK_BED_NO
     , COIL_NO AS STL_NO
     , CURR_PROG_CD
     , ORD_NO
     , ORD_DTL
     , SPEC_ABBSYM
     , COIL_T
     , COIL_W
     , COIL_WT
     , COIL_OUTDIA
     , COIL_LEN
  FROM (
        SELECT CC.*
             , RN
          FROM TB_PT_COILCOMM  CC
             , (
                SELECT ROW_NUMBER() OVER(PARTITION BY YD_CAR_SCH_ID ORDER BY YD_STK_BED_NO) AS RN
                     , CM.*
                  FROM USRYDA.TB_YD_CARFTMVMTL  CM
                 WHERE YD_CAR_SCH_ID IN (
                                         SELECT YD_CAR_SCH_ID
                                           FROM (
                                                 SELECT YD_CAR_SCH_ID
                                                   FROM USRYDA.TB_YD_CARSCH
                                                      , PARAM
                                                  WHERE 1 = 1
                                                    AND TRANS_ORD_DATE BETWEEN TO_CHAR(SYSDATE-3,'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD')
                                                    AND ((CAR_NO = P_CAR_NO OR SUBSTR(CAR_NO, -4) = P_CAR_NO)  AND P_TRANS_ORD_DATE IS NULL)
                                                     OR (TRANS_ORD_DATE = P_TRANS_ORD_DATE AND TRANS_ORD_SEQNO = P_TRANS_ORD_SEQNO)
                                                  ORDER BY YD_CAR_SCH_ID DESC
                                                )
                                          WHERE ROWNUM = 1       
                                        )
               ) MTL
         WHERE CC.COIL_NO = MTL.STL_NO
       ) A
     , (SELECT ROWNUM AS RNUM
          FROM DUAL
       CONNECT BY LEVEL <= 15
       ) R
 WHERE R.RNUM = A.RN(+)
 </pre> */
public final static String getRetnTrgtGds = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getRetnTrgtGds";

