 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getWbIdAxYML007   
SELECT *
  FROM (
        SELECT A.YD_WBOOK_ID
             , A.YD_SCH_CD
             , A.YD_SCH_CD_CNT
             , A.YD_SCH_CD_YN
             , A.YD_WRK_PLAN_TCAR
             , A.YD_WRK_PLAN_CRN
          FROM (
                SELECT YD_WBOOK_ID
                     , YD_SCH_CD
                     , SUM(1) OVER(PARTITION BY YD_SCH_CD) AS YD_SCH_CD_CNT 
                     , 'Y'  AS YD_SCH_CD_YN 
                     , YD_WRK_PLAN_TCAR
                     , YD_WRK_PLAN_CRN
                     , SCH_CNCL_YN
                     , (SELECT YD_SCH_AUTO_ST_YN 
                          FROM TB_YF_SCHRULE 
                         WHERE YD_SCH_CD = WB.YD_SCH_CD 
                           AND DEL_YN = 'N') AS YD_SCH_AUTO_ST_YN --НКФЩСйКА РкЕПБтЕППЉКЮ DEFAULT Y
                  FROM TB_YF_WRKBOOK WB
                 WHERE DEL_YN = 'N'
                                 --ДыТїЛѓТї РЮ АцПь
                   AND 1 =  CASE WHEN WB.YD_SCH_CD LIKE '1_TC__UM%' AND WB.YD_WRK_PLAN_TCAR = '1XTC03' THEN
                                      --ЧіРћРчИХМі >= МГКёУжДыРћРчИХМі РЬИщ СІПм
                                 CASE WHEN (SELECT COUNT(*) 
                                              FROM TB_YF_STKLYR 
                                             WHERE YD_STK_COL_GP = SUBSTR(WB.YD_SCH_CD,1,2)||SUBSTR(WB.YD_WRK_PLAN_TCAR,3,4)
                                               AND STL_NO IS NOT NULL) >= (SELECT STK_MAX_QNTY FROM TB_YF_EQP WHERE YD_EQP_ID = WB.YD_WRK_PLAN_TCAR )
                                      THEN '2'
                                      --ДыТїЧЯТїСЄСіРЇФЁ != РлОїПЙОрИёРћЕП РЬИщ СІПм     
                                      WHEN (SELECT NVL(SUBSTR(YD_CARUD_STOP_LOC,2,1),  WB.YD_AIM_BAY_GP )
                                              FROM TB_YF_TCARSCH 
                                             WHERE DEL_YN = 'N'
                                               AND YD_EQP_ID = WB.YD_WRK_PLAN_TCAR) <> WB.YD_AIM_BAY_GP 
                                      THEN '2'    
                                      --ДыТїЧіРчЕП != РлОїПЙОрРчЗс ЧіРчЕП РЬИщ СІПм     
                                      WHEN (SELECT YD_CURR_BAY_GP
                                              FROM TB_YF_EQP 
                                             WHERE DEL_YN = 'N'
                                               AND YD_EQP_ID = WB.YD_WRK_PLAN_TCAR) <> SUBSTR(WB.YD_SCH_CD,2,1)
                                      THEN '2'
                                      -- ДыТїРЧ BED_ACTIVE АЁ 'L'РЬ ОЦДЯИщ СІПм(ДыТї УтЙпНУ ЙЎСІЙпЛ§)
                                      WHEN (SELECT COUNT(*) 
                                              FROM TB_YF_STKBED 
                                             WHERE YD_STK_COL_GP = SUBSTR(WB.YD_SCH_CD,1,2)||SUBSTR(WB.YD_WRK_PLAN_TCAR,3,4)
                                               AND YD_STK_BED_ACTIVE_STAT NOT IN ('L')) > 0   
                                      THEN '2'
                                      ELSE '1' END
                                 --УпУтРК РлОїПЙОрРЬ ЙЬИЎ ИИЕщОюСіЙЧЗЮ, УпУтПфБИИІ ЙоРЛЖЇ НКФЩСй ЕюЗЯЧиОп?? kbs
                                 WHEN YD_SCH_CD LIKE '1_DC__LM' THEN '2' 
                                 WHEN YD_SCH_CD LIKE '1_FD__LM' THEN '2'
                                 WHEN YD_SCH_CD LIKE '1_KD__LM' THEN '2'
                                 WHEN YD_SCH_CD LIKE '1_QD__LM' THEN '2'
                                 ELSE '1' END   
                   --ДыТї УтЙпШФ ЧЯТїСіПЁ ЕЕТјРќ НКФЩСй БтЕП БнСі 20180425
                   AND 1 = CASE WHEN YD_SCH_CD LIKE '1_TC__LM%' THEN
                                CASE WHEN YD_BAY_GP != (SELECT E.YD_CURR_BAY_GP
                                                          FROM TB_YF_EQP E
                                                         WHERE E.YD_EQP_ID = YD_WRK_PLAN_TCAR) THEN '2'
                                     ELSE '1' END
                           ELSE '1' END 
                              
                   AND 1 = CASE --ТїЗЎ ОјРИИщ БтЕПОШЧд
                                WHEN NVL((SELECT 'Y' 
                                        FROM TB_YF_STKCOL 
                                       WHERE CAR_NO = WB.CAR_NO 
                                         AND SUBSTR(YD_STK_COL_GP,2,1) != SUBSTR(WB.YD_SCH_CD,2,1)
                                     ),'N') = 'Y'
                                THEN '2'
                                
                                --ТїЗЎ ОјРИИщ БтЕПОШЧд
                                WHEN NVL((SELECT 'Y' 
                                        FROM TB_YF_STKCOL 
                                       WHERE TRN_EQP_CD = WB.TRN_EQP_CD 
                                         AND SUBSTR(YD_STK_COL_GP,2,1) != SUBSTR(WB.YD_SCH_CD,2,1)
                                     ),'N') = 'Y'
                                THEN '2'
                                
                                --ЧќЛѓ СИРчЧЯИщ БтЕП ОШЧд
                                WHEN SUBSTR(YD_SCH_CD, 3, 2) = 'PT' AND SUBSTR(YD_SCH_CD,6,1) IN ('1') 
                                     AND (SELECT NVL(MAX(YD_FRM_YN),'N') AS YD_FRM_YN 
                                            FROM TB_YD_CARPOINT 
                                           WHERE YD_STK_COL_GP IN (SUBSTR(YD_SCH_CD, 1, 2)||'PT01', SUBSTR(YD_SCH_CD, 1, 2)||'PT02')
                                         ) = 'Y'
                                THEN '2'
                                
                                --ЧќЛѓ СИРчЧЯИщ БтЕП ОШЧд 1BPT32UM
                                WHEN SUBSTR(YD_SCH_CD, 3, 2) = 'PT' AND SUBSTR(YD_SCH_CD,6,1) NOT IN ('1') 
                                     AND (SELECT NVL(MAX(YD_FRM_YN),'N') AS YD_FRM_YN 
                                            FROM TB_YD_CARPOINT 
                                           WHERE YD_STK_COL_GP IN (SUBSTR(YD_SCH_CD, 1, 2)||'PT03', SUBSTR(YD_SCH_CD, 1, 2)||'PT04')
                                         ) = 'Y'
                                THEN '2'
                                
                                ELSE '1' END 
                   AND TRN_EQP_CD       IS NULL
                   AND YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
                                             FROM TB_YF_CRNSCH
                                            WHERE DEL_YN = 'N')
                   AND (YD_WRK_PLAN_CRN = :V_YD_EQP_ID 
                         OR YD_SCH_CD IN
                            (SELECT YD_SCH_CD
                               FROM TB_YF_SCHRULE
                              WHERE (YD_WRK_CRN = :V_YD_EQP_ID )
                                AND DEL_YN          = 'N')
                       )
                   AND NVL(YD_WRK_PLAN_CRN, :V_YD_EQP_ID ) = :V_YD_EQP_ID
                  ORDER BY (CASE WHEN YD_WRK_PLAN_CRN=:V_YD_EQP_ID  THEN 1 ELSE 2 END ),YD_SCH_PRIOR, YD_WBOOK_ID     
               ) A
         WHERE YD_SCH_CD_YN = 'Y'         
            --ЛчПыРкУыМв НКФЩСйРК МіЕПРИЗЮ СјЧрЧбДй. 
--           AND SCH_CNCL_YN IS NULL
           AND YD_SCH_AUTO_ST_YN = 'Y'
       )
   WHERE ROWNUM = 1
 </pre> */
public final static String getWbIdAxYML007 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getWbIdAxYML007";

