 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppoint
SELECT
    AA.YD_STK_COL_GP,
    AA.YD_PNT_CD,
    COUNT
FROM
    (
        SELECT
            MIN(A.YD_STK_COL_GP) AS YD_STK_COL_GP,
            A.YD_PNT_CD,
            SUM(A.COUNT) AS COUNT
        FROM
            (
                SELECT
                    A.YD_STK_COL_GP,
                    A.YD_PNT_CD,
                    1 AS COUNT
                FROM
                    TB_YF_STKCOL A,
                    USRYDA.TB_YD_CARPOINT B
                WHERE 1=1
                AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
                AND B.YD_STK_COL_ACT_STAT = 'C'   --ЛчПыАЁДЩ
                AND B.DEL_YN = 'N'
                AND A.WLOC_CD =  :V_WLOC_CD
                AND A.YD_GP   =  :V_YD_GP
                AND A.BAY_GP  =  :V_BAY_GP
                AND A.SECT_GP =  'PT'
                AND B.TRN_EQP_CD    IS NULL --ЧіРчТїЗЎСЄСіРЇФЁ
                --AND B.CAR_NO		IS NULL --ПЙОрТїЗЎСЄСіРЇФЁ
                AND B.CARD_NO       IS NULL
                AND
                (
                    (
                        1=1
                        AND A.YD_GP IN ('1')
                        AND A.YD_STK_COL_GP IN
                        (
                            SELECT
                                YD_STK_COL_GP
                            FROM
                                USRYDA.TB_YD_CARPOINT C
                            WHERE 1=1
                            AND C.YD_GP     = A.YD_GP
                            AND C.DEL_YN    = 'N'
                            AND SUBSTR(C.YD_CARPNT_CD, 3, 1) = A.BAY_GP
                            AND C.YD_CAR_USETYPE_GP IN ('GT', 'TO')
                        )
                    )
                    OR
                    (A.YD_GP NOT IN ('1') AND 1=1)
                )
                ORDER BY A.YD_PNT_CD DESC
            ) A
        GROUP BY YD_PNT_CD
    ) AA
WHERE 1=1
AND COUNT >= 1
ORDER BY YD_STK_COL_GP DESC
 </pre> */
public final static String getListloadStoppoint = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppoint";

