 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getL2CrnInfoANew
SELECT A.*
     , MIN(CASE WHEN CRN_ST = 2 AND TO_NUMBER(SUBSTR(EQUIP_GP,6,1)) < TO_NUMBER(SUBSTR(:V_YD_EQP_ID,6,1)) THEN 'L' 
            ELSE 'R' END) OVER() OTHER_CRN_LOC               -- ЛѓДыХЉЗЙРЮ РЇФЁСЄКИ
  FROM (
        SELECT CASE WHEN C.EQUIP_GP  = :V_YD_EQP_ID THEN '1' -- КЛХЉЗЙРЮ СЄКИ
                    ELSE '2' END CRN_ST                      -- ЛѓДыХЉЗЙРЮ СЄКИ
             , C.EQUIP_GP          AS EQUIP_GP
             , CASE WHEN C.WPROG_STAT IN ('4','W') AND C.WORK_MODE = '1'  THEN '0'  -- РлОїДыБт
		            WHEN C.WPROG_STAT IN ('1')     AND C.WORK_MODE = '1'  THEN '1'  -- БЧЛѓРќ
		            WHEN C.WPROG_STAT IN ('2')     AND C.WORK_MODE = '1'  THEN '2'   -- БЧЛѓШФ  
		            ELSE '3' END   AS OTHER_WORK_STAT -- РЬЛѓФЩРЬНК  РЬЛѓ       
             , ''        AS OTHER_CRN_WRK_PROG_STAT
             , 0         AS OTHER_CURR_XAXIS
             , 0         AS OTHER_FROM_XAXIS
             , 0         AS OTHER_TO_XAXIS
             , ''        AS OTHER_DIR_GP

         FROM (SELECT :V_YD_EQP_ID AS CURR_YD_EQP_ID FROM DUAL) B
            , TB_YF_EQUIP C
        WHERE C.EQUIP_GP IN (B.CURR_YD_EQP_ID,  CASE WHEN B.CURR_YD_EQP_ID = '3ACRA1' THEN '3ACRA2' 
                                                     WHEN B.CURR_YD_EQP_ID = '3ACRA2' THEN '3ACRA1' 
                                                     ELSE B.CURR_YD_EQP_ID END  )
       ) A
  ORDER BY CRN_ST, EQUIP_GP 
 </pre> */
public final static String getL2CrnInfoANew = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getL2CrnInfoANew";

