 /** <pre> 
--yf.common.dao.selectStockOfwloc
SELECT
    NVL
    (
        WLOC_CD,
        (
            SELECT
                WLOC_CD
            FROM
                TB_YF_STKCOL
            WHERE 1=1
            AND YD_STK_COL_GP = SUBSTR(A.YD_STK_COL_GP, 1, 4) || '1' || SUBSTR(A.YD_STK_COL_GP, 6, 1)
        )
    ) AS WLOC_CD,
    NVL
    (
        YD_PNT_CD,
        (
            SELECT
                YD_PNT_CD
            FROM
                TB_YF_STKCOL
            WHERE 1=1
            AND YD_STK_COL_GP = SUBSTR(A.YD_STK_COL_GP, 1, 4) || '1' || SUBSTR(A.YD_STK_COL_GP, 6, 1)
        )
    ) AS YD_PNT_CD,
    (
        SELECT
            MAX(YD_CAR_SCH_ID) AS YD_CAR_SCH_ID
        FROM
            USRYDA.TB_YD_CARSCH B
        WHERE 1=1
        AND B.DEL_YN = 'N'
        AND B.CARD_NO = A.CARD_NO
    ) AS YD_CAR_SCH_ID,
    (
        SELECT
            MAX(YD_CAR_PROG_STAT) AS YD_CAR_PROG_STAT
        FROM
            USRYDA.TB_YD_CARSCH B
        WHERE 1=1
        AND B.DEL_YN = 'N'
        AND B.CARD_NO = A.CARD_NO
    ) AS YD_CAR_PROG_STAT,
    (
        SELECT
            MAX(YD_EQP_WRK_STAT) AS YD_EQP_WRK_STAT
        FROM
            USRYDA.TB_YD_CARSCH B
        WHERE 1=1
        AND B.DEL_YN='N'
        AND B.CARD_NO=A.CARD_NO
    ) AS YD_EQP_WRK_STAT,
    (
        SELECT
            MAX(YD_WBOOK_ID) AS YD_WBOOK_ID
        FROM
            USRYFA.TB_YF_STOCK C
        WHERE 1=1
        AND C.CAR_CARD_NO = A.CARD_NO
        AND C.YD_WBOOK_ID IS NOT NULL
    ) AS YD_WBOOK_ID,
    TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS CURDATE
FROM
    TB_YF_STKCOL A
WHERE YD_STK_COL_GP =: V_YD_STK_COL_GP
 </pre> */
public final static String selectStockOfwloc = "bak.yf.common.dao.selectStockOfwloc";

 /** <pre> 
--yf.facilitystatus.facilityinquiry.CraneSchDAO.getDmCarInfo
WITH TEMP_TABLE AS
(
    SELECT
        :V_STL_NO AS STL_NO
    FROM
        DUAL
)
SELECT
    CARD_NO,
    (
        CASE
        WHEN A.TRANS_WORD_SEQNO < 700000 THEN
            (
                SELECT
                    MAX(TRANS_COM_CD)   --//ГЛМі
                FROM
                    TB_DM_TRANSWORDCOMM C
                WHERE 1=1
                AND C.TRANS_WORD_DATE   = A.TRANS_WORD_DATE
                AND C.TRANS_WORD_SEQNO  = A.TRANS_WORD_SEQNO
            )
        WHEN A.TRANS_WORD_SEQNO BETWEEN 700000 AND 799999 THEN
            (
                SELECT
                    MAX(TRANS_COM_CD)   --//РгАЁАј
                FROM
                    TB_DM_GOODSFRTOMOVEWORDCOMM@DL_SMDB C
                WHERE 1=1
                AND C.FRTOMOVE_WORD_DATE    = A.TRANS_WORD_DATE
                AND C.FRTOMOVE_WORD_SEQNO   = A.TRANS_WORD_SEQNO
            )
        WHEN A.TRANS_WORD_SEQNO >= 800000 THEN
            (
                SELECT
                    MAX(TRANS_COM_CD)   --//СІЧАРЬМл
                FROM
                    TB_DM_COILFRTOMOVEWORDCOMM C
                WHERE 1=1
                AND C.FRTOMOVE_WORD_DATE    = A.TRANS_WORD_DATE
                AND C.FRTOMOVE_WORD_SEQNO   = A.TRANS_WORD_SEQNO
            )
        ELSE '' END
    ) AS TRANS_COM_CD,
    CAR_NO,
    CAR_NO_ADDR,
    TRANS_WORD_DATE,
    TRANS_WORD_SEQNO
FROM
    (
        --//УтЧЯ ,РгАЁАј , СІЧАРЬМл
        SELECT
            B.CARD_NO,
            RPAD(B.CAR_NO, 12, ' ') AS CAR_NO,
            SUBSTR(B.CAR_NO, LENGTH(B.CAR_NO) - 3) AS CAR_NO_ADDR,
            A.TRANS_ORD_DATE AS TRANS_WORD_DATE,
            TO_CHAR(A.TRANS_ORD_SEQNO) AS TRANS_WORD_SEQNO
        FROM
            (
                SELECT
                    TRANS_ORD_DATE,
                    TRANS_ORD_SEQNO
                FROM
                    TB_YD_STOCK A
                WHERE 1=1
                AND A.STL_NO = (SELECT STL_NO FROM TEMP_TABLE)

                UNION ALL

                SELECT
                    TRANS_ORD_DATE,
                    TRANS_ORD_SEQNO
                FROM
                    TB_YF_STOCK A
                WHERE 1=1
                AND A.STL_NO =(SELECT STL_NO FROM TEMP_TABLE)
            ) A,
            USRYDA.TB_YD_CARSCH B
        WHERE 1=1
        AND A.TRANS_ORD_DATE    = B.TRANS_ORD_DATE
        AND A.TRANS_ORD_SEQNO   = B.TRANS_ORD_SEQNO
        AND ROWNUM <= 1

        UNION ALL

        --//БИГЛПюМл
        SELECT
            B.TRN_EQP_CD,
            RPAD(NVL(C.CAR_NO, B.TRN_EQP_CD), 12, ' '),
            SUBSTR(NVL(C.CAR_NO, B.TRN_EQP_CD), LENGTH(NVL(C.CAR_NO, B.TRN_EQP_CD)) - 3) AS CAR_NO_ADDR,
            '',
            ''
        FROM
            USRYDA.TB_YD_CARFTMVMTL A,
            USRYDA.TB_YD_CARSCH B,
            USRTSA.TB_TS_CAR_SPEC_RULL C
        WHERE 1=1
        AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
        AND B.TRN_EQP_CD    = C.TRN_EQP_CD(+)
        AND A.STL_NO        = (SELECT STL_NO FROM TEMP_TABLE)
        AND B.YD_CAR_USE_GP = 'L'
        AND A.DEL_YN        = 'N'
        AND C.TRN_EQP_CD IS NOT NULL
        AND ROWNUM <= 1
    ) A
WHERE 1=1
AND ROWNUM <= 1
 </pre> */
public final static String getDmCarInfo = "bak.yf.facilitystatus.facilityinquiry.CraneSchDAO.getDmCarInfo";

