 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYfIFLayout
SELECT ITM_SEQ
      ,ITM_ID
      ,ITM_NM
      ,ITM_DATA_TP
      ,NVL(ITM_DATA_L  ,0) AS ITM_DATA_L
      ,NVL(ITM_DATA_DOT,0) AS ITM_DATA_DOT
      ,ESS_YN
      ,CASE WHEN ITM_ID = 'MSG_ID'  THEN IF_ID
            WHEN ITM_ID = 'DATE'    THEN TO_CHAR(SYSDATE, 'YYYY-MM-DD')
            WHEN ITM_ID = 'TIME'    THEN TO_CHAR(SYSDATE, 'HH24:MI:SS')
            WHEN ITM_ID = 'MSG_GP'  THEN 'I'
            WHEN ITM_ID = 'MSG_LEN' THEN TO_CHAR(SUM(ITM_DATA_L) OVER () - 60,'FM0000')
            ELSE RPAD(' ',ITM_DATA_L,' ')
       END AS DEF_VAL
      ,ESS_YN
      ,REMARKS
      ,IF_ID
      ,ITM_VAL9 AS ITM_VAL
      ,COUNT(*) OVER() TOTALCOUNT
  FROM TB_YF_Z_IFLAYOUT
 WHERE IF_ID = :V_IF_ID
 ORDER BY ITM_SEQ
 </pre> */
public final static String getYfIFLayout = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getYfIFLayout";

 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPO161
SELECT 'YMPOJ161'                                       AS JMS_TC_CD          --JMSTCФкЕх  
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')              AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ  
     , 'YMPOJ161'                                       AS TCCODE
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),1,8)  AS TCDATE
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),9,6)  AS TCTIME
     , 'A'                                              AS PLANTGBN
     , SUBSTR(A.TRK_INFO,1,1)                           AS PROCGBN   --S:1SPM,N:2SPM,H:HFL 
     , A.STL_NO                                         AS COILNO  
     , SUBSTR(A.TRK_INFO,2,1)                           AS PROCESSID --1:КИБо,2:КИБоУыМв,3:УпУт,4:Take-Out,5:Take-In
     , TO_CHAR(SYSDATE,'YYYYMMDD')                      AS DOWNDATE
     , TO_CHAR(SYSDATE,'HH24MISS')                      AS DOWNTIME
     , 'D'||SUBSTR(A.TRK_INFO,2,1)                      AS POSITIONNO
     
  FROM (SELECT CASE WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'S1'  --1SPM КИБоСИ
                    WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'S5'  --1SPM TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('FE') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'H1'  --HFL  КИБоСИ 
                    WHEN SUBSTR(LOC,3,2) IN ('FE') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'H5'  --HFL  TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('QE') AND SUBSTR(YD_SCH_CD,6,2) IN ('1U') THEN 'N1'  --EQL  КИБоСИ 
                    WHEN SUBSTR(LOC,3,2) IN ('QE') AND SUBSTR(YD_SCH_CD,6,2) IN ('2U') THEN 'N5'  --EQL  TAKE IN 
                    ELSE '' END AS TRK_INFO 
            , STL_NO 
         FROM (SELECT :V_YD_DN_WR_LOC  AS LOC  
                    , STL_NO         AS STL_NO
                    , (SELECT YD_SCH_CD FROM TB_YF_CRNSCH WHERE YD_CRN_SCH_ID = C.YD_CRN_SCH_ID) AS YD_SCH_CD
                 FROM TB_YF_CRNWRKMTL C 
                WHERE C.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID) 
       ) A
 </pre> */
public final static String TcYMPO161 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPO161";

