 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStklyrXYZA7YML009
SELECT *
  FROM (
        SELECT *
          FROM (
                SELECT COUNT(*) OVER() AS LOC_ABLE_YN 
                     , A.YD_STK_LYR_ACTIVE_STAT
                     , A.YD_STK_LYR_STAT
                     , A.YD_STK_COL_GP|| A.YD_STK_BED_NO  AS YD_DN_WR_LOC
                     , '0'||A.YD_STK_LYR_NO            AS YD_DN_WR_LYR 
                     , A.YD_STK_LYR_X_AXIS 
                     , A.YD_STK_LYR_Y_AXIS 
                     , COUNT(*) OVER(PARTITION BY A.YD_STK_COL_GP|| A.YD_STK_BED_NO ORDER BY A.YD_STK_COL_GP|| A.YD_STK_BED_NO) AS STACK_COL_ABLE_YN 
                  FROM TB_YF_STKLYR A 
                     , TB_YF_STKBED    B 
                 WHERE SUBSTR(A.YD_STK_COL_GP,1,1) ='1' 
                   AND A.YD_STK_COL_GP = B.YD_STK_COL_GP  
                   AND A.YD_STK_BED_NO = B.YD_STK_BED_NO  
                   AND A.YD_STK_LYR_ACTIVE_STAT = 'E' 
                   AND A.YD_STK_LYR_STAT        = 'E' 
                   AND A.DEL_YN = 'N' 
                   AND B.DEL_YN = 'N' 
                   AND :V_YD_CRN_XAXIS  BETWEEN A.YD_STK_LYR_X_AXIS - NVL(B.YD_STK_BED_XAXIS_TOL,0) AND A.YD_STK_LYR_X_AXIS  + NVL(B.YD_STK_BED_XAXIS_TOL,0)
                   AND :V_YD_CRN_YAXIS  BETWEEN A.YD_STK_LYR_Y_AXIS - NVL(B.YD_STK_BED_YAXIS_TOL,0) AND A.YD_STK_LYR_Y_AXIS  + NVL(B.YD_STK_BED_YAXIS_TOL,0)
                   AND SUBSTR(A.YD_STK_COL_GP, 3, 2) BETWEEN '01' AND '99'
                   AND SUBSTR(A.YD_STK_COL_GP, 2, 1) LIKE SUBSTR(:V_YD_EQP_ID, 2, 1) ||'%'
                ) A
         WHERE LOC_ABLE_YN <= 2 
           AND STACK_COL_ABLE_YN <= 2
         ORDER BY YD_DN_WR_LYR
       ) 
 WHERE ROWNUM <= 1  
 </pre> */
public final static String getYdStklyrXYZA7YML009 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStklyrXYZA7YML009";

