 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandCarNoFrto
SELECT YD_STK_COL_GP
     , YD_STK_BED_NO 
     , YD_STK_LYR_NO 
     , YD_MTL_SH 
  FROM
       (
        SELECT SB.YD_STK_COL_GP
             , SB.YD_STK_BED_NO 
             , SL.YD_STK_LYR_NO 
             ,COUNT(SL.STL_NO) AS YD_MTL_SH
          FROM TB_YF_STKBED SB
              ,TB_YF_STKLYR SL
              ,(SELECT YD_STK_COL_GP AS YD_STK_COL_GP                         
                  FROM TB_YD_CARPOINT                          
                 WHERE CAR_NO = :V_CAR_NO ) SC
         WHERE SB.YD_STK_COL_GP = SL.YD_STK_COL_GP
           AND SB.YD_STK_COL_GP = SC.YD_STK_COL_GP
           AND SB.YD_STK_BED_NO = SL.YD_STK_BED_NO
           AND SB.YD_STK_COL_GP LIKE (SELECT SUBSTR(YD_STK_COL_GP,1,2) 
                                        FROM TB_YF_STKLYR 
                                       WHERE STL_NO = :V_STL_NO) || '%'
           AND SB.YD_STK_BED_NO LIKE NVL((SELECT ITEM
                                           FROM TB_YF_RULE 
                                          WHERE REPR_CD_GP = 'YM1001'
                                            AND CD_GP =  (SELECT YD_CAR_UPP_LOC_CD FROM TB_YF_STOCK WHERE STL_NO = :V_STL_NO)
                                    ),'%')    
           AND SB.DEL_YN       = 'N'
           AND SB.YD_STK_BED_ACTIVE_STAT = 'L' --РћФЁАЁДЩ
           AND SL.YD_STK_LYR_NO='01' --ТїЗЎРЇФЁДТ 1ДмИИ РћФЁ
           AND SB.YD_STK_COL_GP||SB.YD_STK_BED_NO||SL.YD_STK_LYR_NO NOT IN ( SELECT NVL(YD_DN_WO_LOC||YD_DN_WO_LYR,'1') FROM TB_YF_CRNSCH WHERE DEL_YN = 'N')
           AND SL.STL_NO IS NULL
         GROUP BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO, SL.YD_STK_LYR_NO 
         ORDER BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO, SL.YD_STK_LYR_NO 
        )
  WHERE YD_MTL_SH = 0
    AND ROWNUM = 1
 </pre> */
public final static String getYdStkBedByCarUseGpandCarNoFrto = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandCarNoFrto";

