 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandCarNo
SELECT STACK_COL_GP
     , STACK_BED_GP 
     , STACK_LAYER_GP 
     , YD_MTL_SH 
  FROM
(
SELECT SB.STACK_COL_GP
     , SB.STACK_BED_GP 
     , SL.STACK_LAYER_GP 
     , COUNT(SL.STOCK_ID) AS YD_MTL_SH
  FROM TB_YF_STACKER    SB
     , TB_YF_STACKLAYER SL
     , (SELECT YD_STK_COL_GP AS STACK_COL_GP                      
          FROM TB_YD_CARPOINT                          
         WHERE CARD_NO = :V_CARD_NO
           AND DEL_YN = 'N' ) SC
 WHERE SB.STACK_COL_GP = SL.STACK_COL_GP
   AND SB.STACK_BED_GP = SL.STACK_BED_GP
   AND SB.STACK_COL_GP = SC.STACK_COL_GP
   AND SB.DEL_YN       = 'N'
   AND SB.STACK_BED_ACTIVE_STAT = 'L' --РћФЁАЁДЩ
   AND SL.STACK_LAYER_GP        = '01' --ТїЗЎРЇФЁДТ 1ДмИИ РћФЁ
   AND SB.STACK_COL_GP||SB.STACK_BED_GP||SL.STACK_LAYER_GP NOT IN ( SELECT NVL(YD_DN_WO_LOC||YD_DN_WO_LAYER,'1') FROM TB_YF_CRNSCH WHERE DEL_YN = 'N')
   --КЙМіЕП РћПы
   AND SB.STACK_BED_GP||SL.STACK_LAYER_GP NOT IN ( SELECT NVL(B.YD_STK_BED_NO||CASE WHEN LENGTH(B.YD_STK_LYR_NO) = '3' THEN  SUBSTR(B.YD_STK_LYR_NO,2,2)
                                                                                    ELSE B.YD_STK_LYR_NO  END,'1') 
                                                     FROM TB_YD_CARSCH A
                                                        , TB_YD_CARFTMVMTL B 
                                                    WHERE A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
                                                      AND A.CAR_NO = :V_CAR_NO
                                                      AND A.CARD_NO= :V_CARD_NO
                                                      AND A.DEL_YN = 'N'
                                                      AND B.DEL_YN = 'N'
                                                      AND A.CAR_NO NOT IN ('9990','9991','9992','9993','9994')
                                                 )
   AND SL.STOCK_ID IS NULL
   AND SUBSTR(SB.STACK_COL_GP, 1, 2) = SUBSTR(:V_YD_SCH_CD, 1, 2)
 GROUP BY SB.STACK_COL_GP, SB.STACK_BED_GP, SL.STACK_LAYER_GP 
 ORDER BY SB.STACK_COL_GP, SB.STACK_BED_GP, SL.STACK_LAYER_GP 
)
 WHERE YD_MTL_SH = 0
   AND ROWNUM = 1
 </pre> */
public final static String getYdStkBedByCarUseGpandCarNo = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getYdStkBedByCarUseGpandCarNo";

