 /** <pre> 
--yf.facilitystatus.facilityinquiry.CraneSchDAO.getStockInfo
WITH
TEMP_TABLE AS
(
    SELECT
        A.*,
        (
            CASE
            WHEN YD_SCH_CD  IN ('1ATC01UM', '1BTC01UM', '1BTC02UM') THEN CARUNLOAD_LOC      --ЕПАЃРЬРћЛѓТї
            WHEN YD_SCH_CD  IN
            (
                '1APT21LM', '1BPT22LM', '1CPT22LM', '1DPT22LM', '1EPT22LM', '1FPT22LM', '1GPT22LM', '1HPT22LM', '1APT22LM', '1BPT31LM', '1CPT31LM', '1DPT31LM', '1EPT26LM', '1FPT26LM', '1GPT26LM', '1HPT26LM',
                '1APT11LM', '1BPT02LM', '1CPT02LM', '1DPT02LM', '1EPT01LM', '1FPT01LM', '1GPT01LM', '1HPT01LM', '1APT12LM', '1BPT12LM', '1CPT12LM', '1DPT12LM', '1EPT06LM', '1FPT06LM', '1GPT06LM', '1HPT06LM'
            ) THEN MOVE_LOC    --МвРч/СІЧАРЬМлЧЯТї
            WHEN YD_SCH_CD  IN ('1EKD01LM', '1FKD01LM') AND SPM_NEXT_LOC = 'E' THEN SPM_NEXT_LOC    --SPM УпУт РчРлОї НУ
            WHEN YD_SCH_CD  IN ('1CFD01LM', '1EKD01LM', '1FKD01LM', '1FQE01LM', '1GQD01LM') AND ZONE_AIMBAY_GP IS NOT NULL THEN ZONE_AIMBAY_GP  --УпУт НУ СИКА ИёРћЕП
            ELSE NVL(NVL(NVL(CARUNLOAD_LOC, SPM_NEXT_LOC), ZONE_AIMBAY_GP), MOVE_LOC) END
        ) AS CARUNLOAD_PUT_LOC2       --CTS ИёРћЕП АЁСЎПРБт
    FROM
        (
            SELECT
                STL_NO,
                YD_WBOOK_ID,
                YD_MTL_STAT,
                EXPECT_YD_STK_LOC,
                STOCK_MOVE_TERM,
                FRTOMOVE_WORD_NO,
                TRANS_ORD_DATE || TRANS_ORD_SEQNO AS TRANS_WORD_NO,
                CAR_CARD_NO,
                CTS_RELAY_YN,
                CTS_RELAY_BAY,
                CTS_RELAY_SADDLE,
                KEEP_STL_YN,
                REGISTER,
                REG_DDTT,
                MODIFIER,
                MOD_DDTT,
                (
                    CASE
                    WHEN TRANS_ORD_SEQNO > 700000 THEN 'N'
                    ELSE DEL_YN END
                ) AS DEL_YN,
                CAR_NO,
                YD_RULE_PL_RS_GP,
                TRANS_ORD_DATE,
                TRANS_ORD_SEQNO,
                SUBSTR(YD_SCH_CD_LOC, 1, 8) AS YD_SCH_CD,
                (SELECT SLAB_W FROM VW_YD_SLABCOMM WHERE SLAB_NO = A.STL_NO) AS SLAB_W,
                (SELECT SLAB_WT FROM VW_YD_SLABCOMM WHERE SLAB_NO = A.STL_NO) AS SLAB_WT,
                (
                    SELECT
                        'E'
                    FROM
                        TB_PT_COILCOMM B
                    WHERE 1=1
                    AND B.COIL_NO = A.STL_NO
                    AND B.YD_GP = '1'
                    AND B.PASS_PROC1 = '1K'
                    AND (SUBSTR(B.YD_STR_LOC_HIS1, 3, 2) IN ('KE', 'KD') OR SUBSTR(B.YD_STR_LOC, 3, 2) IN ('KE', 'KD'))
                    AND ((B.REMAIN_PROC1 = '1K' AND B.REMAIN_PROC2 = '1Q') OR B.REMAIN_PROC1='1Q')
                ) AS SPM_NEXT_LOC,
                (
                    SELECT
                        (
                            CASE
                            WHEN B.NEXT_PROC ='1Q' THEN 'E'
                            WHEN B.NEXT_PROC ='1K' THEN 'D'
                            WHEN B.NEXT_PROC ='1H' THEN 'B'
                            END
                        )
                    FROM
                        TB_PT_COILCOMM B
                    WHERE 1=1
                    AND B.COIL_NO = A.STL_NO
                ) AS MOVE_LOC,
                '' AS CARUNLOAD_LOC,
                'X' AS ZONE_AIMBAY_GP,
                NVL
                (
                    (
                        SELECT
                            'Y'
                        FROM
                            USRYFA.VW_YF_CONDENSATIONLOC C
                        WHERE 1=1
                        AND C.COIL_NO = A.STL_NO
                        AND YD_ZONE_GP IS NOT NULL
                        AND ROWNUM <= 1
                    ),
                    'N'
                ) AS GOODS_YN,
                (
                    SELECT
                        YD_ZONE_GP
                    FROM
                        USRYFA.VW_YF_CONDENSATIONLOC C
                    WHERE 1=1
                    AND C.COIL_NO = A.STL_NO
                    AND YD_ZONE_GP IS NOT NULL
                    AND ROWNUM <= 1
                ) AS YD_ZONE_GP,
                SUBSTR(YD_SCH_CD_LOC, 6, 1) AS BAY_GP,
                (
                    SELECT
                        NVL(SH.RECEIPT_HOLD_SCRAP_CAUSE_GP, '-')
                    FROM
                        TB_HR_C_SHEARWOWR SH
                    WHERE 1=1
                    AND SH.COIL_NO = A.STL_NO
                    AND SH.STEP_NO = 1
                ) AS RECEIPT_HOLD_SCRAP_YN,
                (
                    SELECT
                        COIL_T
                    FROM
                        TB_PT_COILCOMM CO
                    WHERE 1=1
                    AND CO.COIL_NO = A.STL_NO
                ) AS COIL_T
            FROM
                (
                    SELECT
                        A.*,
                        (
                            SELECT
                                YD_SCH_CD || YD_UP_WO_LOC
                            FROM
                                USRYFA.TB_YF_WRKHIST B
                            WHERE 1=1
                            AND B.STL_NO = A.STL_NO
                            AND B.YD_WRK_HIST_ID =
                            (
                                SELECT
                                    MAX(YD_WRK_HIST_ID)
                                FROM
                                    TB_YF_WRKHIST W
                                WHERE 1=1
                                AND W.STL_NO = B.STL_NO
                            )
                            AND ROWNUM <= 1
                        ) AS YD_SCH_CD_LOC,
                        YD_WBOOK_ID
                    FROM
                        TB_YF_STOCK A
                       ,TB_YF_WRKBOOKMTL B
                    WHERE A.STL_NO = :V_STL_NO
                      AND A.STL_NO = B.STL_NO
                      AND B.DEL_YN = 'N'
                ) A
        ) A

),
TEMP_ANYDONG AS
(
    SELECT
        SUBSTR(C.YD_STK_COL_GP,2,1) AS YD_BAY_GP
    FROM
        USRYFA.TB_YF_STKLYR C,
        USRYFA.TB_YF_STKCOL D
    WHERE 1=1
    AND C.YD_STK_COL_GP = D.YD_STK_COL_GP
    AND C.YD_STK_COL_GP LIKE '1_S%'
    AND C.YD_STK_LYR_ACTIVE_STAT = 'O'
    AND D.YD_STK_COL_USAGE_CD = 'TS'
    AND C.STL_NO IS NULL
    AND
    (
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('CZ', 'BZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('F', 'G', 'H')   --//B,CСИ
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('AZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('A', 'B') --//AСИ
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('DZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('E')      --//КЮРћЧеСИ
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('EZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('G', 'H') --//БЄЦјСИ
        OR
        (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE) IN ('GZ') AND SUBSTR(C.YD_STK_COL_GP,2,1) IN ('E', 'H') --//БЄЦјСИ
    )
    AND SUBSTR(C.YD_STK_COL_GP, 2, 1) <> (SELECT DISTINCT BAY_GP FROM TEMP_TABLE) --РкБтЕПРЬ ОЦДбАцПь
    AND SUBSTR(C.YD_STK_COL_GP, 2, 1) NOT IN
    (
        SELECT
            BAY_GP
        FROM
            VW_YF_CONDENSATIONDONGRATE
        WHERE 1=1
        AND АЁДЩМіЗЎ = 0
        AND YD_ZONE_GP = (SELECT YD_ZONE_GP FROM TEMP_TABLE)
    )
    ORDER BY SUBSTR(C.YD_STK_COL_GP,2,1) DESC
)
SELECT
    B.*,
    NVL
    (
        (
            CASE
            --SPMРчРлОїРчРЮ АцПь
            WHEN RECEIPT_HOLD_SCRAP_YN = 'C'
                AND COIL_T <= 6.5  --6.5T РЬЧЯ
                AND YD_SCH_CD IN ('1CFD01LM') --HFLУпУт
                THEN 'D' --КИЗљScrapПјРЮБИКа : CРЮ АцПь DЕПРИЗЮ РЬРћ
            --X:РќУММБХУ РЮАцПь СИКАЗЮ ИёРћЕП АЫЛі
            WHEN CARUNLOAD_PUT_LOC2 IN ('X')
                AND YD_SCH_CD IN 
                (
                    '1CFD01LM', '1EKD01LM', '1FKD01LM', '1FQE01LM', '1GQD01LM',
                    '1AYD01MM', '1AYD11MM', '1AYD21MM',
                    '1BYD01MM', '1BYD05MM', '1BYD11MM', '1BYD12MM', '1BYD21MM', '1BYD25MM', 
                    '1CYD01MM', '1CYD05MM', '1CYD11MM', '1CYD12MM', '1CYD21MM', '1CYD25MM',
                    '1DYD01MM', '1DYD12MM', '1DYD25MM', 
                    '1EYD01MM', '1EYD05MM', '1EYD11MM', '1EYD12MM', '1EYD21MM', '1EYD25MM',
                    '1FYD01MM', '1FYD05MM', '1FYD11MM', '1FYD12MM', '1FYD21MM', '1FYD25MM',
                    '1GYD01MM', '1GYD05MM', '1GYD11MM', '1GYD12MM', '1GYD21MM', '1GYD25MM',
                    '1HYD01MM', '1HYD05MM', '1HYD11MM', '1HYD12MM', '1HYD21MM', '1HYD25MM'
                )   --УпУт
                AND GOODS_YN = 'Y'    --СІЧА
                AND NOT EXISTS
                (
                    SELECT
                        1
                    FROM
                        USRYFA.TB_YF_STKLYR C,
                        USRYFA.TB_YF_STKCOL D
                    WHERE 1=1
                    AND C.YD_STK_COL_GP = D.YD_STK_COL_GP
                    AND C.YD_STK_COL_GP LIKE '1_S%'
                    AND C.YD_STK_LYR_ACTIVE_STAT = 'O'
                    AND D.YD_STK_COL_USAGE_CD = 'TS'
                    AND C.STL_NO IS NULL
                    AND SUBSTR(C.YD_STK_COL_GP, 2, 1) = B.CARUNLOAD_PUT_LOC2
                    AND ROWNUM <= 1
                )
                THEN (SELECT YD_BAY_GP FROM TEMP_ANYDONG A WHERE ROWNUM <= 1)
            --РкБтЕПАњ ИёРћЕПРЬ ААРК АцПь
            WHEN CARUNLOAD_PUT_LOC2 = (SELECT DISTINCT BAY_GP FROM TEMP_TABLE)
                AND GOODS_YN = 'Y'    --СІЧА
                THEN (SELECT YD_BAY_GP FROM TEMP_ANYDONG A WHERE ROWNUM <= 1)
            ELSE
            (
                CASE
                WHEN CARUNLOAD_PUT_LOC2 NOT IN
                    (
                        SELECT
                            BAY_GP
                        FROM
                            VW_YF_CONDENSATIONDONGRATE
                        WHERE 1=1
                        AND АЁДЩМіЗЎ = 0
                        AND YD_ZONE_GP = (SELECT DISTINCT YD_ZONE_GP FROM TEMP_TABLE)
                    )
                    THEN CARUNLOAD_PUT_LOC2
                ELSE (SELECT YD_BAY_GP FROM TEMP_ANYDONG A WHERE ROWNUM <= 1) END
            ) END
        ),
        (
            CASE
            WHEN CARUNLOAD_PUT_LOC2 = 'X' AND YD_ZONE_GP = 'AZ' THEN 'A'
            ELSE 'H' END
        )
    ) AS CARUNLOAD_PUT_LOC
FROM
    TEMP_TABLE B
 </pre> */
public final static String getStockInfo = "bak.yf.facilitystatus.facilityinquiry.CraneSchDAO.getStockInfo";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getTakeInCoilList
SELECT B.STL_NO || '[' || B.YD_STK_COL_GP || ']'  AS CD_NM,
            B.STL_NO AS CD_VAL 
  FROM TB_YF_STKLYR B 
      ,TB_YF_STKCOL A
      ,TB_PT_COILCOMM D
 WHERE B.YD_STK_COL_GP LIKE '1C%'
   AND B.YD_STK_COL_GP = A.YD_STK_COL_GP
   AND A.SECT_GP BETWEEN '01' AND '99'
   AND B.YD_STK_LYR_STAT IN ('C')
   AND B.STL_NO = D.COIL_NO
   AND D.STL_APPEAR_GP = 'E'
   AND   SUBSTR(
                CASE 
                    WHEN NVL(D.NEXT_DEMAND_PROC,D.NEXT_PROC) IS NULL THEN D.PLAN_PROC1
                    WHEN NVL(D.NEXT_DEMAND_PROC,D.NEXT_PROC) IS NOT  NULL THEN NVL(D.NEXT_DEMAND_PROC,D.NEXT_PROC)
                END
        ,2,1)  = 'H'
    AND NOT EXISTS (
        SELECT 1
        FROM TB_YF_EQPTRACKING S
        WHERE S.STL_NO = B.STL_NO
    )
 </pre> */
public final static String getTakeInCoilList = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getTakeInCoilList";

 /** <pre> 
--yf.common.YfCommon.getClassCode
WITH PARAM AS (
    SELECT :V_TYPE_CD   AS TYPE_CD
          ,:V_CLASS1_CD AS CLASS1_CD
          ,:V_CLASS2_CD AS CLASS2_CD
          ,:V_CLASS3_CD AS CLASS3_CD
          ,:V_CLASS4_CD AS CLASS4_CD
      FROM DUAL)

SELECT A.*
  FROM (SELECT A.TYPE_CD
              ,A.CLASS1_CD
              ,A.CLASS1_NAME1
              ,A.CLASS1_NAME2
              ,A.CLASS1_CONTENTS
              ,B.CLASS2_CD
              ,B.CLASS2_NAME1
              ,B.CLASS2_NAME2
              ,B.CLASS2_CONTENTS
              ,C.CLASS3_CD
              ,C.CLASS3_NAME1
              ,C.CLASS3_NAME2
              ,C.CLASS3_CONTENTS
              ,D.CLASS4_CD
              ,D.CLASS4_NAME1
              ,D.CLASS4_NAME2
              ,D.CLASS4_CONTENTS
          FROM TB_CM_CDCLASS1 A
              ,TB_CM_CDCLASS2 B
              ,TB_CM_CDCLASS3 C
              ,TB_CM_CDCLASS4 D
              ,PARAM P
         WHERE A.TYPE_CD = P.TYPE_CD
           AND A.CLASS1_CD = P.CLASS1_CD
           AND B.TYPE_CD(+)    = A.TYPE_CD
           AND B.CLASS1_CD(+)  = A.CLASS1_CD
           AND C.TYPE_CD(+)    = B.TYPE_CD
           AND C.CLASS1_CD(+)  = B.CLASS1_CD
           AND C.CLASS2_CD(+)  = B.CLASS2_CD
           AND D.TYPE_CD(+)    = C.TYPE_CD
           AND D.CLASS1_CD(+)  = C.CLASS1_CD
           AND D.CLASS2_CD(+)  = C.CLASS2_CD
           AND D.CLASS3_CD(+)  = C.CLASS3_CD ) A
        ,PARAM P
  WHERE A.TYPE_CD = P.TYPE_CD
    AND A.CLASS1_CD = NVL(P.CLASS1_CD,A.CLASS1_CD)
    AND (   ( P.CLASS2_CD IS NULL AND A.CLASS2_CD = A.CLASS2_CD)
         OR ( P.CLASS2_CD IS NOT NULL AND A.CLASS2_CD = P.CLASS2_CD) 
         OR   A.CLASS2_CD IS NULL)
    AND (   ( P.CLASS3_CD IS NULL AND A.CLASS3_CD = A.CLASS3_CD)
         OR ( P.CLASS3_CD IS NOT NULL AND A.CLASS3_CD = P.CLASS3_CD) 
         OR   A.CLASS3_CD IS NULL)
    AND (   ( P.CLASS4_CD IS NULL AND A.CLASS4_CD = A.CLASS4_CD)
         OR ( P.CLASS4_CD IS NOT NULL AND A.CLASS4_CD = P.CLASS4_CD) 
         OR   A.CLASS4_CD IS NULL)
 </pre> */
public final static String getClassCode = "bak.yf.common.YfCommon.getClassCode";

