 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.selectZoneInStocks_Del
SELECT
    STOCK.STL_NO AS STL_NO,             --РњРхЧАID
    COMM.ORD_YEOJAE_GP,                 --СжЙЎПЉРчБИКа
    NVL(COMM.ORD_NO, '') || NVL(COMM.ORD_DTL, '') AS PRODUC_NO, --СІРлЙјШЃЧрЙј
    COMM.SLAB_T,                        --ЕЮВВ
    COMM.SLAB_W,                        --Цј
    COMM.SLAB_LEN,                      --БцРЬ
    COMM.SLAB_WT,                       --СпЗЎ
    COMM.COIL_NO,                       --ПЙСЄCOILNO
    COMM.STACK_LOT_NO AS STACK_LOT_CD,  --ЛъРћ LOT CODE
    COMM.BUY_SLAB_NO                    --БИРдННЖѓКъЙјШЃ
FROM
    TB_YF_STOCK STOCK,
    (
        SELECT
            *
        FROM
            VW_YD_SLABCOMM A,
            TB_QM_BUYSLABINFO B
        WHERE 1=1
        AND A.MSLAB_NO = B.MSLAB_NO(+)
    ) COMM
WHERE 1=1
AND STOCK.CHARGE_LOT_NO IS NOT NULL
AND STOCK.STL_NO = COMM.SLAB_NO
 </pre> */
