 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListUnloadEndpoint_chk3
--ЧиДч РњРхРЇФЁРЧ АГМвФкЕх СИРч ПЉКЮ УМХЉ
SELECT
    B.YD_STK_COL_GP,
    B.YD_PNT_CD
FROM
    TB_YF_STKLYR A,
    TB_YF_STKCOL B
WHERE 1=1
AND A.YD_STK_COL_GP LIKE :V_YD_GP || :V_BAY_GP || :V_SECT_GP || '%'
AND A.YD_STK_BED_NO = '01'
AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
AND B.WLOC_CD       = :V_WLOC_CD
AND (B.CAR_CARD_NO IS NOT NULL OR B.TRN_EQP_CD IS NOT NULL OR B.CARD_NO IS NOT NULL)
 </pre> */
public final static String getListUnloadEndpoint_chk3 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListUnloadEndpoint_chk3";

