 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getAxYML008CarSchLd
--ХЉЗЙРЮБЧЛѓНЧРћ ЛѓТї ТїЗЎНКФЩСй СЖШИ 
SELECT TS.YD_CAR_SCH_ID               --ОпЕхТїЗЎНКФЩСьID
      ,TS.YD_CAR_USE_GP               --ОпЕхТїЗЎЛчПыБИКа
      ,TS.TRN_EQP_CD                  --ПюМлРхКёФкЕх
      ,TS.SPOS_WLOC_CD                --ЙпСіАГМвФкЕх
      ,TS.ARR_WLOC_CD                 --ТјСіАГМвФкЕх
      ,SC.YD_PNT_CD AS SPOS_YD_PNT_CD --ЙпСіОпЕхЦїРЮЦЎФкЕх
      ,TS.CARD_NO                     --ФЋЕхЙјШЃ
      ,TS.CAR_NO                      --ТїЗЎЙјШЃ
      ,TS.TRANS_ORD_DATE              --ПюМлРлОїСіНУРЯРк
      ,TS.TRANS_ORD_SEQNO             --ПюМлРлОїСіНУМјЙј
      ,TS.CMBN_CARLD_YN               --КЙМіЕП
      ,TS.TRANS_EQUIPMENT_TYPE        --ПюМлРхКёType
      ,TS.YD_CAR_PROG_STAT            --ОпЕхТїЗЎСјЧрЛѓХТ
      ,'Y' AS SEND_YDDMR007
      --,CASE WHEN (SELECT COUNT(*) FROM TB_YF_STKLYR WHERE YD_STK_COL_GP = SUBSTR(:V_YD_UP_WR_LOC,1,6) AND STL_NO IS NOT NULL) >0 THEN 'N'
      --      ELSE 'Y' END AS SEND_YDDMR007
  FROM TB_YF_CRNSCH   CS
      ,TB_YF_STKCOL SC
      ,TB_YD_CARSCH   TS
      ,(SELECT WM.YD_WBOOK_ID
              ,WM.YD_AIM_YD_GP
              ,MV.ARR_WLOC_CD
          FROM TB_PT_STLFRTOMOVE MV
              ,(SELECT WB.YD_WBOOK_ID
                      ,WB.YD_AIM_YD_GP
                      ,WM.STL_NO
                  FROM TB_YF_WRKBOOK    WB
                      ,TB_YF_WRKBOOKMTL WM
                 WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
                   AND WB.YD_WBOOK_ID = :V_YD_WBOOK_ID
                   AND WM.DEL_YN = 'N'
                   AND ROWNUM = 1) WM
         WHERE MV.STL_NO = WM.STL_NO
           AND MV.TRANSWORD_SEQNO = (SELECT MAX(MM.TRANSWORD_SEQNO)
                                       FROM TB_PT_STLFRTOMOVE MM
                                      WHERE MM.STL_NO = MV.STL_NO)) MV
 WHERE CS.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
   AND CS.YD_WBOOK_ID   = MV.YD_WBOOK_ID(+)
   AND SC.YD_STK_COL_GP = SUBSTR(CS.YD_DN_WO_LOC,1,6)
   AND SC.YD_CAR_USE_GP = TS.YD_CAR_USE_GP
   AND ((SC.YD_CAR_USE_GP = 'L' AND SC.TRN_EQP_CD = TS.TRN_EQP_CD) --БИГЛПюМл
     OR (SC.YD_CAR_USE_GP = 'G' AND SC.CARD_NO = TS.CARD_NO  AND SC.CAR_NO=TS.CAR_NO)) --УтЧЯТїЗЎ
--   AND TS.YD_CAR_PROG_STAT IN ('2','3') --ЛѓТїЕЕТј,АЫМі
   AND TS.DEL_YN = 'N'
 </pre> */
public final static String getAxYML008CarSchLd = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getAxYML008CarSchLd";

