 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getAbleYdLocGp
SELECT
    SECT_GP AS CD_VAL,
    SECT_GP AS CD_NM
FROM
    (
        SELECT DISTINCT
            SUBSTR(YD_STK_COL_GP, 3, 2) AS SECT_GP
        FROM
            TB_YF_STKLYR
        WHERE 1=1
        AND SUBSTR(YD_STK_COL_GP, 1, 2) = :V_YD_STK_COL_GP
        AND SUBSTR(YD_STK_COL_GP, 3, 2) NOT IN ('CR', 'TR', 'TT', 'XX', 'PT', 'TC', 'CT', 'MT', 'SR','SL')
        AND DEL_YN = 'N'
        AND YD_STK_LYR_ACTIVE_STAT IN ('L', 'E')
    )
ORDER BY SECT_GP
 </pre> */
