 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListFrtostlListsangcha
SELECT
    A.STL_NO,
    A.YD_STK_BED_NO,
    SUBSTR('00'||A.YD_STK_LYR_NO,-2) AS STK_LYR,
    A.YD_CAR_SCH_ID,
    B.STL_APPEAR_GP
FROM
    TB_YD_CARFTMVMTL A,
    TB_PT_COILCOMM B,
    TB_YF_STOCK C
WHERE 1=1
AND A.STL_NO = B.COIL_NO
AND A.STL_NO = C.STL_NO
AND A.DEL_YN = 'N'
AND A.YD_CAR_SCH_ID =
(
    SELECT
        MAX(YD_CAR_SCH_ID)
    FROM
        TB_YD_CARSCH
    WHERE 1=1
    AND TRN_EQP_CD  = :V_TRN_EQP_CD
    AND DEL_YN      = 'N'
)
ORDER BY A.YD_STK_BED_NO, A.YD_STK_LYR_NO
 </pre> */
public final static String getListFrtostlListsangcha = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListFrtostlListsangcha";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarPntFrmYnToChk
SELECT
    YD_CARPNT_CD
FROM
    TB_YD_CARPOINT A
WHERE 1=1
AND A.YD_CAR_USETYPE_GP = 'MT'
AND A.YD_GP     = :V_YD_GP
AND A.YD_BAY_GP = :V_TO_YD_BAY_GP
AND CASE
    WHEN SUBSTR(A.YD_STK_COL_GP, 6, 1) IN ('1', '2') THEN 'L'
    ELSE 'R' END
    =
    CASE
    WHEN :V_PT_LOC IN ('1', '4') THEN 'R'
    WHEN :V_PT_LOC IN ('2', '3') THEN 'L'
    END
 </pre> */
public final static String getCarPntFrmYnToChk = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarPntFrmYnToChk";

 /** <pre> 
SELECT  ROWNUM AS RNUM 
      , AA.*
      , CASE WHEN AA.CURR_PROG_CD IS NOT NULL THEN
            ('[' || AA.CURR_PROG_CD || '] ' || ( SELECT CD_MNNG FROM BRE.VW_CM_CODES WHERE CD_EN_ID = 'PROG_CD' AND CD_CAT_ID = 'HS0000' AND CD_VAL = AA.CURR_PROG_CD ) )
        END AS CURR_PROG_CD_NM
      , CASE WHEN AA.NEXT_PROC IS NOT NULL THEN
            ('[' || AA.NEXT_PROC || '] ' || ( SELECT CD_MNNG FROM BRE.VW_CM_CODES WHERE CD_EN_ID = 'NEXT_PROC' AND CD_CAT_ID = 'HS0000' AND CD_VAL = AA.NEXT_PROC ) )
        END AS NEXT_PROC_NM
      , CASE WHEN AA.CUST_CD IS NOT NULL THEN
            ('[' || AA.CUST_CD || '] ' || ( SELECT CUST_KO_NAME FROM TB_SM_CUSTINFO WHERE CUST_CD = AA.CUST_CD ) )
        END AS CUST_NM
      , CASE WHEN AA.CUST_CD IS NOT NULL THEN
            ( SELECT CUST_KO_NAME FROM TB_SM_CUSTINFO WHERE CUST_CD = AA.CUST_CD ) 
        END AS CUST_NM2
  FROM  (  
                SELECT  A.PROC_GP
                  , DECODE(A.PROC_GP,'F','HFL','K','SPM','Q','EQL','???') AS PROC_GP_NM
                  --, D.YD_EQP_GP 
                  , A.STL_NO
                  , A.YD_EQP_NM
                  , A.PROC_GP || '_' || SUBSTR(A.YD_STK_COL_GP,2,1) || ROW_NUMBER() OVER( PARTITION BY A.YD_GP, A.PROC_GP, SUBSTR(A.YD_STK_COL_GP,2,1)  ORDER BY A.SORT_SEQ)  AS EQUIP_ID
                  , C.COIL_T -- ЕЮВВ
                  , C.COIL_W -- Цј
                  , C.COIL_OUTDIA -- ПмАц
                  , C.COIL_WT -- СпЗЎ
                  , C.COIL_T AS COIL_T2
                  , TRIM(TO_CHAR(C.COIL_W,'9,999,999'))  AS COIL_W2
                  , TRIM(TO_CHAR(C.COIL_OUTDIA,'9,999,999')) AS COIL_OUTDIA2
                  , TRIM(TO_CHAR(C.COIL_WT,'9,999,999')) AS COIL_WT2
                  , C.STL_APPEAR_GP
                  , C.SPEC_ABBSYM
                  , C.ITEMNAME_CD
                  , C.CURR_PROG_CD
                  , CASE 
                        WHEN C.SKINPASS_YN IN('A', 'E')  AND C.SCRAP_CAUSE_CD IS  NULL AND C.CURR_PROG_CD NOT IN ('G','F','H')
                        THEN 'D'
                        WHEN C.SCRAP_CAUSE_CD IS NOT NULL AND C.CURR_PROG_CD <> 'C' AND A.PROC_GP <> 'F'
                        THEN 'S'
                        WHEN C.NEXT_PROC = '9S' AND C.CURR_PROG_CD <> 'C'
                        THEN 'I'
                        WHEN C.NEXT_PROC = '9C' AND C.CURR_PROG_CD = 'D'
                        THEN 'H'
                        ELSE DECODE(C.CURR_PROG_CD
                                 , '2', 'H'
                                 , '3', 'D'
                                 , '4', 'E'
                                 , '6', 'L'
                                 , '7', 'K'
                                 , '8', 'M'
                                 , '9', 'P'
                                 , C.CURR_PROG_CD)
                   END AS CURR_PROG_CD_IMG
                  , C.NEXT_PROC
                  , C.CUST_CD
                  , A.LOC_NO
                  , A.SKID_NO
                  , A.YD_STK_COL_GP
                  , A.YD_STK_BED_NO
                  , NVL((SELECT 'S' FROM TB_YF_WRKBOOKMTL WM WHERE WM.STL_NO = A.STL_NO AND WM.DEL_YN = 'N' AND ROWNUM = 1),D.YD_STK_LYR_STAT) AS YD_STK_LYR_STAT
                  , COUNT(A.STL_NO) OVER() AS TOTALCOUNT
                  , SUM(C.COIL_WT) OVER() AS TOTAL_WT  
                  , A.YD_BAY_GP
                  , SR.SHEAR_WORK_DT -- СЄСЄРЯНУ
                  , NVL(CASE WHEN A.PROC_GP = 'F' THEN 'Y' ELSE CASE WHEN SR.STEP_NO IS NULL THEN 'N' ELSE 'Y' END END,'N') AS IS_SHEAR_RST -- СЄСЄНЧРћ ЙпЛ§ПЉКЮ
                  , CASE WHEN NVL(SR.GOODS_DIVIDE_QNTY,0)>1 THEN 'Y' ELSE 'N' END AS IS_DCOIL -- ФкРЯЛ§МКБИКа(РкФкРЯ)
                  , (
                        SELECT R.REPR_CD_CONTENTS
                        FROM VW_YF_CONDENSATIONLOC VW, TB_YF_RULE R
                        WHERE VW.COIL_NO = A.STL_NO
                        AND R.REPR_CD_GP = 'YM6001'
                        AND R.CD_GP = '1'
                        AND R.DEL_YN = 'N'
                        AND VW.YD_ZONE_GP = R.ITEM
                  ) AS YD_ZONE_GP
                  , C.USAGE_CD 
                  , CASE WHEN A.STL_NO LIKE 'S%' THEN 'Y' ELSE 'N' END AS IS_SCRAP
                  , CASE WHEN
                        (
                            --СЄСЄ НЧРћ УГИЎЕШ ЧзИё Сп УжБй НЧРћРЬ РчРлОїРЮ АцПь УпУт.
                            SELECT
                                COUNT(*)
                            FROM
                                TB_HR_C_SHEARWOWR SR
                            WHERE 1=1
                            AND SR.STEP_NO =
                            (
                                SELECT --+ INDEX_DESC(A PK_HR_C_SHEARWOWR)
                                    MAX(STEP_NO)
                                FROM
                                    TB_HR_C_SHEARWOWR A
                                WHERE 1=1
                                AND COIL_NO = SR.COIL_NO
                                AND WORK_STAT = '*'
                                AND ROWNUM<=1
                            )
                            AND SR.COIL_NO = A.STL_NO
                            AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP in('J', 'Q')
                        ) = 1 THEN 'Y'
                        WHEN
                        (
                            SELECT
                                COUNT(*)
                            FROM
                                TB_PT_COILCOMM B
                            WHERE 1=1
                            AND B.COIL_NO = A.STL_NO
                            AND ((B.REMAIN_PROC1='1K' AND B.REMAIN_PROC2='1Q') OR B.REMAIN_PROC1='1Q')
                        ) = 1 THEN 'Y'
                        WHEN
                        (
                            SELECT
                                COUNT(*)
                            FROM
                                TB_PT_COILCOMM B
                            WHERE 1=1
                            AND B.COIL_NO = A.STL_NO
                            AND B.CURR_PROG_CD = 'F'
                            AND B.HOLD_CAUSE_CD = '43'  --ЦЧСЄКИЗљ : '43'
                        ) = 1 THEN 'Y'
                  ELSE 'N' END AS IS_RESKCAPING
                    --
                  , NVL((CASE   WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%1K%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%5K%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%6K%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%HK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%EK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%CK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%BK%' THEN 'Y'
                            WHEN  C.PASS_PROC1||C.PASS_PROC2||C.PASS_PROC3||C.PASS_PROC4||C.PASS_PROC5 LIKE '%AK%' THEN 'Y'
                            ELSE 'N' END),'N') AS IS_RESKCAPING
                   
              FROM  TB_YF_EQPTRACKING A
                  , TB_PT_COILCOMM C
                  , TB_YF_STKLYR D 
                  , TB_HR_C_SHEARWOWR SR
             WHERE  A.YD_GP = '1'
               AND  A.PROC_GP IN ('F', 'K', 'Q')
               AND  A.PROC_GP LIKE :V_PROC_GP || '%' --F:HFL,K:SPM,Q:EQL
               AND  A.STL_NO = C.COIL_NO(+)
               AND  A.STL_NO = SR.COIL_NO(+)
               AND  NVL(SR.STEP_NO,0) = ( SELECT NVL(MAX(X.STEP_NO),0) FROM TB_HR_C_SHEARWOWR X WHERE X.COIL_NO = A.STL_NO)
               AND  A.YD_STK_COL_GP = D.YD_STK_COL_GP(+)
               AND  A.YD_STK_BED_NO = D.YD_STK_BED_NO(+)
               AND  D.YD_STK_LYR_NO(+) = '01' 
             ORDER BY A.YD_GP, A.PROC_GP, A.SORT_SEQ 
) AA
 </pre> */
public final static String getListCOILGPTrackingByHFLSPMEQL = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListCOILGPTrackingByHFLSPMEQL";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCStkLyrMtl
WITH CSM AS
(
    SELECT
        CM.STL_NO,
        SUBSTR(CS.YD_UP_WO_LOC,1,6) AS YD_STK_COL_GP_UP,
        SUBSTR(CS.YD_UP_WO_LOC,7,2) AS YD_STK_BED_NO_UP,
        SUBSTR(CS.YD_DN_WO_LOC,1,6) AS YD_STK_COL_GP_DN,
        SUBSTR(CS.YD_DN_WO_LOC,7,2) AS YD_STK_BED_NO_DN,
        CS.YD_UP_WO_LYR AS YD_STK_LYR_GP,
        CS.YD_CRN_SCH_ID,
        CS.YD_TO_LOC_DCSN_MTD
    FROM
        TB_YF_CRNSCH CS,
        (
            SELECT
                CS.YD_CRN_SCH_ID AS YD_CRN_SCH_ID,
                CM.STL_NO
            FROM
                TB_YF_CRNSCH    CS,
                TB_YF_CRNWRKMTL CM
            WHERE 1=1
            AND CM.YD_CRN_SCH_ID    = CS.YD_CRN_SCH_ID
            AND CS.YD_WBOOK_ID      = :V_YD_WBOOK_ID
            AND CM.YD_CRN_SCH_ID    = :V_YD_CRN_SCH_ID
            AND CS.DEL_YN           = 'N'
            AND CM.DEL_YN           = 'N'
        ) CM
    WHERE 1=1
    AND CS.YD_CRN_SCH_ID    = CM.YD_CRN_SCH_ID
    AND CS.DEL_YN           = 'N'
)
SELECT
    YD_STK_COL_GP,
    YD_STK_BED_NO,
    YD_STK_LYR_NO,
    MAX(STL_NO) AS STL_NO,
    MIN(YD_STK_LYR_STAT) AS YD_STK_LYR_STAT
FROM
    (
        --ПјЗЁРЇФЁ
        SELECT
            SL.YD_STK_COL_GP,
            SL.YD_STK_BED_NO,
            SL.YD_STK_LYR_NO,
            SL.STL_NO,
            'C' AS YD_STK_LYR_STAT --РћФЁСп
        FROM
            TB_YF_STKLYR SL,
            CSM
        WHERE 1=1
        AND SL.STL_NO           = CSM.STL_NO
        AND SL.YD_STK_COL_GP    = CSM.YD_STK_COL_GP_UP
        AND SL.YD_STK_LYR_STAT  = 'U' --БЧЛѓДыБт
        
        UNION ALL
        
        --БЧЧЯСіНУРЇФЁ
        SELECT
            SL.YD_STK_COL_GP,
            SL.YD_STK_BED_NO,
            SL.YD_STK_LYR_NO,
            NULL AS STL_NO,
            'E' AS YD_STK_LYR_STAT --РћФЁАЁДЩ
        FROM
            TB_YF_STKLYR SL,
            CSM
        WHERE 1=1
        AND SL.YD_STK_LYR_STAT  = 'D' --БЧЧЯДыБт
        AND SL.STL_NO           = CSM.STL_NO
        AND SL.YD_STK_COL_GP    = CSM.YD_STK_COL_GP_DN
        AND SL.YD_STK_BED_NO    = CSM.YD_STK_BED_NO_DN
    )
GROUP BY YD_STK_COL_GP, YD_STK_BED_NO, YD_STK_LYR_NO
 </pre> */
public final static String getCrnWrkMgtSCStkLyrMtl = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCrnWrkMgtSCStkLyrMtl";

