 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAxYML009CarSchLd2
WITH DATA_TBL AS
(
    SELECT
        CTS_RELAY_SADDLE,
        STL_NO AS V_STL_NO,
        :V_YD_CRN_SCH_ID AS V_YD_CRN_SCH_ID
    FROM
        TB_YF_STOCK A
    WHERE STL_NO = :V_STL_NO
)
SELECT
    A.YD_CAR_SCH_ID,
    A.YD_CAR_USE_GP,
    A.CAR_NO,
    A.CARD_NO,
    A.BAY_WRK_CNT,      -- ЧиДчЛѓТїЕЕ РлОїДыЛѓ
    A.BAY_WRK_END_CNT,  -- ЧиДч ЛѓТїЕЕ РлОїПЯЗс
    A.TRANS_ORD_DATE,
    A.TRANS_ORD_SEQNO,
    A.YD_STK_COL_GP,
    A.WLOC_CD,
    A.YD_PNT_CD,
    (SELECT YD_CARPNT_CD FROM TB_YD_CARPOINT WHERE YD_STK_COL_GP = A.YD_STK_COL_GP) AS YD_CARPNT_CD,
    A.YD_CAR_PROG_STAT, -- ТїЗЎСјЧр
    CASE
    WHEN A.BAY_WRK_CNT <= A.BAY_WRK_END_CNT THEN 'Y'
    ELSE 'N' END AS CAR_LD_CMPL_YN,  --ЧиДчЛѓТїЕЕ
    A.CARUNLOAD_BAY AS TO_BAY_GP,
    A.CTS_RELAY_SADDLE,
    CASE
    WHEN A.CTS_RELAY_SADDLE IN ('1') THEN '1' || A.CARUNLOAD_BAY ||'PT32LM'
    WHEN A.CTS_RELAY_SADDLE IN ('2') THEN '1' || A.CARUNLOAD_BAY ||'PT31LM'
    WHEN A.CTS_RELAY_SADDLE IN ('3') THEN '1' || A.CARUNLOAD_BAY ||'PT31LM'
    WHEN A.CTS_RELAY_SADDLE IN ('4') THEN '1' || A.CARUNLOAD_BAY ||'PT32LM'
    END AS TO_YD_SCH_CD,
    A.CTS_RELAY_SADDLE
FROM
    (
        SELECT
            TS.YD_CAR_SCH_ID,
            TS.YD_CAR_USE_GP,
            TS.CAR_NO,
            TS.CARD_NO,
            TS.TRANS_ORD_DATE,
            TS.TRANS_ORD_SEQNO,
            TS.DEST_TEL_NO,
            TS.YD_CAR_PROG_STAT,
            TS.TRANS_EQUIPMENT_TYPE,
            TS.CMBN_CARLD_YN,
            SC.YD_STK_COL_GP,
            SC.WLOC_CD,
            SC.YD_PNT_CD,
            ST.CTS_RELAY_SADDLE,
            --ЧиДчЛѓТїЕЕ РлОїДыЛѓ АЧМі
            --УтЧЯ
            (
                SELECT
                    COUNT(DISTINCT(B.STL_NO))
                FROM
                    TB_YF_STOCK B,
                    TB_YD_CARPOINT C,
                    TB_YF_STKLYR D
                WHERE 1=1
                AND B.STL_NO = D.STL_NO
                AND B.TRANS_ORD_DATE = TS.TRANS_ORD_DATE
                AND B.TRANS_ORD_SEQNO = TS.TRANS_ORD_SEQNO
                AND SUBSTR(D.YD_STK_COL_GP, 2, 1) = SUBSTR(C.YD_STK_COL_GP, 2, 1)
                AND C.YD_STK_COL_GP = SC.YD_STK_COL_GP
                AND D.YD_STK_LYR_STAT IN ('U', 'C')
            ) AS BAY_WRK_CNT,
            --ЧиДчЛѓТїЕЕ РлОїПЯЗс АЧМі
            (
                SELECT
                    COUNT(DISTINCT(A.COIL_NO))
                FROM
                    TB_PT_COILCOMM A
                WHERE 1=1
                AND SUBSTR(A.YD_STR_LOC,3,2) IN ('PT')
                AND A.COIL_NO IN 
                (
                    SELECT
                        B.STL_NO
                    FROM
                        TB_YF_STOCK B,
                        TB_YD_CARPOINT C,
                        TB_YF_STKLYR D
                    WHERE 1=1
                    AND B.STL_NO = D.STL_NO
                    AND B.TRANS_ORD_DATE = TS.TRANS_ORD_DATE
                    AND B.TRANS_ORD_SEQNO = TS.TRANS_ORD_SEQNO
                    AND SUBSTR(D.YD_STK_COL_GP, 2, 1) = SUBSTR(C.YD_STK_COL_GP, 2, 1)
                    AND C.YD_STK_COL_GP = SC.YD_STK_COL_GP
                    AND D.YD_STK_LYR_STAT IN ('C')
                )
            ) AS BAY_WRK_END_CNT,
            (
                SELECT
                    WB.YD_AIM_BAY_GP
                FROM TB_YF_CRNSCH CR, TB_YF_WRKBOOK WB
                WHERE CR.YD_CRN_SCH_ID = ST.V_YD_CRN_SCH_ID
                AND CR.YD_WBOOK_ID = WB.YD_WBOOK_ID
            ) AS CARUNLOAD_BAY -- ЧЯТїЕП БИЧЯБт 2020 01-15 
        FROM
            TB_YF_STKCOL SC,
            USRYDA.TB_YD_CARSCH TS,
            DATA_TBL ST
        WHERE 1=1
        AND SC.YD_STK_COL_GP = :V_YD_STK_COL_GP
        AND SC.YD_CAR_USE_GP = TS.YD_CAR_USE_GP
        AND SC.YD_CAR_USE_GP = 'G'
        AND SC.CAR_NO = TS.CAR_NO
        AND TS.DEL_YN = 'N'
    ) A
 </pre> */
public final static String getAxYML009CarSchLd2 = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAxYML009CarSchLd2";

