 /** <pre> 
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.getCarMvMtlBySchIdLyr 
WITH CAR_INFO AS (
    SELECT
         A.YD_CAR_SCH_ID                 --ОпЕхТїЗЎНКФЩСьID
        ,A.TRN_EQP_CD                    --ПюМлРхКёФкЕх
        ,A.YD_CARUD_STOP_LOC             --ОпЕхЧЯТїСЄСіРЇФЁ(ПьИЎУј СЄСіРЇФЁ)
        ,CM.CD_MNNG         AS YD_CAR_PROG_STAT_NM
     FROM TB_YD_CARSCH A
         ,VW_CM_CODES CM
    WHERE A.TRN_EQP_CD = :V_TRN_EQP_CD
      AND A.TRN_EQP_CD IS NOT NULL
      AND A.DEL_YN ='N'
      AND A.YD_CAR_PROG_STAT = CM.CD_VAL(+)
      AND CM.CD_EN_ID(+) = 'YD_CAR_PROG_STAT'
      AND CM.CD_CAT_ID(+) = 'HS0000'
)
,CARFTMVMTL AS (
    SELECT MV.YD_STK_BED_NO 
          ,SUBSTR(NVL(MV.YD_STK_LYR_NO,'001'),-2) AS YD_STK_LYR_NO 
          ,MV.STL_NO
          ,MV.STL_NO AS OLD_SSTL_NO
          ,SLAB.SLAB_T 
          ,SLAB.SLAB_W
          ,SLAB.SLAB_LEN 
          ,SLAB.SLAB_WT 
          ,SLAB.SLAB_T AS SLAB_T2
          ,TRIM(TO_CHAR(SLAB.SLAB_W,'9,999,999'))  AS SLAB_W2
          ,TRIM(TO_CHAR(SLAB.SLAB_LEN,'9,999,999')) AS SLAB_LEN2
          ,TRIM(TO_CHAR(SLAB.SLAB_WT,'9,999,999')) AS SLAB_WT2
          ,SLAB.ITEMNAME_CD
          ,SLAB.CURR_PROG_CD
          ,SLAB.SPEC_ABBSYM
          ,MV.YD_CAR_SCH_ID
          ,MV.DEL_YN
          
          ,SLAB.SCARFING_YN
          ,SLAB.SCARFING_DONE_YN 
          ,SLAB.STL_APPEAR_GP
          ,SLAB.SLAB_NO
          ,SLAB.ORD_YEOJAE_GP
          ,SLAB.SLAB_WO_RT_CD
          ,H.CT_MILL_SPEC_WRK_STAT_GP
          
          ,CAR.TRN_EQP_CD
          ,CAR.YD_CARUD_STOP_LOC
          ,CAR.YD_CAR_PROG_STAT_NM
          
    FROM   TB_YD_CARFTMVMTL MV
          ,VW_YD_SLABCOMM SLAB
          ,TB_CT_K_HRMILLSPEC H
          ,CAR_INFO CAR
    WHERE  MV.YD_CAR_SCH_ID = CAR.YD_CAR_SCH_ID
    AND    MV.STL_NO = SLAB.SLAB_NO(+)
    AND    MV.STL_NO = H.STL_NO(+)
    AND    MV.DEL_YN = 'N'
    ORDER BY MV.YD_STK_LYR_NO
)

            SELECT    SL.YD_STK_BED_NO      
                    , SL.YD_STK_LYR_NO   
                    , MA.YD_STK_BED_NO AS YD_STK_BED_NO2      
                    , MA.YD_STK_LYR_NO AS YD_STK_LYR_NO2      
                    , MA.STL_NO             
                    , MA.OLD_SSTL_NO        
                    , MA.SLAB_T             
                    , MA.SLAB_W             
                    , MA.SLAB_LEN           
                    , MA.SLAB_WT            
                    , MA.SLAB_T AS SLAB_T2  
                    , MA.SLAB_W2            
                    , MA.SLAB_LEN2          
                    , MA.SLAB_WT2           
                    , MA.ITEMNAME_CD        
                    , MA.CURR_PROG_CD       
                    , MA.SPEC_ABBSYM        
                    , MA.YD_CAR_SCH_ID      
                    , MA.DEL_YN       
                    , MA.TRN_EQP_CD
                    , MA.YD_CARUD_STOP_LOC
                    , MA.YD_CAR_PROG_STAT_NM
            FROM   (
                        SELECT A.YD_STK_BED_NO 
                              ,A.YD_STK_LYR_NO 
                        FROM   TB_YF_STKLYR   A
                        WHERE  YD_STK_COL_GP LIKE  :V_YD_GP || 'APT01'
                        AND    YD_STK_LYR_NO < '07'
                        ORDER BY YD_STK_LYR_NO DESC,YD_STK_BED_NO
                   ) SL
                  ,CARFTMVMTL MA
            WHERE  SL.YD_STK_BED_NO = MA.YD_STK_BED_NO(+)
            AND    SL.YD_STK_LYR_NO = MA.YD_STK_LYR_NO(+)
 </pre> */
