 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getCF1BP04BackUp 
--КаБт LINE OFF НЧРћ
SELECT NEW_TC_CD                           AS JMS_TC_CD          --JMSTCФкЕх
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
      ,JMS_TC_CD                                     --РќЙЎID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DD')       --Л§МКРЯНУ
     ||TO_CHAR(SYSDATE,'HH24-MI-SS')       --Л§МКРЯНУ
     ||RPAD(NVL(TC_ID                 ,'I'), 1,' ') --РќЙЎБИКа
     ||'0012'                                        --РќЙЎБцРЬ
     ||RPAD(NVL(STL_NO              ,' '),10,' ') --COILNO
     ||RPAD(' ',2,' ')                              --РгНУ
       AS JMS_TC_MESSAGE --JMSTCMESSAGE
FROM (
        SELECT 'POCFL104'           AS NEW_TC_CD  -- CF1BP04 --> POCFL104
             , 'CF1BP04'            AS JMS_TC_CD    --РќЙЎID
             , 'I'                  AS TC_ID        --РќЙЎБИКа
             , A.STL_NO             AS STL_NO
          FROM TB_YF_CRNWRKMTL A
         WHERE YD_CRN_SCH_ID = (
                                  SELECT MAX(CM.YD_CRN_SCH_ID) AS YD_CRN_SCH_ID
                                    FROM TB_YF_CRNWRKMTL CM
                                       , TB_YF_CRNSCH    CR
                                   WHERE CM.YD_CRN_SCH_ID = CR.YD_CRN_SCH_ID
                                     AND CM.STL_NO = :V_STL_NO
                               )
        )
 </pre> */
