 /** <pre> 
--yf.facilitystatus.facilityinquiry.YfCommonDAO.getLyrUpperSlab2
WITH PARAM AS(
SELECT :V_STL_NO        AS STL_NO
  FROM DUAL 
)

, STKLYR AS (
SELECT A.YD_STK_COL_GP
      ,A.YD_STK_BED_NO
      ,A.YD_STK_LYR_NO
      ,A.STL_NO
  FROM TB_YF_STKLYR A
      ,PARAM P
 WHERE A.STL_NO = P.STL_NO
)
  
SELECT A.*
  FROM TB_YF_STKLYR A
      ,STKLYR
 WHERE A.YD_STK_COL_GP = STKLYR.YD_STK_COL_GP
   AND A.YD_STK_BED_NO = STKLYR.YD_STK_BED_NO
   AND A.YD_STK_LYR_NO >= STKLYR.YD_STK_LYR_NO
   AND A.YD_STK_LYR_NO < 16
   AND A.STL_NO IS NOT NULL
 ORDER BY A.YD_STK_LYR_NO ASC
 </pre> */
