 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilYdNEqpXyaxisSet
SELECT X.YD_STK_COL_GP                                                    -- РћФЁП­БИКа
      ,X.COL_GP                                                          -- РћФЁП­ЙјШЃ
      ,X.YD_STK_COL_ACTIVE_STAT                                           -- РћФЁП­ШАМКЛѓХТ
      ,decode(X.YD_STK_COL_ACTIVE_STAT,'C','КёШАМКШ­'
                                   ,'L','РћФЁ АЁДЩ'
                                   ,'N','ЛчПы КвАЁ')
                                   AS YD_STK_COL_ACTIVE_STATHIDDEN        -- РћФЁП­ШАМКЛѓХТ
      ,Y.SUM_LYR_CNT_L1 + SUM_LYR_CNT_L2 AS SUM_LYR_CNT_TOT              -- УжДыРћФЁАЁДЩКЛМі
      ,Y.SUM_LYR_CNT_L1                                                  -- 1ДмРћФЁАЁДЩКЛМі
      ,Y.SUM_LYR_CNT_L2                                                  -- 2ДмРћФЁАЁДЩКЛМі
      ,Y.SUM_STL_CNT_TOT                                                 -- ЧіРћФЁКЛМі
      ,Y.SUM_STL_CNT_L1                                                  -- 1ДмРћФЁКЛМі
      ,Y.SUM_STL_CNT_L2                                                  -- 2ДмРћФЁКЛМі
      ,X.YD_STK_COL_RULE_X_AXIS 
      ,X.YD_STK_COL_RULE_Y_AXIS 
      ,X.YD_STK_COL_RULE_Z_AXIS
      ,X.YD_STK_COL_RULE_X_AXIS AS YD_STK_COL_RULE_X_AXIS_HIDDEN
      ,X.YD_STK_COL_RULE_Y_AXIS AS YD_STK_COL_RULE_Y_AXIS_HIDDEN
      ,X.YD_STK_COL_RULE_Z_AXIS AS YD_STK_COL_RULE_Z_AXIS_HIDDEN
      ,(CASE WHEN X.MOD_DDTT > Z.MOD_DDTT THEN X.MODIFIER
        ELSE Z.MODIFIER END) AS MODIFIER
      ,TO_CHAR((CASE WHEN X.MOD_DDTT > Z.MOD_DDTT THEN X.MOD_DDTT
        ELSE Z.MOD_DDTT END), 'YYYY-MM-DD HH24:MI') AS MOD_DDTT
      ,X.ROTATION_ANGLE
      ,X.STOCK_ITEM
      ,X.YD_STK_COL_USAGE_CD
      ,X.YD_ZONE_GP
  FROM (SELECT YD_STK_COL_GP
              ,COL_GP
              ,YD_STK_COL_ACTIVE_STAT
              ,YD_STK_COL_RULE_X_AXIS
              ,YD_STK_COL_RULE_Y_AXIS
              ,YD_STK_COL_RULE_Z_AXIS
              ,MODIFIER
              ,MOD_DDTT
              ,ROTATION_ANGLE
              ,STOCK_ITEM
              ,YD_STK_COL_USAGE_CD
              ,YD_ZONE_GP
          FROM TB_YF_STKCOL
         WHERE YD_GP = :V_YD_GP
           AND BAY_GP  LIKE :V_YD_BAY_GP  || '%'
           AND SECT_GP LIKE :V_YD_SECT_GP || '%'
           AND COL_GP  LIKE :V_YD_COL_GP  || '%'
           AND DEL_YN = 'N'
           AND SECT_GP NOT IN ('CR','TR','TT','XX')
         ORDER BY COL_GP ) X
      ,(SELECT YD_STK_COL_GP
              ,SUM(CASE WHEN YD_STK_LYR_NO = '01' AND YD_STK_LYR_STAT = 'E' THEN 1 ELSE 0 END) AS SUM_LYR_CNT_L1 -- 1ДмРћФЁАЁДЩКЛМі
              ,SUM(CASE WHEN YD_STK_LYR_NO = '02' AND YD_STK_LYR_STAT = 'E' THEN 1 ELSE 0 END) AS SUM_LYR_CNT_L2 -- 2ДмРћФЁАЁДЩКЛМі
              ,SUM(DECODE(STL_NO, NULL, 0, 1)) AS SUM_STL_CNT_TOT                                                -- ЧіРћФЁКЛМі
              ,SUM(DECODE(STL_NO, NULL, 0, DECODE(YD_STK_LYR_NO, '01', 1, 0))) AS SUM_STL_CNT_L1                -- 1ДмРћФЁКЛМі
              ,SUM(DECODE(STL_NO, NULL, 0, DECODE(YD_STK_LYR_NO, '02', 1, 0))) AS SUM_STL_CNT_L2                -- 2ДмРћФЁКЛМі
          FROM TB_YF_STKLYR
         WHERE YD_STK_COL_GP LIKE :V_YD_GP || NVL(:V_YD_BAY_GP,'_') || NVL(:V_YD_SECT_GP,'__') || NVL(:V_YD_COL_GP,'') || '%'
           AND DEL_YN = 'N'
         GROUP BY YD_STK_COL_GP ) Y
      ,(SELECT * 
          FROM TB_YF_STKBED
         WHERE YD_STK_BED_NO = '01') Z
 WHERE X.YD_STK_COL_GP = Y.YD_STK_COL_GP
   AND X.YD_STK_COL_GP = Z.YD_STK_COL_GP(+)
 ORDER BY X.YD_STK_COL_GP
 </pre> */
public final static String getacoilYdNEqpXyaxisSet = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getacoilYdNEqpXyaxisSet";

 /** <pre> 
--com.inisteel.cim.yf.aslab.dao.ASlabDAO.getStockIdByLoc
SELECT
    STL_NO,
    YD_STK_LYR_STAT,
    YD_STK_LYR_ACTIVE_STAT,
    TRIM(TO_CHAR(YD_STK_BED_NO + 1, '00')) AS NEXT_BED_GP,
    YD_STK_COL_GP,
    YD_STK_BED_NO,
    YD_STK_LYR_NO
FROM
    TB_YF_STKLYR
WHERE 1=1
AND YD_STK_COL_GP = :V_YD_STK_COL_GP
AND YD_STK_BED_NO = :V_YD_STK_BED_NO
AND YD_STK_LYR_NO LIKE :V_YD_STK_LYR_NO || '%'
 </pre> */
public final static String getStockIdByLoc = "bak.com.inisteel.cim.yf.aslab.dao.ASlabDAO.getStockIdByLoc";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfColBedInfo 
-- РћФЁП­Bed СЄКИ СЖШИ 
SELECT COL.YD_STK_COL_GP
     , COL.YD_GP
     , COL.BAY_GP
     , COL.SECT_GP
     , COL.COL_GP
     , COL.YD_STK_COL_ACTIVE_STAT
     , BED.YD_STK_BED_NO
--     , BED.YD_STK_BED_ACTIVE_STAT
     , 'C' || SUBSTR(BED.YD_STK_COL_GP,5,2) AS COL_ID
     , 'C' || SUBSTR(BED.YD_STK_COL_GP,5,2) || 'B' || BED.YD_STK_BED_NO AS BED_ID
     --
     , CASE WHEN YD_STK_LYR_ACTIVE_STAT_01 = 'E' AND YD_STK_LYR_ACTIVE_STAT_02 = 'E'       THEN 'L' --РћФЁАЁДЩ
            WHEN YD_STK_LYR_ACTIVE_STAT_01 = 'E' AND YD_STK_LYR_ACTIVE_STAT_02 = 'N' THEN 'A' --2ДмРћФЁКвАЁ
            WHEN YD_STK_LYR_ACTIVE_STAT_01 = 'E' AND YD_STK_LYR_ACTIVE_STAT_02 = 'C' THEN 'C2' --2ДмРћФЁКвАЁ
            WHEN YD_STK_LYR_ACTIVE_STAT_01 = 'C' THEN 'C' --2ДмРћФЁКвАЁ
            ELSE 'X' END 
       AS YD_STK_BED_ACTIVE_STAT
     
     , YD_STK_LYR_ACTIVE_STAT_01 AS YD_STK_LYR_ACTIVE_STAT
     , YD_STK_LYR_ACTIVE_STAT_02
					, YD_STK_LYR_YD_STK_LOT_NO2_01
					, YD_STK_LYR_YD_STK_LOT_NO2_02
     , MAX(TO_NUMBER(BED.YD_STK_BED_NO)) OVER(PARTITION BY BED.YD_STK_COL_GP )-1 AS MAX_LYR2_BED_NO -- 2Дм ЧЅЧі 
  FROM TB_YF_STKCOL COL
     , TB_YF_STKBED  BED
     ,(
        SELECT YD_STK_COL_GP
             , YD_STK_BED_NO
             , MAX(YD_STK_LYR_ACTIVE_STAT_01) AS YD_STK_LYR_ACTIVE_STAT_01
             , NVL(MAX(YD_STK_LYR_ACTIVE_STAT_02), 'N') AS YD_STK_LYR_ACTIVE_STAT_02
													, MAX(YD_STK_LYR_YD_STK_LOT_NO2_01) AS YD_STK_LYR_YD_STK_LOT_NO2_01
													, MAX(YD_STK_LYR_YD_STK_LOT_NO2_02) AS YD_STK_LYR_YD_STK_LOT_NO2_02
         FROM (
                SELECT YD_STK_COL_GP
                     , YD_STK_BED_NO
                     , CASE WHEN YD_STK_LYR_NO = '01' THEN YD_STK_LYR_ACTIVE_STAT ELSE '' END AS YD_STK_LYR_ACTIVE_STAT_01
                     , CASE WHEN YD_STK_LYR_NO = '02' THEN YD_STK_LYR_ACTIVE_STAT ELSE '' END AS YD_STK_LYR_ACTIVE_STAT_02
																					, CASE WHEN YD_STK_LYR_NO = '01' THEN YD_STK_LYR_YD_STK_LOT_NO2 ELSE '' END AS YD_STK_LYR_YD_STK_LOT_NO2_01
																					, CASE WHEN YD_STK_LYR_NO = '02' THEN YD_STK_LYR_YD_STK_LOT_NO2 ELSE '' END AS YD_STK_LYR_YD_STK_LOT_NO2_02
                  FROM (       
                        SELECT YD_STK_COL_GP
                             , YD_STK_BED_NO
                             , YD_STK_LYR_NO
                             , YD_STK_LYR_ACTIVE_STAT
																													, CASE YD_STK_LYR_YD_STK_LOT_NO2 WHEN 'Z' THEN '(Пь)' WHEN 'Y' THEN '(БтХИ)' END AS YD_STK_LYR_YD_STK_LOT_NO2
                          FROM TB_YF_STKLYR
                         WHERE YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
                       )
               )
         GROUP BY YD_STK_COL_GP, YD_STK_BED_NO
       ) LYR
 WHERE COL.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
   AND COL.YD_STK_COL_GP = BED.YD_STK_COL_GP
   AND BED.YD_STK_COL_GP = LYR.YD_STK_COL_GP
   AND BED.YD_STK_BED_NO = LYR.YD_STK_BED_NO
   AND COL.DEL_YN = 'N'
   AND BED.DEL_YN = 'N'
 ORDER BY YD_STK_COL_GP, BED.YD_STK_BED_NO
 </pre> */
public final static String getYfColBedInfo = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfColBedInfo";

