 /** <pre> 
--com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabInfo
SELECT SLAB.SLAB_NO
      ,SLAB.SLAB_T 
      ,SLAB.SLAB_W
      ,SLAB.SLAB_LEN 
      ,SLAB.SLAB_WT 
      ,SLAB.SLAB_T AS SLAB_T2
      ,TRIM(TO_CHAR(SLAB.SLAB_W,'9,999,999'))  AS SLAB_W2
      ,TRIM(TO_CHAR(SLAB.SLAB_LEN,'9,999,999')) AS SLAB_LEN2
      ,TRIM(TO_CHAR(SLAB.SLAB_WT,'9,999,999')) AS SLAB_WT2
      ,SLAB.ITEMNAME_CD
      ,SLAB.CURR_PROG_CD
      ,SLAB.SPEC_ABBSYM
      ,SLAB.HCR_GP
      ,(SELECT COUNT(STL_NO)
          FROM TB_YF_STKLYR A
         WHERE A.STL_NO = SLAB.SLAB_NO
           AND A.DEL_YN = 'N'
           AND A.STL_NO NOT IN ( SELECT STL_NO
                                   FROM TB_YD_CARFTMVMTL B
                                  WHERE B.DEL_YN = 'N'
                                    AND B.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
                                )) AS SLAB_CHK
      ,(SELECT ARR_WLOC_CD
          FROM TB_PT_STLFRTOMOVE A
         WHERE A.STL_NO = SLAB.SLAB_NO
           AND A.TRANSWORD_SEQNO = (SELECT MAX(Z.TRANSWORD_SEQNO)
                                      FROM TB_PT_STLFRTOMOVE Z
                                     WHERE Z.STL_NO = A.STL_NO)) AS ARR_WLOC_CD
     ,(SELECT SPOS_WLOC_CD
         FROM TB_PT_STLFRTOMOVE A
        WHERE A.STL_NO = SLAB.SLAB_NO
          AND A.TRANSWORD_SEQNO = (SELECT MAX(Z.TRANSWORD_SEQNO)
                                     FROM TB_PT_STLFRTOMOVE Z
                                    WHERE Z.STL_NO = A.STL_NO)) AS SPOS_WLOC_CD
                          
  FROM VW_YD_SLABCOMM SLAB 
 WHERE SLAB.HCR_GP IS NOT NULL
   AND SLAB.SLAB_NO = :V_SLAB_NO
   
 </pre> */
public final static String getSlabInfo = "bak.com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabInfo";

 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getYdTableColumnInfo 
    SELECT
          A.OWNER
        , A.TABLE_NAME
        , A.COLUMN_ID
        , A.COLUMN_NAME
        , A.DATA_TYPE
        , CASE A.DATA_TYPE 
            WHEN 'DATE' THEN NULL
            WHEN 'NUMBER' THEN A.DATA_PRECISION || '.' || A.DATA_SCALE
          ELSE TO_CHAR(A.DATA_LENGTH) END AS DATA_LENGTH
        , A.NULLABLE
        ,(
            SELECT
                COMMENTS
            FROM ALL_COL_COMMENTS
            WHERE  OWNER = A.OWNER
            AND TABLE_NAME = A.TABLE_NAME
            AND COLUMN_NAME = A.COLUMN_NAME
        ) AS COMMENTS,
        (
            SELECT S1.CONSTRAINT_TYPE
            FROM ALL_CONSTRAINTS S1
                , ALL_CONS_COLUMNS S2
            WHERE S2.TABLE_NAME = A.TABLE_NAME
            AND S2.COLUMN_NAME = A.COLUMN_NAME
            AND S2.CONSTRAINT_NAME = S1.CONSTRAINT_NAME
            AND S2.TABLE_NAME  = S1.TABLE_NAME
            AND S1.CONSTRAINT_TYPE = 'P'
        ) AS CONSTRAINT_TYPE
    FROM ALL_TAB_COLS A, ALL_TAB_COLUMNS B
    WHERE A.TABLE_NAME = :V_TABLE_NAME
    AND A.OWNER = B.OWNER
    AND A.TABLE_NAME = B.TABLE_NAME
    AND A.COLUMN_NAME = B.COLUMN_NAME
    ORDER BY A.COLUMN_ID
 </pre> */
public final static String getYdTableColumnInfo = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getYdTableColumnInfo";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.updZoneCd1
MERGE INTO TB_YF_SCHLOCSRCH_ZONE_V USING (
    SELECT  
            :V_VER_ID                AS V_VER_ID
          , :V_YD_ZONE_GP            AS V_YD_ZONE_GP
		  , :V_YD_STK_COL_GP         AS V_YD_STK_COL_GP
		  , :V_MODIFIER              AS V_MODIFIER
		  , :V_YD_LOC_SRCH_RNG_SEQ   AS V_YD_LOC_SRCH_RNG_SEQ
             
      FROM  DUAL
) ON (      
                   VER_ID        = V_VER_ID
            AND YD_STK_COL_GP = V_YD_STK_COL_GP
     )
WHEN MATCHED THEN
    UPDATE SET YD_LOC_SRCH_RNG_SEQ = V_YD_LOC_SRCH_RNG_SEQ
             , YD_ZONE_GP = V_YD_ZONE_GP
    		 , MODIFIER = V_MODIFIER
    		 , MOD_DDTT = SYSDATE
	    	 , DEL_YN   = 'N'
WHEN NOT MATCHED THEN
    INSERT  (
                  VER_ID
		        , YD_STK_COL_GP
		        , REGISTER
		        , REG_DDTT
		        , MODIFIER
		        , MOD_DDTT
		        , DEL_YN
		        , YD_LOC_SRCH_RNG_SEQ
                , YD_ZONE_GP
		    ) VALUES (
                  V_VER_ID
		        , V_YD_STK_COL_GP
		        , V_MODIFIER
		        , SYSDATE
		        , V_MODIFIER
		        , SYSDATE
		        , 'N'
		        , V_YD_LOC_SRCH_RNG_SEQ
                , V_YD_ZONE_GP
		    )
 </pre> */
public final static String updZoneCd1 = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.updZoneCd1";

 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.chkXAxis 
SELECT CASE WHEN BEFO_X = 0 THEN 'F' --AND CURR_X + RNG < NEXT_X   THEN 'T'
            WHEN NEXT_X = 0 THEN 'F' --AND CURR_X + RNG > BEFO_X   THEN 'T'
            WHEN CURR_X BETWEEN (BEFO_X+NEXT_X)/2 - RNG AND (BEFO_X+NEXT_X)/2 + RNG THEN 'T'
            ELSE 'F' END AS CHK_VAL
     , BEFO_X
     , CURR_X
     , NEXT_X
     , BEFO_YD_STK_COL_GP
     , YD_STK_COL_GP
     , NEXT_YD_STK_COL_GP
     , RNG
  FROM (
        SELECT A.*
             , :V_YD_STK_COL_RULE_X_AXIS AS CURR_X
             , NVL((SELECT YD_STK_COL_RULE_X_AXIS FROM TB_YF_STKCOL WHERE YD_STK_COL_GP = A.BEFO_YD_STK_COL_GP),0) AS BEFO_X
             , NVL((SELECT YD_STK_COL_RULE_X_AXIS FROM TB_YF_STKCOL WHERE YD_STK_COL_GP = A.NEXT_YD_STK_COL_GP),0) AS NEXT_X
             , B.DTL_ITEM1 AS RNG
          FROM (
                SELECT *
                  FROM (
                        SELECT LAG (A.YD_STK_COL_GP, 2) OVER (ORDER BY YD_STK_COL_GP) BEFO_YD_STK_COL_GP2
                             , LAG (A.YD_STK_COL_GP, 1) OVER (ORDER BY YD_STK_COL_GP) BEFO_YD_STK_COL_GP
                             , A.YD_STK_COL_GP
                             , LEAD(A.YD_STK_COL_GP, 1) OVER (ORDER BY YD_STK_COL_GP) NEXT_YD_STK_COL_GP
                             , LEAD(A.YD_STK_COL_GP, 2) OVER (ORDER BY YD_STK_COL_GP) NEXT_YD_STK_COL_GP2
                          FROM TB_YF_STKCOL A
                         WHERE 1 = 1
                           AND A.YD_STK_COL_GP LIKE SUBSTR(:V_YD_STK_COL_GP,1,2)||'%'
                           AND SUBSTR(A.YD_STK_COL_GP,3,2) BETWEEN '01' AND '99'
                           AND DEL_YN = 'N'
                         ORDER BY A.YD_STK_COL_GP
                       )
                 WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
               ) A
             , (SELECT DTL_ITEM1
                  FROM TB_YF_RULE 
                 WHERE REPR_CD_GP = 'X_AXIS' 
                   AND CD_GP = :V_YD_GP
               ) B
         WHERE 1 = 1        
       )
 </pre> */
public final static String chkXAxis = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.chkXAxis";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookDelChk2
SELECT
    (
        SELECT
            A.YD_CRN_SCH_ID
        FROM
            TB_YF_CRNSCH A,
            TB_YF_CRNWRKMTL B
        WHERE 1=1
        AND A.YD_CRN_SCH_ID = B.YD_CRN_SCH_ID
        AND B.STL_NO    = :V_STL_NO
        AND A.DEL_YN    = 'N'
        AND B.DEL_YN    = 'N'
        AND A.YD_WRK_PROG_STAT IN ('W', 'S')
        AND ROWNUM = 1
    ) AS YD_CRN_SCH_ID,
    (
        SELECT --+INDEX(B1 PK_YM_WRKBOOKMTL)
            A1.YD_WBOOK_ID
        FROM
            TB_YF_WRKBOOK A1,
            TB_YF_WRKBOOKMTL B1
        WHERE 1=1
        AND A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
        AND B1.STL_NO   = :V_STL_NO
        AND A1.DEL_YN   = 'N'
        AND B1.DEL_YN   = 'N'
        AND ROWNUM = 1
    ) AS YD_WBOOK_ID,
    (
        SELECT
            A.YD_WRK_PROG_STAT
        FROM
            TB_YF_CRNSCH A,
            TB_YF_CRNWRKMTL B
        WHERE 1=1
        AND A.YD_CRN_SCH_ID = B.YD_CRN_SCH_ID
        AND B.STL_NO    = :V_STL_NO
        AND A.DEL_YN    = 'N'
        AND B.DEL_YN    = 'N'
        AND ROWNUM = 1
    ) AS YD_WRK_PROG_STAT
FROM
    DUAL
 </pre> */
public final static String getYdWrkbookDelChk2 = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookDelChk2";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilSpanUnitCarMvstkRegNew.getBecauseMv 
SELECT CC.*
  FROM (
  
        SELECT ROWNUM AS RNUM
              ,AA.*
              ,BB.YD_WBOOK_ID
              ,BB.YD_SCH_CD
              ,BB.CD_CONTENTS
              
          FROM (
          
                SELECT STK.STL_NO
                      ,STK.STOCK_ITEM
                      ,LYR.YD_STK_COL_GP||LYR.YD_STK_BED_NO||LYR.YD_STK_LYR_NO AS FROMLOC
                      ,LYR.YD_STK_LYR_NO
                      ,LYR.YD_STK_LYR_STAT
                      ,COM.CURR_PROG_CD AS STL_PROG_CD -- СјЕЕ
                      ,COM.NEXT_PROC -- ДйРНАјСЄ
                      ,COM.COIL_T AS YD_MTL_T -- ЕЮВВ 
                      ,COM.COIL_W AS YD_MTL_W -- Цј 
                      ,COM.COIL_WT AS YD_MTL_WT -- СпЗЎ 
                      ,COM.COIL_OUTDIA -- ПмАц 
                      ,COUNT(*) OVER() AS TOTALCOUNT
                      
                  FROM TB_YF_STKLYR LYR
                      ,TB_YF_STKCOL COL
                      ,TB_YF_STOCK STK
                      ,TB_PT_COILCOMM COM
                      
                      
                 WHERE LYR.YD_STK_COL_GP LIKE :V_YD_GP || :V_BAY_GP || :V_SECT_GP || :V_COL_GP || '%'
                   AND LYR.DEL_YN = 'N'
                   AND LYR.STL_NO IS NOT NULL
                   AND LYR.YD_STK_LYR_STAT IN ('C', 'U')  --РћФЁСп,БЧЛѓДыБт 
                   AND LYR.YD_STK_COL_GP = COL.YD_STK_COL_GP
                   AND COL.SECT_GP BETWEEN '00' AND '99'
                   AND LYR.STL_NO = STK.STL_NO
                   AND STK.STL_NO = COM.COIL_NO
                   AND COM.CURR_PROG_CD LIKE :V_CURR_PROG_CD || '%'
                   AND NVL(COM.NEXT_PROC,'-') LIKE :V_NEXT_PROC || '%'
                   AND (
                          --------------------------------------------------------- 
                          (:V_STL_NO IS NULL AND STK.STL_NO = COM.COIL_NO) OR (
                             :V_STL_NO IS NOT NULL AND STK.STL_NO IN (
                                SELECT SUBSTR (AA, INSTR (AA, ',', 1, LEVEL) + 1, INSTR (AA, ',', 1, LEVEL + 1) - INSTR (AA, ',', 1, LEVEL) - 1 ) AS COIL_NO
                                  FROM (SELECT ',' || :V_STL_NO || ',' AA FROM DUAL)
                                CONNECT BY LEVEL <= LENGTH (AA) - LENGTH (REPLACE (AA, ',')) - 1             
                             )
                          )
                          --------------------------------------------------------- 
                       )
                   AND STK.STL_NO NOT IN (
                          SELECT B.STL_NO 
                            FROM TB_YF_WRKBOOK A
                               , TB_YF_WRKBOOKMTL B
                           WHERE A.YD_WBOOK_ID=B.YD_WBOOK_ID
                             AND A.DEL_YN='N'
                             AND B.DEL_YN='N'
                             AND (A.YD_SCH_CD LIKE '1_PT31%' OR A.YD_SCH_CD LIKE '1_PT32%') --ЙкЦЧП­ПЌФкРЯ ТїЗЎЕПАЃРЬРћ LEFT RIGHT СІПм
                       )       
                 ORDER BY LYR.YD_STK_COL_GP 
                         ,LYR.YD_STK_BED_NO 
                         ,LYR.YD_STK_LYR_NO   DESC
          
               ) AA
              ,(
              
                 SELECT A.STL_NO
                       ,A.YD_WBOOK_ID
                       ,B.YD_SCH_CD
                       ,C.CD_CONTENTS
                   FROM TB_YF_WRKBOOKMTL A
                       ,TB_YF_WRKBOOK B
                       ,TB_YF_SCHRULE C
                  WHERE A.DEL_YN = 'N'
                    AND A.YD_WBOOK_ID = B.YD_WBOOK_ID
                    AND B.DEL_YN = 'N' 
                    AND B.YD_SCH_CD = C.YD_SCH_CD(+)
                    
               ) BB
         WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE
           AND AA.STL_NO = BB.STL_NO(+)

       ) CC
 WHERE RNUM >= (( :V_PAGE_NO - 1 )* :V_PAGE_SIZE) + 1
 </pre> */
public final static String getBecauseMv = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilSpanUnitCarMvstkRegNew.getBecauseMv";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYFF1L007
WITH PARAM AS (
    SELECT :V_YD_EQP_ID AS V_YD_EQP_ID
      FROM DUAL
)


SELECT 'YFF1L007'                          AS JMS_TC_CD --JMSTCФкЕх
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
      ,'YFF1L007'                                 --РќЙЎID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')    --Л§МКРЯНУ
     ||'I'                                        --РќЙЎБИКа
     ||'0046' --РќЙЎБцРЬ
     ||RPAD(' ',29,' ')                           --РгНУ
     ||RPAD(NVL(P.V_YD_EQP_ID       ,' '), 6,' ')  --ОпЕхМГКёID
     ||RPAD(NVL(YD_SCH_FLAG1       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT1        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG2       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT2        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG3       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT3        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG4       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT4        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG5       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT5        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG6       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT6        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG7       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT7        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG8       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT8        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG9       ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT9        ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     ||RPAD(NVL(YD_SCH_FLAG10      ,' '), 1,' ')  --ПфБИНКФЩСьБИКа1
     ||RPAD(NVL(YD_SCH_CNT10       ,' '), 3,' ')  --ПфБИНКФЩСьАЧМі1
     
       AS JMS_TC_MESSAGE    --JMSTCMessage
  FROM (

        SELECT MAX(DECODE(CNT, 1,YD_SCH_FLAG,''))  AS YD_SCH_FLAG1
             , MAX(DECODE(CNT, 1,YD_SCH_CNT,''))   AS YD_SCH_CNT1
             , MAX(DECODE(CNT, 2,YD_SCH_FLAG,''))  AS YD_SCH_FLAG2
             , MAX(DECODE(CNT, 2,YD_SCH_CNT,''))   AS YD_SCH_CNT2
             , MAX(DECODE(CNT, 3,YD_SCH_FLAG,''))  AS YD_SCH_FLAG3
             , MAX(DECODE(CNT, 3,YD_SCH_CNT,''))   AS YD_SCH_CNT3
             , MAX(DECODE(CNT, 4,YD_SCH_FLAG,''))  AS YD_SCH_FLAG4
             , MAX(DECODE(CNT, 4,YD_SCH_CNT,''))   AS YD_SCH_CNT4
             , MAX(DECODE(CNT, 5,YD_SCH_FLAG,''))  AS YD_SCH_FLAG5
             , MAX(DECODE(CNT, 5,YD_SCH_CNT,''))   AS YD_SCH_CNT5
             , MAX(DECODE(CNT, 6,YD_SCH_FLAG,''))  AS YD_SCH_FLAG6
             , MAX(DECODE(CNT, 6,YD_SCH_CNT,''))   AS YD_SCH_CNT6
             , MAX(DECODE(CNT, 7,YD_SCH_FLAG,''))  AS YD_SCH_FLAG7
             , MAX(DECODE(CNT, 7,YD_SCH_CNT,''))   AS YD_SCH_CNT7
             , MAX(DECODE(CNT, 8,YD_SCH_FLAG,''))  AS YD_SCH_FLAG8
             , MAX(DECODE(CNT, 8,YD_SCH_CNT,''))   AS YD_SCH_CNT8
             , MAX(DECODE(CNT, 9,YD_SCH_FLAG,''))  AS YD_SCH_FLAG9
             , MAX(DECODE(CNT, 9,YD_SCH_CNT,''))   AS YD_SCH_CNT9
             , MAX(DECODE(CNT,10,YD_SCH_FLAG,''))  AS YD_SCH_FLAG10
             , MAX(DECODE(CNT,10,YD_SCH_CNT,''))   AS YD_SCH_CNT10
          FROM     
        (     
        SELECT YD_SCH_FLAG 
             , LPAD(TO_CHAR(COUNT(*)),'3',0) AS YD_SCH_CNT
             , ROW_NUMBER() OVER(ORDER BY YD_SCH_FLAG) AS CNT
          FROM (
                SELECT USRYFA.SF_YF_GET_SCH_FLAG(A.YD_SCH_CD) AS YD_SCH_FLAG
                    ,B.YD_WRK_CRN ,B.YD_ALT_CRN,A.YD_SCH_CD
                FROM TB_YF_CRNSCH A
                   , TB_YF_SCHRULE B
                   , TB_YF_EQP C
                   , PARAM P
                WHERE A.YD_SCH_CD = B.YD_SCH_CD
                 AND B.YD_WRK_CRN = C.YD_EQP_ID
                 AND A.DEL_YN='N'
                 AND (CASE C.YD_EQP_PROG_STAT WHEN 'B' THEN B.YD_ALT_CRN ELSE A.YD_EQP_ID END)=P.V_YD_EQP_ID
                ) A
                ,PARAM P
         GROUP BY YD_SCH_FLAG
        ) 
),PARAM P
 </pre> */
public final static String TcYFF1L007 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYFF1L007";

