 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSelectEqpTracking1
--YD_STK_COL_GP(РћФЁП­:УЙЙјТАРкИЎ ОпЕхБИКа, ЕЮЙјТА РкИЎ ЕПБИКа)
SELECT
    YD_STK_COL_GP,
    SUBSTR(YD_STK_COL_GP, 1, 1) AS YD_STK_COL_GP1,
    SUBSTR(YD_STK_COL_GP, 2, 1) AS YD_STK_COL_GP2,
    YD_STK_BED_NO,
    '01' AS YD_STK_LYR_NO,
    NVL((SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP022' AND ROWNUM = 1), 'N') AS APP022_YN,
    (
        CASE
        WHEN
        (
            --СЄСЄ НЧРћ УГИЎЕШ ЧзИё Сп УжБй НЧРћРЬ РчРлОїРЮ АцПь УпУт.
            SELECT
                COUNT(*)
            FROM
                TB_HR_C_SHEARWOWR SR
            WHERE 1=1
            AND SR.STEP_NO =
            (
                SELECT --+ INDEX_DESC(A PK_HR_C_SHEARWOWR)
                    MAX(STEP_NO)
                FROM
                    TB_HR_C_SHEARWOWR A
                WHERE 1=1
                AND COIL_NO = SR.COIL_NO
                AND WORK_STAT = '*'
                AND ROWNUM<=1
            )
            AND SR.COIL_NO = A.STL_NO
            AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP in('J', 'Q')
        ) = 1 THEN 'J'
        WHEN
        (
            SELECT
                COUNT(*)
            FROM
                TB_PT_COILCOMM B
            WHERE 1=1
            AND B.COIL_NO = A.STL_NO
            AND ((B.REMAIN_PROC1='1K' AND B.REMAIN_PROC2='1Q') OR B.REMAIN_PROC1='1Q')
        ) = 1 THEN 'Q'
        WHEN
        (
            SELECT
                COUNT(*)
            FROM
                TB_PT_COILCOMM B
            WHERE 1=1
            AND B.COIL_NO = A.STL_NO
            AND B.CURR_PROG_CD = 'F'    --СјЕЕФкЕх : 'F' (ЦЧСЄКИЗљ)
        ) = 1 THEN 'F'
        WHEN
        (
            SELECT
                COUNT(*)
            FROM
                TB_PT_COILCOMM B
            WHERE 1=1
            AND B.COIL_NO = A.STL_NO
            AND B.HOLD_CAUSE_CD = '43'  --ЦЧСЄКИЗљ : '43'
        ) = 1 THEN '43'
        ELSE 'X' END
    ) AS CHK
FROM
    TB_YF_EQPTRACKING A
WHERE 1=1
AND STL_NO = :V_STL_NO
 </pre> */
public final static String getSelectEqpTracking1 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSelectEqpTracking1";

 /** <pre> 
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.aslabCommDtlInqjl.ListStockLocHistory 
-- SLAB РњРхЙАЧАРЇФЁКЏАцРЬЗТСЖШИ 
SELECT ROWNUM AS SEQ
     , A.*
  FROM (
       SELECT 
              STL_NO
            , MOD_DDTT
            , MODIFIER
            , SCH_NAME
            , FR_YD
            , TO_YD
            , FR_WR_LOC
            , TO_WR_LOC
            , YD_WRK_CRN
            , YD_GP
            , CRANE_WRSLT_ID
            , YD_AID_WRK_YN
            , NVL(CASE YD_UP_WRK_MODE2 
                    WHEN 'M' THEN 'РЏРЮ'
                    WHEN 'R' THEN 'ИЎИ№ФС'
                    WHEN 'A' THEN 'РкЕП'
                    WHEN 'H' THEN 'HMI'
              ELSE
                NVL(YD_UP_WRK_MODE2  ,'-')
              END,'-') AS YD_UP_WRK_MODE2  
            , CASE YD_DN_WRK_MODE2 
                    WHEN 'M' THEN 'РЏРЮ'
                    WHEN 'R' THEN 'ИЎИ№ФС'
                    WHEN 'A' THEN 'РкЕП'
                    WHEN 'H' THEN 'HMI'
              ELSE
                NVL(YD_DN_WRK_MODE2 ,'-')
              END AS YD_DN_WRK_MODE2 
            , YD_WRK_HIST_ID
            , REG_DDTT
            , YD_GNT_GP
            , SPOS_WLOC_CD
            , ARR_WLOC_CD
            , YD_AIM_RT_GP
            , YD_SCH_CD
            , YD_WORD_DT
       FROM VW_YD_WRKHIST T
       WHERE T.STL_NO = :V_STL_NO
       ORDER BY MOD_DDTT DESC , YD_WRK_HIST_ID DESC
      ) A
 </pre> */
public final static String ListStockLocHistory = "bak.com.inisteel.cim.yf.aslab.dao.ASlabDAO.aslabCommDtlInqjl.ListStockLocHistory";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.fromveridname
SELECT 
     REPR_CD_CONTENTS
FROM TB_YF_RULE
WHERE REPR_CD_GP || CD_GP || ITEM = :V_VER_ID
 </pre> */
public final static String fromveridname = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.fromveridname";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfToLocMainSql
SELECT A.* 
  FROM
       ( 
        SELECT A.*   
              ,ROW_NUMBER() OVER(PARTITION BY A.PRIOR1 ORDER BY CASE WHEN LOC_ABLE_CHK ='PASS' THEN 1 ELSE 2 END
                                                               ,L_CAR_CHK DESC
                                                               ,R_CAR_CHK DESC
                                                               ,GROUP_SEQ     --РЇФЁАЫЛіБзЗь
                                                               ,PRIOR0        --ДмПьМБМјРЇ 
                                                               ,PRIOR1        --СТПь КЃЕх ЛѓХТ
                                                               ,PRIOR2        --ОпЕхРЇФЁ АЫЛіЙќРЇМјМ­ 
                                                               ,PRIOR3        --BED + SPAN + П­(ДѕЙЬРќПы)
                                                               ,PRIOR4        --П­(ДѕЙЬРќПы)
                                                               ,TAG_YD_STK_BED_NO
                                                            ) AS GROUP_ROW    
              
              ,CASE  
                -- РлОїРЮ АцПь  
                WHEN A.TAG_YD_STK_COL_GP LIKE '1_TC%' AND NVL(A.GROUP_SEQ,'1')='1' THEN '1' 
                -- 1ДмРЬИщМ­ МвРчРЮ АцПь
                WHEN A.TAG_YD_STK_LYR_NO = '01' AND C_PROG_CD NOT IN ('F','G','H','J','K','L','M','5','6','7','8') 
                THEN CASE WHEN C_PROG_CD = L_PROG_CD AND C_PROG_CD = R_PROG_CD  THEN '1' --ЕПРЯ(СТПь) СјЕЕФкЕх
                          WHEN C_PROG_CD = L_PROG_CD  OR C_PROG_CD = R_PROG_CD  THEN '2' --ЕПРЯ(СТПь) СјЕЕФкЕх
                          WHEN L_COIL_NO IS NULL     AND R_COIL_NO IS NOT NULL  THEN '3' --СТ АјBED
                          WHEN R_COIL_NO IS NULL     AND L_COIL_NO IS NOT NULL  THEN '3' --Пь АјBED
                          ELSE '7' END 
                
                -- 2ДмРЬИщМ­ МвРчРЮ АцПь     
                WHEN A.TAG_YD_STK_LYR_NO = '02' AND C_PROG_CD NOT IN ('F','G','H','J','K','L','M','5','6','7','8')
                THEN CASE WHEN L_JJANG_GP = 'Y'  OR  R_JJANG_GP = 'Y'            THEN '9' -- ТЏБИ РЇПЁ Иј ПУИАДй.
                          WHEN L_WB = 'S'        OR  R_WB  = 'S'                 THEN '8' --СТЧЯДмПьЧЯДм РлОї ПЙОр
                          WHEN C_PROG_CD  = L_PROG_CD AND C_PROG_CD = R_PROG_CD  THEN '1' --ЕПРЯ(СТЧЯДмПьЧЯДм) СјЕЕФкЕх
                          WHEN C_PROG_CD  = L_PROG_CD  OR C_PROG_CD = R_PROG_CD  THEN '2' 
                          ELSE '2' END
                          
                -- 1ДмРЬИщМ­ СІЧАРЮ АцПь           
                WHEN A.TAG_YD_STK_LYR_NO = '01' AND C_PROG_CD     IN ('F','G','H','J','K','L','M','5','6','7','8')   
                THEN CASE WHEN C_DEMANDER_CD = L_DEMANDER_CD             
                           AND C_DEMANDER_CD = R_DEMANDER_CD 
                           AND C_ORD_NO||C_ORD_DTL = L_ORD_NO||L_ORD_DTL 
                           AND C_ORD_NO||C_ORD_DTL = R_ORD_NO||R_ORD_DTL     THEN '1' --СТПьУр ЕПРЯ АэАДЛч+СжЙЎЙјШЃЧрЙј
                          WHEN C_ORD_NO||C_ORD_DTL = L_ORD_NO||L_ORD_DTL 
                           AND C_ORD_NO||C_ORD_DTL = R_ORD_NO||R_ORD_DTL     THEN '2' --СТПьУј ЕПРЯ СжЙЎЙјШЃЧрЙј
                          WHEN C_ORD_NO||C_ORD_DTL = L_ORD_NO||L_ORD_DTL     THEN '2' --СТУј   ЕПРЯ СжЙЎЙјШЃЧрЙј
                          WHEN C_ORD_NO||C_ORD_DTL = R_ORD_NO||R_ORD_DTL     THEN '2' --ПьУј   ЕПРЯ СжЙЎЙјШЃЧрЙј
                          WHEN C_ORD_NO = L_ORD_NO AND C_ORD_NO = R_ORD_NO   THEN '4' --СТПьУј ЕПРЯ СжЙЎЙјШЃ 
                          WHEN C_ORD_NO = L_ORD_NO                           THEN '4' --ПьУј   ЕПРЯ СжЙЎЙјШЃ 
                          WHEN C_ORD_NO = R_ORD_NO                           THEN '4' --СТУј   ЕПРЯ СжЙЎЙјШЃ 
                          WHEN L_COIL_NO IS NULL   AND R_COIL_NO IS NOT NULL THEN '4' --СТ АјBED
                          WHEN R_COIL_NO IS NULL   AND L_COIL_NO IS NOT NULL THEN '4' --Пь АјBED
                          ELSE '7' END         
                
                -- 2ДмРЬИщМ­ СІЧАРЮ АцПь           
                WHEN A.TAG_YD_STK_LYR_NO = '02' AND C_PROG_CD IN ('F','G','H','J','K','L','M','5','6','7','8') --СІЧА
                THEN CASE WHEN L_JJANG_GP = 'Y' OR  R_JJANG_GP = 'Y'           THEN '9' -- ТЏБИ РЇПЁ Иј ПУИАДй.
                          WHEN L_WB = 'S'       OR  R_WB  = 'S'                THEN '8' --СТЧЯДмПьЧЯДм РлОї ПЙОр
                          WHEN C_DEMANDER_CD = L_DEMANDER_CD             
                           AND C_DEMANDER_CD = R_DEMANDER_CD 
                           AND C_ORD_NO||C_ORD_DTL = L_ORD_NO||L_ORD_DTL 
                           AND C_ORD_NO||C_ORD_DTL = R_ORD_NO||R_ORD_DTL       THEN '1' --СТПьЧЯДм ЕПРЯ АэАДЛч+СжЙЎЙјШЃЧрЙј
                          WHEN C_ORD_NO||C_ORD_DTL = L_ORD_NO||L_ORD_DTL 
                           AND C_ORD_NO||C_ORD_DTL = R_ORD_NO||R_ORD_DTL       THEN '2' --СТПьЧЯДм ЕПРЯ СжЙЎЙјШЃЧрЙј 
                          WHEN C_ORD_NO||C_ORD_DTL = L_ORD_NO||L_ORD_DTL       THEN '2' --СТЧЯДм   ЕПРЯ СжЙЎЙјШЃЧрЙј 
                          WHEN C_ORD_NO||C_ORD_DTL = R_ORD_NO||R_ORD_DTL       THEN '2' --ПьЧЯДм   ЕПРЯ СжЙЎЙјШЃЧрЙј 
                          WHEN C_ORD_NO = L_ORD_NO AND C_ORD_NO = R_ORD_NO     THEN '4' --СТПьЧЯДм ЕПРЯ СжЙЎЙјШЃ 
                          WHEN C_ORD_NO = L_ORD_NO                             THEN '4' --ПьЧЯДм   ЕПРЯ СжЙЎЙјШЃ 
                          WHEN C_ORD_NO = R_ORD_NO                             THEN '4' --СТЧЯДм   ЕПРЯ СжЙЎЙјШЃ 
                          ELSE '7' END
                 ELSE '9' END GRIDE              
             
          FROM (
                SELECT A.*                                                                                    
                      ,CASE --TOРЇФЁАЁ РЯЙн ОпЕхРЯ АцПь
                            WHEN REGEXP_INSTR(SUBSTR(TAG_YD_STK_COL_GP,3,2),'[^0-9]') = '0' THEN 
                                 CASE WHEN A.IS_AUTO = 'Y' AND A.TAG_YD_STK_COL_GP NOT IN (SELECT R.ITEM FROM TB_YF_RULE R 
                                                                                            WHERE R.REPR_CD_GP = 'CR0001'
                                                                                            AND R.CD_GP      = A.YD_EQP_ID
                                                                                            AND R.DEL_YN     = 'N') THEN 'TOРЇФЁАЁ ХЉЗЙРЮ РлОї ЙќРЇИІ УЪАњ'
                                                                                        
                                      WHEN A.TAG_YD_STK_COL_GP||A.TAG_YD_STK_BED_NO||A.TAG_YD_STK_LYR_NO IN ( SELECT NVL(YD_DN_WO_LOC||YD_DN_WO_LYR,'1') 
                                                                                                                FROM TB_YF_CRNSCH 
                                                                                                               WHERE DEL_YN = 'N') THEN 'TOРЇФЁПЁ ХЉЗЙРЮБЧЧЯСіНУАЁ СИРч'
                                                                                                                         
                                      WHEN A.TAG_YD_STK_COL_GP||A.TAG_YD_STK_BED_NO||A.TAG_YD_STK_LYR_NO IN (SELECT NVL(A1.NEXT_COIL_UP_LOC,1)  AS NEXT_COIL_UP_LOC 
                                                                                                               FROM (SELECT NEXT_COIL_UP_LOC, ROW_SEQ FROM TABLE(USRYFA.SF_GET_NEXT_COIL_UP_LOC(:V_YD_EQP_ID))) A1
                                                                                                                   ,(SELECT * FROM TB_YF_RULE WHERE REPR_CD_GP = 'APP110' AND DEL_YN ='N' AND CD_GP ='1') B1  
                                                                                                              WHERE A1.ROW_SEQ >  0  
                                                                                                                AND A1.ROW_SEQ <= TO_NUMBER(B1.DTL_ITEM3)) THEN 'TOРЇФЁПЁ А№ СЄСЄРлОїЧв РчЗсАЁ СИРч'
                                
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND A.C_JJANG_GP = 'Y'  THEN 'ТЏБИФкРЯРЯ АцПь 2ДмСІПм' 
                                
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.L_ISHOT ='TRUE' OR A.R_ISHOT='TRUE') THEN '1ДмПЁ ЧжФкРЯРЬ СИРчЧд'
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.TAG_LEFT_ACTIVE_STAT != 'E' OR A.TAG_RIGHT_ACTIVE_STAT != 'E' 
                                                                      OR A.TAG_LEFT_LAYER_STAT  != 'C' OR A.TAG_RIGHT_LAYER_STAT  != 'C') THEN 'СЄКИРЬЛѓ. 1Дм LAYERАЁ РћФЁСпРЬ ОЦДд'
                                                                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '01' AND (A.TAG_2DAN_LEFT_STL_NO IS NOT NULL OR A.TAG_2DAN_RIGHT_STL_NO IS NOT NULL) THEN 'СЄКИРЬЛѓ. 2ДмПЁ РчЗсАЁ СИРч' 
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '01' AND (SELECT DTL_ITEM1 
                                                                             FROM TB_YF_RULE 
                                                                            WHERE REPR_CD_GP = 'APP044' 
                                                                              AND CD_GP  = '1'
                                                                              AND DEL_YN = 'N'
                                                                              AND ITEM = SUBSTR(A.TAG_YD_STK_COL_GP,2,1)) = 'N'
                                                                      AND (   --ABS(TO_NUMBER(A.C_OUTDIA)-TO_NUMBER(NVL(A.L_OUTDIA,A.C_OUTDIA))) >= A.ODIA_DIFF1  --СпКЙЕЧДТ БтСи
                                                                           --OR ABS(TO_NUMBER(A.C_OUTDIA)-TO_NUMBER(NVL(A.R_OUTDIA,A.C_OUTDIA))) >= A.ODIA_DIFF1
                                                                              ABS(TO_NUMBER(A.C_WIDTH) -TO_NUMBER(NVL(A.L_WIDTH,A.C_WIDTH))) >= A.WID_DIFF1 
                                                                           OR ABS(TO_NUMBER(A.C_WIDTH) -TO_NUMBER(NVL(A.R_WIDTH,A.C_WIDTH))) >= A.WID_DIFF1) THEN 'СТПь РчЗсПЭРЧ ЦјЦэТїАЁ БтСи УЪАњ'
                                                                          
                                      WHEN A.TAG_YD_STK_LYR_NO = '01' AND (SELECT DTL_ITEM1 
                                                                             FROM TB_YF_RULE 
                                                                            WHERE REPR_CD_GP = 'APP044' 
                                                                              AND CD_GP  = '1'
                                                                              AND DEL_YN = 'N'
                                                                              AND ITEM = SUBSTR(A.TAG_YD_STK_COL_GP,2,1)) = 'Y'
                                                                      AND (   ABS(TO_NUMBER(A.C_OUTDIA)-TO_NUMBER(NVL(A.L_OUTDIA,A.C_OUTDIA))) >= A.ODIA_DIFF1  
                                                                           OR ABS(TO_NUMBER(A.C_OUTDIA)-TO_NUMBER(NVL(A.R_OUTDIA,A.C_OUTDIA))) >= A.ODIA_DIFF1) THEN 'СТПь РчЗсПЭРЧ ПмАцЦэТїАЁ БтСи УЪАњ'   
                                     
                                      WHEN A.TAG_YD_STK_LYR_NO = '01' AND A.BEFORE_COL_WID > 0 AND ((A.TAG_YD_STK_LYR_X_AXIS-A.BEFORE_COL_X_AXIS) - ((A.BEFORE_COL_WID/2)+(A.C_WIDTH/2))) < A.WID_LIFT1 THEN 'Рќ П­АњРЧ АЃАн БтСи ЙЬДо'
                                      WHEN A.TAG_YD_STK_LYR_NO = '01' AND A.NEXT_COL_WID   > 0 AND ((A.NEXT_COL_X_AXIS-A.TAG_YD_STK_LYR_X_AXIS)   - ((A.NEXT_COL_WID/2)+(A.C_WIDTH/2)))   < A.WID_LIFT1 THEN 'ДйРН П­АњРЧ АЃАн БтСи ЙЬДо'
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.WGT_DIFF2 + A.MIN_COIL_WT + (A.MIN_COIL_WT * (CASE WHEN A.MIN_COIL_T < 7  AND A.MIN_COIL_W <  1301 THEN 0.13
                                                                                                                                WHEN A.MIN_COIL_T < 7  AND A.MIN_COIL_W >= 1301 THEN 0.14
                                                                                                                                WHEN A.MIN_COIL_T >= 7 AND A.MIN_COIL_W <  1301 THEN 0.14
                                                                                                                                WHEN A.MIN_COIL_T >= 7 AND A.MIN_COIL_W >= 1301 THEN 0.15 END))) < C_WEIGTH 
                                                                                                                                THEN '1Дм РчЗсРЧ СпЗЎАЁСпФЁАЁ БтСи ЙЬДо' 
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.WID_DIFF2 + A.MAX_COIL_W) < A.C_WIDTH THEN '1Дм РчЗс ЦјРЬ БтСи ЙЬДо' 
                                     
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND A.C_OUTDIA - (A.BED_DIFF2 - ((A.L_OUTDIA + A.R_OUTDIA)/2)) <= ODIA_DIFF2 THEN '1Дм РчЗс ПмАц БтСи ЙЬДо'  
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.C_YAXIS_AUTO - A.L_YAXIS_AUTO) - ((A.C_OUTDIA + A.L2DAN_OUTDIA)/2) <= 20 THEN 'ШОЧрСТЧЅ АХИЎ БтСи ЙЬДо1' 
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.R_YAXIS_AUTO - A.C_YAXIS_AUTO) - ((A.C_OUTDIA + A.R2DAN_OUTDIA)/2) <= 20 THEN 'ШОЧрСТЧЅ АХИЎ БтСи ЙЬДо2' 
                                    
                                    
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND A.INCLINE_CHK ='N' THEN '2Дм ФкРЯРћРч БтПяБт БтСи УЪАњ'
                                      
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND A.C_HEATING_COIL_YN = 'Y'  THEN 'Г­ЙцФкРЯРЯ АцПь 2ДмСІПм' 
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' AND (A.L_HEATING_COIL_YN ='Y' OR A.R_HEATING_COIL_YN='Y') THEN '1ДмПЁ Г­ЙцФкРЯРЬ СИРчЧд'
                                      
                                      WHEN A.TAG_YD_STK_COL_GP||A.TAG_YD_STK_BED_NO IN ('1E050211','1C080305','1F120210') 
                                           AND A.STL_NO NOT IN ('BDDC001','BDSP001','BDEQ001') THEN 'КаЕПФкРЯ СіСЄ РЇФЁ'
                                      
                                      WHEN A.TAG_YD_STK_LYR_NO = '02' 
                                           AND (A.L_COIL_NO IN ('BDDC001','BDSP001','BDEQ001') 
                                                OR A.R_COIL_NO IN ('BDDC001','BDSP001','BDEQ001')) THEN '1ДмПЁ КаЕПФкРЯРЬ СИРчЧд'
                                      
                                      
                                      
                                      ELSE 'PASS' 
                                END
                                
                            --TO РЇФЁАЁ ШЎРхДыТїРЯ АцПь
                            WHEN SUBSTR(TAG_YD_STK_COL_GP,3,4)='TC03' THEN
                                 CASE 
                                       WHEN --ДыТїАЁ ДйИЅЕППЁ РжАэ
                                            (SELECT YD_CURR_BAY_GP 
                                               FROM TB_YF_EQP 
                                              WHERE YD_EQP_ID = '1XTC03') != SUBSTR(A.YD_SCH_CD,2,1)   
                                            AND --ДыТїРЇПЁ РЬЙЬ ДйИЅ РчЗсАЁ СИРчЧЯАХГЊ
                                            --(SELECT COUNT(*) 
                                            --  FROM TB_YF_STKLYR 
                                            -- WHERE YD_STK_COL_GP = SUBSTR(A.YD_EQP_ID,1,1)||A.YD_AIM_BAY_GP ||'TC03' 
                                            --   AND DEL_YN = 'N'
                                            --   AND STL_NO IS NOT NULL)
                                            --ДыТїАЁ ЛѓТїДыБт, ЛѓТїЕЕТј ЛѓХТРЬАХГЊ
                                            --(SELECT COUNT(*) 
                                            --  FROM TB_YF_TCARSCH 
                                            -- WHERE YD_EQP_ID = '1XTC03' 
                                            --   AND DEL_YN = 'N'
                                            --  AND YD_CAR_PROG_STAT IN ('0','2'))
                                            --ИёРћЕППЁ ЛѓТї НКФЩСй СИРчЧЯИщ  
                                            --(SELECT COUNT(*) 
                                            --  FROM TB_YF_CRNSCH 
                                            -- WHERE DEL_YN = 'N'
                                            --   AND YD_GP     = '1'
                                            --   AND SUBSTR(YD_DN_WO_LOC,1,6) = '1'||A.YD_AIM_BAY_GP ||'TC03') >0 THEN 'ШЎРхДыТїАЁ ДйИЅЕППЁМ­ ЛѓТїСп'
                                           (SELECT COUNT(*) 
                                              FROM TB_YF_WRKBOOK 
                                             WHERE DEL_YN = 'N'
                                               AND YD_WRK_PLAN_TCAR = '1XTC03'
                                               AND YD_SCH_CD LIKE '1'||A.YD_AIM_BAY_GP||'____UM') >0 THEN 'ИёРћЕППЁ ЛѓТїРлОїПЙОрРЬ СИРч'

                                      WHEN (SELECT YD_EQP_PROG_STAT 
                                              FROM TB_YF_EQP 
                                             WHERE YD_EQP_ID = '1XTC03') = 'B' THEN 'ДыТї АэРх' 
                                             
                                      --РЯЙн LINE OFF ПЃ ИёРћЕПРЬ ОјРН
                                      WHEN (NVL(A.YD_AIM_BAY_GP,'A') NOT IN ('A','B') OR SUBSTR(A.YD_SCH_CD,2,1) NOT IN ('A','B')) THEN 'ДыТї РЬРћ АЁДЩ ДыЛѓРЬ ОЦДд' 
                                      WHEN A.YD_WRK_PLAN_TCAR = '1XTC01' THEN 'АшШЙ ДыТїАЁ CTS Рг'
                                      WHEN A.YD_AIM_BAY_GP = SUBSTR(A.YD_SCH_CD,2,1) THEN 'ЧіРчЕПРЬ ИёРћЕПРг'
                                      ELSE 'PASS' 
                                 END  
                                 
                            --ЛѕЕщ, ТїЗЎ, МГКё..ЕюЕю      
                            ELSE CASE WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,2) IN ('SR','SL') AND A.YD_WRK_PLAN_TCAR = '1XTC03' THEN 'АшШЙ ДыТїАЁ ШЎРхДыТї Рг'
                                      WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,2) IN ('SR','SL') AND A.YD_AIM_BAY_GP = SUBSTR(A.YD_SCH_CD,2,1) THEN 'ЧіРчЕПРЬ ИёРћЕПРг'
                                      ELSE 'PASS' 
                                 END
                            --   DC,EC TOРЇФЁ СІПм(ЙкЦЧ УМХЉЧвАЭ. kbs)
                            --   AND A.YD_STK_COL_GP NOT IN ( SELECT YD_STK_COL_GP FROM TB_YF_SCHLOCSRCH D 
                            --                                WHERE D.YD_SCH_CD     IN ('3ADC01LM','3BDC01LM','3CDC01LM','3BEC01LM','3CEC01LM','3DEC01LM')
                            --                                  AND SUBSTR(D.YD_STK_COL_GP,1,2) =  SUBSTR(C.YD_STK_COL_GP,1,2) 
                            --                                  AND D.DEL_YN='N')
                            --   AND 1 = CASE WHEN :V_YD_EQP_ID = '3CCRC1' AND SUBSTR(TAG_YD_STK_COL_GP, 3, 2) > '08' THEN 2 ELSE 1 END 
                            --   AND 1 = CASE WHEN :V_YD_EQP_ID = '3CCRC3' AND SUBSTR(TAG_YD_STK_COL_GP, 3, 2) < '13' THEN 2 ELSE 1 END 
                            END AS LOC_ABLE_CHK                
                  FROM 
                  (
                    -- TO РЇФЁФкРЯСЄКИ SELECT
                    SELECT CASE WHEN A.RULL_DAN_PRIOR = A.TAG_YD_STK_LYR_NO THEN '1' 
                                WHEN REGEXP_INSTR(SUBSTR(A.TAG_YD_STK_COL_GP,3,2),'[^0-9]') != '0' THEN '1' --МГКёЖѓИщ
                                ELSE '2' END AS PRIOR0 --ДмПьМБМјРЇ
                         , CASE WHEN L.STL_NO IS NOT NULL AND R.STL_NO IS NOT NULL THEN '1'
                                WHEN L.STL_NO IS NOT NULL OR  R.STL_NO IS NOT NULL THEN '2'
                                WHEN REGEXP_INSTR(SUBSTR(A.TAG_YD_STK_COL_GP,3,2),'[^0-9]') != '0' THEN '1' --МГКёЖѓИщ
                                ELSE '3' END AS PRIOR1 
                         , A.PRIOR2 --АЫЛіМјРЇ
                         , A.PRIOR3 
                         , A.PRIOR4                    
               
                         --РћФЁДмСЄКИ
                         , A.STL_NO
                         , A.TAG_YD_STK_COL_GP || A.TAG_YD_STK_BED_NO || A.TAG_YD_STK_LYR_NO AS TAG_YD_STK_DAN_GP
                         , A.TAG_YD_STK_COL_GP
                         , A.TAG_YD_STK_BED_NO
                         , A.TAG_YD_STK_LYR_NO
                         , A.TAG_COL_USE_CD
                         , A.TAG_LEFT_BED
                         , A.TAG_LEFT_LAYER
                         , A.TAG_RIGHT_BED
                         , A.TAG_RIGHT_LAYER     
                         , A.TAG_YD_STK_LYR_X_AXIS
                         , L.YD_STK_LYR_ACTIVE_STAT     AS TAG_LEFT_ACTIVE_STAT 
                         , L.YD_STK_LYR_STAT            AS TAG_LEFT_LAYER_STAT
                         , L.STL_NO                     AS TAG_LEFT_STL_NO
                         , R.YD_STK_LYR_ACTIVE_STAT     AS TAG_RIGHT_ACTIVE_STAT 
                         , R.YD_STK_LYR_STAT            AS TAG_RIGHT_LAYER_STAT
                         , R.STL_NO                     AS TAG_RIGHT_STL_NO
                           
                         , L2DAN.STL_NO                 AS TAG_2DAN_LEFT_STL_NO
                         , R2DAN.STL_NO                 AS TAG_2DAN_RIGHT_STL_NO  
                         
                         --ФкРЯАјХыСЄКИ
                         , C_COIL.COIL_NO               AS C_COIL_NO
                         , C_COIL.COIL_OUTDIA           AS C_OUTDIA 
                         , C_COIL.COIL_W                AS C_WIDTH
                         , C_COIL.COIL_WT               AS C_WEIGTH
                         , C_COIL.COIL_T                AS C_THICK  
                         , C_COIL.CURR_PROG_CD          AS C_PROG_CD    -- СјЕЕФкЕх
                         , C_COIL.NEXT_PROC             AS C_NEXT_PROC  -- ТїАјСЄ
                         , C_COIL.HR_SPEC_ABBSYM        AS C_SPEC_ABBSYM-- БдАнОрШЃ
                         , C_COIL.ORD_NO                AS C_ORD_NO     -- СжЙЎЙјШЃ
                         , C_COIL.ORD_DTL               AS C_ORD_DTL    -- СжЙЎЧрЙј
                         , C_COIL.RECEIPT_DATE          AS C_RECEIPT_DT -- РдАэРЯРк
                         , C_COIL.MILL_INI_DATE         AS C_MILL_DT    -- ОаПЌРЯНУ
                         , C_COIL.DEMANDER_CD           AS C_DEMANDER_CD-- МіПфАЁФкЕх 
                         , L_COIL.COIL_NO               AS L_COIL_NO
                         , L_COIL.COIL_OUTDIA           AS L_OUTDIA 
                         , L_COIL.COIL_W                AS L_WIDTH 
                         , L_COIL.COIL_WT               AS L_WEIGTH   
                         , L_COIL.COIL_T                AS L_THICK
                         , L_COIL.CURR_PROG_CD          AS L_PROG_CD    -- СјЕЕФкЕх
                         , L_COIL.NEXT_PROC             AS L_NEXT_PROC  -- ТїАјСЄ
                         , L_COIL.HR_SPEC_ABBSYM        AS L_SPEC_ABBSYM-- БдАнОрШЃ
                         , L_COIL.ORD_NO                AS L_ORD_NO     -- СжЙЎЙјШЃ
                         , L_COIL.ORD_DTL               AS L_ORD_DTL    -- СжЙЎЧрЙј
                         , L_COIL.RECEIPT_DATE          AS L_RECEIPT_DT -- РдАэРЯРк
                         , L_COIL.MILL_INI_DATE         AS L_MILL_DT    -- ОаПЌРЯНУ
                         , L_COIL.DEMANDER_CD           AS L_DEMANDER_CD-- МіПфАЁФкЕх
                         , R_COIL.COIL_NO               AS R_COIL_NO  
                         , R_COIL.COIL_OUTDIA           AS R_OUTDIA  
                         , R_COIL.COIL_W                AS R_WIDTH  
                         , R_COIL.COIL_WT               AS R_WEIGTH
                         , R_COIL.COIL_T                AS R_THICK
                         , R_COIL.CURR_PROG_CD          AS R_PROG_CD    -- СјЕЕФкЕх
                         , R_COIL.NEXT_PROC             AS R_NEXT_PROC  -- ТїАјСЄ
                         , R_COIL.HR_SPEC_ABBSYM        AS R_SPEC_ABBSYM-- БдАнОрШЃ
                         , R_COIL.ORD_NO                AS R_ORD_NO     -- СжЙЎЙјШЃ
                         , R_COIL.ORD_DTL               AS R_ORD_DTL    -- СжЙЎЧрЙј
                         , R_COIL.RECEIPT_DATE          AS R_RECEIPT_DT -- РдАэРЯРк
                         , R_COIL.MILL_INI_DATE         AS R_MILL_DT    -- ОаПЌРЯНУ
                         , R_COIL.DEMANDER_CD           AS R_DEMANDER_CD-- МіПфАЁФкЕх
                         
                         --РлОїПЙОрСЄКИ         
                         ,A.YD_SCH_CD
                         
                         --ОпЕхРлОїАшШЙДыТї
                         ,A.YD_AIM_BAY_GP  
                         ,CASE WHEN A.YD_WRK_PLAN_TCAR IS NOT NULL           THEN A.YD_WRK_PLAN_TCAR
                               WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,4) = 'TC03' THEN '1XTC03' 
                               WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,2) = 'SR'   THEN '1XTC01' 
                               WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,2) = 'SL'   THEN '1XTC01' END AS YD_WRK_PLAN_TCAR
                         
                         , (SELECT DISTINCT A1.YD_WRK_PLAN_TCAR   
                              FROM TB_YF_WRKBOOK A1
                                 , TB_YF_WRKBOOKMTL B1
                             WHERE A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
                               AND A1.DEL_YN = 'N'
                               AND B1.DEL_YN = 'N'
                               AND B1.STL_NO = A.STL_NO) AS WK_BOOK_PLAN_TCAR 
                         
                         
                         --ДыТїУтЙпСЄКИ
                         ,CASE --ЧіРчЕППЁ ДыТїАЁ СИРчЧЯСі ОЪДТДйИщ, АјДыТїУтЙпСіНУ
                               WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,4) = 'TC03' 
                                    AND (SELECT YD_CURR_BAY_GP 
                                           FROM TB_YF_EQP 
                                          WHERE YD_EQP_ID = '1XTC03') != SUBSTR(A.YD_SCH_CD,2,1) THEN 'Y'
                               
                               --ДыТїНКФЩСйРЬ СИРчЧЯСі ОЪДТДйИщ, АјДыТїУтЙп СіНУ           
                               WHEN SUBSTR(A.TAG_YD_STK_COL_GP,3,4) = 'TC03' 
                                    AND (SELECT COUNT(*) FROM TB_YF_TCARSCH WHERE YD_EQP_ID = '1XTC03' AND DEL_YN ='N') < 1 THEN 'Y'
                                    
                               --ДыТї СпЗЎ УЪАњЖѓИщ, РлОїСіНУДТ ГЛИЎЕЧ, ДыТїИІ ИеРњ УтЙп НУХВДй.      
                               WHEN (SELECT AA.STK_MAX_WT
                                      FROM TB_YF_EQP AA
                                     WHERE AA.YD_EQP_ID = '1XTC03'
                                       AND AA.DEL_YN ='N'
                                    ) 
                                    < 
                                    (SELECT SUM(BB.COIL_WT)
                                       FROM TB_YF_STKLYR AA
                                           ,TB_PT_COILCOMM BB
                                      WHERE AA.STL_NO = BB.COIL_NO
                                        AND AA.YD_STK_COL_GP = '1'||SUBSTR(A.YD_SCH_CD,2,1)||'TC03'
                                        AND AA.YD_STK_LYR_STAT = 'C'
                                     ) + C_COIL.COIL_WT THEN 'S' 
                                             
                               ELSE 'N' END AS TC_START_GP
                                             
                         --УжМв ЛчОч
                         , CASE WHEN L_COIL.COIL_WT > R_COIL.COIL_WT THEN R_COIL.COIL_WT ELSE L_COIL.COIL_WT END AS MIN_COIL_WT 
                         , CASE WHEN L_COIL.COIL_WT > R_COIL.COIL_WT THEN R_COIL.COIL_T  ELSE L_COIL.COIL_T  END AS MIN_COIL_T --ЕЮВВДТ СпЗЎРИЗЮ КёБГЧбДй.
                         , CASE WHEN L_COIL.COIL_W  > R_COIL.COIL_W  THEN R_COIL.COIL_W  ELSE L_COIL.COIL_W  END AS MIN_COIL_W
                         , CASE WHEN L_COIL.COIL_W  > R_COIL.COIL_W  THEN L_COIL.COIL_W  ELSE R_COIL.COIL_W  END AS MAX_COIL_W
                         
                         --МГКёСЄКИ
                         , CR.YD_EQP_ID
                         , CR.YD_EQP_PROG_STAT
                         , CASE WHEN    CR.YD_EQP_ID IN ('1ACRA1', '1ACRA2')           AND CR.YD_EQP_WRK_MODE2 IN ('A','R')  --A:ЙЋРЮ, R:ИЎИ№ФС, E:СЄКё, M:РЏРЮ  
                                     OR CR.YD_EQP_ID IN ('1CCRC1', '1CCRC2', '1CCRC3') AND CR.YD_EQP_WRK_MODE2 IN ('A','R')   
                                     OR CR.YD_EQP_ID IN ('1ECRE1', '1ECRE2', '1ECRE3') AND CR.YD_EQP_WRK_MODE2 = 'A'          
                                THEN 'Y'
                                ELSE 'Y' END AS IS_AUTO 
                         
                         --ТїЗЎНКФЩСйСИРч ПЉКЮ
                         ,(SELECT 'Y'
                             FROM TB_YF_STOCK A
                             , USRYDA.TB_YD_CARSCH B
                            WHERE A.TRANS_ORD_DATE=B.TRANS_ORD_DATE
                              AND A.TRANS_ORD_SEQNO=B.TRANS_ORD_SEQNO
                              AND B.DEL_YN='N'
                              AND A.STL_NO=NVL(L.STL_NO,'-')
                              AND ROWNUM<=1) AS L_CAR_CHK
                         , (SELECT 'Y'
                             FROM TB_YF_STOCK A
                             , USRYDA.TB_YD_CARSCH B
                            WHERE A.TRANS_ORD_DATE=B.TRANS_ORD_DATE
                              AND A.TRANS_ORD_SEQNO=B.TRANS_ORD_SEQNO
                              AND B.DEL_YN='N'
                              AND A.STL_NO=NVL(R.STL_NO,'-')
                              AND ROWNUM<=1) AS R_CAR_CHK 
                            
                         
                         --СТПь РлОїПЙОр СИРч ПЉКЮ 
                         , (SELECT CASE WHEN COUNT(*) > 0 THEN 'S' ELSE 'N' END   
                              FROM TB_YF_WRKBOOK A1
                                 , TB_YF_WRKBOOKMTL B1
                             WHERE A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
                               AND A1.DEL_YN = 'N'
                               AND B1.DEL_YN = 'N'
                               AND B1.STL_NO = L_COIL.COIL_NO) AS     L_WB         
                         
                         , (SELECT CASE WHEN COUNT(*) > 0 THEN 'S' ELSE 'N' END   
                              FROM TB_YF_WRKBOOK A1
                                 , TB_YF_WRKBOOKMTL B1
                             WHERE A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
                               AND A1.DEL_YN = 'N'
                               AND B1.DEL_YN = 'N'
                               AND B1.STL_NO = R_COIL.COIL_NO) AS     R_WB    
                         
                         --HOT COILБИКа
                         ,CASE WHEN L_COIL.STL_APPEAR_GP != 'Y' THEN 
                               CASE WHEN TO_CHAR(SYSDATE,'MM') IN ('03','04','05') AND TO_NUMBER(TRUNC((SYSDATE - L_COIL.COIL_CREATE_DDTT) * 24)) < 72
                                         OR
                                         TO_CHAR(SYSDATE,'MM') IN ('06','07','08') AND TO_NUMBER(TRUNC((SYSDATE - L_COIL.COIL_CREATE_DDTT) * 24)) < 96
                                         OR 
                                         TO_CHAR(SYSDATE,'MM') IN ('09','10','11') AND TO_NUMBER(TRUNC((SYSDATE - L_COIL.COIL_CREATE_DDTT) * 24)) < 72
                                         OR
                                         TO_CHAR(SYSDATE,'MM') IN ('12','01','02') AND TO_NUMBER(TRUNC((SYSDATE - L_COIL.COIL_CREATE_DDTT) * 24)) < 48
                                    THEN 'TRUE'
                                    ELSE 'FALSE'
                               END
                           ELSE 'FALSE' END AS L_ISHOT
                          ,CASE WHEN R_COIL.STL_APPEAR_GP != 'Y' THEN 
                                CASE WHEN TO_CHAR(SYSDATE,'MM') IN ('03','04','05') AND TO_NUMBER(TRUNC((SYSDATE - R_COIL.COIL_CREATE_DDTT) * 24)) < 72
                                          OR
                                          TO_CHAR(SYSDATE,'MM') IN ('06','07','08') AND TO_NUMBER(TRUNC((SYSDATE - R_COIL.COIL_CREATE_DDTT) * 24)) < 96
                                          OR 
                                          TO_CHAR(SYSDATE,'MM') IN ('09','10','11') AND TO_NUMBER(TRUNC((SYSDATE - R_COIL.COIL_CREATE_DDTT) * 24)) < 72
                                          OR
                                          TO_CHAR(SYSDATE,'MM') IN ('12','01','02') AND TO_NUMBER(TRUNC((SYSDATE - R_COIL.COIL_CREATE_DDTT) * 24)) < 48
                                     THEN 'TRUE'
                                     ELSE 'FALSE'
                                END
                           ELSE 'FALSE' END AS R_ISHOT
                           
                         --ТЏБИБИКа
                         , CASE WHEN (SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'YM004' AND CD_GP = '1' AND DEL_YN = 'N' AND DTL_ITEM1=C_COIL.HR_SPEC_ABBSYM) IS NOT NULL                                  
                                 AND NVL(C_COIL.NEXT_PROC,1) NOT IN('1K','1Q')                               
                                 AND TRUNC((SYSDATE - C_COIL.HRMILL_CMPL_DT)*24,0)<=48                                    
                                THEN 'Y'  
                                ELSE 'N' END  AS C_JJANG_GP 
                         , CASE WHEN (SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'YM004' AND CD_GP = '1' AND DEL_YN = 'N' AND DTL_ITEM1=R_COIL.HR_SPEC_ABBSYM) IS NOT NULL                                  
                                 AND NVL(R_COIL.NEXT_PROC,1) NOT IN('1K','1Q')                                 
                                 AND TRUNC((SYSDATE - R_COIL.HRMILL_CMPL_DT)*24,0)<=48 --ОаПЌНУАЃ 48НУАЃРЬ ОШЕШ АцПь                                       
                                THEN 'Y'  
                                ELSE 'N' END  AS R_JJANG_GP  --ТЏБИПЉКЮ
                         , CASE WHEN (SELECT DTL_ITEM1 FROM TB_YF_RULE WHERE REPR_CD_GP = 'YM004' AND CD_GP = '1' AND DEL_YN = 'N' AND DTL_ITEM1=R_COIL.HR_SPEC_ABBSYM) IS NOT NULL                                  
                                 AND NVL(L_COIL.NEXT_PROC,1) NOT IN('1K','1Q')                               
                                 AND TRUNC((SYSDATE - L_COIL.HRMILL_CMPL_DT)*24,0)<=48                                    
                                THEN 'Y'  
                                ELSE 'N' END  AS L_JJANG_GP    
                         
                         
                          --СТПь П­ РчЗс Цј СЄКИ
                         ,(SELECT NVL(MAX(BB.COIL_W),0) FROM TB_YF_STKLYR AA, USRPTA.TB_PT_COILCOMM BB 
                            WHERE AA.YD_STK_COL_GP = SUBSTR(A.TAG_YD_STK_COL_GP,1,4) || LPAD(TO_NUMBER(SUBSTR(A.TAG_YD_STK_COL_GP,5,2))-1 ,2, '0' )
                              AND AA.YD_STK_BED_NO IN (A.TAG_YD_STK_BED_NO, DECODE(A.TAG_YD_STK_LYR_NO,'01',LPAD(TO_NUMBER(A.TAG_YD_STK_BED_NO) - 1, 2, '0')))
                              AND AA.YD_STK_LYR_NO IN ('02'               , DECODE(A.TAG_YD_STK_LYR_NO,'01','01'))
                              AND AA.STL_NO        = BB.COIL_NO
                          ) AS BEFORE_COL_WID
                         ,(SELECT NVL(MAX(BB.COIL_W),0) FROM TB_YF_STKLYR AA, USRPTA.TB_PT_COILCOMM BB  
                            WHERE AA.YD_STK_COL_GP = SUBSTR(A.TAG_YD_STK_COL_GP,1,4) || LPAD(TO_NUMBER(SUBSTR(A.TAG_YD_STK_COL_GP,5,2))+1 ,2, '0' )
                              AND AA.YD_STK_BED_NO IN (A.TAG_YD_STK_BED_NO, DECODE(A.TAG_YD_STK_LYR_NO,'01',LPAD(TO_NUMBER(A.TAG_YD_STK_BED_NO) - 1, 2, '0')))
                              AND AA.YD_STK_LYR_NO IN ('02'               , DECODE(A.TAG_YD_STK_LYR_NO,'01','01'))
                              AND AA.STL_NO        = BB.COIL_NO
                          ) AS NEXT_COL_WID
                         ,(SELECT MAX(AA.YD_STK_LYR_X_AXIS) FROM TB_YF_STKLYR AA
                            WHERE AA.YD_STK_COL_GP = SUBSTR(A.TAG_YD_STK_COL_GP,1,4) || LPAD(TO_NUMBER(SUBSTR(A.TAG_YD_STK_COL_GP,5,2))-1 ,2, '0' )
                              AND AA.YD_STK_BED_NO = A.TAG_YD_STK_BED_NO
                              AND AA.YD_STK_LYR_NO = '01'
                          ) AS BEFORE_COL_X_AXIS
                         ,(SELECT MAX(AA.YD_STK_LYR_X_AXIS) FROM TB_YF_STKLYR AA  
                            WHERE AA.YD_STK_COL_GP = SUBSTR(A.TAG_YD_STK_COL_GP,1,4) || LPAD(TO_NUMBER(SUBSTR(A.TAG_YD_STK_COL_GP,5,2))+1 ,2, '0' )
                              AND AA.YD_STK_BED_NO = A.TAG_YD_STK_BED_NO
                              AND AA.YD_STK_LYR_NO = '01'
                          ) AS NEXT_COL_X_AXIS
                          
                          
                          --ШОЧрСТЧЅ АХИЎ АшЛъРЛ РЇЧб, 2Дм СТПь ФкРЯ ПмАц
                         ,(SELECT COIL_OUTDIA FROM TB_YF_STKLYR AA, USRPTA.TB_PT_COILCOMM BB  
                            WHERE AA.YD_STK_COL_GP = A.TAG_YD_STK_COL_GP
                              AND AA.YD_STK_BED_NO = LPAD(TO_NUMBER(A.TAG_YD_STK_BED_NO) - 1, 2, '0')
                              AND AA.YD_STK_LYR_NO = '02'
                              AND AA.STL_NO        = BB.COIL_NO
                          ) AS L2DAN_OUTDIA
                         ,(SELECT COIL_OUTDIA FROM TB_YF_STKLYR AA, USRPTA.TB_PT_COILCOMM BB  
                            WHERE AA.YD_STK_COL_GP = A.TAG_YD_STK_COL_GP
                              AND AA.YD_STK_BED_NO = LPAD(TO_NUMBER(A.TAG_YD_STK_BED_NO) + 1, 2, '0')
                              AND AA.YD_STK_LYR_NO = '02'
                              AND AA.STL_NO        = BB.COIL_NO
                          ) AS R2DAN_OUTDIA 
                         ,CASE WHEN A.TAG_YD_STK_LYR_NO ='02' THEN SF_YF_WO_LOC_YAXIS_AUTO(A.TAG_YD_STK_COL_GP,A.TAG_YD_STK_BED_NO) END AS C_YAXIS_AUTO
                         ,CASE WHEN A.TAG_YD_STK_LYR_NO ='02' THEN SF_YF_WO_LOC_YAXIS_AUTO(A.TAG_YD_STK_COL_GP,LPAD(TO_NUMBER(A.TAG_YD_STK_BED_NO) - 1, 2, '0')) END AS L_YAXIS_AUTO
                         ,CASE WHEN A.TAG_YD_STK_LYR_NO ='02' THEN SF_YF_WO_LOC_YAXIS_AUTO(A.TAG_YD_STK_COL_GP,LPAD(TO_NUMBER(A.TAG_YD_STK_BED_NO) + 1, 2, '0')) END AS R_YAXIS_AUTO
                         
                          --2Дм РћРч БтПяБт ЛѓХТ УМХЉ
                         ,CASE WHEN A.TAG_YD_STK_LYR_NO ='02' THEN SF_YF_INCLINE_CHK(A.TAG_YD_STK_COL_GP,A.TAG_YD_STK_BED_NO) END AS INCLINE_CHK
                         
                         --ДмПьМБМјРЇ БтСи
                         ,A.RULL_DAN_PRIOR
                         --АЫЛіСЖАЧ БзЗьМјРЇ
                         ,A.GROUP_SEQ
                         
                         --Г­ЙцФкРЯ РЏЙЋ
                         ,C_STOCK.HEATING_COIL_YN AS C_HEATING_COIL_YN
                         ,L_STOCK.HEATING_COIL_YN AS L_HEATING_COIL_YN
                         ,R_STOCK.HEATING_COIL_YN AS R_HEATING_COIL_YN
                         
                          --TOРЇФЁ РћФЁАЁДЩ БтСи
                         ,NVL(TO_NUMBER(RULE.BED_DIFF2)  ,1300) AS BED_DIFF2
                         ,NVL(TO_NUMBER(RULE.ODIA_DIFF1) ,180)  AS ODIA_DIFF1
                         ,NVL(TO_NUMBER(RULE.ODIA_DIFF2) ,550)  AS ODIA_DIFF2
                         ,NVL(TO_NUMBER(RULE.WID_DIFF1)  ,200)  AS WID_DIFF1 
                         ,NVL(TO_NUMBER(RULE.WID_LIFT1)  ,680)  AS WID_LIFT1 
                         ,NVL(TO_NUMBER(RULE.WGT_DIFF2)  ,0)    AS WGT_DIFF2 
                         ,NVL(TO_NUMBER(RULE.WID_DIFF2)  ,200)  AS WID_DIFF2 
                         
                         --РћФЁП­ ПыЕЕПЁ ЕћИЅ ПьМБМјРЇ
                         ,(SELECT CASE WHEN RUL.ITEM ='R1' THEN (CASE WHEN C_COIL.COIL_OUTDIA BETWEEN TO_NUMBER(RUL.ITEM_VALUE1) AND TO_NUMBER(RUL.ITEM_VALUE2) 
                                                                      THEN 1 ELSE 2 END)
                                  END 
                             FROM TB_YF_RULE RUL 
                            WHERE RUL.ITEM = A.YD_STK_COL_USAGE_CD
                              AND RUL.DEL_YN ='N'
                              AND RUL.DTL_ITEM1 = 'Y'
                              AND RUL.REPR_CD_GP ='YF0003'
                           ) AS USAGE_PRIOR
                         
                         --ЦФЖѓЙЬХЭ
                         ,:V_BIZ_GP     AS BIZ_GP
                         ,:V_YD_ZONE_GP AS YD_ZONE_GP
                      FROM TABLE(USRYFA.SF_GET_TO_LOC_DATA(:V_YD_EQP_ID    ,:V_YD_SCH_CD
                                                          ,:V_STL_NO       ,:V_YD_TO_LOC_GUIDE
                                                          ,:V_YD_STK_LYR_NO,:V_SEARCH_ALL
                                                          ,:V_YD_ZONE_GP   ,:V_BIZ_GP)) A
                          ,(SELECT MAX(BED_DIFF2) AS BED_DIFF2, MAX(ODIA_DIFF1) AS ODIA_DIFF1, MAX(ODIA_DIFF2) AS ODIA_DIFF2
                                 , MAX(SKID_GAP)  AS SKID_GAP,  MAX(SKID_SKID)  AS SKID_SKID,  MAX(SMLR_W)     AS SMLR_W 
                                 , MAX(SMLR_WT)   AS SMLR_WT,   MAX(WGT_DIFF2)  AS WGT_DIFF2,  MAX(WID_DIFF1)  AS WID_DIFF1
                                 , MAX(WID_DIFF2) AS WID_DIFF2, MAX(WID_LIFT1)  AS WID_LIFT1,  MAX(WID_SKID1)  AS WID_SKID1
                              FROM 
                              ( SELECT DECODE(ITEM,'BED_DIFF2'  ,DTL_ITEM1) AS BED_DIFF2
                                      ,DECODE(ITEM,'ODIA_DIFF1' ,DTL_ITEM1) AS ODIA_DIFF1 
                                      ,DECODE(ITEM,'ODIA_DIFF2' ,DTL_ITEM1) AS ODIA_DIFF2
                                      ,DECODE(ITEM,'SKID_GAP'   ,DTL_ITEM1) AS SKID_GAP
                                      ,DECODE(ITEM,'SKID_SKID'  ,DTL_ITEM1) AS SKID_SKID
                                      ,DECODE(ITEM,'SMLR_W'     ,DTL_ITEM1) AS SMLR_W
                                      ,DECODE(ITEM,'SMLR_WT'    ,DTL_ITEM1) AS SMLR_WT
                                      ,DECODE(ITEM,'WGT_DIFF2'  ,DTL_ITEM1) AS WGT_DIFF2
                                      ,DECODE(ITEM,'WID_DIFF1'  ,DTL_ITEM1) AS WID_DIFF1
                                      ,DECODE(ITEM,'WID_DIFF2'  ,DTL_ITEM1) AS WID_DIFF2
                                      ,DECODE(ITEM,'WID_LIFT1'  ,DTL_ITEM1) AS WID_LIFT1
                                      ,DECODE(ITEM,'WID_SKID1'  ,DTL_ITEM1) AS WID_SKID1
                              FROM TB_YF_RULE WHERE REPR_CD_GP = 'SCH_TO' AND CD_GP = '1' AND DEL_YN = 'N')
                           ) RULE 
                          ,TB_YF_STKLYR             L
                          ,TB_YF_STKLYR             R
                          ,TB_YF_STKLYR             L2DAN
                          ,TB_YF_STKLYR             R2DAN
                          ,USRPTA.TB_PT_COILCOMM    C_COIL  --ДыЛѓФкРЯ
                          ,USRPTA.TB_PT_COILCOMM    L_COIL  --ЧЯДмLEFT
                          ,USRPTA.TB_PT_COILCOMM    R_COIL  --ЧЯДмRIGHT
                          ,TB_YF_EQP                CR
                          ,TB_YF_STOCK              C_STOCK --ДыЛѓФкРЯ
                          ,TB_YF_STOCK              L_STOCK --ЧЯДмLEFT
                          ,TB_YF_STOCK              R_STOCK --ЧЯДмRIGHT
                          
                     WHERE A.TAG_YD_STK_COL_GP  = L.YD_STK_COL_GP(+)
                       AND A.TAG_LEFT_BED       = L.YD_STK_BED_NO(+)
                       AND A.TAG_LEFT_LAYER     = L.YD_STK_LYR_NO(+)
                       
                       AND A.TAG_YD_STK_COL_GP  = R.YD_STK_COL_GP(+)
                       AND A.TAG_RIGHT_BED      = R.YD_STK_BED_NO(+)
                       AND A.TAG_RIGHT_LAYER    = R.YD_STK_LYR_NO(+)
                       
                       AND A.TAG_YD_STK_COL_GP  = L2DAN.YD_STK_COL_GP(+)
                       AND A.TAG_LEFT_BED       = L2DAN.YD_STK_BED_NO(+)
                       AND '02'                 = L2DAN.YD_STK_LYR_NO(+)
                       
                       AND A.TAG_YD_STK_COL_GP  = R2DAN.YD_STK_COL_GP(+)
                       AND A.TAG_YD_STK_BED_NO  = R2DAN.YD_STK_BED_NO(+)
                       AND '02'                 = R2DAN.YD_STK_LYR_NO(+)
                       
                       AND A.STL_NO             = C_COIL.COIL_NO(+) 
                       AND L.STL_NO             = L_COIL.COIL_NO(+) 
                       AND R.STL_NO             = R_COIL.COIL_NO(+)
                       
                       AND A.STL_NO             = C_STOCK.STL_NO(+)
                       AND L.STL_NO             = L_STOCK.STL_NO(+)
                       AND R.STL_NO             = R_STOCK.STL_NO(+)
                       
                       AND CR.YD_EQP_ID         = :V_YD_EQP_ID
                       AND CR.DEL_YN            = 'N'
                       
                ) A 
            ) A
        ) A          
--1П­РЬ И№ЕЮ КёОюРжРЛ АцПь. РћФЁЙшЕх ИјУЃДТ АцПь ЖЇЙЎПЁ 30АГЗЮ МіСЄ     
WHERE ((PRIOR1 < 3) OR (PRIOR1 = 3 AND GROUP_ROW <= CASE WHEN NVL(:V_SEARCH_ALL,'N') = 'Y'  THEN 50 ELSE 30 END)) -- PRIOR1=3РК АјBED: 10АГИИ АЫЛі.    
ORDER BY  CASE WHEN LOC_ABLE_CHK ='PASS' THEN 1 ELSE 2 END
         ,USAGE_PRIOR
         ,L_CAR_CHK DESC
         ,R_CAR_CHK DESC
         ,GROUP_SEQ     --РЇФЁАЫЛіБзЗь
         ,PRIOR0        --ДмПьМБМјРЇ 
         ,PRIOR1        --СТПь КЃЕх ЛѓХТ
         ,PRIOR2        --ОпЕхРЇФЁ АЫЛіЙќРЇМјМ­ 
         ,PRIOR3        --BED + SPAN + П­(ДѕЙЬРќПы)
         ,PRIOR4        --П­(ДѕЙЬРќПы)    
         ,GRIDE         --ЦђСЁ
         ,CASE WHEN YD_SCH_CD LIKE '1DPT__LM' THEN 100 - TO_NUMBER(TAG_YD_STK_BED_NO) --DЕП МвРчРЬМлЧЯТїДТ ПЊМј
               ELSE TO_NUMBER(TAG_YD_STK_BED_NO) 
          END
 </pre> */
public final static String getYfToLocMainSql = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfToLocMainSql";

