 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListCTSTracking  
SELECT A.YD_EQP_GP,
       A.YD_EQP_ID,                                --ЙјСі
       A.YD_EQP_NAME,
       A.YD_CTS_SCH_ID,
       A.YD_EQP_PROG_STAT,
       A.YD_WRK_PROG_STAT,
       A.YD_CURR_BAY_GP,
       '1_S___' AS EQP_NAME,
       DECODE(A.YD_EQP_GP, 'TC', A.YD_EQP_NAME,
                           'SL', A.YD_BAY_GP||'ЕП СТУј'||A.YD_EQP_NO||'П­',
                           'SR', A.YD_BAY_GP||'ЕП ПьУј'||A.YD_EQP_NO||'П­',
                           '.T.') AS BUNSU,
       CASE WHEN A.YD_EQP_ID IN ('1XTC01','1XTC02') THEN 
            CASE WHEN A.YD_EQP_PROG_STAT = 'B' THEN 'КёАЁЕП' ELSE 'АЁЕП' END  
       ELSE A.YD_STK_LYR_ACTIVE_STAT END AS YD_STK_LYR_ACTIVE_STAT,
       CASE WHEN A.YD_EQP_ID IN ('1XTC01','1XTC02') THEN 
                    CASE WHEN A.YD_EQP_PROG_STAT IN ('1','2','3','4') AND A.STL_NO IS NOT NULL THEN 'РЬМлСп'
                         WHEN A.YD_EQP_PROG_STAT IN ('N', 'W') AND A.STL_NO IS NULL THEN 'РЬМлДыБт(*)' 
                         WHEN A.YD_EQP_PROG_STAT = 'B' THEN 'АэРх'
                         END
       ELSE 
            CASE WHEN A.YD_STK_LYR_STAT = 'C' AND A.STL_NO IS NULL AND A.YD_CTS_SCH_ID IS NULL THEN 'DATAПРЗљ'
            ELSE CASE
                    A.YD_STK_LYR_STAT 
                    WHEN 'C' THEN CASE CTS_TO_YARD_SCH_YN WHEN 'Y' THEN 'CTS ЧЯТї(*)' ELSE 'РлОїДыБт(*)' END
                    WHEN 'U' THEN CASE CTS_TO_YARD_SCH_YN WHEN 'Y' THEN 'CTS ЧЯТї(U)' ELSE 'БЧЛѓДыБт(U)' END
                    WHEN 'D' THEN 'БЧЧЯДыБт(D)'
                    WHEN 'E' THEN ''
                END 
            END
       END AS SADDLE_STK_STAT,
       CASE WHEN A.YD_STK_LYR_STAT = 'C' THEN '*' ELSE A.YD_STK_LYR_STAT END AS YD_STK_LYR_STAT,  
       A.STL_NO, 
       A.YD_STK_COL_GP,
       B.STOCK_ITEM,
       NVL(A.CTS_RELAY_SADDLE, '-') AS CTS_RELAY_SADDLE,
       C.COIL_WT, 
       C.COIL_OUTDIA,
       C.COIL_T, 
       C.COIL_W,
       C.CURR_COIL_LEN, 
       C.NEXT_PROC,
       CASE WHEN C.CURR_PROG_CD ='1' THEN 'Л§ЛъПЙСЄЛѓХТ' 		|| '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='2' THEN 'МвРчРдАэДыБт'      || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='3' THEN 'МвРчРЬМлСіНУДыБт'  || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='A' THEN 'РчСњЦЧСЄДыБт'      || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='B' THEN 'СЄСЄРлОїСіНУДыБт'  || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='C' THEN 'СЄСЄРлОїДыБт'      || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='D' THEN 'РЬМлРлОїСіНУДыБт'  || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='E' THEN 'РЬМлРлОїДыБт'      || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='F' THEN 'ЦЧСЄКИЗљ'         || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='G' THEN 'СОЧеЦЧСЄ ДыБт'     || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='H' THEN 'РдАэДыБт'         || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='J' THEN 'ЙнГГДыБт'         || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='K' THEN 'УтЧЯРлОїСіНУДыБт'  || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='L' THEN 'УтЧЯРлОїДыБт'      || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='M' THEN 'УтЧЯПЯЗс'         || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='N' THEN 'МБРћДыБт'         || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='P' THEN 'РЮЕЕПЯЗс'         || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='Y' THEN 'РчАјУцДчДыБт'      || '(' || C.CURR_PROG_CD || ')'
            WHEN C.CURR_PROG_CD ='Y' THEN 'СІЧАУцДчДыБт'      || '(' || C.CURR_PROG_CD || ')'
            ELSE ''  
             END AS CURR_PROG_CD,

       C.USAGE_CD, --ПыЕЕФкЕх
       (
                SELECT R.DTL_ITEM1
                FROM TB_YF_RULE R
                WHERE R.REPR_CD_GP='PRI007' 
                AND R.CD_GP = '1'
                AND R.DEL_YN='N'
           )  AS CTS_CENTER,
      (SELECT R.REPR_CD_CONTENTS
          FROM TB_YF_RULE R
         WHERE R.REPR_CD_GP='YM6001' 
           AND R.CD_GP = '1'
           AND R.ITEM= B.YD_ZONE_GP 
           AND R.DEL_YN='N'
           ) AS YD_ZONE_GP_NM,
      B.YD_ZONE_GP,
      A.NEXT_EQP_ID,
      A.NEXT_EQP_ID_NM,
      A.YD_CTS_WRK_SEQ,
      A.YD_STK_COL_USAGE_CD,
      A.YD_AIM_BAY_GP AS YD_AIM_BAY_GP,
      CASE WHEN A.JOB_KIND = 'UM'
           THEN A.YD_CARLD_WO_LOC ||'->'|| A.YD_CARUD_WO_LOC 
	   END AS MOVE_TXT,
      A.YD_CARUD_WO_LOC,
      A.YD_CARLD_WO_LOC,
      CASE 
        WHEN A.YD_EQP_ID = '1XTC01' AND B.STL_NO IS NOT NULL THEN 'LM'
        WHEN A.YD_EQP_ID = '1XTC02' AND B.STL_NO IS NOT NULL THEN 'LM' 
      ELSE
         A.JOB_KIND
      END AS JOB_KIND,
      A.ORG_YD_CTS_WRK_SEQ
  FROM ( SELECT A.YD_GP, 
                A.YD_BAY_GP, 
                A.YD_EQP_ID, 
                A.YD_EQP_NO, 
                A.YD_EQP_GP, 
                A.YD_EQP_PROG_STAT,
                A.YD_EQP_NAME,  
                A.YD_CURR_BAY_GP,
                B.YD_STK_LYR_STAT, 
                B.STL_NO,
                B.YD_STK_LYR_ACTIVE_STAT,
                C.YD_STK_COL_USAGE_CD,
                C.YD_STK_COL_GP,
                CT.YD_EQP_ID AS NEXT_EQP_ID,
                ( SELECT S.YD_EQP_NAME FROM TB_YF_EQP S WHERE S.YD_EQP_ID = CT.YD_EQP_ID ) AS NEXT_EQP_ID_NM,
                DECODE(CT.YD_CARUD_WO_LOC,C.YD_STK_COL_GP,NULL,CT.YD_CTS_WRK_SEQ) AS YD_CTS_WRK_SEQ,
                CT.YD_CTS_RELAY_YN,
                CT.YD_CTS_RELAY_BAY_GP,
                DECODE(CT.YD_CARUD_WO_LOC,C.YD_STK_COL_GP,NULL,CT.YD_CARUD_WO_LOC) AS CTS_RELAY_SADDLE,
                CT.YD_CARLD_WO_LOC,
                CT.YD_CARUD_WO_LOC,
                CT.YD_CARLD_WR_LOC,
                CT.YD_CARUD_WR_LOC,
                CT.ORG_YD_CTS_WRK_SEQ,
                NVL(CT.WB_YD_AIM_BAY_GP,(
                     SELECT M.YD_AIM_BAY_GP
                     FROM TB_YF_WRKBOOK M
                        , TB_YF_WRKBOOKMTL M1
                     WHERE M.YD_WBOOK_ID = M1.YD_WBOOK_ID
                     AND M1.STL_NO = B.STL_NO
                     AND M.DEL_YN = 'N'
                     AND M1.DEL_YN = 'N'
                )) AS YD_AIM_BAY_GP,
                CT.YD_CTS_SCH_ID,
                CASE WHEN  B.YD_STK_LYR_ACTIVE_STAT <> 'E' THEN ''
                ELSE 
                    CASE
                        WHEN B.YD_STK_COL_GP = CT.YD_CARUD_WO_LOC THEN 'UM'
                        WHEN B.YD_STK_COL_GP = CT.YD_CARLD_WO_LOC THEN 'LM'
                        WHEN B.YD_STK_LYR_STAT = 'C' THEN 'LM'
                        WHEN B.YD_STK_LYR_STAT = 'U' AND CT.STL_NO IS NULL THEN 'LM'
                    END
                END AS JOB_KIND,
                NVL((
                    SELECT 'Y'
                    FROM TB_YF_WRKBOOK S1
                         , TB_YF_WRKBOOKMTL S2
                    WHERE S1.YD_WBOOK_ID = S2.YD_WBOOK_ID
                    AND S2.STL_NO = B.STL_NO
                    AND S1.DEL_YN = 'N'
                    AND S2.DEL_YN = 'N'
                    AND S1.YD_SCH_CD LIKE '1_TC_1LM' -- CTS ЧЯТї 
                ),'N') AS CTS_TO_YARD_SCH_YN,
                CT.YD_WRK_PROG_STAT
           FROM TB_YF_EQP A, 
                TB_YF_STKLYR B,
                TB_YF_STKCOL C,
                (SELECT Z.STL_NO
                       ,Z.YD_EQP_ID
                       ,ROW_NUMBER() OVER (PARTITION BY Z.YD_EQP_ID ORDER BY YD_CTS_WRK_SEQ) AS YD_CTS_WRK_SEQ
                       ,YD_CTS_WRK_SEQ AS ORG_YD_CTS_WRK_SEQ
                       ,Z.YD_CTS_RELAY_YN
                       ,Z.YD_CTS_RELAY_BAY_GP
                       ,Z.YD_CARUD_WO_LOC
                       ,Z.YD_CARLD_WO_LOC
                       ,Z.YD_CARUD_WR_LOC
                       ,Z.YD_CARLD_WR_LOC
                       ,Z.YD_AIM_BAY_GP
                       ,Z.YD_CTS_SCH_ID
                       ,Z.YD_AIM_BAY_GP AS WB_YD_AIM_BAY_GP
                       ,Z.YD_WRK_PROG_STAT 
                   FROM TB_YF_CTS_SCH Z, TB_YF_WRKBOOK Z1
                  WHERE Z.DEL_YN = 'N' 
                  AND Z.YD_WBOOK_ID = Z1.YD_WBOOK_ID(+)
                  ) CT
          WHERE A.YD_EQP_ID LIKE '1%'
            AND ( A.YD_EQP_GP IN( 'SL', 'SR')
              OR A.YD_EQP_ID IN ('1XTC01','1XTC02')
            )
            AND A.YD_EQP_ID = B.YD_STK_COL_GP
            AND A.YD_EQP_ID = C.YD_STK_COL_GP
            AND B.STL_NO = CT.STL_NO(+)) A, 
       TB_YF_STOCK B, 
       TB_PT_COILCOMM C
 WHERE A.STL_NO = B.STL_NO(+)
   AND A.STL_NO = C.COIL_NO(+)
 ORDER BY DECODE(YD_EQP_GP,'TC',0,1), A.YD_EQP_ID
 </pre> */
public final static String getListCTSTracking = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getListCTSTracking";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L017
--CTSРлОїУтЙпСіНУ
SELECT 'YFF1L017' AS JMS_TC_CD                                    				--JMSTCФкЕх
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT 	--JMSTCЛ§МКРЯНУ
      ,'YFF1L017'                                     				--РќЙЎID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DD')       							--Л§МКРЯНУ
     ||TO_CHAR(SYSDATE,'HH24-MI-SS')       							--Л§МКРЯНУ
     ||'I' 				--РќЙЎБИКа
     ||'0317'                                        				--РќЙЎБцРЬ
     ||RPAD(' ',29,' ')                           --РгНУ
     ||RPAD(NVL(:V_YD_EQP_ID            , ' '),  6 , ' ')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_1       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_1       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_1                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_1 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_2       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_2       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_2                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_2 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_3       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_3       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_3                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_3 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_4       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_4       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_4                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_4 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_5       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_5       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_5                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_5 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_6       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_6       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_6                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_6 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_7       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_7       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_7                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_7 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_8       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_8       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_8                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_8 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_9       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_9       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_9                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_9 ,'FM0000000'),'0'),7 ,'0')
     
     ||RPAD(NVL(YD_CARLD_WO_LOC_10       , ' '),  6 , ' ')
     ||RPAD(NVL(YD_CARUD_WO_LOC_10       , ' '),  6 , ' ')
     ||RPAD(NVL(STL_NO_10                , ' '),  11, ' ')
     ||RPAD(NVL(TO_CHAR(YD_EQP_WRK_WT_10 ,'FM0000000'),'0'),7 ,'0')

     ||RPAD(NVL(YD_CTS_RELAY_BAY_GP  , ' '),  1, ' ')
     ||RPAD(NVL(CTS_WRK_GP           , ' '),  1, ' ')
     ||RPAD(NVL(' '                  , ' '),  9, ' ')
     
       AS JMS_TC_MESSAGE --JMSTCMessage
  FROM (SELECT MAX(YD_EQP_ID) AS YD_EQP_ID
              ,MAX(YD_CARLD_WO_LOC_1) AS YD_CARLD_WO_LOC_1, MAX(YD_CARUD_WO_LOC_1) AS YD_CARUD_WO_LOC_1, MAX(STL_NO_1) AS STL_NO_1, MAX(YD_EQP_WRK_WT_1) AS YD_EQP_WRK_WT_1
              ,MAX(YD_CARLD_WO_LOC_2) AS YD_CARLD_WO_LOC_2, MAX(YD_CARUD_WO_LOC_2) AS YD_CARUD_WO_LOC_2, MAX(STL_NO_2) AS STL_NO_2, MAX(YD_EQP_WRK_WT_2) AS YD_EQP_WRK_WT_2
              ,MAX(YD_CARLD_WO_LOC_3) AS YD_CARLD_WO_LOC_3, MAX(YD_CARUD_WO_LOC_3) AS YD_CARUD_WO_LOC_3, MAX(STL_NO_3) AS STL_NO_3, MAX(YD_EQP_WRK_WT_3) AS YD_EQP_WRK_WT_3
              ,MAX(YD_CARLD_WO_LOC_4) AS YD_CARLD_WO_LOC_4, MAX(YD_CARUD_WO_LOC_4) AS YD_CARUD_WO_LOC_4, MAX(STL_NO_4) AS STL_NO_4, MAX(YD_EQP_WRK_WT_4) AS YD_EQP_WRK_WT_4
              ,MAX(YD_CARLD_WO_LOC_5) AS YD_CARLD_WO_LOC_5, MAX(YD_CARUD_WO_LOC_5) AS YD_CARUD_WO_LOC_5, MAX(STL_NO_5) AS STL_NO_5, MAX(YD_EQP_WRK_WT_5) AS YD_EQP_WRK_WT_5
              ,MAX(YD_CARLD_WO_LOC_6) AS YD_CARLD_WO_LOC_6, MAX(YD_CARUD_WO_LOC_6) AS YD_CARUD_WO_LOC_6, MAX(STL_NO_6) AS STL_NO_6, MAX(YD_EQP_WRK_WT_6) AS YD_EQP_WRK_WT_6
              ,MAX(YD_CARLD_WO_LOC_7) AS YD_CARLD_WO_LOC_7, MAX(YD_CARUD_WO_LOC_7) AS YD_CARUD_WO_LOC_7, MAX(STL_NO_7) AS STL_NO_7, MAX(YD_EQP_WRK_WT_7) AS YD_EQP_WRK_WT_7
              ,MAX(YD_CARLD_WO_LOC_8) AS YD_CARLD_WO_LOC_8, MAX(YD_CARUD_WO_LOC_8) AS YD_CARUD_WO_LOC_8, MAX(STL_NO_8) AS STL_NO_8, MAX(YD_EQP_WRK_WT_8) AS YD_EQP_WRK_WT_8
              ,MAX(YD_CARLD_WO_LOC_9) AS YD_CARLD_WO_LOC_9, MAX(YD_CARUD_WO_LOC_9) AS YD_CARUD_WO_LOC_9, MAX(STL_NO_9) AS STL_NO_9, MAX(YD_EQP_WRK_WT_9) AS YD_EQP_WRK_WT_9
              ,MAX(YD_CARLD_WO_LOC_10) AS YD_CARLD_WO_LOC_10, MAX(YD_CARUD_WO_LOC_10) AS YD_CARUD_WO_LOC_10, MAX(STL_NO_10) AS STL_NO_10, MAX(YD_EQP_WRK_WT_10) AS YD_EQP_WRK_WT_10
              ,MAX(DTL_ITEM1) AS YD_CTS_RELAY_BAY_GP
              ,MAX(CTS_WRK_GP) AS CTS_WRK_GP  
          FROM
          (
                SELECT YD_EQP_ID, DTL_ITEM1 
                   ,CASE WHEN RNK =1 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_1
                   ,CASE WHEN RNK =1 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_1 
                   ,CASE WHEN RNK =1 THEN STL_NO END            AS STL_NO_1
                   ,CASE WHEN RNK =1 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_1
                   ,CASE WHEN RNK =1 THEN CTS_WRK_GP END        AS CTS_WRK_GP
                   
                   ,CASE WHEN RNK =2 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_2
                   ,CASE WHEN RNK =2 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_2 
                   ,CASE WHEN RNK =2 THEN STL_NO END            AS STL_NO_2
                   ,CASE WHEN RNK =2 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_2
                   
                   ,CASE WHEN RNK =3 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_3
                   ,CASE WHEN RNK =3 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_3 
                   ,CASE WHEN RNK =3 THEN STL_NO END            AS STL_NO_3
                   ,CASE WHEN RNK =3 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_3
                   
                   ,CASE WHEN RNK =4 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_4
                   ,CASE WHEN RNK =4 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_4 
                   ,CASE WHEN RNK =4 THEN STL_NO END            AS STL_NO_4
                   ,CASE WHEN RNK =4 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_4
                   
                   ,CASE WHEN RNK =5 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_5
                   ,CASE WHEN RNK =5 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_5 
                   ,CASE WHEN RNK =5 THEN STL_NO END            AS STL_NO_5
                   ,CASE WHEN RNK =5 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_5
                   
                   ,CASE WHEN RNK =6 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_6
                   ,CASE WHEN RNK =6 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_6 
                   ,CASE WHEN RNK =6 THEN STL_NO END            AS STL_NO_6
                   ,CASE WHEN RNK =6 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_6
                   
                   ,CASE WHEN RNK =7 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_7
                   ,CASE WHEN RNK =7 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_7 
                   ,CASE WHEN RNK =7 THEN STL_NO END            AS STL_NO_7
                   ,CASE WHEN RNK =7 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_7
                   
                   ,CASE WHEN RNK =8 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_8
                   ,CASE WHEN RNK =8 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_8 
                   ,CASE WHEN RNK =8 THEN STL_NO END            AS STL_NO_8
                   ,CASE WHEN RNK =8 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_8
                   
                   ,CASE WHEN RNK =9 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_9
                   ,CASE WHEN RNK =9 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_9 
                   ,CASE WHEN RNK =9 THEN STL_NO END            AS STL_NO_9
                   ,CASE WHEN RNK =9 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_9
                   
                   ,CASE WHEN RNK =10 THEN YD_CARLD_WO_LOC END   AS YD_CARLD_WO_LOC_10
                   ,CASE WHEN RNK =10 THEN YD_CARUD_WO_LOC END   AS YD_CARUD_WO_LOC_10 
                   ,CASE WHEN RNK =10 THEN STL_NO END            AS STL_NO_10
                   ,CASE WHEN RNK =10 THEN YD_EQP_WRK_WT END     AS YD_EQP_WRK_WT_10
                FROM
                (
                    SELECT A.YD_EQP_ID
                         , C.DTL_ITEM1
                         , A.YD_CARLD_WO_LOC
                         , A.YD_CARUD_WO_LOC
                         , A.STL_NO
                         , CASE WHEN A.YD_CTS_RELAY_YN ='Y' THEN 'R'
                                ELSE 'E' END AS CTS_WRK_GP
                         , (SELECT COIL_WT FROM TB_PT_COILCOMM WHERE COIL_NO = A.STL_NO) AS YD_EQP_WRK_WT
                         , RANK() OVER(ORDER BY A.YD_WRK_PROG_STAT, A.YD_CTS_WRK_SEQ ,A.REG_DDTT) AS RNK
                      FROM TB_YF_CTS_SCH A
                          ,TB_YF_EQP B
                          ,TB_YF_RULE C
                     WHERE A.YD_EQP_ID          = B.YD_EQP_ID
                       AND A.DEL_YN             = 'N'
                       AND A.YD_WRK_PROG_STAT   IN ('W','S','2') --CTSРлОїПфБИ РЯЖЇДТ ЛѓТїСп(2)ЕЕ КИГЛОп Чд
                      -- AND B.YD_EQP_PROG_STAT   = 'W'
                       AND A.YD_EQP_ID = :V_YD_EQP_ID 
                       AND C.REPR_CD_GP = 'PRI007'
                       AND C.DEL_YN             = 'N'
                       AND A.YD_CARUD_WO_LOC IS NOT NULL --ЧЯТїРЇФЁ ОјРИИщ СІПм, ЧЯТїРЇФЁ ОјДТ АЭРЬ 1МјРЇЗЮ СіНУ ГЛЗСАЅМіРжРН.
                 )
            )
       )
 </pre> */
public final static String getYFF1L017 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L017";

 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getCtsWrkSeq
--ctsРлОїМјМ­СЖШИ 
SELECT  MAX(CASE WHEN DATA.DTL_ITEM1  = 'X' AND A.REPR_CD_GP = 'PRI001' THEN A.DTL_ITEM3 END) AS MOVE_1
       ,MAX(CASE WHEN DATA.DTL_ITEM1 != 'X' AND A.REPR_CD_GP = 'PRI002' THEN A.DTL_ITEM3 END) AS MOVE_A
       ,MAX(CASE WHEN DATA.DTL_ITEM1 != 'X' AND A.REPR_CD_GP = 'PRI003' THEN A.DTL_ITEM3 END) AS MOVE_B
       ,MAX(CASE WHEN DATA.DTL_ITEM1  = 'X' AND A.REPR_CD_GP = 'PRI004' THEN A.DTL_ITEM3 END) AS EMER_1
       ,MAX(CASE WHEN DATA.DTL_ITEM1 != 'X' AND A.REPR_CD_GP = 'PRI005' THEN A.DTL_ITEM3 END) AS EMER_A
       ,MAX(CASE WHEN DATA.DTL_ITEM1 != 'X' AND A.REPR_CD_GP = 'PRI006' THEN A.DTL_ITEM3 END) AS EMER_B
       ,MAX(DATA.DTL_ITEM1) AS RELAY_GP
FROM TB_YF_RULE A
    ,(SELECT DTL_ITEM1
        FROM TB_YF_RULE
       WHERE REPR_CD_GP = 'PRI007') B
WHERE A.DTL_ITEM1 = :V_YD_CURR_BAY_GP
  AND A.DTL_ITEM2 = :V_YD_AIM_BAY_GP
  AND (
        (B.DTL_ITEM1 = 'X')
      OR
          (       B.DTL_ITEM1 != 'X'
              AND A.DTL_ITEM1 BETWEEN 'A'         AND B.DTL_ITEM1
              AND A.DTL_ITEM1 BETWEEN B.DTL_ITEM1 AND 'Z' 
          )
      )
 </pre> */
public final static String getCtsWrkSeq = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getCtsWrkSeq";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCTSSchData
--CTSНКФЩСй СЖШИ
SELECT 
 YD_CTS_SCH_ID
,REGISTER
,REG_DDTT
,MODIFIER
,MOD_DDTT
,DEL_YN
,YD_EQP_ID
,YD_CTS_WRK_SEQ
,STL_NO
,YD_WRK_PROG_STAT
,YD_WBOOK_ID
,YD_AIM_BAY_GP
,YD_CTS_RELAY_YN
,YD_CTS_RELAY_BAY_GP
,YD_CARLD_WO_LOC
,YD_CARUD_WO_LOC
,YD_WORD_DT
,YD_CARLD_WR_LOC
,YD_CARLD_WR_DT
,YD_CARUD_WR_LOC
,YD_CARUD_WR_DT
FROM TB_YF_CTS_SCH
WHERE DEL_YN    = 'N'
  AND YD_CTS_SCH_ID    = :V_YD_CTS_SCH_ID
 </pre> */
public final static String getCTSSchData = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCTSSchData";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getRequstPassTimeByEqp2 
SELECT
    T1.YD_WRK_CRN
    , T1.YD_EQP_GP
    , T2.YD_EQP_NO
    , CASE SUBSTR(T1.YD_EQP_GP,1,1)
      WHEN 'F' THEN 'HFL'
      WHEN 'K' THEN 'SPM'
      WHEN 'Q' THEN 'EQL'
       END AS EQP_KIND
    , T2.YD_EQP_NAME
    , T2.YD_BAY_GP
    , TO_CHAR(T1.WBOOK_REG_DATE, 'YYYYMMDDHH24MISS') AS WBOOK_REG_DATE
    , TO_CHAR(T1.WBOOK_REG_DATE, 'HH24') AS WBOOK_REG_HH24
    , TO_CHAR(T1.WBOOK_REG_DATE, 'MI') AS WBOOK_REG_MI
    , TO_CHAR(T1.WBOOK_REG_DATE, 'SS') AS WBOOK_REG_SS
    ,REPLACE(( 
       REPLACE('('||TRUNC(SYSDATE - T1.WBOOK_REG_DATE) ||')','()','')||
       LPAD(TRUNC(MOD(SYSDATE - T1.WBOOK_REG_DATE,1)*24), 2, '0') || ':' ||  
       LPAD(TRUNC(MOD((SYSDATE - T1.WBOOK_REG_DATE)*24,1)*60), 2, '0') ||':'||  
       LPAD(TRUNC(MOD((SYSDATE - T1.WBOOK_REG_DATE)*24*60,1)*60), 2, '0')
     ),'::','') AS PASS_TIME 
    ,(CASE WHEN T1.YD_EQP_GP = 'FD' THEN  (CASE WHEN TRUNC((SYSDATE - T1.WBOOK_REG_DATE)*24) >= 1 THEN 'Y' ELSE 'N' END )   --АсМгРх 1НУАЃ РЬЛѓ ОЫЖї
           WHEN T1.YD_EQP_GP IN ('KD','QD') THEN  (CASE WHEN TRUNC((SYSDATE - T1.WBOOK_REG_DATE)*24*60)>=20 THEN 'Y' ELSE 'N' END ) -- МГКё 20Ка РЬЛѓ ОЫЖї
           ELSE 'N' END
      ) PASS_TIME_YN
    ,(SELECT CASE DTL_ITEM1
             WHEN 'Y' THEN 'АэРх(' || TO_CHAR(Z.MOD_DDTT,'YYYY-MM-DD HH24:MI:SS') || ')'
             ELSE 'СЄЛѓ'
             END AS TT_STATUS
        FROM TB_YF_RULE Z
       WHERE REPR_CD_GP = 'YF0009'
         AND CD_GP = '1'
         AND ITEM = 'TT'
         AND DEL_YN = 'N') AS CONVEY_CHK
     ,NVL((SELECT WM_CONCAT(YD_EQP_NAME)
         FROM TB_YF_EQP
        WHERE YD_EQP_GP = 'CR'
          AND YD_EQP_PROG_STAT = 'B'),'СЄЛѓ') AS CRANE_CHK
     ,(SELECT CASE YD_EQP_PROG_STAT
              WHEN 'B' THEN 'АэРх'
              ELSE 'СЄЛѓ' END 
         FROM TB_YF_EQP
        WHERE YD_EQP_ID = '1XTC03') AS ABCAR_CHK
     ,NVL((SELECT WM_CONCAT(YD_EQP_NAME)
         FROM TB_YF_EQP
        WHERE YD_EQP_ID IN ('1XTC01','1XTC02')
          AND YD_EQP_PROG_STAT = 'B'),'СЄЛѓ') AS CTSCAR_CHK
FROM
(
    SELECT  
         B.YD_WRK_CRN
        ,SUBSTR(B.YD_SCH_CD,3,2) AS YD_EQP_GP
        ,MIN(A.REG_DDTT  ) AS WBOOK_REG_DATE         
    FROM  TB_YF_SCHRULE B
        , TB_YF_WRKBOOK A
    WHERE B.YD_SCH_CD = A.YD_SCH_CD(+)
      AND B.DEL_YN = 'N'
      AND B.YD_GP = '1'
      AND A.DEL_YN(+) = 'N'
      --
        ПьМБ TAKE-OUTРК СІПм 
        УпУтИИ ДыЛѓРИЗЮ СјЧрЧбДй.
      
      AND 
      ( B.YD_SCH_CD LIKE '1_FD01LM'
        OR B.YD_SCH_CD LIKE '1_KD01LM'
        OR B.YD_SCH_CD LIKE '1_QD01LM'
      ) 
    GROUP BY B.YD_WRK_CRN, SUBSTR(B.YD_SCH_CD,3,2)
) T1, TB_YF_EQP T2
WHERE T1.YD_WRK_CRN = T2.YD_EQP_ID
ORDER BY T2.YD_EQP_ID ASC, T1.YD_EQP_GP
 </pre> */
public final static String getRequstPassTimeByEqp2 = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getRequstPassTimeByEqp2";

