 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getTcarSchByEqpid
SELECT YD_TCAR_SCH_ID
     , CASE WHEN :V_YD_MOVE_GP = 'S' THEN                   --ОпЕхДыТїРЬЕПБИКа(S:УтЙп,E:ЕЕТј)
                CASE WHEN YD_EQP_WRK_STAT = 'U' THEN '1'    --АјДыТї(ЛѓТї)УтЙп
                     WHEN YD_EQP_WRK_STAT = 'L' THEN 'A' END--ПЕДыТї(ЧЯТї)УтЙп
       
            ELSE 
                CASE WHEN YD_EQP_WRK_STAT = 'L'        THEN 'B' --ПЕДыТї(ЧЯТї)ЕЕТј
                     WHEN YD_CARLD_WRK_BOOK_ID IS NULL THEN '0' --АјДыТї(ЛѓТїДыБт)ЕЕТј
                     ELSE '2' END                               --АјДыТї(ЛѓТї)ЕЕТј
       END AS YD_CAR_PROG_STAT                              --ОпЕхТїЗЎСјЧрЛѓХТ
       
     , YD_CAR_PROG_STAT AS  BF_CAR_PROG_STAT                --КЏАцРќ ТїЗЎ СјЧрЛѓХТ
  FROM TB_YF_TCARSCH
 WHERE YD_EQP_ID = :V_YD_EQP_ID
   AND DEL_YN    = 'N'
 </pre> */
public final static String getTcarSchByEqpid = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getTcarSchByEqpid";

 /** <pre> 
--yf.common.dao.selectSkidIniInfoREAll
WITH PARAM AS (
SELECT :V_YD_GP AS YD_GP
      ,:V_YD_STK_COL_GP AS YD_STK_COL_GP
  FROM DUAL
)
SELECT   (SELECT b.YD_EQP_NO  as CRANE_NO
            FROM TB_CM_CDCLASS3 a, 
                 TB_YF_EQP b
           Where a.type_cd       = 'YM002'
             AND a.class1_cd     = 'EQPNO'
             AND a.class3_cd     = b.YD_EQP_ID
             AND a.class2_cd     = P.YD_GP
             AND a.CLASS3_CD     = P.YD_STK_COL_GP) AS SADDLE_NAME 
       , DECODE(YD_STK_LYR_ACTIVE_STAT,'C','N','O','Y') AS EQUIP_STAT
       , SUBSTR((SELECT YD_STK_COL_USAGE_CD FROM TB_YF_STKCOL A
                  WHERE A.YD_STK_COL_GP=B.YD_EQP_ID),1,1) AS YD_STK_COL_USAGE_CD      
FROM TB_YF_EQP  B 
   , TB_YF_STKLYR AA
   , PARAM P
WHERE B.YD_EQP_ID = AA.YD_STK_COL_GP
  AND (AA.YD_STK_COL_GP LIKE P.YD_GP ||'_SL%' OR AA.YD_STK_COL_GP LIKE P.YD_GP ||'_SR%' )
 </pre> */
public final static String selectSkidIniInfoREAll = "bak.yf.common.dao.selectSkidIniInfoREAll";

 /** <pre> 
--com.inisteel.cim.yf.dao.yfcarschdao.YfCarschDao.getYdCarschInfo
WITH PARAM AS (
    SELECT :V_CAR_NO AS CAR_NO
      FROM DUAL
)

SELECT A.YD_CAR_SCH_ID
      ,A.CAR_NO
      ,A.TRN_EQP_CD
      ,A.YD_CAR_PROG_STAT
      ,(SELECT CD_MNNG
          FROM VW_CM_CODES
         WHERE CD_EN_ID = 'YD_CAR_PROG_STAT'
           AND CD_CAT_ID = 'HS0000'
           AND CD_VAL = YD_CAR_PROG_STAT
        ) AS YD_CAR_PROG_STAT_NM
      ,B.YD_STK_BED_NO      
      ,B.YD_STK_LYR_NO
      ,B.YD_CAR_UPP_LOC_CD
      ,C.SLAB_NO
      ,C.SLAB_T
      ,C.SLAB_W
      ,C.SLAB_LEN
      ,C.SLAB_WT
      ,SUM(C.SLAB_WT) OVER() AS TOTAL_WT
  FROM TB_YD_CARSCH A
      ,TB_YD_CARFTMVMTL B
      ,VW_YD_SLABCOMM C
      ,PARAM P
 WHERE A.DEL_YN='N'
   AND B.DEL_YN='N'
   AND (A.CAR_NO = P.CAR_NO OR A.TRN_EQP_CD = P.CAR_NO )
   AND A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
   AND B.STL_NO = C.SLAB_NO
 ORDER BY A.YD_CAR_SCH_ID,YD_STK_BED_NO,YD_STK_LYR_NO DESC
 </pre> */
