 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAcoilEqpIdMaintHistInqjlExcel 
SELECT 
         ROWNUM AS RNUM
        ,BASE_DATA_ALL.*
    FROM 
        ( 
            SELECT
                A.YD_EQP_ID,    
                A.YD_EQP_PAUSE_OCCR_SEQ, --ШоСі ЙпЛ§МјМ­
                B.YD_EQP_NAME,
                TO_CHAR(A.YD_EQP_PAUSE_OCC_DT,'YYYY.MM.DD HH24:MI:SS') AS YD_EQP_PAUSE_OCC_DT, --ШоСі ЙпЛ§РЯНУ
                TO_CHAR(A.YD_EQP_PAUSE_END_DT,'YYYY.MM.DD HH24:MI:SS') AS YD_EQP_PAUSE_END_DT, --ШоСі СОЗсРЯНУ
                CASE A.YD_EQP_PAUSE_CODE
                       WHEN '0001' THEN 'АцЙЬЧбРлОїКвАЁ'
                       WHEN '0002' THEN 'ФЁИэРћРлОїКвАЁ'
                       WHEN '0003'THEN 'СЄБтШоСі'
                        ELSE 'СЄЛѓЛѓХТ' --END
                     END AS YD_EQP_PAUSE_CODE,
                DECODE(B.YD_EQP_STAT,'O','СЄЛѓ','АэРх') AS YD_EQP_STAT,
                A.REGISTER,
                A.YD_EQP_PAUSE_RCVR_CNTS--, --ШоСіКЙБИГЛПы
             FROM TB_YF_EQPPAUSE A, TB_YF_EQP B
            WHERE A.YD_EQP_ID LIKE :V_YD_GP||'%'
              AND A.YD_EQP_ID = B.YD_EQP_ID
              AND B.YD_EQP_ID LIKE '%'||:V_YD_EQP_ID||'%' -- МГКёСОЗљФкЕх(CR)
              AND A.YD_EQP_PAUSE_OCC_DT BETWEEN TO_DATE(TO_CHAR(:V_DATE_FROM)||'000000', 'YYYYMMDDHH24MISS') 
                                            AND TO_DATE(TO_CHAR(:V_DATE_TO)||'235959', 'YYYYMMDDHH24MISS') --ОпЕхМГКёШоСіЙпЛ§РЯНУ
            ORDER BY YD_EQP_PAUSE_OCC_DT DESC
          ) BASE_DATA_ALL
 </pre> */
public final static String getAcoilEqpIdMaintHistInqjlExcel = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAcoilEqpIdMaintHistInqjlExcel";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookDelChk
SELECT
    (
        SELECT
            A.YD_CRN_SCH_ID
        FROM
            TB_YF_CRNSCH A,
            TB_YF_CRNWRKMTL B
        WHERE 1=1
        AND A.YD_CRN_SCH_ID = B.YD_CRN_SCH_ID
        AND B.STL_NO    = :V_STL_NO
        AND A.DEL_YN    = 'N'
        AND B.DEL_YN    = 'N'
        AND A.YD_WRK_PROG_STAT IN ('W', 'S')
        AND A.YD_SCH_CD LIKE '%PT%'
        AND ROWNUM = 1
    ) AS YD_CRN_SCH_ID,
    (
        SELECT --+INDEX(B1 PK_YM_WRKBOOKMTL)
            A1.YD_WBOOK_ID
        FROM
            TB_YF_WRKBOOK A1,
            TB_YF_WRKBOOKMTL B1
        WHERE 1=1
        AND A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
        AND B1.STL_NO   = :V_STL_NO
        AND A1.DEL_YN   = 'N'
        AND B1.DEL_YN   = 'N'
        AND A1.YD_SCH_CD LIKE '%PT%'
        AND ROWNUM = 1
    ) AS YD_WBOOK_ID
FROM
    DUAL
 </pre> */
public final static String getYdWrkbookDelChk = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYdWrkbookDelChk";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCrnReschWoEqp
--ХЉЗЙРЮИЎНКФЩСй РлОїСіНУМГКё СЖШИ 
SELECT EQ.YD_EQP_ID
  FROM TB_YF_EQP EQ
      ,(SELECT DISTINCT DECODE(DD.BR_GP,'B',SR.YD_ALT_CRN,SR.YD_WRK_CRN) AS YD_EQP_ID
          FROM TB_YF_SCHRULE SR
              ,(SELECT :V_YD_EQP_ID AS YD_EQP_ID
                      ,:V_BR_GP     AS BR_GP --АэРхКЙБИБИКа
                  FROM DUAL) DD
         WHERE SR.YD_GP      = SUBSTR(DD.YD_EQP_ID,1,1)
           AND SR.YD_BAY_GP  = SUBSTR(DD.YD_EQP_ID,2,1)
           AND SR.YD_WRK_CRN = DD.YD_EQP_ID
           AND SR.DEL_YN     = 'N') SR
 WHERE EQ.YD_EQP_ID       = SR.YD_EQP_ID
   AND EQ.DEL_YN         = 'N'
   AND EQ.YD_EQP_PROG_STAT     = 'W'
--   AND EQ.YD_EQP_WRK_MODE = '1'
 </pre> */
public final static String getCrnReschWoEqp = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCrnReschWoEqp";

