 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getProcedureList 
SELECT 
    A.OWNER 
    , A.OBJECT_NAME
    , A.PROCEDURE_NAME
    , B.STATUS
    , TO_CHAR( B.LAST_DDL_TIME, 'YYYY-MM-DD HH24:MI:SS') AS LAST_DDL_TIME
FROM ALL_PROCEDURES A, ALL_OBJECTS B
WHERE A.OWNER IN ('USRYMA', 'USEYDA', 'USRYFA')
AND A.OBJECT_TYPE = 'PROCEDURE'
AND A.OBJECT_NAME = B.OBJECT_NAME
AND A.OWNER = B.OWNER
AND A.OWNER = :V_OWNER
 </pre> */
