 /** <pre> 
--yf.facilitystatus.facilityinquiry.CraneSchDAO.getYMDM001Info
WITH PARAM AS
(
    SELECT :V_STL_NO AS STL_NO FROM DUAL
)
SELECT
    A.YD_STK_COL_GP || A.YD_STK_BED_NO || A.YD_STK_LYR_NO AS PUT_POSITION,
    D.CURR_PROG_CD
FROM
    TB_YF_STKLYR A,
    TB_YF_STKCOL B,
    TB_YF_STOCK C,
    TB_PT_COILCOMM D
WHERE 1=1
AND A.STL_NO        = (SELECT STL_NO FROM PARAM)
AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
AND A.STL_NO        = C.STL_NO
AND A.STL_NO        = D.COIL_NO
AND D.CURR_PROG_CD  IN('2','H') --А­АќСјЕЕЦїЧд
AND B.SECT_GP BETWEEN '00' AND '99'

UNION

SELECT
    YD_STR_LOC AS PUT_POSITION ,
    CURR_PROG_CD
FROM
    TB_PT_COILCOMM D
WHERE 1=1
AND COIL_NO LIKE 'R%' AND D.CURR_PROG_CD = '3' ----БИРдФкРЯ
AND COIL_NO = (SELECT STL_NO FROM PARAM)

UNION

SELECT
    A.YD_STK_COL_GP || A.YD_STK_BED_NO || A.YD_STK_LYR_NO AS PUT_POSITION,
    D.CURR_PROG_CD
FROM
    TB_YF_STKLYR A,
    TB_YF_STKCOL B,
    TB_YF_STOCK C,
    TB_PT_COILCOMM D
WHERE 1=1
AND A.STL_NO    	        = :V_STL_NO
AND A.YD_STK_LYR_STAT       = 'L'
AND A.YD_STK_COL_GP 	    = B.YD_STK_COL_GP
AND A.STL_NO                = C.STL_NO
AND A.STL_NO                = D.COIL_NO
AND B.YD_STK_COL_USAGE_CD   = 'CX' -- ДыТї
AND C.STOCK_MOVE_TERM       = 'L1' -- ДыТїУтЧЯПЯЗс
 </pre> */
public final static String getYMDM001Info = "bak.yf.facilitystatus.facilityinquiry.CraneSchDAO.getYMDM001Info";

