 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAdvSchRuleList 
-- АэЕЕШ­ХЉЗЙРЮНКФЩСйБтСиСЖШИ 
SELECT X.*
  FROM(SELECT ROWNUM AS RNUM
            , A.*
         FROM(SELECT COUNT(*) OVER() AS TOTALCOUNT
                   , YD_SCH_CD
                   , TERM1
                   , TERM2
                   , TERM3
                   , TERM4
                   , TERM5
                   , REGISTER
                   , REG_DDTT
                   , MODIFIER
                   , MOD_DDTT
                   , DEL_YN
                   , YD_GP
                   , YD_BAY_GP
                   , YD_WRK_CRN_PRIOR
                   , CD_CONTENTS
                   , TERM_CONTENTS
                FROM TB_YF_ADV_SCHRULE
               WHERE YD_GP     LIKE '%' || :V_YD_GP || '%'
                 AND YD_BAY_GP LIKE '%' || :V_YD_BAY_GP || '%'
               ORDER BY YD_BAY_GP, YD_SCH_CD, SORT_SEQ
             ) A
        WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE) X
 WHERE RNUM >= ((:V_PAGE_NO-1)* :V_PAGE_SIZE)+1
 </pre> */
public final static String getAdvSchRuleList = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getAdvSchRuleList";

 /** <pre> 
--yf.facilitystatus.facilityinquiry.YfCommonDAO.getBlankBed
WITH PARAM AS (
SELECT :V_YD_STK_COL_GP AS YD_STK_COL_GP
  FROM DUAL
)

SELECT DISTINCT 
       A.YD_STK_BED_NO
  FROM TB_YF_STKLYR A
      ,PARAM P
 WHERE A.YD_STK_COL_GP  	= NVL(P.YD_STK_COL_GP,A.YD_STK_COL_GP)
   AND A.YD_STK_LYR_NO   <= 15
   AND A.YD_STK_LYR_ACTIVE_STAT = 'O'
   AND A.STL_NO IS NULL
   AND A.DEL_YN = 'N'
 ORDER BY A.YD_STK_BED_NO
 </pre> */
public final static String getBlankBed = "bak.yf.facilitystatus.facilityinquiry.YfCommonDAO.getBlankBed";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCoilTotYdNextproctList2 
SELECT CHK2 , A.NEXT_PROC  ,GP
    , round(NVL(TODAYN,0)) AS TODAYN
    , round(NVL(TODAY6,0)) AS TODAY6
    , round(NVL(TODAY5,0)) AS TODAY5
    , round(NVL(TODAY4,0)) AS TODAY4
    , round(NVL(TODAY3,0)) AS TODAY3
    , round(NVL(TODAY2,0)) AS TODAY2
    , round(NVL(TODAY1,0)) AS TODAY1
    , round(NVL(TODAY,0)) AS TODAY
    , round(NVL(SUM_TODAY,0)) AS SUM_TODAY
 FROM (
     SELECT 'СЄСЄМвРч' AS GP 
            , DECODE(SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),2,1),'K','SPM','R','SPM','H','HFL') AS CHK
            , DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)) as NEXT_PROC
            , SUM(CASE WHEN MILL_INI_DATE<=TO_CHAR(SYSDATE-7,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAYN
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-6,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY6
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-5,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY5
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-4,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY4
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-3,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY3
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-2,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY2
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-1,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY1
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY
            , SUM(COIL_WT)/1000 AS SUM_TODAY
       FROM TB_YM_STACKLAYER A, TB_YM_STOCK B, TB_PT_COILCOMM C
      WHERE A.STACK_COL_GP LIKE '3%'  --ОпЕхБИКа(1)
        AND A.STACK_LAYER_STAT IN ('L', 'S', 'U', 'C')
        AND C.CURR_PROG_CD IN ('1','A','B','C','D','E','F','G','H','Y')
        AND A.STOCK_ID = B.STOCK_ID(+)
        AND A.STOCK_ID = C.COIL_NO(+)
        AND A.DEL_YN != 'Y'
        AND C.RECORD_PROG_STAT != 3
        AND ((SUBSTR(A.STACK_COL_GP,3,2) BETWEEN '01' AND '99') OR (SUBSTR(A.STACK_COL_GP,3,2) = 'WT'))
        AND substr(DECODE(NVL(NEXT_DEMAND_PROC||NEXT_PROC,''),'',PLAN_PROC1,NEXT_DEMAND_PROC||NEXT_PROC),1,1) in ('5','6')
        GROUP BY DECODE(SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),2,1),'K','SPM','R','SPM','H','HFL')  
             , DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC))
    UNION ALL
    SELECT 'СЄСЄМвРч' AS GP 
            , DECODE(SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),2,1),'K','SPM','R','SPM','H','HFL','Q','EQL') AS CHK
            , DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)) as NEXT_PROC
            , SUM(CASE WHEN MILL_INI_DATE<=TO_CHAR(SYSDATE-7,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAYN
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-6,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY6
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-5,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY5
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-4,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY4
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-3,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY3
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-2,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY2
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-1,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY1
            , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY
            , SUM(COIL_WT)/1000 AS SUM_TODAY
     FROM TB_YF_STKLYR A, TB_YF_STOCK B, TB_PT_COILCOMM C
      WHERE A.YD_STK_COL_GP LIKE '1%'  --ОпЕхБИКа(1)
        AND A.YD_STK_LYR_STAT IN('L', 'S', 'U', 'C')
        AND C.CURR_PROG_CD IN ('1','A','B','C','D','E','F','G','H','Y')
        AND A.STL_NO = B.STL_NO(+)
        AND A.STL_NO = C.COIL_NO(+)
        AND A.DEL_YN != 'Y'
        AND C.RECORD_PROG_STAT != 3
        AND ((SUBSTR(A.YD_STK_COL_GP,3,2) BETWEEN '01' AND '99') OR (SUBSTR(A.YD_STK_COL_GP,3,2) = 'WT'))
        AND DECODE(NVL(NEXT_DEMAND_PROC||NEXT_PROC,''),'',PLAN_PROC1,NEXT_DEMAND_PROC||NEXT_PROC) LIKE '1%' 
        GROUP BY DECODE(SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),2,1),'K','SPM','R','SPM','H','HFL','Q','EQL')  
             , DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC))
    UNION ALL
    SELECT 'СЄСЄМвРч' AS GP 
        , DECODE(SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),2,1),'K','SPM','R','SPM','H','HFL') AS CHK
        , DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)) as NEXT_PROC
        , SUM(CASE WHEN MILL_INI_DATE<=TO_CHAR(SYSDATE-7,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAYN
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-6,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY6
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-5,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY5
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-4,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY4
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-3,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY3
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-2,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY2
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-1,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY1
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY
        , SUM(COIL_WT)/1000 AS SUM_TODAY
     FROM USRYDA.TB_YD_STKLYR A , USRPTA.TB_PT_COILCOMM C
    WHERE A.STL_NO=C.COIL_NO
     AND A.YD_STK_COL_GP LIKE 'H%'
     AND A.YD_STK_LYR_MTL_STAT IN ('C','U')
     AND C.RECORD_PROG_STAT IN('1','2') 
     AND SUBSTR(A.YD_STK_COL_GP,3,2) BETWEEN '00' AND '99'
     AND C.CURR_PROG_CD IN ('1','A','B','C','D','E','F','G','H','Y')
     AND (YD_GP='H' AND SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),1,1) IN('A','B','C','D','E','F','G','H'))
          
     GROUP BY DECODE(SUBSTR(DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC)),2,1),'K','SPM','R','SPM','H','HFL')  
             , DECODE(NVL(NVL(NEXT_DEMAND_PROC,NEXT_PROC),''),'',PLAN_PROC1,NVL(NEXT_DEMAND_PROC,NEXT_PROC))
     UNION ALL
     SELECT 'РЬМлЙоРЛЗЎ' AS GP , DECODE(SUBSTR(NEXT_PROC,2,1),'K','SPM','R','SPM','H','HFL','Q','EQL') AS CHK
        , NEXT_PROC
        , SUM(CASE WHEN MILL_INI_DATE<=TO_CHAR(SYSDATE-7,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAYN
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-6,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY6
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-5,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY5
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-4,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY4
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-3,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY3
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-2,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY2
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE-1,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY1
        , SUM(CASE WHEN MILL_INI_DATE=TO_CHAR(SYSDATE,'YYYYMMDD') THEN COIL_WT ELSE 0 END)/1000 AS TODAY
        , SUM(COIL_WT)/1000 AS SUM_TODAY
     FROM USRPTA.TB_PT_COILCOMM A
        , USRPTA.TB_PT_STLFRTOMOVE B
    WHERE A.COIL_NO=B.STL_NO
      AND A.RECORD_PROG_STAT IN('1','2')
      AND A.YD_GP IN('H','1','3')
      AND A.NEXT_PROC IS NOT NULL
      AND A.YD_EQP_GP BETWEEN '00' AND '99'
      AND B.TRANSWORD_SEQNO=(SELECT MAX(TRANSWORD_SEQNO) FROM TB_PT_STLFRTOMOVE C
                            WHERE C.STL_NO=B.STL_NO
                            )
     AND B.FRTOMOVE_STAT_CD||'' IN('1','3')
     AND B.ARR_WLOC_CD IN ('DJY21','DJY22', 'D3Y41', 'D3Y42')
     AND ((A.YD_GP='H' AND SUBSTR(NEXT_PROC,1,1) IN('A','B','C','D','E','F','G','H'))
          OR
          (A.YD_GP='1' AND SUBSTR(NEXT_PROC,1,1) ='1')
          OR
          (A.YD_GP='3' AND SUBSTR(NEXT_PROC,1,1) IN('5','6'))
         )
     GROUP BY DECODE(SUBSTR(A.NEXT_PROC,2,1),'K','SPM','R','SPM','H','HFL','Q','EQL')  , A.NEXT_PROC
     ) A
     ,(SELECT *
       FROM (SELECT 'SPM' AS CHK2 FROM DUAL UNION ALL
             SELECT 'HFL' AS CHK2 FROM DUAL UNION ALL
             SELECT 'EQL' AS CHK2 FROM DUAL
         
         )E
       ) B
WHERE B.CHK2 =A.CHK(+)
 ORDER BY CHK2 DESC, NEXT_PROC ,GP DESC
 </pre> */
public final static String getCoilTotYdNextproctList2 = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCoilTotYdNextproctList2";

