 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdTcarWbookid
SELECT YD_WBOOK_ID FROM
    (
    SELECT CASE WHEN A.YD_WBOOK_ID = D.YD_WBOOK_ID THEN '1'
                ELSE '2' END AS SEQ
         , A.YD_WBOOK_ID
         , A.YD_WRK_PLAN_TCAR
         , C.YD_STK_LYR_NO
         , A.YD_SCH_CD
      FROM TB_YF_WRKBOOK A
         , TB_YF_WRKBOOKMTL B   
         , TB_YF_STKLYR C
         , (SELECT * FROM TB_YF_WRKBOOK
             WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID) D
     WHERE A.YD_WBOOK_ID   = B.YD_WBOOK_ID  
       AND B.STL_NO      = C.STL_NO  
       AND A.YD_SCH_CD     = D.YD_SCH_CD  
       AND A.YD_AIM_BAY_GP = D.YD_AIM_BAY_GP
       AND C.YD_STK_LYR_STAT = 'C' 
       AND A.DEL_YN = 'N'
       AND B.DEL_YN = 'N'
     ORDER BY CASE WHEN A.YD_WBOOK_ID = D.YD_WBOOK_ID THEN '1'
                ELSE '2' END 
         , C.YD_STK_LYR_NO DESC
         , YD_WBOOK_ID   
    ) A
 WHERE ROWNUM <= ((SELECT STK_MAX_QNTY FROM TB_YF_EQP WHERE YD_EQP_ID = A.YD_WRK_PLAN_TCAR ) 
                   -
                  (SELECT COUNT(*) 
                     FROM TB_YF_CRNSCH 
                    WHERE YD_SCH_CD = A.YD_SCH_CD
                      AND DEL_YN = 'N')  --ЧіРчБтЕПЕШ SCH АЙМі
                  )  
 </pre> */
public final static String getYdTcarWbookid = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdTcarWbookid";

