 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarPntFrmYnToUp
SELECT
    AA.*,
    (
        SELECT
            NVL(YD_FRM_YN,'N')
        FROM
            USRYDA.TB_YD_CARPOINT
        WHERE 1=1
        AND YD_STK_COL_GP = AA.YD_STK_COL_GP
    ) AS YD_FRM_YN
FROM
    (
        SELECT
            A.YD_WBOOK_ID,
            CTS_RELAY_SADDLE AS PT_LOC,
            (
                SELECT
                    YD_STK_COL_GP
                FROM
                    USRYDA.TB_YD_CARPOINT
                WHERE 1=1
                AND YD_CAR_USETYPE_GP = 'MT'
                AND YD_GP     = SUBSTR(A.YD_SCH_CD, 1, 1)
                AND YD_BAY_GP = SUBSTR(A.YD_SCH_CD, 2, 1)
                AND CASE
                    WHEN SUBSTR(YD_STK_COL_GP, 6, 1) IN ('1', '2') THEN 'L'
                    ELSE 'R' END
                    =
                    CASE
                    WHEN C.CTS_RELAY_SADDLE IN ('3', '4') THEN 'R'
                    WHEN C.CTS_RELAY_SADDLE IN ('1', '2') THEN 'L'
                    END
                AND CAR_NO IS NULL
                AND ROWNUM = 1
            ) AS YD_STK_COL_GP
        FROM
            TB_YF_WRKBOOK A,
            TB_YF_WRKBOOKMTL B,
            TB_YF_STOCK C
        WHERE 1=1
        AND A.YD_WBOOK_ID = B.YD_WBOOK_ID
        AND B.STL_NO = C.STL_NO
        AND A.DEL_YN = 'N'
        AND B.DEL_YN = 'N'
        AND A.CARD_NO = :V_CARD_NO
        AND SUBSTR(A.YD_SCH_CD, 7, 1) = 'U'  --ЛѓТї
        ORDER BY A.YD_WBOOK_ID
    ) AA
 </pre> */
public final static String getCarPntFrmYnToUp = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getCarPntFrmYnToUp";

