 /** <pre> 
-- com.inisteel.cim.yf.aslab.dao.ASlabDAO.getaslabYdNEqpXyaxisSet 
SELECT X.YD_STK_COL_GP           -- РћФЁП­БИКа
      ,X.COL_GP          -- РћФЁП­ЙјШЃ
      ,X.YD_STK_COL_ACTIVE_STAT    -- РћФЁП­ШАМКЛѓХТ
      ,decode(X.YD_STK_COL_ACTIVE_STAT,'C','КёШАМКШ­'
                                   ,'L','РћФЁ АЁДЩ'
                                   ,'N','ЛчПы КвАЁ')
                                   AS YD_STK_COL_ACTIVE_STATHIDDEN        -- РћФЁП­ШАМКЛѓХТ
      ,X.YD_STK_COL_USAGE_CD
      ,A.DTL_ITEM2 AS CLASS2_NAME1
      ,A.ITEM AS CLASS2_CD
      ,Y.SUM_LYR_CNT AS SUM_LYR_CNT_TOT        -- УжДыРћФЁАЁДЩКЛМі
      ,Y.SUM_STL_CNT_TOT        -- ЧіРћФЁКЛМі
      ,X.YD_STK_COL_RULE_X_AXIS 
      ,X.YD_STK_COL_RULE_Y_AXIS 
      ,X.YD_STK_COL_RULE_Z_AXIS
      ,X.YD_STK_COL_RULE_X_AXIS AS YD_STK_COL_RULE_X_AXIS_HIDDEN
      ,X.YD_STK_COL_RULE_Y_AXIS AS YD_STK_COL_RULE_Y_AXIS_HIDDEN
      ,X.YD_STK_COL_RULE_Z_AXIS AS YD_STK_COL_RULE_Z_AXIS_HIDDEN
      ,(CASE WHEN X.MOD_DDTT > Z.MOD_DDTT THEN X.MODIFIER
        ELSE Z.MODIFIER END) AS MODIFIER
      ,TO_CHAR((CASE WHEN X.MOD_DDTT > Z.MOD_DDTT THEN X.MOD_DDTT
        ELSE Z.MOD_DDTT END), 'YYYY-MM-DD HH24:MI') AS MOD_DDTT
      ,RULE.DTL_ITEM1 AS RULE_L
      ,RULE.DTL_ITEM2 AS RULE_W
  FROM (SELECT YD_STK_COL_GP
              ,COL_GP
              ,YD_STK_COL_ACTIVE_STAT
              ,YD_STK_COL_USAGE_CD
              ,YD_STK_COL_RULE_X_AXIS 
              ,YD_STK_COL_RULE_Y_AXIS
              ,YD_STK_COL_RULE_Z_AXIS
              ,MODIFIER
              ,MOD_DDTT
          FROM TB_YF_STKCOL
         WHERE YD_GP = :V_YD_GP
           AND BAY_GP  LIKE :V_BAY_GP  || '%'
           AND SECT_GP LIKE :V_SECT_GP || '%'
           AND COL_GP  LIKE :V_COL_GP  ||'%'
           AND DEL_YN = 'N'
           AND SECT_GP NOT IN ('CR','TR','TT','XX')
         ORDER BY COL_GP ) X
      ,(SELECT YD_STK_COL_GP
              ,SUM(CASE WHEN YD_STK_LYR_STAT = 'E' THEN 1 ELSE 0 END) AS SUM_LYR_CNT -- 1ДмРћФЁАЁДЩКЛМі
              --,SUM(CASE WHEN YD_STK_LYR_NO = '02' AND YD_STK_LYR_STAT = 'E' THEN 1 ELSE 0 END) AS SUM_LYR_CNT_L2 -- 2ДмРћФЁАЁДЩКЛМі
              ,SUM(DECODE(STL_NO, NULL, 0, 1)) AS SUM_STL_CNT_TOT -- ЧіРћФЁКЛМі 
          FROM TB_YF_STKLYR
         WHERE YD_STK_COL_GP LIKE :V_YD_GP || NVL(:V_BAY_GP,'_') || NVL(:V_SECT_GP,'__') || NVL(:V_COL_GP,'') || '%'
           AND DEL_YN = 'N'
         GROUP BY YD_STK_COL_GP ) Y
      ,(SELECT * 
          FROM TB_YF_STKBED
         WHERE YD_STK_BED_NO = '01') Z
       ,(SELECT * 
           FROM TB_YF_RULE
          WHERE REPR_CD_GP = 'YM103'
            AND CD_GP ='0') A 
      ,(SELECT *
          FROM TB_YF_RULE
         WHERE REPR_CD_GP = 'X_AXIS'
           AND CD_GP = '0'
           AND ITEM = '1') RULE
       
 WHERE X.YD_STK_COL_GP = Y.YD_STK_COL_GP
   AND X.YD_STK_COL_GP = Z.YD_STK_COL_GP(+)
   AND X.YD_STK_COL_USAGE_CD = A.ITEM 
 ORDER BY X.YD_STK_COL_GP
 </pre> */
public final static String getaslabYdNEqpXyaxisSet = "bak.com.inisteel.cim.yf.aslab.dao.ASlabDAO.getaslabYdNEqpXyaxisSet";

 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdEqpTcByBay
--ЕПКАДыТїМГКёIDСЖШИ
WITH PARAM AS 
(
    SELECT 
        :V_YD_GP  AS P_YD_GP,
        :V_YD_BAY_GP AS P_BAY_GP,
        :V_TO_BAY_GP AS P_TO_BAY_GP
    FROM
        DUAL
)
SELECT
      E.YD_EQP_ID   AS CD_VAL
    , E.YD_EQP_NAME AS CD_NM
    , E.YD_BAY_GP
FROM
      TB_YF_EQP E
    , PARAM P
WHERE 1=1
AND E.YD_GP   = P.P_YD_GP 
AND E.YD_EQP_GP = 'TC'
AND E.DEL_YN     = 'N'
AND 
(
    ( NVL(P.P_BAY_GP, 'X') = E.YD_BAY_GP AND E.YD_EQP_NO IN ('03'))
    OR
    (P.P_BAY_GP = 'A' AND E.YD_EQP_NO IN ('03'))
    OR
    (P.P_BAY_GP = 'B' AND E.YD_EQP_NO IN ('03')) )
AND
(
    ( NVL(P.P_TO_BAY_GP, 'X') = E.YD_BAY_GP AND E.YD_EQP_NO IN ('03'))
    OR
    (P.P_TO_BAY_GP = 'A' AND E.YD_EQP_NO IN ('03'))
    OR
    (P.P_TO_BAY_GP = 'B' AND E.YD_EQP_NO IN ('03')) )
 </pre> */
public final static String getCodeYdEqpTcByBay = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getCodeYdEqpTcByBay";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockInfoChk 
-- ЛъРћРЇФЁ РњРхЧА СЄКИ СЖШИ 
WITH PARAM AS (
SELECT :V_STL_NO   AS P_STL_NO 
     , :V_YD_STR_LOC AS P_YD_STR_LOC
  FROM DUAL
)
SELECT NVL(MAX(MODIFY_YN) OVER(), 'N00') AS MODIFY_YN
     , STL_NO
     , YD_GP
     , (SELECT CD_MNNG
          FROM BRE.VW_CM_CODES 
         WHERE CD_EN_ID = 'YD_GP'
           AND CD_CAT_ID = 'HS0000'
           AND CD_VAL = YD_GP) AS YD_GP_NM
  FROM (
        SELECT CASE WHEN YD_WRKBOOK_YN2 ='Y' OR YD_WRKBOOK_YN3 ='Y' THEN 'N05'
                    WHEN CASE WHEN IS_YF IS NOT NULL THEN IS_YF WHEN IS_YM IS NOT NULL THEN IS_YM WHEN IS_YD IS NOT NULL THEN IS_YD END != '1' THEN 'N10'  --ХИ ОпЕхПЉКЮ
                    WHEN CHK_02 = 'N'        THEN 'N15'  --ЧЯДм ФкРЯ ХЉЗЙРЮНКФЩСй СИРчПЉКЮ
                    WHEN YD_CRN_SCH_YN = 'Y' THEN 'N20'  --ХЉЗЙРЮНКФЩСй СИРчПЉКЮ
                    WHEN YD_CARSCH_YN  = 'Y' THEN 'N30'  --ТїЗЎНКФЩСй СИРчПЉКЮ
                    WHEN YD_TCARSCH_YN = 'Y' THEN 'N40'  --ДыТїНКФЩСй СИРчПЉКЮ                   
                    WHEN YD_STK_LYR_ACTIVE_STAT IN ('N','X') THEN 'N50' --РћФЁДмШАМКЛѓХТ ЛчПыБнСі
                    WHEN YD_STK_LYR_STAT IN ('U') THEN 'N60' --TOРЇФЁ БЧЛѓПЙОр РњРхЧА СИРч
                    WHEN SECT_GP = 'TC' AND STL_NO IS NOT NULL THEN 'N70' -- ДыТїРЯАцПь ЧиДч ДыТїРЇПЁ РњРхЧАРЬ РжРИИщ ОШЕЪ 
                    
                    
                    WHEN YD_WRKBOOK_YN   = 'Y' THEN 'Y10'  --РлОїПЙОр СИРчПЉКЮ
                    WHEN TO_LOC_STOCK_YN = 'Y' AND YD_STK_LYR_STAT IN('C') THEN 'Y20'  --TOРЇФЁ РњРхЧА СИРчПЉКЮ(РћФЁ)
                    WHEN YD_STOCK_YN     = 'N' THEN 'Y30'  --ЧиДч РњРхЧА СИРчПЉКЮ
                    WHEN YD_STK_LYR_ACTIVE_STAT IN ('C')      THEN 'Y40' -- CLOSEКёШАМКШ­
                    WHEN YD_STK_LYR_STAT        IN ('X', 'V') THEN 'Y50' --РћФЁКвАЁ
                    WHEN YD_STK_LYR_STAT        IN ('D')      THEN 'Y60' --TOРЇФЁ БЧЧЯПЙОр РњРхЧА СИРч
                    WHEN YD_CTS_YN = 'Y' THEN 'Y70'  --CTSДыТїНКФЩСй СИРчПЉКЮ
                    WHEN YD_CTS_YN = 'N' AND FROM_YD_STK_COL_GP IN ( '1XTC01', '1XTC02') THEN 'Y80'  --CTSНКФЩСьРК ОјДТЕЅ CTSДыТїРЇПЁ СИРч ЧпРЛ АцПь
                    ELSE 'Y00'
               END AS MODIFY_YN
             , STL_NO
             , CASE WHEN IS_YF IS NOT NULL THEN IS_YF WHEN IS_YM IS NOT NULL THEN IS_YM WHEN IS_YD IS NOT NULL THEN IS_YD END AS YD_GP                
          FROM (
                SELECT (SELECT SUBSTR(YD_STK_COL_GP , 1, 1) FROM TB_YF_STKLYR WHERE STL_NO = P_STL_NO AND ROWNUM <= 1) AS IS_YF
                     , (SELECT SUBSTR(STACK_COL_GP , 1, 1) FROM TB_YM_STACKLAYER WHERE STOCK_ID = P_STL_NO AND ROWNUM <= 1) AS IS_YM
                     , (SELECT SUBSTR(YD_STK_COL_GP, 1, 1) FROM TB_YD_STKLYR  WHERE STL_NO   = P_STL_NO AND ROWNUM <= 1) AS IS_YD
                     , DECODE((SELECT COUNT(*) AS YD_CRN_SCH_ID_CNT
                                 FROM TB_YF_CRNSCH    B1
                                    , TB_YF_CRNWRKMTL C1
                                WHERE B1.YD_CRN_SCH_ID = C1.YD_CRN_SCH_ID
                                  AND C1.STL_NO      = A.STL_NO
                                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_CRN_SCH_YN --ХЉЗЙРЮНКФЩСй СИРчРЏЙЋ
                     , DECODE((SELECT COUNT(*) AS WRKBOOK_CNT
                                 FROM TB_YF_WRKBOOK    B1
                                    , TB_YF_WRKBOOKMTL C1
                                WHERE B1.YD_WBOOK_ID = C1.YD_WBOOK_ID
                                  AND C1.STL_NO = A.STL_NO
                                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_WRKBOOK_YN --РлОїПЙОр СИРчРЏЙЋ
                     , DECODE((SELECT COUNT(*) AS WRKBOOK_CNT
                                 FROM TB_YD_WRKBOOK    B1
                                    , TB_YD_WRKBOOKMTL C1
                                WHERE B1.YD_WBOOK_ID = C1.YD_WBOOK_ID
                                  AND C1.STL_NO = A.STL_NO
                                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_WRKBOOK_YN2    
                     , DECODE((SELECT YD_STK_LYR_STAT
                                 FROM TB_YF_STKLYR 
                                WHERE STL_NO = A.STL_NO
                                  AND ROWNUM = 1), 'S', 'Y', 'N') AS YD_WRKBOOK_YN3                                  
                     , DECODE((SELECT COUNT(*) AS CARSCH_CNT
                                 FROM TB_YF_WRKBOOKMTL A1
                                      , TB_YF_WRKBOOK B1
                                      , TB_YD_CARSCH C1 
                                WHERE A1.STL_NO = A.STL_NO
                                AND A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
                                AND (B1.TRN_EQP_CD = C1.TRN_EQP_CD OR B1.CAR_NO = C1.CAR_NO)
                                AND A1.DEL_YN = 'N'
                                AND B1.DEL_YN = 'N'
                                AND C1.DEL_YN = 'N'
                                ),0,'N','Y') AS YD_CARSCH_YN
                     , DECODE((SELECT COUNT(*) AS CARSCH_CNT
                                 FROM TB_TS_MATL_FTMV_WO B1
                                WHERE B1.STL_NO = A.STL_NO 
                                AND B1.TS_MATL_FTMV_STAT_GP = '1' --БИГЛПюМлМвРчРЬМлЛѓХТБИКа 1:РЬМлСіНУПЯЗс
                                AND B1.MATL_FTMV_WO_NML_HD_YN IN ('Y','X') --МвРчРЬМлСіНУСЄЛѓУГИЎПЉКЮ Y:СЄЛѓ, X:КёСЄЛѓ(А­СІЕюЗЯ)
                                ),0,'N','Y') AS YD_MVSTOCK_YN
                     , DECODE((SELECT COUNT(*) AS TCARSCH_CNT
                                 FROM TB_YF_TCARSCH     B1
                                    , TB_YF_TCARFTMVMTL C1
                                WHERE B1.YD_TCAR_SCH_ID    = C1.YD_TCAR_SCH_ID
                                  AND C1.STL_NO = A.STL_NO
                                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_TCARSCH_YN
                     , DECODE((SELECT COUNT(*) AS YD_CTS_YN
                                 FROM TB_YF_CTS_SCH     B1 
                                WHERE B1.STL_NO = A.STL_NO
                                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_CTS_YN
                     , CASE WHEN A.DEL_YN = 'N' THEN 'Y' ELSE 'N' END AS YD_STOCK_YN   --РњРхЧА СИРч РЏЙЋ                  
                     , DECODE(SUM(CASE WHEN SL.STL_NO IS NULL THEN 0 ELSE 1 END)OVER(), 0, 'N', 'Y') AS TO_LOC_STOCK_YN --TOРЇФЁ РњРхЧА СИРчПЉКЮ
                     , SL.STL_NO
                     , SL.YD_STK_LYR_ACTIVE_STAT
                     , SL.YD_STK_LYR_STAT
                     , SL.SECT_GP
                     , A.YD_STK_COL_GP AS FROM_YD_STK_COL_GP
                     , CASE WHEN SL.YD_STK_LYR_NO = '01' THEN 'Y'
                            WHEN SL.YD_STK_LYR_NO = '02' 
                             AND (SELECT YD_STK_LYR_STAT 
                                    FROM TB_YF_STKLYR
                                   WHERE YD_STK_COL_GP     = SL.YD_STK_COL_GP
                                     AND YD_STK_BED_NO     = SL.YD_STK_BED_NO
                                     AND YD_STK_LYR_NO   = '01'
                                 ) IN ('C', 'E')
                             AND (SELECT YD_STK_LYR_STAT 
                                    FROM TB_YF_STKLYR
                                   WHERE YD_STK_COL_GP     = SL.YD_STK_COL_GP
                                     AND YD_STK_BED_NO     = LPAD((TO_NUMBER(SL.YD_STK_BED_NO)+1), 2, '0')
                                     AND YD_STK_LYR_NO   = '01'
                                 ) IN ('C', 'E')
                            THEN 'Y'
                            ELSE 'N' END AS CHK_02 --МіСЄРЇФЁАЁ 2ДмРЯ ЖЇ 1Дм ФкРЯ НКФЩСй УМХЉ
                  FROM TB_PT_COILCOMM CC
                     ,(SELECT A.STL_NO
                            , A.STOCK_ITEM
                            , A.STOCK_MOVE_TERM
                            , NVL(SUBSTR(B.YD_STK_COL_GP, 1, 1), '') AS YD_GP
                            , B.YD_STK_COL_GP
                            , A.DEL_YN
                         FROM TB_YF_STOCK       A
                            , TB_YF_STKLYR  B
                            , PARAM 
                        WHERE A.STL_NO = B.STL_NO(+)
                          AND A.STL_NO = P_STL_NO
                          AND B.YD_STK_LYR_STAT IN ('C', 'U', 'L', 'S')
                       
                UNION ALL
                      SELECT A.STL_NO
                            , A.STOCK_ITEM
                            , A.STOCK_MOVE_TERM
                            , NVL(SUBSTR(B.YD_STK_COL_GP, 1, 1), '') AS YD_GP 
                            , B.YD_STK_COL_GP
                            , A.DEL_YN
                         FROM TB_YF_STOCK       A
                            , TB_YD_STKLYR      B
                            , PARAM
                        WHERE A.STL_NO = B.STL_NO(+)
                          AND A.STL_NO = P_STL_NO
                          AND B.YD_STK_LYR_MTL_STAT IN ('C', 'U', 'S', 'L')                          
                      ) A
                     , PARAM
                     , (SELECT STL_NO
                             , YD_STK_LYR_ACTIVE_STAT
                             , YD_STK_LYR_STAT
                             , SUBSTR(YD_STK_COL_GP, 3, 2) AS SECT_GP
                             , YD_STK_COL_GP
                             , YD_STK_BED_NO
                             , YD_STK_LYR_NO
                          FROM TB_YF_STKLYR
                             , PARAM
                         WHERE YD_STK_COL_GP||YD_STK_BED_NO||YD_STK_LYR_NO = P_YD_STR_LOC
                       ) SL
                 WHERE 1 = 1
                   AND CC.COIL_NO = A.STL_NO(+)
                   AND CC.COIL_NO = P_STL_NO
              )
      )
 </pre> */
public final static String getStockInfoChk = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockInfoChk";

