 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfRackInfo 
-- Rack Layer СЄКИ СЖШИ 

SELECT LYR.*
     , 'C' || SUBSTR(LYR.YD_STK_COL_GP,5,2) AS COL_ID
     , 'C' || SUBSTR(LYR.YD_STK_COL_GP,5,2) || 'B' || LYR.YD_STK_BED_NO AS BED_ID
     , 'C' || SUBSTR(LYR.YD_STK_COL_GP,5,2) || 'B' || LYR.YD_STK_BED_NO || 'L' || LYR.YD_STK_LYR_NO AS LAYER_ID
     , CASE WHEN LYR.STOCK_MOVE_TERM = 'A8' OR EXISTS ( SELECT 1 FROM TB_HR_C_SHEARWOWR S WHERE S.COIL_NO = LYR.STL_NO AND S.G_WRAP_CMPL_YN = 'Y') THEN '_J' ELSE '' END AS IS_GF_YN
  FROM(
       SELECT LYR.YD_STK_COL_GP
             ,LYR.YD_STK_BED_NO
             ,LYR.YD_STK_LYR_NO
             ,SUBSTR(LYR.YD_STK_COL_GP,3,2) AS SECT_GP
             ,LYR.STL_NO
             ,LYR.YD_STK_COL_GP||LYR.YD_STK_BED_NO||LYR.YD_STK_LYR_NO AS YD_LOC
             ,(CASE WHEN PT.STL_APPEAR_GP = 'Y'        THEN 'CG' 
                    WHEN LYR.YD_STK_COL_GP LIKE '1ESC%' AND LYR.STL_NO IS NOT NULL THEN 'SCRAP'
                    WHEN LYR.YD_STK_COL_GP LIKE '1ESC%' AND LYR.STL_NO IS NULL     THEN 'EMPTY'
                    ELSE 'CM' END) AS GOODS_YN --РчЗсПмЧќБИКа Y(СІЧА)РЬИщ CG(coilСІЧА) ОЦДЯИщCM(coilМвРч)
             ,LYR.YD_STK_LYR_ACTIVE_STAT
             ,CASE WHEN LYR.YD_STK_LYR_STAT = 'C' THEN NVL((SELECT 'S' 
                                                               FROM TB_YF_WRKBOOKMTL WM
                                                                  , TB_YF_WRKBOOK    WB
                                                              WHERE WM.STL_NO    = LYR.STL_NO 
                                                                AND WM.YD_WBOOK_ID = WB.YD_WBOOK_ID
                                                                AND WB.DEL_YN = 'N' 
                                                                AND WM.DEL_YN = 'N' 
                                                                AND ROWNUM = 1), 'C')
                   ELSE LYR.YD_STK_LYR_STAT END
               AS YD_STK_LYR_STAT
             ,LYR.MOD_DDTT
             ,PT.COIL_T  AS YD_MTL_T
             ,TRIM(TO_CHAR(PT.COIL_W,'9,999,999'))  AS YD_MTL_W
             ,TRIM(TO_CHAR(PT.COIL_WT,'9,999,999')) AS YD_MTL_WT
             ,PT.COIL_LEN  AS YD_MTL_L
             ,TRIM(TO_CHAR(PT.COIL_OUTDIA,'9,999,999')) AS YD_MTL_OUTDIA
             ,PT.SPEC_ABBSYM
             ,PT.HEAT_NO
             ,PT.CUST_CD
             , (SELECT CUST_KO_NAME
                  FROM TB_SM_CUSTINFO
                 WHERE CUST_CD = PT.CUST_CD) AS CUST_NM
             ,PT.STL_APPEAR_GP
             ,PT.CURR_PROG_CD
             ,(SELECT CD_MNNG FROM VW_CM_CODES
                WHERE CD_EN_ID = 'CURR_PROG_CD'
                  AND CD_CAT_ID = 'HS0000'
                  AND CD_VAL   = PT.CURR_PROG_CD
              ) AS CURR_PROG_CD_NM
             ,PT.ITEMNAME_CD
             ,PT.NEXT_PROC
             ,(SELECT CD_MNNG FROM VW_CM_CODES
                WHERE CD_EN_ID = 'NEXT_PROC'
                  AND CD_CAT_ID = 'HS0000'
                  AND CD_VAL   = PT.NEXT_PROC
              ) AS NEXT_PROC_NM
              
             ,COUNT(*) OVER() AS TOTALCOUNT
             ,SUM(PT.COIL_WT) OVER() AS TOT_MTL_WT
             ,CASE WHEN PT.STL_APPEAR_GP = 'Y' THEN
                CASE TO_CHAR(PT.COIL_CREATE_DDTT,'MM') 
                    WHEN '01' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_01 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '02' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_02 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '03' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_03 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '04' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_04 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '05' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_05 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '06' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_06 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '07' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_07 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '08' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_08 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '09' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_09 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '10' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_10 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '11' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_11 THEN 'TRUE' ELSE 'FALSE' END
                    WHEN '12' THEN CASE WHEN TO_NUMBER(TRUNC((SYSDATE - PT.COIL_CREATE_DDTT) * 24)) <= COLD_BT_TIME_12 THEN 'TRUE' ELSE 'FALSE' END
                END
             ELSE 
                'FALSE' END AS ISHOT  -- ГУАЂАцАњРЯРкПЁ ЕћИЅ КаБтКА ЧжФкРЯ СЄРЧ
            , CASE WHEN PT.USAGE_CD IN ('Z98', 'Z98B') THEN 'Y' ELSE 'N' END ISCHK_COIL
            , TO_CHAR(PT.MILL_WORD_DATE,'YYYY.MM.DD') AS MILL_WORD_DATE  --ОаПЌРЯРк
--            , CASE  WHEN PT.COIL_CREATE_GP = 'B' THEN 'Y' ELSE 'N' END AS IS_DCOIL-- РкФкРЯПЉКЮ
            , NVL((SELECT (CASE WHEN GOODS_DIVIDE_QNTY>1 THEN 'Y' ELSE 'N' END)
               FROM   TB_HR_C_SHEARWOWR F
              WHERE STEP_NO = (SELECT MAx(STEP_NO) FROM TB_HR_C_SHEARWOWR G
                                WHERE F.COIL_NO = G.COIL_NO)
                  AND F.COIL_NO = LYR.STL_NO
             ),'N') AS IS_DCOIL
            , (
                SELECT MIN(R.REPR_CD_CONTENTS)
                FROM   VW_YF_CONDENSATIONLOC VW
                     , TB_YF_RULE R
                WHERE VW.COIL_NO = STK.STL_NO
                AND R.REPR_CD_GP(+) = 'YM6001'
                AND R.CD_GP(+) = '1'
              ) AS YD_ZONE_GP -- ФкРЯРЧ ИёРћСИРЛ ЧЅЧіЧбДй.
            , STK.STOCK_MOVE_TERM
         FROM TB_YF_STKLYR LYR 
            , TB_YF_STOCK      STK 
            , TB_PT_COILCOMM   PT
            , (
                SELECT
                        NVL(MIN(CASE WHEN ITEM = '01' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_01
                      , NVL(MIN(CASE WHEN ITEM = '02' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_02
                      , NVL(MIN(CASE WHEN ITEM = '03' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_03
                      , NVL(MIN(CASE WHEN ITEM = '04' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_04
                      , NVL(MIN(CASE WHEN ITEM = '05' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_05
                      , NVL(MIN(CASE WHEN ITEM = '06' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_06
                      , NVL(MIN(CASE WHEN ITEM = '07' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_07
                      , NVL(MIN(CASE WHEN ITEM = '08' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_08
                      , NVL(MIN(CASE WHEN ITEM = '09' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_09
                      , NVL(MIN(CASE WHEN ITEM = '10' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_10
                      , NVL(MIN(CASE WHEN ITEM = '11' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_11
                      , NVL(MIN(CASE WHEN ITEM = '12' THEN DTL_ITEM1 END),0) AS COLD_BT_TIME_12
                FROM TB_YF_RULE
                WHERE REPR_CD_GP = 'YF0004'
                AND CD_GP = 'HRCOIL'
            ) CD
        WHERE LYR.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP || '%'
          AND LYR.YD_STK_BED_NO NOT IN ('00')
          AND LYR.STL_NO = PT.COIL_NO(+)
          AND LYR.DEL_YN = 'N'
          AND LYR.STL_NO = STK.STL_NO(+)
      ) LYR
 WHERE YD_STK_BED_NO = CASE SECT_GP 
                       WHEN 'DC' THEN '01'
                       ELSE YD_STK_BED_NO
                        END 
 ORDER BY LYR.YD_STK_COL_GP, LYR.YD_STK_BED_NO, LYR.YD_STK_LYR_NO
 </pre> */
public final static String getYfRackInfo = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getYfRackInfo";

 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.TcYDPTJ002 
SELECT 'YDPTJ002'                          AS JMS_TC_CD          --JMSTCФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
     , 'YDPTJ002'                          AS TC_CODE            --IFБИКаФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT     --TCЛ§МКРЯНУ

     , A.COIL_NO                           AS STL_NO
     , A.ORD_NO                            AS ORD_NO
     , A.ORD_DTL                           AS ORD_DTL
     , A.PLNT_PROC_CD                      AS PLNT_PROC_CD
     , A.STL_APPEAR_GP                     AS STL_APPEAR_GP
     , A.CURR_PROG_CD                      AS CURR_PROG_CD
     , A.ORD_YEOJAE_GP                     AS ORD_YEOJAE_GP
     , A.COIL_WT                           AS STL_WT
     , ''                                  AS DS_MTL_WT
     , A.RECORD_PROG_STAT                  AS MTL_STAT_GP
     , A.RECORD_END_GP                     AS RECORD_END_GP
     , ''                                  AS RECORD_END_GP1
     , A.BEFO_PROG_CD                      AS BEFO_PROG_CD
     , A.BEF_ORD_NO                        AS BEF_ORD_NO
     , A.BEF_ORD_DTL                       AS BEF_ORD_DTL
     , A.MMATL_FEE_NO                      AS MMATL_FEE_NO
     , A.MATCH_ORDERTRANS_GP               AS ORDERTRANS_MATCH_GP
  FROM TB_PT_COILCOMM A
 WHERE A.COIL_NO = :V_COIL_NO
 </pre> */
public final static String TcYDPTJ002 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.TcYDPTJ002";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockLoc 
-- ЛъРћРЇФЁ СЖШИ 
WITH PARAM AS (
SELECT :V_STL_NO AS P_STL_NO FROM DUAL
)
SELECT 
       NVL(A.YD_GP,CASE WHEN SUBSTR(C.YD_STR_LOC,1,1) = '3' THEN '3' ELSE '-' END) AS YD_GP
     , C.COIL_NO AS STL_NO
     , A.YD_STK_COL_GP  
     , A.YD_STK_BED_NO  
     , A.YD_STK_LYR_NO
     , A.ADDR AS FROM_ADDR
     , DECODE(A.ADDR, NULL, 'ОјРН', 'РћФЁ') AS STK_STAT
     ,(SELECT YD_SCH_CD
         FROM TB_YF_WRKBOOK    WB
            , TB_YF_WRKBOOKMTL WM
        WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
          AND WB.DEL_YN = 'N'
          AND WM.DEL_YN = 'N'
          AND WM.STL_NO = C.COIL_NO
      ) AS YD_SCH_CD
     , C.CURR_PROG_CD
     , DECODE((SELECT COUNT(*) AS YD_STOCK_CNT
                 FROM TB_YF_STOCK B1
                WHERE B1.STL_NO = A.STL_NO
                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_STOCK_YN
     , DECODE((SELECT COUNT(*) AS YD_CRN_SCH_ID_CNT
                 FROM TB_YF_CRNSCH    B1
                    , TB_YF_CRNWRKMTL C1
                WHERE B1.YD_CRN_SCH_ID = C1.YD_CRN_SCH_ID
                  AND C1.STL_NO = A.STL_NO
                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_CRN_SCH_ID_YN
     , DECODE((SELECT COUNT(*) AS WRKBOOK_CNT
                 FROM TB_YF_WRKBOOK    B1
                    , TB_YF_WRKBOOKMTL C1
                WHERE B1.YD_WBOOK_ID = C1.YD_WBOOK_ID
                  AND C1.STL_NO = A.STL_NO
                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_WRKBOOK_YN
     , DECODE((SELECT COUNT(*) AS WRKBOOK_CNT
                 FROM TB_YF_WRKBOOK    B1
                    , TB_YF_WRKBOOKMTL C1
                WHERE B1.YD_WBOOK_ID = C1.YD_WBOOK_ID
                  AND C1.STL_NO = A.STL_NO
                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_WRKBOOK_YN2    
     , DECODE((SELECT YD_STK_LYR_STAT
                 FROM TB_YF_STKLYR 
                WHERE STL_NO = A.STL_NO
                  AND ROWNUM = 1), 'S', 'Y', 'N') AS YD_WRKBOOK_YN3
     , DECODE((SELECT COUNT(*) AS CARSCH_CNT
                 FROM TB_YF_WRKBOOKMTL A1
                      , TB_YF_WRKBOOK B1
                      , TB_YD_CARSCH C1 
                WHERE A1.STL_NO = A.STL_NO
                AND A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
                AND (B1.TRN_EQP_CD = C1.TRN_EQP_CD OR B1.CAR_NO = C1.CAR_NO)
                AND A1.DEL_YN = 'N'
                AND B1.DEL_YN = 'N'
                AND C1.DEL_YN = 'N'
                ),0,'N','Y') AS YD_CARSCH_YN
     , DECODE((SELECT COUNT(*) AS CARSCH_CNT
                 FROM TB_TS_MATL_FTMV_WO B1
                WHERE B1.STL_NO = A.STL_NO 
                AND B1.TS_MATL_FTMV_STAT_GP = '1' --БИГЛПюМлМвРчРЬМлЛѓХТБИКа 1:РЬМлСіНУПЯЗс
                AND B1.MATL_FTMV_WO_NML_HD_YN IN ('Y','X') --МвРчРЬМлСіНУСЄЛѓУГИЎПЉКЮ Y:СЄЛѓ, X:КёСЄЛѓ(А­СІЕюЗЯ)
                ),0,'N','Y') AS YD_MVSTOCK_YN
     , DECODE((SELECT COUNT(*) AS TCARSCH_CNT
                 FROM TB_YF_TCARSCH     B1
                    , TB_YF_TCARFTMVMTL C1
                WHERE B1.YD_TCAR_SCH_ID    = C1.YD_TCAR_SCH_ID
                  AND C1.STL_NO = A.STL_NO
                  AND B1.DEL_YN = 'N'
                  AND C1.DEL_YN = 'N'
                  ),0,'N','Y') AS YD_TCARSCH_YN
     , DECODE((SELECT COUNT(*) AS YD_CTS_YN
                 FROM TB_YF_CTS_SCH     B1 
                WHERE B1.STL_NO = A.STL_NO
                  AND B1.DEL_YN = 'N'),0,'N','Y') AS YD_CTS_YN
     , A.DEL_YN                  
     , (
        SELECT CASE WHEN MAX(YD_GP) IS NULL THEN 'N' ELSE 'Y' END
          FROM (
               SELECT SUBSTR(YD_STK_COL_GP,  1, 1) AS YD_GP FROM TB_YF_STKLYR, PARAM WHERE STL_NO = P_STL_NO UNION ALL
               SELECT SUBSTR(YD_STK_COL_GP, 1, 1) AS YD_GP FROM TB_YD_STKLYR, PARAM WHERE STL_NO   = P_STL_NO 
               )
         WHERE YD_GP NOT IN ('3')            
       ) AS DIFF_YD_YN
  FROM(SELECT A.STL_NO
            , A.STOCK_ITEM
            , A.STOCK_MOVE_TERM
            , NVL(SUBSTR(B.YD_STK_COL_GP, 1, 1), '') AS YD_GP
            , B.YD_STK_COL_GP
            , B.YD_STK_BED_NO
            , B.YD_STK_LYR_NO
            , B.YD_STK_COL_GP||B.YD_STK_BED_NO||B.YD_STK_LYR_NO AS ADDR
            , A.DEL_YN
         FROM TB_YF_STOCK   A
            , TB_YF_STKLYR  B
            , PARAM
        WHERE A.STL_NO = B.STL_NO(+)
          AND A.STL_NO = P_STL_NO
          AND B.YD_STK_LYR_STAT IN ('C', 'U', 'L', 'S')
UNION ALL
SELECT A.STOCK_ID
            , A.STOCK_ITEM
            , A.STOCK_MOVE_TERM 
            , NVL(SUBSTR(B.STACK_COL_GP, 1, 1), '') AS YD_GP
            , B.STACK_COL_GP
            , B.STACK_BED_GP
            , B.STACK_LAYER_GP
            , B.STACK_COL_GP||B.STACK_BED_GP||B.STACK_LAYER_GP AS ADDR
            , A.DEL_YN
         FROM TB_YM_STOCK       A
            , TB_YM_STACKLAYER  B
            , PARAM
        WHERE A.STOCK_ID = B.STOCK_ID(+)
          AND A.STOCK_ID = P_STL_NO
          AND B.STACK_LAYER_STAT IN ('C', 'U', 'L', 'S')
UNION ALL
      SELECT A.STL_NO
            , A.YD_MTL_ITEM
            , A.YD_AIM_RT_GP
            , NVL(SUBSTR(B.YD_STK_COL_GP, 1, 1), '') AS YD_GP
            , B.YD_STK_COL_GP AS YD_STK_COL_GP
            , B.YD_STK_BED_NO AS YD_STK_BED_NO
            , B.YD_STK_LYR_NO AS YD_STK_LYR_NO
            , B.YD_STK_COL_GP||B.YD_STK_BED_NO||B.YD_STK_LYR_NO AS ADDR
            , A.DEL_YN
         FROM TB_YD_STOCK       A
            , TB_YD_STKLYR      B
            , PARAM
        WHERE A.STL_NO = B.STL_NO(+)
          AND A.STL_NO = P_STL_NO
          AND B.YD_STK_LYR_MTL_STAT IN ('C', 'U', 'S', 'L')
      ) A      
     , TB_PT_COILCOMM C
 WHERE 1 = 1
   AND C.COIL_NO = A.STL_NO(+) 
   AND C.COIL_NO = :V_STL_NO
 </pre> */
public final static String getStockLoc = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getStockLoc";

