 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getMvCarSchByTrnEqpCd 
WITH MVCAR_SCH AS (
    SELECT YD_CAR_SCH_ID
          ,TRN_EQP_CD
          ,YD_CAR_PROG_STAT
          ,DECODE(YD_CAR_PROG_STAT,'0','ЛѓТїДыБт','1','ЛѓТїУтЙп'
                                  ,'2','ЛѓТїЕЕТј','3','ЛѓТїАЫМі'
                                  ,'4','ЛѓТїАГНУ','5','ЛѓТїПЯЗс'
                                  ,'A','ЧЯТїУтЙп','B','ЧЯТїЕЕТј'
                                  ,'C','ЧЯТїАЫМі','D','ЧЯТїАГНУ'
                                  ,'E','ЧЯТїПЯЗс') AS YD_CAR_PROG_STAT_NM
                                  
          ,SPOS_WLOC_CD
          ,YD_PNT_CD1
          ,YD_CARLD_STOP_LOC
          ,ARR_WLOC_CD
          ,YD_PNT_CD3
          ,YD_CARUD_STOP_LOC
          ,CASE WHEN YD_CAR_PROG_STAT BETWEEN '1' AND '4' THEN YD_CARLD_WRK_BOOK_ID 
                WHEN YD_CAR_PROG_STAT BETWEEN 'A' AND 'D' THEN YD_CARUD_WRK_BOOK_ID 
                ELSE '' END AS YD_WBOOK_ID
    FROM   USRYDA.TB_YD_CARSCH
    WHERE  DEL_YN = 'N'
    AND    YD_CAR_USE_GP = 'L'
    AND    TRN_EQP_CD = :V_TRN_EQP_CD
)
SELECT MC.*
      ,WB.YD_SCH_CD
      ,(SELECT MAX(CD_CONTENTS )
        FROM   TB_YF_SCHRULE
        WHERE  YD_SCH_CD =  WB.YD_SCH_CD) AS YD_SCH_CD_NM
FROM   MVCAR_SCH MC
      ,TB_YF_WRKBOOK WB
WHERE  MC.YD_WBOOK_ID = WB.YD_WBOOK_ID(+)
ORDER BY MC.YD_CAR_SCH_ID DESC
 </pre> */
