 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilOrdInfoIdInvInqjl.getCoidGdsYdOrdInfoMtl 
-- СжЙЎСЄКИКА РчАэСЖШИ
SELECT ROWNUM AS RNUM 
      ,K.*
  FROM 
(SELECT A.STL_NO
      ,B.YD_STK_COL_GP || B.YD_STK_BED_NO || B.YD_STK_LYR_NO AS STK_POS
      ,C.ORD_NO
      ,C.ORD_DTL
      ,C.CURR_PROG_CD
      ,C.SPEC_ABBSYM
      ,C.COIL_T
      ,C.COIL_W
      ,C.COIL_OUTDIA
      ,C.COIL_WT
      ,C.PASS_PROC1 || '/' || C.PASS_PROC2 || '/' || C.PASS_PROC3 || '/' || C.PASS_PROC4 || '/' || C.PASS_PROC5 AS PASS_PROC
      ,C.MILL_INI_DATE
      , (SELECT CUST_KO_NAME
            FROM TB_SM_CUSTINFO
          WHERE CUST_CD=D.CUST_CD) AS DEMANDER_NM -- МіПфАЁ 
      , (SELECT DEST_NAME
           FROM TB_DM_DESTCD
          WHERE DEST_CD =D.DEST_CD ) AS DEST_NM -- ИёРћСі
      , (SELECT CUST_KO_NAME
            FROM TB_SM_CUSTINFO
          WHERE CUST_CD=D.CUST_CD) AS CUST_NM -- АХЗЁУГ
      
  FROM TB_YF_STOCK       A
     , TB_YF_STKLYR  B
     , TB_PT_COILCOMM    C
     , TB_PT_OSCOMM      D
 WHERE 1=1
   AND A.DEL_YN = 'N'
   AND B.DEL_YN = 'N'
   AND A.STL_NO = B.STL_NO
   AND B.YD_STK_LYR_STAT IN ('C','U')
   AND A.STL_NO = C.COIL_NO
   AND C.ORD_NO  = D.ORD_NO (+)
   AND C.ORD_DTL = D.ORD_DTL(+)
   AND B.YD_STK_COL_GP LIKE :V_YD_GP ||'%'   
   AND NVL(C.ORD_NO  ,' ' ) LIKE :V_ORD_NO || '%'
   AND NVL(C.ORD_DTL ,' ' ) LIKE :V_ORD_DTL || '%'
--   AND NVL(D.DEST_CD , ' ') LIKE :V_DEST_CD || '%'
   AND NVL(D.CUST_CD , ' ') LIKE :V_CUST_CD || '%'
 ORDER BY B.YD_STK_COL_GP, B.YD_STK_LYR_NO ) K
 </pre> */
public final static String getCoidGdsYdOrdInfoMtl = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilOrdInfoIdInvInqjl.getCoidGdsYdOrdInfoMtl";

