 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.TcYDQMJ002BackUp 
SELECT 'YDQMJ002'                          AS JMS_TC_CD          --JMSTCФкЕх  
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ  
     , SUBSTR(A.PTOP_PLNT_GP, 2, 1)        AS PTOP_PLNT_GP            --IFБИКаФкЕх  
     , A.STL_APPEAR_GP                     AS STL_APPEAR_GP     --TCЛ§МКРЯНУ  
     , A.COIL_NO                           AS STL_NO  
  FROM (SELECT B.PTOP_PLNT_GP
             , B.STL_APPEAR_GP
             , B.COIL_NO
          FROM TB_YF_CRNWRKMTL A
             , TB_PT_COILCOMM  B
         WHERE A.STL_NO = B.COIL_NO
           AND A.YD_CRN_SCH_ID = (
                                  SELECT MAX(CM.YD_CRN_SCH_ID) AS YD_CRN_SCH_ID
                                    FROM TB_YF_CRNWRKMTL CM
                                       , TB_YF_CRNSCH    CR
                                   WHERE CM.YD_CRN_SCH_ID = CR.YD_CRN_SCH_ID
                                     AND CM.STL_NO = :V_STL_NO
                                    )
       ) A
 </pre> */
