 /** <pre> 
--yf.facilitystatus.facilityinquiry.YfCommonDAO.getSlabListInfo
WITH STL_LIST AS (
 SELECT regexp_substr(STL_LIST,'[^,]+',1,LEVEL) AS STL_NO
   FROM (SELECT :V_STL_NO AS STL_LIST FROM DUAL) A
CONNECT BY LEVEL <= length(regexp_replace(STL_LIST,'[^,]+',''))+1
)

SELECT *
  FROM TB_YF_STKLYR STKLYR
 WHERE STKLYR.STL_NO IN ( SELECT STL_NO FROM STL_LIST )
 ORDER BY YD_STK_COL_GP ASC,YD_STK_BED_NO ASC,YD_STK_LYR_NO DESC
 </pre> */
public final static String getSlabListInfo = "bak.yf.facilitystatus.facilityinquiry.YfCommonDAO.getSlabListInfo";

