 /** <pre> 
--com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabProducList
SELECT
   X.*
FROM
( 
    SELECT AA.*, ROWNUM AS RNUM
    FROM (
            SELECT
                A.* 
                ,TO_CHAR(DECODE(C.BUY_ORD_T,NULL,A.SLAB_T_TMP,C.BUY_ORD_T), '99,999,990') AS BUY_ORD_T
                ,TO_CHAR(DECODE(C.BUY_ORD_W,NULL,A.SLAB_W_TMP,C.BUY_ORD_W), '99,999,990') AS BUY_ORD_W
                ,DECODE(C.MAKER_NAME,NULL,'HYUNDAI STEEL',C.MAKER_NAME) AS MAKER_NAME
                ,C.BUY_SLAB_NO --БИРдННЖѓКъ ЙјШЃ
            FROM
            (
                SELECT
                   A.*
                   ,C.PLAN_SLAB_NO --AS ПЙСЄSLABNO
                   ,(CASE WHEN USRPMA.FN_PM_B_ГУПЌЧАИэУЃБт(C.ITEMNAME_CD) = 'Y' THEN C.HR_SPEC_ABBSYM ELSE C.SPEC_ABBSYM END) AS SPEC_ABBSYM  -- БдАнОрШЃ
                   ,TO_CHAR(C.REAL_MEASURE_SLAB_T, '99,999,990')    AS SLAB_T      --ЕЮВВ
                   ,TO_CHAR(C.REAL_MEASURE_SLAB_W, '99,999,990')    AS SLAB_W      --Цј
                   ,TO_CHAR(C.REAL_MEASURE_SLAB_LEN, '99,999,990')  AS SLAB_LEN    --БцРЬ
                   ,TO_CHAR(C.SLAB_WT, '99,999,990')   AS SLAB_WT     --СпЗЎ
                   ,C.MSLAB_NO
                   ,C.SLAB_T AS SLAB_T_TMP
                   ,C.SLAB_W AS SLAB_W_TMP
                FROM 
                (
                    SELECT COUNT(*) OVER() AS TOTALCOUNT,
                           DECODE(SUBSTR(A.YD_STK_COL_GP, 1, 1),0,'ЙкЦЧП­ПЌ SLABОпЕх',2,'1П­ПЌ SLABОпЕх') AS YD_GP,
                           SUBSTR(A.YD_STK_COL_GP, 2, 1) AS BAY_GP,
                           SUBSTR(A.YD_STK_COL_GP, 3, 2) AS SPAN_GP,
                           A.YD_STK_COL_GP||A.YD_STK_BED_NO||A.YD_STK_LYR_NO AS EXPECT_YD_STK_LOC, -- РњРхРЇФЁ
                           A.STL_NO, -- РњРхЧА ID(SLAB_NO)
                           A.YD_STK_COL_GP, A.YD_STK_BED_NO, A.YD_STK_LYR_NO
                      FROM TB_YF_STKLYR A, TB_YF_STOCK B
                        WHERE A.YD_STK_COL_GP LIKE NVL(:V_YD_STK_COL_GP,'0') || '%'-- ОпЕхБИКа+ЕПБИКа+П­БИКа(1A01)
                          --AND A.YD_STK_LYR_STAT IN('L', 'S', 'U') АќЗУ КЮКа МіСЄСп
                          AND A.STL_NO = B.STL_NO
                ) A, VW_YD_SLABCOMM C
                WHERE A.STL_NO = C.SLAB_NO(+)
            ) A, TB_QM_BUYSLABINFO C
            WHERE A.MSLAB_NO = C.MSLAB_NO(+)
            ORDER BY A.YD_STK_COL_GP, A.YD_STK_BED_NO, A.YD_STK_LYR_NO  
        ) AA
        WHERE ROWNUM  <= :V_PAGE_NO * :V_PAGE_SIZE
) X
 WHERE RNUM>= ((:V_PAGE_NO-1)* :V_PAGE_SIZE)+1
 </pre> */
public final static String getSlabProducList = "bak.com.inisteel.cim.yf.aslab.dao.ASlabDAO.getSlabProducList";

