 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR020 
SELECT 'YDDMR020'                          AS JMS_TC_CD            --JMSTCФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT   --JMSTCЛ§МКРЯНУ
     , 'YDDMR020'                          AS TC_CODE              --IFБИКаФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT       --TCЛ§МКРЯНУ
     , CASE WHEN YD_CAR_PROG_STAT IN ('2','3','4','5')       THEN 'U'   
            ELSE 'D' END                   AS UPCARUNLOAD_GP
     , CARD_NO                             AS CARD_NO         
     , CAR_NO                              AS CAR_NO
     , SUBSTR(YD_CARLD_STOP_LOC,1,1)       AS YD_GP
     , CASE WHEN  YD_CAR_PROG_STAT IN ('2','3','4','5') 
            THEN SUBSTR(TO_CHAR(YD_CARLD_ST_DT,'YYYYMMDDHH24MISS'),1,8) 
            ELSE SUBSTR(TO_CHAR(YD_CARUD_ST_DT,'YYYYMMDDHH24MISS'),1,8) END  AS CARLOAD_START_DATE
     , CASE WHEN  YD_CAR_PROG_STAT IN ('2','3','4','5')
            THEN SUBSTR(TO_CHAR(YD_CARLD_ST_DT,'YYYYMMDDHH24MISS'),9,6) 
            ELSE SUBSTR(TO_CHAR(YD_CARUD_ST_DT,'YYYYMMDDHH24MISS'),9,6) END  AS CARLOAD_START_TIME 
     , TRANS_ORD_DATE                      AS TRANS_WORD_DATE
     , TRANS_ORD_SEQNO                     AS TRANS_WORD_SEQNO
  FROM TB_YD_CARSCH C
 WHERE YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String TcYDDMR020 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR020";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getListACCountToExcel
SELECT A.YD_GP AS ОпЕхБИКа, 
       A.BAY_GP AS ЕПБИКа, 
       DECODE(A.BAY_GP, 'T', 'ЧеАш', A.BAY_GP||'ЕП') AS ЕПРЬИЇ, 
       TO_CHAR(A.QT_01, '99,999,999')        AS AРчАјМіЗЎ,
       NVL(TO_CHAR(A.QT_02, '99,999,999'),0) AS BРчАјМіЗЎ,
       NVL(TO_CHAR(A.QT_0C, '99,999,999'),0) AS CРчАјМіЗЎ,
       
       TO_CHAR(A.WT_01, '99,999,999')        AS AРчАјСпЗЎ,
       NVL(TO_CHAR(A.WT_02, '99,999,999'),0) AS BРчАјСпЗЎ,
       NVL(TO_CHAR(A.WT_0C, '99,999,999'),0) AS CРчАјСпЗЎ,
       
       TO_CHAR(A.QT_01+A.QT_03 , '99,999,999')       AS AМіЗЎ,
       NVL(TO_CHAR(A.WT_01+A.WT_03, '99,999,999'),0) AS AСпЗЎ,
       TO_CHAR((A.QT_01+NVL(A.QT_02,0)+NVL(A.QT_0C,0)) / A.TOT_QT * 100, '990.00') AS РчАјКёРВ,
       TO_CHAR(A.QT_03, '99,999,999')        AS AРдАэМіЗЎ,
       NVL(TO_CHAR(A.QT_04, '99,999,999'),0) AS BРдАэМіЗЎ,
       NVL(TO_CHAR(A.QT_05, '99,999,999'),0) AS CРдАэМіЗЎ,
       
       TO_CHAR(A.WT_03, '99,999,999')        AS AРдАэСпЗЎ,
       NVL(TO_CHAR(A.WT_04, '99,999,999'),0) AS BРдАэСпЗЎ,
       NVL(TO_CHAR(A.WT_05, '99,999,999'),0) AS CРдАэСпЗЎ,
       
       TO_CHAR(NVL(A.QT_02,0)+NVL(A.QT_04,0) , '99,999,999') AS BМіЗЎ,
       NVL(TO_CHAR(A.WT_02+A.WT_04, '99,999,999'),0)         AS BСпЗЎ,
       TO_CHAR((A.QT_03+NVL(A.QT_04,0)+NVL(A.QT_05,0)) / A.TOT_QT * 100, '990.00') AS РдАэКёРВ,
       
       TO_CHAR(NVL(A.QT_0C,0)+NVL(A.QT_05,0) , '99,999,999') AS CМіЗЎ,
       NVL(TO_CHAR(A.WT_0C+A.WT_05, '99,999,999'),0)         AS CСпЗЎ,       
       
       TO_CHAR(A.TOT_QT, '99,999,999') AS УбМіЗЎ, 
       TO_CHAR(A.TOT_WT, '999,999,999') AS УбСпЗЎ 
FROM (
       SELECT C.NO, A.YD_GP, 
              DECODE(C.NO, '01', A.BAY_GP, 'T') AS BAY_GP,
              SUM(DECODE(B.CURR_PROG_CD, 'M', 1, -- СОЗсЛѓХТ
                                         'A', 1, -- РчСњЦЧСЄДыБт
                                         'B', 1, -- СЄСЄСіНУДыБт
                                         'C', 1, -- СЄСЄРлОїДыБт
                                         'D', 1, -- РЬМлСіНУДыБт
                                         'E', 1, -- РЬМлРлОїДыБт
                                         'F', 1, -- ЦЧСЄКИЗљ
                                         'G', 1, -- ЦЧСЄДыБт
                                         'H', 1, -- РдАэДыБт
                                         'J', 1, -- ЙнГГДыБт
                                         'K', 1, -- УтЧЯСіНУДыБт
                                         'N', 1, -- УтЧЯСіНУДыБт
                                         'L', 1, -- УтЧЯРлОїДыБт
                                         'X', 1, -- АцИХДыЛѓМБСЄ
                                         'Y', 1, -- РчАјУцДчДыБт
                                         'Z', 1, -- СІЧАУцДчДыБт
                                         'R', 1, -- РчСњЦЧСЄДыБт
                                         0)) AS TOT_QT,
              SUM(DECODE(B.CURR_PROG_CD, 'M', B.COIL_WT, -- СОЗсЛѓХТ
                                         'A', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         'B', B.COIL_WT, -- СЄСЄСіНУДыБт
                                         'C', B.COIL_WT, -- СЄСЄРлОїДыБт
                                         'D', B.COIL_WT, -- РЬМлСіНУДыБт
                                         'E', B.COIL_WT, -- РЬМлРлОїДыБт
                                         'F', B.COIL_WT, -- ЦЧСЄКИЗљ
                                         'G', B.COIL_WT, -- ЦЧСЄДыБт
                                         'H', B.COIL_WT, -- РдАэДыБт
                                         'J', B.COIL_WT, -- ЙнГГДыБт
                                         'K', B.COIL_WT, -- УтЧЯСіНУДыБт
                                         'N', B.COIL_WT, -- УтЧЯСіНУДыБт
                                         'L', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'X', B.COIL_WT, -- АцИХДыЛѓМБСЄ
                                         'Y', B.COIL_WT, -- РчАјУцДчДыБт
                                         'Z', B.COIL_WT, -- СІЧАУцДчДыБт
                                         'R', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         0)) AS TOT_WT,
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, '1', 1, -- СОЗсЛѓХТ
                                         'A', 1, -- РчСњЦЧСЄДыБт
                                         'B', 1, -- СЄСЄСіНУДыБт
                                         'C', 1, -- СЄСЄРлОїДыБт
                                         'D', 1, -- РЬМлСіНУДыБт
                                         'E', 1, -- РЬМлРлОїДыБт
                                         'F', 1, -- ЦЧСЄКИЗљ
                                         'G', 1, -- ЦЧСЄДыБт
                                         'H', 1, -- РдАэДыБт
                                         'Y', 1, -- РчАјУцДчДыБт
                                         'R', 1, -- РчСњЦЧСЄДыБт
                                         0)))) AS QT_01, -- AРчАјМіЗЎ
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, '1', 1, -- СОЗсЛѓХТ
                                         'A', 1, -- РчСњЦЧСЄДыБт
                                         'B', 1, -- СЄСЄСіНУДыБт
                                         'C', 1, -- СЄСЄРлОїДыБт
                                         'D', 1, -- РЬМлСіНУДыБт
                                         'E', 1, -- РЬМлРлОїДыБт
                                         'F', 1, -- ЦЧСЄКИЗљ
                                         'G', 1, -- ЦЧСЄДыБт
                                         'H', 1, -- РдАэДыБт
                                         'Y', 1, -- РчАјУцДчДыБт
                                         'R', 1, -- РчСњЦЧСЄДыБт
                                         0)))) AS QT_02, -- BРчАјМіЗЎ
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, '1', 1, -- СОЗсЛѓХТ
                                         'A', 1, -- РчСњЦЧСЄДыБт
                                         'B', 1, -- СЄСЄСіНУДыБт
                                         'C', 1, -- СЄСЄРлОїДыБт
                                         'D', 1, -- РЬМлСіНУДыБт
                                         'E', 1, -- РЬМлРлОїДыБт
                                         'F', 1, -- ЦЧСЄКИЗљ
                                         'G', 1, -- ЦЧСЄДыБт
                                         'H', 1, -- РдАэДыБт
                                         'Y', 1, -- РчАјУцДчДыБт
                                         'R', 1, -- РчСњЦЧСЄДыБт
                                         0)))) AS QT_0C, -- CРчАјМіЗЎ
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, '1', B.COIL_WT, -- СОЗсЛѓХТ
                                         'A', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         'B', B.COIL_WT, -- СЄСЄСіНУДыБт
                                         'C', B.COIL_WT, -- СЄСЄРлОїДыБт
                                         'D', B.COIL_WT, -- РЬМлСіНУДыБт
                                         'E', B.COIL_WT, -- РЬМлРлОїДыБт
                                         'F', B.COIL_WT, -- ЦЧСЄКИЗљ
                                         'G', B.COIL_WT, -- ЦЧСЄДыБт
                                         'H', B.COIL_WT, -- РдАэДыБт
                                         'Y', B.COIL_WT, -- РчАјУцДчДыБт
                                         'R', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         0)))) AS WT_01, --A РчАэСпЗЎ
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, '1', B.COIL_WT, -- СОЗсЛѓХТ
                                         'A', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         'B', B.COIL_WT, -- СЄСЄСіНУДыБт
                                         'C', B.COIL_WT, -- СЄСЄРлОїДыБт
                                         'D', B.COIL_WT, -- РЬМлСіНУДыБт
                                         'E', B.COIL_WT, -- РЬМлРлОїДыБт
                                         'F', B.COIL_WT, -- ЦЧСЄКИЗљ
                                         'G', B.COIL_WT, -- ЦЧСЄДыБт
                                         'H', B.COIL_WT, -- РдАэДыБт
                                         'Y', B.COIL_WT, -- РчАјУцДчДыБт
                                         'R', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         0)))) AS WT_02,  --B РчАэСпЗЎ    
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, '1', B.COIL_WT, -- СОЗсЛѓХТ
                                         'A', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         'B', B.COIL_WT, -- СЄСЄСіНУДыБт
                                         'C', B.COIL_WT, -- СЄСЄРлОїДыБт
                                         'D', B.COIL_WT, -- РЬМлСіНУДыБт
                                         'E', B.COIL_WT, -- РЬМлРлОїДыБт
                                         'F', B.COIL_WT, -- ЦЧСЄКИЗљ
                                         'G', B.COIL_WT, -- ЦЧСЄДыБт
                                         'H', B.COIL_WT, -- РдАэДыБт
                                         'Y', B.COIL_WT, -- РчАјУцДчДыБт
                                         'R', B.COIL_WT, -- РчСњЦЧСЄДыБт
                                         0)))) AS WT_0C,  --C РчАэСпЗЎ    
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, 'J', 1, -- ЙнГГДыБт
                                         'K', 1, -- УтЧЯСіНУДыБт
                                         'L', 1, -- УтЧЯРлОїДыБт
                                         'N', 1, -- УтЧЯРлОїДыБт
                                         'X', 1, -- АцИХДыЛѓМБСЄ
                                         'Z', 1, -- СІЧАУцДчДыБт
                                         'M', 1, -- СОЗс
                                         0)))) AS QT_03,   -- AРдАэМіЗЎ
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, 'J', 1, -- ЙнГГДыБт
                                         'K', 1, -- УтЧЯСіНУДыБт
                                         'L', 1, -- УтЧЯРлОїДыБт
                                         'N', 1, -- УтЧЯРлОїДыБт
                                         'X', 1, -- АцИХДыЛѓМБСЄ
                                         'Z', 1, -- СІЧАУцДчДыБт
                                         'M', 1, -- СОЗс
                                         0)))) AS QT_04,   -- BРдАэМіЗЎ
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, 'J', 1, -- ЙнГГДыБт
                                         'K', 1, -- УтЧЯСіНУДыБт
                                         'L', 1, -- УтЧЯРлОїДыБт
                                         'N', 1, -- УтЧЯРлОїДыБт
                                         'X', 1, -- АцИХДыЛѓМБСЄ
                                         'Z', 1, -- СІЧАУцДчДыБт
                                         'M', 1, -- СОЗс
                                         0)))) AS QT_05,   -- CРдАэМіЗЎ
              SUM(DECODE(GUBUN,'H',(DECODE(B.CURR_PROG_CD, 'J', B.COIL_WT, -- ЙнГГДыБт
                                         'K', B.COIL_WT, -- УтЧЯСіНУДыБт
                                         'L', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'N', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'X', B.COIL_WT, -- АцИХДыЛѓМБСЄ
                                         'Z', B.COIL_WT, -- СІЧАУцДчДыБт
                                         'M', B.COIL_WT, -- СОЗс
                                         0)))) AS WT_03, --A РдАэ СпЗЎ                                                              
              SUM(DECODE(GUBUN,'K',(DECODE(B.CURR_PROG_CD, 'J', B.COIL_WT, -- ЙнГГДыБт
                                         'K', B.COIL_WT, -- УтЧЯСіНУДыБт
                                         'L', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'N', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'X', B.COIL_WT, -- АцИХДыЛѓМБСЄ
                                         'Z', B.COIL_WT, -- СІЧАУцДчДыБт
                                         'M', B.COIL_WT, -- СОЗс
                                         0)))) AS WT_04, --B РдАэ СпЗЎ 
              SUM(DECODE(GUBUN,'C',(DECODE(B.CURR_PROG_CD, 'J', B.COIL_WT, -- ЙнГГДыБт
                                         'K', B.COIL_WT, -- УтЧЯСіНУДыБт
                                         'L', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'N', B.COIL_WT, -- УтЧЯРлОїДыБт
                                         'X', B.COIL_WT, -- АцИХДыЛѓМБСЄ
                                         'Z', B.COIL_WT, -- СІЧАУцДчДыБт
                                         'M', B.COIL_WT, -- СОЗс
                                         0)))) AS WT_05 --C РдАэ СпЗЎ  
       FROM (
                  SELECT SUBSTR(A.YD_STK_COL_GP,1,1) AS YD_GP, 
                         SUBSTR(A.YD_STK_COL_GP,2,1) AS BAY_GP,
                         SUBSTR(A.YD_STK_COL_GP,3,2) AS SECT_GP,
                         DECODE(B.YD_STK_LYR_STAT, 'L', 1, 'S', 1, 'U', 1, 0) AS LOAD_YN, 
                         B.STL_NO,
                         NVL(C.KEEP_STL_YN, 'N') AS KEEP_YN,
                         SUBSTR(B.STL_NO,1,1) AS GUBUN
                      FROM TB_YF_STKCOL A, TB_YF_STKLYR B , TB_YF_STOCK C
                  WHERE A.YD_STK_COL_GP LIKE :V_YD_GP ||'%' -- ? ОпЕхБИКа
                    AND A.SECT_GP BETWEEN '01' AND '99'
                    AND B.YD_STK_LYR_STAT IN ('L','S','U')
                    AND A.YD_STK_COL_GP = B.YD_STK_COL_GP
                    AND B.STL_NO =C.STL_NO
                    AND B.YD_STK_LYR_ACTIVE_STAT IN ( 'E', 'O' )
                ) A, TB_PT_COILCOMM B ,(SELECT LPAD(LEVEL,2,'0') AS NO FROM DUAL CONNECT BY LEVEL <= 99 ) C
           WHERE A.SECT_GP BETWEEN '01' AND '99'
             AND A.KEEP_YN LIKE :V_KEEP_YN --  КИАќИХУтПЉКЮ
             AND A.STL_NO = B.COIL_NO(+)
             AND C.NO < '03'
           GROUP BY C.NO, A.YD_GP, DECODE(C.NO, '01', A.BAY_GP, 'T')     
     ) A
ORDER BY A.NO, A.YD_GP, A.BAY_GP
 </pre> */
public final static String getListACCountToExcel = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getListACCountToExcel";

