 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.TcYDPTJ003 
SELECT 'YDPTJ003'                          AS JMS_TC_CD          --JMSTCФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
     , 'YDPTJ003'                          AS TC_CODE            --IFБИКаФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT     --TCЛ§МКРЯНУ

     , A.COIL_NO                           AS STL_NO
     , A.ORD_NO                            AS ORD_NO
     , A.ORD_DTL                           AS ORD_DTL
     , A.PLNT_PROC_CD                      AS PLNT_PROC_CD
     , A.STL_APPEAR_GP                     AS STL_APPEAR_GP
     , A.CURR_PROG_CD                      AS CURR_PROG_CD
     , A.ORD_YEOJAE_GP                     AS ORD_YEOJAE_GP
     , A.COIL_WT                           AS STL_WT
     , ''                                  AS DS_MTL_WT
     , A.RECORD_PROG_STAT                  AS MTL_STAT_GP
     , A.RECORD_END_GP                     AS RECORD_END_GP
     , ''                                  AS RECORD_END_GP1
     , A.BEFO_PROG_CD                      AS BEFO_PROG_CD
     , A.BEF_ORD_NO                        AS BEF_ORD_NO
     , A.BEF_ORD_DTL                       AS BEF_ORD_DTL
     , A.MMATL_FEE_NO                      AS MMATL_FEE_NO
     , A.MATCH_ORDERTRANS_GP               AS ORDERTRANS_MATCH_GP
  FROM TB_PT_COILCOMM A
 WHERE A.COIL_NO = :V_COIL_NO
 </pre> */
public final static String TcYDPTJ003 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.TcYDPTJ003";

 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPOJ161  
SELECT 'YMPOJ161'                           AS JMS_TC_CD          --JMSTCФкЕх  
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ  
     , 'YMPOJ161'                           AS tcCode
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),1,8) AS tcDate
     , substr(TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS'),9,6) AS tcTime
     , 'B'                                 AS plantGbn  
     , SUBSTR(A.TRK_INFO,1,1)              AS procGbn            --S:1SPM,N:2SPM,H:HFL 
     , A.STL_NO                          AS coilNo  
     , SUBSTR(A.TRK_INFO,2,1)              AS processId  
     , TO_CHAR(SYSDATE,'YYYYMMDD')         AS downDate  
     , TO_CHAR(SYSDATE,'HH24MISS')         AS downTime  
     , SUBSTR(A.TRK_INFO,2,1)              AS positionNo  
  FROM (SELECT CASE WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,2,6) IN ('DKE01U','EKE01U') THEN 'N1'  --2SPM КИБоСИ 
                    WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,3,5) IN ('KE01U'          ) THEN 'S1'  --1SPM КИБоСИ 
                    WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,3,6) IN ('DKE03U','EKE03U') THEN 'N5'  --2SPM TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('KE') AND SUBSTR(YD_SCH_CD,3,5) IN ('KE03U'          ) THEN 'S5'  --1SPM TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('FE') AND SUBSTR(YD_SCH_CD,3,5) IN ('FE01U'          ) THEN 'H1'  --HFL  КИБоСИ 
                    WHEN SUBSTR(LOC,3,2) IN ('FE') AND SUBSTR(YD_SCH_CD,3,5) IN ('FE03U'          ) THEN 'H5'  --HFL  TAKE IN 
                    WHEN SUBSTR(LOC,3,2) IN ('FE')                                                  THEN 'F1'  --2SPMГЛ HFLКИБо 
                    ELSE '' END AS TRK_INFO 
            , STL_NO 
         FROM (SELECT :V_YD_DN_WR_LOC  AS LOC  
                    , STL_NO         AS STL_NO
                    , (SELECT YD_SCH_CD FROM TB_YF_CRNSCH WHERE YD_CRN_SCH_ID = C.YD_CRN_SCH_ID) AS YD_SCH_CD
                 FROM TB_YF_CRNWRKMTL C 
                WHERE C.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID) 
       ) A 
 </pre> */
public final static String TcYMPOJ161 = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.TcYMPOJ161";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getSumProgCoilInfoNEW14 
WITH TEMP_TABLE AS (
SELECT 'МвРч' AS CHK,
        (CASE WHEN SPOS_WLOC_CD IN('D2Y44','D2Y45')  THEN 'ЙкЦЧП­ПЌ'
                       WHEN SPOS_WLOC_CD IN('D3Y41','D3Y42') THEN '1П­ПЌ'
                       WHEN SPOS_WLOC_CD IN('DJY1E','DJY21','DJY22')  THEN '2П­ПЌ'
                       ELSE '2П­ПЌ'
                END ) AS YD_GP_SPOS 
                ,(CASE  WHEN ARR_WLOC_CD IN('D2Y44','D2Y45') THEN 'ЙкЦЧП­ПЌ' 
                        WHEN ARR_WLOC_CD IN('D3Y41','D3Y42') THEN '1П­ПЌ' 
                        WHEN ARR_WLOC_CD IN('DJY1E','DJY21','DJY22') THEN '2П­ПЌ' 
                        END) AS YD_GP_ARR 
                , COIL_WT
                ,A.FTMV_HDS_DD
                ,A.STL_NO 
FROM  USRPTA.TB_PT_STLFRTOMOVE A
   ,TB_PT_COILCOMM B
   , USRPTA.TB_PT_COILCOMMSUB C
WHERE A.STL_NO=B.COIL_NO
   AND B.COIL_NO=C.COIL_NO
   AND A.FRTOMOVE_STAT_CD='*' 
   AND A.SPOS_WLOC_CD IN('D2Y44','D2Y45','D3Y41','D3Y42','DJY1E','DJY21','DJY22')
   AND A.ARR_WLOC_CD IN('D2Y44','D2Y45','D3Y41','D3Y42','DJY1E','DJY21','DJY22')
   AND A.FRTOMOVE_DONE_DATE>=TO_CHAR(SYSDATE-32,'YYYYMMDD') 
   AND A.FTMV_HDS_DD LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%' 
   AND A.FTMV_HDS_DD <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
UNION ALL
SELECT 'СІЧА' AS CHK,
                (CASE WHEN CARLD_PNT_CD LIKE '1%'  THEN 'ЙкЦЧП­ПЌ'
                       WHEN CARLD_PNT_CD LIKE '3%' THEN '1П­ПЌ'
                       WHEN CARLD_PNT_CD LIKE 'J%'  THEN '2П­ПЌ'             
                END ) AS YD_GP_SPOS 
                ,(CASE  WHEN CARUD_PNT_CD LIKE '1%'   THEN 'ЙкЦЧП­ПЌ' 
                        WHEN CARUD_PNT_CD LIKE '3%' THEN '1П­ПЌ' 
                        WHEN CARUD_PNT_CD LIKE 'J%' THEN '2П­ПЌ' 
                        END) AS YD_GP_ARR
               ,GOODS_WT
               , FRTOMOVE_WORD_DATE
               , GOODS_NO
 FROM  TB_DM_GOODSFRTOMOVEWORDDETAIL @DL_SMDB A
  WHERE  A.FRTOMOVE_WORD_DATE>=TO_CHAR(SYSDATE-32,'YYYYMMDD') 
   AND A.FRTOMOVE_WORD_DATE LIKE TO_CHAR((CASE WHEN TO_CHAR(SYSDATE,'DD')='01' and SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN SYSDATE-1 ELSE SYSDATE END),'YYYYMM')||'%' 
   AND A.FRTOMOVE_WORD_DATE <=TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
) 
, TEMP_TABLE2 AS ( --РЯАш С§Аш
SELECT CHK ,YD_NAME
           , NVL(A_YD,0) AS SA_YD
           , NVL(B_YD,0) AS SB_YD            
           , NVL(C_YD,0) AS SC_YD
           , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0) AS STOT_YD
           , NVL(MA_YD,0) AS EA_YD
           , NVL(MB_YD,0) AS EB_YD            
           , NVL(MC_YD,0) AS EC_YD 
           , NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS ETOT_YD
            , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0)+NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS TOT_YD
 
FROM (
        SELECT 1 AS CHK , 'ЙкЦЧП­ПЌ' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='ЙкЦЧП­ПЌ'
            AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
         UNION ALL
         SELECT 2 AS CHK , '1П­ПЌ' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='1П­ПЌ'
         AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
          UNION ALL
         SELECT 3 AS CHK , '2П­ПЌ' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='2П­ПЌ'
           AND A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
      UNION ALL
        SELECT 4 AS CHK , 'Аш' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE A.FTMV_HDS_DD =TO_CHAR(SYSDATE-(CASE WHEN SYSDATE<TO_DATE(TO_CHAR(SYSDATE,'YYYYMMDD')||'070000', 'YYYYMMDDHH24MISS') THEN 1 ELSE 0 END),'YYYYMMDD') 
     
           
       )
 ) 
 , TEMP_TABLE3 AS (
SELECT CHK  ,YD_NAME
           , NVL(A_YD,0) AS SA_YD
           , NVL(B_YD,0) AS SB_YD            
           , NVL(C_YD,0) AS SC_YD
           , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0) AS STOT_YD
           , NVL(MA_YD,0) AS EA_YD
           , NVL(MB_YD,0) AS EB_YD            
           , NVL(MC_YD,0) AS EC_YD 
           , NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS ETOT_YD
            , NVL(A_YD,0)+NVL(B_YD,0)+NVL(C_YD,0)+NVL(MA_YD,0)+NVL(MB_YD,0)+NVL(MC_YD,0) AS TOT_YD
 
FROM (
        SELECT 11 AS CHK , 'ЙкЦЧП­ПЌ' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='ЙкЦЧП­ПЌ'
             UNION ALL
         SELECT 12 AS CHK , '1П­ПЌ' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='1П­ПЌ'
           UNION ALL
         SELECT 13 AS CHK ,  '2П­ПЌ' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
         WHERE YD_GP_SPOS='2П­ПЌ'
            UNION ALL
        SELECT 14 AS CHK , 'Аш' AS YD_NAME                  
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS A_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS B_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='МвРч' THEN COIL_WT ELSE 0 END) AS C_YD 
                  , SUM(CASE WHEN YD_GP_ARR='ЙкЦЧП­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MA_YD
                  , SUM(CASE WHEN YD_GP_ARR='1П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MB_YD
                  , SUM(CASE WHEN YD_GP_ARR='2П­ПЌ' AND CHK='СІЧА' THEN COIL_WT ELSE 0 END)  AS MC_YD
          FROM TEMP_TABLE A
          
       )
 )
SELECT
    T.*
  , COUNT(*) OVER(PARTITION BY YD_NAME2) AS GROUP_CNT
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY YD_NAME2 ORDER BY CHK, YD_NAME) = 1 THEN 'Y'
    ELSE 'N' END AS SHOW_ROWSPAN
  , CASE 
    WHEN ROW_NUMBER() OVER(PARTITION BY YD_NAME2 ORDER BY CHK, YD_NAME2) = COUNT(*) OVER(PARTITION BY YD_NAME2) THEN 'Y'
    ELSE 'N' END AS SHOW_SUM
  , CASE WHEN YD_NAME2 = YD_NAME THEN 'Y' ELSE 'N' END AS SHOW_COLSPAN
FROM
(
    SELECT CHK
            ,'РЯАш' AS YD_NAME2
             ,YD_NAME
            , TO_CHAR(ROUND(SA_YD/1000), '9,999,999,999') AS SA_YD
            , TO_CHAR(ROUND(SB_YD/1000), '9,999,999,999') AS SB_YD            
            , TO_CHAR(ROUND(SC_YD/1000), '9,999,999,999') AS SC_YD
            , TO_CHAR(ROUND(STOT_YD/1000), '9,999,999,999') AS STOT_YD
            , TO_CHAR(ROUND(EA_YD/1000), '9,999,999,999') AS EA_YD
            , TO_CHAR(ROUND(EB_YD/1000), '9,999,999,999') AS EB_YD            
            , TO_CHAR(ROUND(EC_YD/1000), '9,999,999,999') AS EC_YD
            , TO_CHAR(ROUND(ETOT_YD/1000), '9,999,999,999') AS ETOT_YD
            , TO_CHAR(ROUND(TOT_YD/1000), '9,999,999,999') AS TOT_YD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD') AS FTMV_HDS_DD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD HH24:MI:SS') AS HDS_DATE
       FROM (
             SELECT  CHK, YD_NAME
                        , SA_YD
                        , SB_YD
                        , SC_YD
                        , STOT_YD
                        , EA_YD
                        , EB_YD
                        , EC_YD
                        , ETOT_YD                        
                        , TOT_YD
                FROM TEMP_TABLE2      
          )
    UNION ALL
    SELECT CHK
            ,'ПљАш' AS YD_NAME2
             ,YD_NAME
            , TO_CHAR(ROUND(SA_YD/1000), '9,999,999,999') AS SA_YD
            , TO_CHAR(ROUND(SB_YD/1000), '9,999,999,999') AS SB_YD            
            , TO_CHAR(ROUND(SC_YD/1000), '9,999,999,999') AS SC_YD
            , TO_CHAR(ROUND(STOT_YD/1000), '9,999,999,999') AS STOT_YD
            , TO_CHAR(ROUND(EA_YD/1000), '9,999,999,999') AS EA_YD
            , TO_CHAR(ROUND(EB_YD/1000), '9,999,999,999') AS EB_YD            
            , TO_CHAR(ROUND(EC_YD/1000), '9,999,999,999') AS EC_YD
            , TO_CHAR(ROUND(ETOT_YD/1000), '9,999,999,999') AS ETOT_YD
            , TO_CHAR(ROUND(TOT_YD/1000), '9,999,999,999') AS TOT_YD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD') AS FTMV_HDS_DD
            ,TO_CHAR(SYSDATE,'YYYY.MM.DD HH24:MI:SS') AS HDS_DATE
       FROM (
             SELECT  CHK
                         , YD_NAME
                        , SA_YD
                        , SB_YD
                        , SC_YD
                        , STOT_YD
                        , EA_YD
                        , EB_YD
                        , EC_YD
                        , ETOT_YD                        
                        , TOT_YD
                FROM TEMP_TABLE3            
          )
) T
ORDER BY T.CHK
 </pre> */
public final static String getSumProgCoilInfoNEW14 = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getSumProgCoilInfoNEW14";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getCustCdPp  
SELECT WB.*
  FROM (SELECT ROWNUM AS RNUM
             , WB.*
          FROM ( SELECT  COUNT(*) OVER() AS TOTALCOUNT
                             , CUST_CD
                             , CUST_KO_NAME
                             , ADDRESS
                             , COMREGNO
                       FROM TB_SM_CUSTINFO
                       WHERE CUST_CD LIKE :V_CUST_CD || '%'
                       AND   CUST_KO_NAME LIKE '%' || :V_CUST_KO_NAME || '%'
                       AND   COMREGNO LIKE :V_COMREGNO || '%') WB
         WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE) WB
 WHERE RNUM >= (( :V_PAGE_NO -1)* :V_PAGE_SIZE ) + 1
 </pre> */
