 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK
WITH TEMP_TABLE AS
(
    SELECT
        :V_YD_CARPNT_CD AS V_YD_CARPNT_CD,
        :V_CAR_KIND     AS V_CAR_KIND,
        (
            SELECT
                ITEM1
            FROM
                USRYFA.TB_YF_RULE
            WHERE 1=1
            AND REPR_CD_GP = 'J00002'
            AND CD_GP = '*'
            AND ITEM  = '*'
        ) AS PRE_SUP_YN
    FROM
        DUAL
)
--//TR--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C' --ЛчПыАЁДЩ
AND B.V_CAR_KIND            = 'TR'
AND A.YD_CAR_USETYPE_GP     IN ('TR', 'RT', 'RA', 'TO')             --ЦЎЗЙРЯЗЏ
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//TT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C' --ЛчПыАЁДЩ
AND B.V_CAR_KIND            = 'TT'
AND A.YD_CAR_USETYPE_GP     IN ('TT', 'AT', 'RT', 'TO')         --TT_CAR
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//PT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C' --ЛчПыАЁДЩ
AND B.V_CAR_KIND            = 'PT'
AND A.YD_CAR_USETYPE_GP     IN ('PT', 'GT', 'AT', 'RA', 'TO')   --PT
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))
 </pre> */
public final static String getYdCarPointCHK = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getPageHelpDocList
-- ЙкЦЧП­ПЌ Ш­Ищ ЕЕПђИЛ - УЗКЮЙЎМ­ ИёЗЯ СЖШИ 
SELECT    D.PAGE_ID   -- Ш­ИщID   
        , D.DOC_SEQ   -- ЙЎМ­ЙјШЃ 
        , D.DOC_NM    -- ЙЎМ­Иэ   
        , D.DOC_PATH  -- ЙЎМ­АцЗЮ 
        , D.REGISTER  -- ЕюЗЯРк   
        , D.REG_DDTT  -- ЕюЗЯ РЯНУ
        , D.MODIFIER  -- МіСЄРк   
        , D.MOD_DDTT  -- МіСЄ РЯНУ
        , D.DEL_YN    -- ЛшСІПЉКЮ 
  FROM USRYFA.TB_YF_HELP_DOC D
 WHERE D.PAGE_ID = :V_PAGE_ID
   AND D.DEL_YN  = 'N'
ORDER BY D.DOC_SEQ DESC
 </pre> */
public final static String getPageHelpDocList = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getPageHelpDocList";

 /** <pre> 
--yf.facilitystatus.facilityinquiry.dao.YardFicilityDAO.getListASPTTracking
SELECT A.YD_STK_COL_GP
      ,A.YD_STK_BED_NO
      ,A.YD_STK_LYR_NO
      ,A.STL_NO
      ,(CASE WHEN B.TAPERED_GP IN ('A''V')
                THEN 'T| '||A.STL_NO
                ELSE A.STL_NO
              END)            AS STL_NO2 --РњРхЧАID2
      ,LEAD(A.STL_NO) OVER (ORDER BY A.YD_STK_COL_GP ASC,A.YD_STK_LYR_NO DESC) AS DOWN_FLAG
      ,(SELECT BUY_SLAB_NO FROM TB_QM_BUYSLABINFO WHERE MSLAB_NO = A.STL_NO) AS BUY_SLAB_NO --БИРдSLABЙјШЃ
      ,D.STOCK_MOVE_TERM
      ,A.YD_STK_LYR_ACTIVE_STAT
      ,A.YD_STK_LYR_STAT
      ,B.SLAB_WT
      ,NVL(B.SLAB_T,0) AS SLAB_T
      ,NVL(B.SLAB_W,0) AS SLAB_W
      ,NVL(B.SLAB_LEN,0) AS SLAB_LEN
      ,B.STACK_LOT_NO
      ,B.INSPECTOR_MSG
      ,B.SPEC_ABBSYM
      ,B.MSLAB_FS_CMPL_DT
      ,B.WO_MSLAB_RPR_MTD
      ,B.SLAB_WO_RT_CD
      ,B.CURR_PROG_CD
      ,(SELECT CS_CMPL_DT FROM TB_CS_CSWR CSWR WHERE CSWR.HEAT_NO = B.HEAT_NO) AS CS_CMPL_DT
      ,(SELECT 'C:'||C_WRSLT||' MN:'||MN_WRSLT FROM TB_PM_HEATWRSLTCOMM WHERE HEAT_NO=B.HEAT_NO) AS SLAB_CNM
      ,(SELECT Z.REPR_CD_CONTENTS 
          FROM TB_YF_RULE Z
         WHERE Z.REPR_CD_GP = 'PM018'
           AND Z.CD_GP = '0'
           AND Z.DEL_YN = 'N'
           AND Z.ITEM = B.CURR_PROG_CD) AS CURR_PROG_CD_NM
      
      ,(CASE WHEN 790 - (TRUNC((SYSDATE - NVL(B.SLAB_CREATE_DDTT,D.REG_DDTT))*24) * DECODE(SCARFING_YN,'Y',1524))<=100 
                          THEN 0 
                          ELSE  790 - (TRUNC((SYSDATE - NVL(B.SLAB_CREATE_DDTT,D.REG_DDTT))*24) * DECODE(SCARFING_YN,'Y',1524)) 
                 END) AS TEMP
      ,C.TRN_EQP_CD
      ,C.YD_PNT_CD  
      ,C.CAR_CARD_NO
      ,C.WLOC_CD 
      ,(SELECT YD_WRK_ALW_WT
          FROM TB_YD_CARSPEC Z
         WHERE Z.TRN_EQP_CD = C.TRN_EQP_CD
           AND Z.DEL_YN = 'N'
           AND ROWNUM = 1) AS YD_WRK_ALW_WT
      ,(SELECT CARSCH.ARR_WLOC_CD
          FROM TB_YD_CARSCH CARSCH
         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
           AND CARSCH.DEL_YN = 'N'
           AND ROWNUM = 1) AS ARR_WLOC_CD
      ,(SELECT CARSCH.SPOS_WLOC_CD
          FROM TB_YD_CARSCH CARSCH
         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
           AND CARSCH.DEL_YN = 'N'
           AND ROWNUM = 1) AS SPOS_WLOC_CD
      ,(SELECT CM.CD_MNNG
          FROM TB_YD_CARSCH CARSCH
              ,VW_CM_CODES CM
         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
           AND CARSCH.DEL_YN = 'N'
           AND CM.CD_EN_ID = 'ARR_WLOC_CD'
           AND CM.CD_CAT_ID = 'HS0000'
           AND CARSCH.ARR_WLOC_CD = CM.CD_VAL
           AND ROWNUM = 1) AS ARR_WLOC_CD_NM
      ,(SELECT CM.CD_MNNG
          FROM TB_YD_CARSCH CARSCH
              ,VW_CM_CODES CM
         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
           AND CARSCH.DEL_YN = 'N'
           AND CM.CD_EN_ID = 'SPOS_WLOC_CD'
           AND CM.CD_CAT_ID = 'HS0000'
           AND CARSCH.SPOS_WLOC_CD = CM.CD_VAL
           AND ROWNUM = 1) AS SPOS_WLOC_CD_NM
      ,(SELECT CARSCH.YD_CAR_PROG_STAT
          FROM TB_YD_CARSCH CARSCH
         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
           AND CARSCH.DEL_YN = 'N'
           AND ROWNUM = 1) AS YD_CAR_PROG_STAT
      ,(SELECT CM.CD_MNNG
          FROM TB_YD_CARSCH CARSCH
              ,VW_CM_CODES CM
         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
           AND CARSCH.DEL_YN = 'N'
           AND CM.CD_EN_ID = 'YD_CAR_PROG_STAT'
           AND CM.CD_CAT_ID = 'HS0000'
           AND CARSCH.YD_CAR_PROG_STAT = CM.CD_VAL
           AND ROWNUM = 1) AS YD_CAR_PROG_STAT_NM
      ,(SELECT RTNHIST.YD_RETHT_RSN_CD
          FROM TB_YD_RETHTHIST RTNHIST
         WHERE RTNHIST.STL_NO = A.STL_NO
           AND RTNHIST.DEL_YN = 'N'
           AND RTNHIST.YD_CAR_SCH_ID = (SELECT MAX(CARSCH.YD_CAR_SCH_ID)
                                          FROM TB_YD_CARSCH CARSCH
                                         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
                                           AND CARSCH.DEL_YN = 'N')
           AND ROWNUM = 1) AS YD_RETHT_RSN_CD
      ,(SELECT RTNHIST.YD_RETHT_RSN_CNTS
          FROM TB_YD_RETHTHIST RTNHIST
         WHERE RTNHIST.STL_NO = A.STL_NO
           AND RTNHIST.DEL_YN = 'N'
           AND RTNHIST.YD_CAR_SCH_ID = (SELECT MAX(CARSCH.YD_CAR_SCH_ID)
                                          FROM TB_YD_CARSCH CARSCH
                                         WHERE CARSCH.TRN_EQP_CD = C.TRN_EQP_CD
                                           AND CARSCH.DEL_YN = 'N')
           AND ROWNUM = 1) AS YD_RETHT_RSN_CNTS
      ,(SELECT ARR_WLOC_CD
          FROM TB_PT_STLFRTOMOVE Z
         WHERE Z.STL_NO = A.STL_NO
           AND Z.TRANSWORD_SEQNO = (SELECT MAX(Y.TRANSWORD_SEQNO)
                                      FROM TB_PT_STLFRTOMOVE Y
                                     WHERE Y.STL_NO = Z.STL_NO)) AS ITEM_ARR_WLOC_CD
      ,D.MKNG_GP
      ,D.CHARGE_LOT_NO
      ,D.YD_RULE_PL_RS_GP
      ,D.BENDING_GP
      ,D.BENDING_AXIS
      ,DECODE(B.ORD_YEOJAE_GP,'1','СжЙЎРч','2','ПЉРч') ORD_YEOJAE_GP_NM --СжЙЎПЉРчБИКаИэ
      ,NVL(CASE 
           WHEN E.ORD_CONV_T < 1 THEN '0' || TO_CHAR(E.ORD_CONV_T)
           ELSE TO_CHAR(E.ORD_CONV_T)
            END,'0') || ' * ' || NVL(E.ORD_CONV_W,'0') AS ORD_TW
      
      ,CASE WHEN A.STL_NO IS NULL AND A.YD_STK_LYR_ACTIVE_STAT = 'C'    THEN '#FF99CC'
            WHEN A.STL_NO IS NULL                                       THEN '#FFFFCC'
            WHEN YD_RULE_PL_RS_GP='Y'                                   THEN '#339933' 
            WHEN CHARGE_LOT_NO IS NOT NULL                              THEN '#FF4500' 
            WHEN B.CURR_PROG_CD = 'K'                                   THEN '#00BFFF' 
            WHEN B.CURR_PROG_CD = 'L'                                   THEN '#1E90FF' 
            ELSE
                CASE WHEN B.REAGENT_PICK_TARGET_YN = 'Y' AND NVL(B.REAGENTPICK_DONE_YN,'N') != 'Y' 
                        THEN 
                            CASE WHEN NVL(B.SCARFING_YN,'N') = 'Y' AND NVL(B.SCARFING_DONE_YN,'N') != 'Y' 
                                    THEN
                                        CASE WHEN B.WO_MSLAB_RPR_MTD = 'Q' THEN '#FF3399' -- НУЦэ CHECKED
                                             WHEN B.WO_MSLAB_RPR_MTD = 'G' THEN '#FF3399' -- НУЦэ CHECKED
                                             WHEN B.WO_MSLAB_RPR_MTD = 'Z' THEN '#FF9B00' -- НУЦэ МеСњФкЕх
                                                                           ELSE '#BBE0E3' -- НУЦэ SCARFING 
                                         END
                                 WHEN B.ORD_YEOJAE_GP='2' THEN '#CCCC66' --ПЉРч
                                 WHEN NVL(B.SCARFING_YN,'N') != 'Y' OR (NVL(B.SCARFING_YN,'N') = 'Y' AND NVL(B.SCARFING_DONE_YN,'N') = 'Y') 
                                    THEN '#FFFF00' -- НУЦэ 
                             END   
                     WHEN NVL(B.REAGENT_PICK_TARGET_YN,'N') != 'Y' OR ( NVL(B.REAGENT_PICK_TARGET_YN,'N') = 'Y' AND NVL(B.REAGENTPICK_DONE_YN,'N') = 'Y') 
                        THEN
                            CASE WHEN NVL(B.SCARFING_YN,'N') = 'Y' AND NVL(B.SCARFING_DONE_YN,'N') != 'Y' 
                                    THEN
                                        CASE WHEN B.WO_MSLAB_RPR_MTD = 'Q' THEN '#CC00CC' -- CHECKED
                                             WHEN B.WO_MSLAB_RPR_MTD = 'G' THEN '#CC00CC' -- CHECKED
                                             WHEN B.WO_MSLAB_RPR_MTD = 'X' THEN '#66FF33' -- CHECKED
                                             WHEN B.WO_MSLAB_RPR_MTD = 'Y' THEN '#CC00CC' -- CHECKED
                                             WHEN B.WO_MSLAB_RPR_MTD = 'Z' THEN '#CD7070' -- МеСњФкЕх
                                                                           ELSE '#66FF33' -- SCARFING 
                                     END
                                 WHEN B.ORD_YEOJAE_GP='2' 
                                    THEN '#CCCC66' --ПЉРч
                                 WHEN NVL(B.SCARFING_YN,'N') != 'Y' OR (NVL(B.SCARFING_YN,'N') = 'Y' AND B.SCARFING_DONE_YN = 'Y') 
                                    THEN '#BFC8BE' 
                              END    
                        END 
                 END AS SLAB_COLOR
FROM TB_YF_STKLYR A
    ,VW_YD_SLABCOMM B
    ,TB_YF_STKCOL C
    ,TB_YF_STOCK D
    ,TB_PT_OSCOMM E
    ,TB_CT_K_HRMILLSPEC H
WHERE A.YD_STK_COL_GP LIKE :V_YD_GP || :V_BAY_GP || '%PT01'
AND   A.YD_STK_LYR_ACTIVE_STAT IN ('O','C')
AND   A.STL_NO = B.SLAB_NO(+)
AND   A.YD_STK_COL_GP = C.YD_STK_COL_GP
AND   A.STL_NO = D.STL_NO(+)
AND   A.STL_NO = H.STL_NO(+)
AND   A.YD_STK_LYR_NO < 7
AND   B.ORD_NO = E.ORD_NO(+)
AND   B.ORD_DTL = E.ORD_DTL(+)
ORDER BY A.YD_STK_COL_GP ASC,A.YD_STK_LYR_NO DESC
 </pre> */
public final static String getListASPTTracking = "bak.yf.facilitystatus.facilityinquiry.dao.YardFicilityDAO.getListASPTTracking";

