 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.getEqpOprnStat 
SELECT 
         A.YD_GP
       , A.YD_BAY_GP
       , A.YD_EQP_NAME
       , A.YD_EQP_ID
       , DECODE(A.YD_EQP_PROG_STAT, 'B', 'АэРх', 'СЄЛѓ') AS YD_EQP_STAT 
       , A.YD_EQP_PROG_STAT
       , D.YD_UP_WR_LYR
       , D.YD_DN_WR_LYR
       , D.YD_ALT_CRN_YN
       , D.YD_ALT_CRN
       , B.YD_EQP_NAME AS YD_ALT_CRN_NM
       , A.YD_EQP_WRK_MODE2 AS YD_EQP_WRK_MODE 
       , D.YD_CRN_SCH_ID
FROM TB_YF_EQP A 
    ,TB_YF_EQP B
    ,(
        SELECT  B.YD_CRN_SCH_ID
              , B.YD_EQP_ID
              , B.YD_WBOOK_ID
              , B.YD_SCH_CD
              , B.YD_WRK_PROG_STAT
              , B.YD_UP_WO_LOC
              , B.YD_UP_WO_LYR
              , B.YD_DN_WO_LOC
              , B.YD_DN_WO_LYR
              , B.YD_UP_WR_LYR
              , B.YD_DN_WR_LYR
              , B.YD_WORD_DT
              , C.YD_ALT_CRN_YN
              , C.YD_ALT_CRN
              , (SELECT MAX(YD_AID_WRK_YN) FROM TB_YF_CRNWRKMTL WHERE YD_CRN_SCH_ID = B.YD_CRN_SCH_ID) AS YD_AID_WRK_YN
              , (SELECT CD_CONTENTS FROM TB_YF_SCHRULE WHERE YD_SCH_CD = B.YD_SCH_CD) AS YD_SCH_CD_NM
          FROM  TB_YF_CRNSCH B, TB_YF_SCHRULE C
         WHERE  B.YD_SCH_CD = C.YD_SCH_CD
           AND  B.YD_GP = C.YD_GP
           AND  B.DEL_YN = C.DEL_YN
           AND  B.DEL_YN = 'N'
           AND  B.YD_WRK_PROG_STAT||B.YD_CRN_SCH_ID IN (
           
                            SELECT MIN(CHK) AS CHK
                            FROM   (
                                        SELECT YD_CRN_SCH_ID
                                              ,YD_WRK_PROG_STAT
                                              ,YD_WBOOK_ID
                                              ,YD_EQP_ID
                                              ,MIN(YD_WRK_PROG_STAT||YD_CRN_SCH_ID) OVER (PARTITION BY  YD_WBOOK_ID ) AS CHK
                                        FROM   TB_YF_CRNSCH
                                        WHERE  DEL_YN = 'N'
                                   )
                            GROUP BY YD_EQP_ID
                        )
      ) D
WHERE A.YD_EQP_ID LIKE :V_YD_EQP_ID  -- МГКёБИКа
  AND A.YD_EQP_ID = D.YD_EQP_ID(+)
  AND D.YD_ALT_CRN = B.YD_EQP_ID(+)
  ORDER BY A.YD_EQP_ID
 </pre> */
public final static String getEqpOprnStat = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getEqpOprnStat";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getA7YML008SangChaEndChk
WITH DATA_TBL AS (
   SELECT TRANS_ORD_DATE
        , TRANS_ORD_SEQNO
     FROM TB_YF_STOCK 
    WHERE STL_NO = :V_STL_NO
)   
SELECT CASE WHEN STOCK_CNT > 0  AND STOCK_CNT <= LAYER_CNT THEN 'Y' 
            ELSE 'N' END AS SANG_CHA_END_YN
  FROM (
        SELECT (
                SELECT COUNT(*) 
                  FROM TB_YF_STOCK A
                     , DATA_TBL    B
                 WHERE A.TRANS_ORD_DATE  = B.TRANS_ORD_DATE
                   AND A.TRANS_ORD_SEQNO = B.TRANS_ORD_SEQNO
               )  AS STOCK_CNT    
             , (SELECT COUNT(DISTINCT(A.STL_NO)) + 1
                  FROM TB_YF_STKLYR A
                 WHERE ((SUBSTR(A.YD_STK_COL_GP,3,2) IN ('PT') AND YD_STK_LYR_STAT = 'C'))
                   AND STL_NO IN (SELECT B.STL_NO
                                      FROM TB_YF_STOCK B
                                         , DATA_TBL    C
                                     WHERE B.TRANS_ORD_DATE  = C.TRANS_ORD_DATE
                                       AND B.TRANS_ORD_SEQNO = C.TRANS_ORD_SEQNO )
               ) AS LAYER_CNT   
               
          FROM DUAL
      )
 </pre> */
public final static String getA7YML008SangChaEndChk = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getA7YML008SangChaEndChk";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCM
SELECT
    BB.YD_STK_COL_GP AS YD_STK_COL_GP,
    BB.YD_PNT_CD
FROM
    (
        SELECT
            MIN(A.YD_STK_COL_GP) AS YD_STK_COL_GP,
            A.YD_PNT_CD,
            SUM(A.COUNT) AS COUNT
        FROM
            (
                SELECT
                    YD_STK_COL_GP,
                    YD_PNT_CD,
                    1 AS COUNT
                FROM
                    TB_YF_STKCOL A
                WHERE 1=1
                AND SUBSTR(YD_STK_COL_GP, 3, 2) IN ('PT')
                AND WLOC_CD = :V_WLOC_CD
                AND BAY_GP  = :V_BAY_GP
                AND TRN_EQP_CD  IS NULL --ЧіРчТїЗЎСЄСіРЇФЁ
                AND CAR_CARD_NO IS NULL --ПЙОрТїЗЎСЄСіРЇФЁ
                AND CARD_NO     IS NULL
            )A
        GROUP BY YD_PNT_CD
    ) AA,
    TB_YD_CARPOINT BB
WHERE 1=1
AND AA.YD_STK_COL_GP = BB.YD_STK_COL_GP  
AND BB.YD_CAR_USETYPE_GP IN ('GT', 'TO')
AND BB.DEL_YN = 'N'
AND COUNT <= '2'
ORDER BY YD_PNT_CD DESC
 </pre> */
public final static String getListloadStoppointCM = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListloadStoppointCM";

 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getCrnSchId 
SELECT NVL(MAX(YD_EQP_WRK_STAT), 'W') AS YD_EQP_WRK_STAT
  FROM TB_YF_CRNSCH 
 WHERE DEL_YN = 'N'
   AND YD_CRN_SCH_ID = (
                        SELECT YD_CRN_SCH_ID
                          FROM TB_YF_CRNSCH 
                         WHERE YD_EQP_ID = :V_YD_EQP_ID 
                           AND DEL_YN    = 'N'
                           AND YD_EQP_WRK_STAT NOT IN ('W')
                        )
 </pre> */
