 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.getblMvStkWrkBookBedPp 
--РЬРћРлОїПЙОрЕюЗЯ BEDСЄКИСЖШИ
SELECT YD_STK_BED_LYR_MAX
      ,MTL_SH_C
      ,MTL_SH_U
      ,MTL_SH_D
      ,WBOOK_SH
      ,(CASE WHEN :V_YD_STK_COL_GP LIKE '1_TY%' AND 6 - MTL_SH_C > 0 THEN 1 ELSE STK_ABLE_SH END) AS STK_ABLE_SH --РћФЁАЁДЩДмМі 
  FROM (     
        SELECT YD_STK_BED_LYR_MAX
              ,MTL_SH_C
              ,MTL_SH_U
              ,MTL_SH_D
              ,WBOOK_SH
              ,(SELECT COUNT(*)
                   FROM
                        (
                         SELECT LYR.YD_STK_COL_GP, LYR.YD_STK_BED_NO, LYR.YD_STK_LYR_NO
                           FROM TB_YF_STKLYR   LYR
                              , TB_YF_STKBED      BED
                          WHERE LYR.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP||'%'
                            AND LYR.YD_STK_BED_NO LIKE :V_YD_STK_BED_NO||'%'
                            AND LYR.STL_NO IS NULL
                            AND LYR.YD_STK_LYR_STAT IN('E')
                            AND LYR.YD_STK_LYR_ACTIVE_STAT IN('E')
                            AND LYR.YD_STK_COL_GP = BED.YD_STK_COL_GP
                            AND LYR.YD_STK_BED_NO = BED.YD_STK_BED_NO
                            AND BED.YD_STK_BED_ACTIVE_STAT IN('L', 'O')
                          GROUP BY LYR.YD_STK_COL_GP, LYR.YD_STK_BED_NO, LYR.YD_STK_LYR_NO
                        ) 
                 ) AS STK_ABLE_SH --РћФЁАЁДЩДмМі               
                
          FROM
                (
                SELECT MAX(YD_STK_BED_LYR_MAX) AS YD_STK_BED_LYR_MAX
                      ,SUM(MTL_SH_C          ) AS MTL_SH_C
                      ,SUM(MTL_SH_U          ) AS MTL_SH_U
                      ,SUM(MTL_SH_D          ) AS MTL_SH_D
                      ,SUM(WBOOK_SH          ) AS WBOOK_SH
                  FROM (SELECT SB.YD_STK_COL_GP
                              ,SB.YD_STK_BED_NO
                              , '2'                   AS YD_STK_BED_LYR_MAX
                              ,NVL(SUM(DECODE(SL.YD_STK_LYR_STAT,'C',1)),0) AS MTL_SH_C
                              ,NVL(SUM(DECODE(SL.YD_STK_LYR_STAT,'U',1)),0) AS MTL_SH_U
                              ,NVL(SUM(DECODE(SL.YD_STK_LYR_STAT,'D',1)),0) AS MTL_SH_D
                              ,NVL(SUM(DECODE(WM.STL_NO,NULL,NULL,1)),0)   AS WBOOK_SH
                          FROM TB_YF_STKBED     SB
                              ,TB_YF_STKLYR  SL
                              ,TB_YF_STKCOL    SC
                              ,TB_YF_WRKBOOKMTL  WM
                         WHERE SB.YD_STK_COL_GP = SL.YD_STK_COL_GP
                           AND SB.YD_STK_COL_GP = SC.YD_STK_COL_GP
                           AND SB.YD_STK_BED_NO = SL.YD_STK_BED_NO
                           AND SB.YD_STK_BED_ACTIVE_STAT = 'L'
                           AND SL.STL_NO     = WM.STL_NO(+)
                           AND 'N'             = WM.DEL_YN(+)
                           AND SB.YD_STK_COL_GP LIKE :V_YD_STK_COL_GP||'%'
                           AND SB.YD_STK_BED_NO LIKE :V_YD_STK_BED_NO||'%'
                         GROUP BY SB.YD_STK_COL_GP, SB.YD_STK_BED_NO
                        ) SL
                )   
        )
 </pre> */
public final static String getblMvStkWrkBookBedPp = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.getblMvStkWrkBookBedPp";

 /** <pre> 
-- com.inisteel.cim.yf.common.dao.YfCommDAO.getselectYdStkColGp 
-- YD_STK_COL_GP(РћФЁП­:УЙЙјТАРкИЎ ОпЕхБИКа, ЕЮЙјТА РкИЎ ЕПБИКа), YD_STK_LYR_STAT(РћФЁДм ЛѓХТ L:РћФЁСп)
SELECT A.YD_STK_COL_GP
     , SUBSTR(A.YD_STK_COL_GP,1,1) YD_STK_COL_GP1
     , SUBSTR(A.YD_STK_COL_GP,2,1) YD_STK_COL_GP2
     , A.YD_STK_BED_NO
     , A.YD_STK_LYR_STAT
     , A.YD_STK_LYR_NO
     , (CASE WHEN (--СЄСЄ НЧРћ УГИЎЕШ ЧзИё Сп УжБй НЧРћРЬ РчРлОїРЮ АцПь УпУт.
                    SELECT COUNT(*)
                      FROM TB_HR_C_SHEARWOWR SR
                     WHERE SR.STEP_NO = (SELECT --+ INDEX_DESC(A PK_HR_C_SHEARWOWR)
                                            MAX (STEP_NO)
                                           FROM TB_HR_C_SHEARWOWR A
                                          WHERE COIL_NO = SR.COIL_NO
                                            AND WORK_STAT = '*'
                                            AND ROWNUM<=1  )
                       AND SR.COIL_NO=A.STL_NO  
                       AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP IN('J','Q')
                  )=1 THEN 'J'   
             WHEN (SELECT COUNT(*) 
                     FROM TB_PT_COILCOMM B
                    WHERE B.COIL_NO=A.STL_NO
                      AND ((B.REMAIN_PROC1='1K' AND B.REMAIN_PROC2='1Q')
                          OR B.REMAIN_PROC1='1Q')
                    --AND B.COIL_T>2.9
                     )=1
              THEN 'Q'
              ELSE 'X' END) AS CHK
  FROM TB_YF_STKLYR  A
WHERE STL_NO = :V_STL_NO
 </pre> */
public final static String getselectYdStkColGp = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getselectYdStkColGp";

