 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK2
WITH TEMP_TABLE AS
(
    SELECT
        :V_YD_CARPNT_CD AS V_YD_CARPNT_CD,
        :V_CAR_KIND     AS V_CAR_KIND,
        (
            SELECT
                ITEM1
            FROM
                USRYFA.TB_YF_RULE
            WHERE 1=1
            AND REPR_CD_GP = 'J00002'
            AND CD_GP = '*'
            AND ITEM  = '*'
        ) AS PRE_SUP_YN
    FROM
        DUAL
)
--//TR--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C'   --ЛчПыАЁДЩ
AND B.V_CAR_KIND            = 'TR'
AND A.YD_CAR_USETYPE_GP     IN ('TR', 'RT', 'RA', 'TO')         --ЦЎЗЙРЯЗЏ
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//TT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C'   --ЛчПыАЁДЩ
AND B.V_CAR_KIND            = 'TT'
AND A.YD_CAR_USETYPE_GP     IN ('TT', 'AT', 'RT', 'TO')         --TT_CAR
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))

UNION ALL

--//PT--------------------------------------
SELECT
    *
FROM
    USRYDA.TB_YD_CARPOINT A,
    TEMP_TABLE B
WHERE 1=1
AND A.YD_CARPNT_CD          LIKE SUBSTR(B.V_YD_CARPNT_CD, 1, 3) ||'%'
AND A.DEL_YN                = 'N'
AND A.YD_STK_COL_ACT_STAT   = 'C'   --ЛчПыАЁДЩ
AND B.V_CAR_KIND            = 'PT'
AND A.YD_CAR_USETYPE_GP     IN ('PT', 'GT', 'AT', 'RA', 'TO')   --PT
AND ((A.YD_CARPNT_CD LIKE '1%' AND B.PRE_SUP_YN = 'N') OR ( A.YD_CARPNT_CD NOT LIKE '1%' AND 1=1))
 </pre> */
public final static String getYdCarPointCHK2 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarPointCHK2";

