 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSchCdWrkBook 
WITH PARAM AS (
    SELECT :V_OPRN      AS V_OPRN
          ,:V_YD_GP     AS V_YD_GP 
          ,:V_YD_BAY_GP AS V_YD_BAY_GP 
      FROM DUAL
)

SELECT YD_SCH_CD AS CD_VAL
     , (SELECT CD_CONTENTS FROM TB_YF_SCHRULE WHERE YD_SCH_CD = A.YD_SCH_CD) AS CD_NM
  FROM (
        SELECT DISTINCT WK.YD_SCH_CD
          FROM TB_YF_WRKBOOKMTL WM
             , TB_YF_WRKBOOK    WK
             , TB_YF_CRNSCH     CR
             , PARAM            P
         WHERE WM.DEL_YN = 'N'
           AND WK.DEL_YN = 'N'
           AND CR.DEL_YN(+) = 'N'
           AND WK.YD_GP  = P.V_YD_GP
           AND WM.YD_WBOOK_ID = WK.YD_WBOOK_ID
           AND WM.YD_WBOOK_ID = CR.YD_WBOOK_ID(+)
           AND WK.YD_BAY_GP LIKE P.V_YD_BAY_GP||'%'
           AND (  ( NVL(P.V_OPRN, 'N') = 'N' AND YD_CRN_SCH_ID IS NULL)
                OR  NVL(P.V_OPRN, 'N') = 'Y')
       ) A
 </pre> */
