 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCrnSchRuleInqjl.getSchRuleMgtList 
-- ХЉЗЙРЮНКФЩСйБтСиСЖШИ 
WITH PARAM AS (
    SELECT :V_YD_GP         AS V_YD_GP
          ,:V_YD_BAY_GP     AS V_YD_BAY_GP
          ,:V_YD_SCH_CD     AS V_YD_SCH_CD
          ,:V_PAGE_NO       AS V_PAGE_NO
          ,:V_PAGE_SIZE     AS V_PAGE_SIZE
      FROM DUAL 
)

SELECT X.RNUM                         AS RNUM                   --RowNum
     , X.TOTAL                        AS TOTALCOUNT             --УбЖѓРЮМі  
     , X.YD_SCH_CD                    AS YD_SCH_CD              --НКФЩСьФкЕх    
     , X.YD_GP                        AS YD_GP                  --ОпЕхБИКа
     , X.YD_BAY_GP                    AS YD_BAY_GP              --ЕПБИКа    
     , X.YD_SCH_RULE_ACT_STAT         AS YD_SCH_RULE_ACT_STAT   --БтСиШАМКШ­ЛѓХТ               
     , X.CD_CONTENTS                  AS CD_CONTENTS            --НКФЩСьИэ      
     , X.YD_SCH_RNG_CD                AS YD_SCH_RNG_CD          --НКФЩСьЙќРЇ                
     , X.YD_SCH_WHIO_GP               AS YD_SCH_WHIO_GP         --НКФЩСьРдУтАэБИКа            
     , X.YD_WRK_CRN                   AS YD_WRK_CRN             --РлОїХЉЗЙРЮ            
     , X.YD_WRK_CRN                   AS YD_WRK_CRN_OLD         --РлОїХЉЗЙРЮ            
     , X.YD_ALT_CRN                   AS YD_ALT_CRN             --ДыУМХЉЗЁРЮ           
     , X.YD_SCH_PROH_EXN              AS YD_SCH_PROH_EXN        --БнСіЧиСІ           
     , X.YD_SCH_DIV_GP                AS YD_SCH_DIV_GP          --НКФЩСьКаЧвБИКа           
     , X.YD_WRK_CRN_PRIOR             AS YD_WRK_CRN_PRIOR       --РлОїХЉЗЙРЮРлОїМјРЇ            
     , X.YD_ALT_CRN_YN                AS YD_ALT_CRN_YN          --ДыУМХЉЗЙРЮРЏЙЋ            
     , X.YD_ALT_CRN_PRIOR             AS YD_ALT_CRN_PRIOR       --ДыУМХЉЗЙРЮРлОїМјРЇ            
     , SUBSTR(X.YD_SCH_RNG_CD, 1, 2)  AS YD_MTL_ITEM            --      
     , SUBSTR(X.YD_SCH_RNG_CD, 3, 2)  AS YD_EQP_GP              --    
     , (SELECT YD_EQP_PROG_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = X.YD_WRK_CRN) AS YD_WRK_EQUIP_STAT
     , (SELECT YD_EQP_PROG_STAT FROM TB_YF_EQP WHERE YD_EQP_ID = X.YD_ALT_CRN) AS YD_ALT_EQUIP_STAT
     , X.DAN_PRIOR
     , X.YD_SCH_AUTO_ST_YN
     , X.ADV_CRN_PRIOR
     , CASE WHEN X.YD_SCH_CD IN ('1EKE02MM','1EKE10UM', '1EYD99MM') THEN 'N' ELSE 'Y' END MODIFY_YN -- МіСЄКвАЁДЩЧб НКФЩСь 
  FROM(SELECT ROWNUM AS RNUM
            ,A.TOTAL
            ,A.YD_SCH_CD
            ,A.YD_GP
            ,A.YD_BAY_GP
            ,A.YD_SCH_RULE_ACT_STAT
            ,A.CD_CONTENTS
            ,A.YD_SCH_RNG_CD
            ,A.YD_SCH_WHIO_GP
            ,A.YD_WRK_CRN
            ,A.YD_ALT_CRN
            ,A.YD_SCH_PROH_EXN
            ,A.YD_SCH_DIV_GP   
            ,A.YD_WRK_CRN_PRIOR
            ,A.YD_ALT_CRN_YN   
            ,A.YD_ALT_CRN_PRIOR
            ,A.DAN_PRIOR
            ,A.YD_SCH_AUTO_ST_YN
            ,A.ADV_CRN_PRIOR
        FROM (SELECT COUNT(*) OVER() AS TOTAL
                ,A.YD_SCH_CD
                ,A.YD_GP
                ,A.YD_BAY_GP
                ,A.YD_SCH_RULE_ACT_STAT
                ,A.CD_CONTENTS
                ,A.YD_SCH_RNG_CD
                ,A.YD_SCH_WHIO_GP
                ,A.YD_WRK_CRN
                ,A.YD_ALT_CRN
                ,A.YD_SCH_PROH_EXN
                ,A.YD_SCH_DIV_GP
                ,A.YD_WRK_CRN_PRIOR
                ,A.YD_ALT_CRN_YN
                ,A.YD_ALT_CRN_PRIOR
                ,A.DAN_PRIOR
                ,A.YD_SCH_AUTO_ST_YN
                ,A.ADV_CRN_PRIOR
            FROM TB_YF_SCHRULE A 
                ,PARAM P
            WHERE A.YD_GP     LIKE '%' || P.V_YD_GP || '%'
            AND A.YD_BAY_GP   LIKE '%' || P.V_YD_BAY_GP || '%'
            AND A.YD_SCH_CD   LIKE '%' || P.V_YD_SCH_CD || '%'
            AND A.DEL_YN = 'N'  
           ORDER BY A.YD_WRK_CRN_PRIOR,A.YD_SCH_CD
           )A, PARAM P
    WHERE ROWNUM <= P.V_PAGE_NO * P.V_PAGE_SIZE) X
        ,PARAM P
 WHERE RNUM >= ((P.V_PAGE_NO-1)* P.V_PAGE_SIZE)+1
 </pre> */
public final static String getSchRuleMgtList = "bak.com.inisteel.cim.yf.acoil.dao.ACoilDAO.acoilCrnSchRuleInqjl.getSchRuleMgtList";

 /** <pre> 
--com.inisteel.cim.yf.common.dao.YfCommDAO.getYdRt
--ОпЕх ЧрМБ
WITH PARAM AS 
(
    SELECT
        :V_YD_GP     AS P_YD_GP,
        :V_YD_SCH_CD AS P_YD_SCH_CD
    FROM
        DUAL
)
SELECT
    *
FROM
    (
        SELECT
            ITEM AS CD_VAL,
            REPR_CD_CONTENTS AS CD_NM,
            'YD_RT' AS CD_TP
        FROM
            TB_YF_RULE,
            PARAM P
        WHERE 1=1
        AND REPR_CD_GP = 'YD_RT'
        AND SUBSTR(CD_GP, 0, 1) = (SELECT P_YD_GP FROM PARAM)
        AND DEL_YN = 'N'       
        AND 
        (
            P.P_YD_SCH_CD LIKE CD_GP||'%'
            OR
            CD_GP = P.P_YD_GP
        )
        
--        ЧЪПфЧЯИщ БзЖЇ УпАЁ 2019 12 26 kbs
--        UNION
--        SELECT
--            CD_VAL,
--            CD_VAL||':'||CD_MNNG AS CD_NM,
--            'CURR_PROG_CD' AS CD_TP
--        FROM
--            BRE.VW_CM_CODES,
--            PARAM P
--        WHERE 1=1
--        AND CD_EN_ID  = 'CURR_PROG_CD'
--        AND CD_CAT_ID = 'PT0110'
--        AND CD_VAL NOT IN ('0','1','A')
--        AND P.P_YD_SCH_CD LIKE '1_YD0_MM'||'%'
        
    )
ORDER BY CASE CD_VAL
         WHEN '1' THEN '0'
         ELSE '1'
          END
 </pre> */
public final static String getYdRt = "bak.com.inisteel.cim.yf.common.dao.YfCommDAO.getYdRt";

