 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarwbookid
SELECT
    A.*
FROM
    TB_YD_CARSCH A,
    (
        SELECT
            TRANS_ORD_DATE,TRANS_ORD_SEQNO
        FROM
            USRYDA.TB_YD_STOCK
        WHERE 1=1
        AND STL_NO= :V_STL_NO
        
        UNION
        
        SELECT
            NVL(TRANS_ORD_DATE2, SUBSTR(TRANS_WORD_NO,1,8)),
            NVL(TRANS_ORD_SEQNO2, SUBSTR(TRANS_WORD_NO,9))
        FROM
            USRYMA.TB_YM_STOCK
        WHERE 1=1
        AND STOCK_ID = :V_STL_NO
        
        UNION
        
        SELECT
            TRANS_ORD_DATE,
            TRANS_ORD_SEQNO
        FROM
            USRYFA.TB_YF_STOCK
        WHERE 1=1
        AND STL_NO =:V_STL_NO
    ) B
WHERE 1=1
AND A.TRANS_ORD_DATE    = B.TRANS_ORD_DATE
AND A.TRANS_ORD_SEQNO   = B.TRANS_ORD_SEQNO
AND DEL_YN              = 'N'
ORDER BY A.YD_CAR_SCH_ID DESC
 </pre> */
public final static String getYdCarwbookid = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarwbookid";

