 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStockLayerCntChk
SELECT
    CASE
    WHEN STOCK_CNT = LAYER_CNT THEN 'Y' --СЄЛѓ
    ELSE 'N' END AS STOCK_LAYER_CHK     --КёСЄЛѓ
FROM
    (
        SELECT
            COUNT(*) AS STOCK_CNT
        FROM
            TB_YF_STOCK
        WHERE 1=1
        AND TRANS_ORD_DATE  = :V_TRANS_ORD_DT
        AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
        AND DEL_YN = 'N'
    ) A,
    (
        SELECT
            COUNT(*) AS LAYER_CNT
        FROM
            TB_YF_STKLYR
        WHERE 1=1
        AND STL_NO IN
        (
            SELECT
                STL_NO
            FROM
                TB_YF_STOCK
            WHERE 1=1
            AND TRANS_ORD_DATE  = :V_TRANS_ORD_DT
            AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
        )
        AND YD_STK_LYR_STAT IN ('C','U','L')
    ) B
WHERE 1=1
AND STOCK_CNT = LAYER_CNT
 </pre> */
public final static String getYdStockLayerCntChk = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStockLayerCntChk";

