 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSectList 
 SELECT A.SECT_GP AS CD_VAL
       ,B.CD_MNNG AS CD_NM
   FROM (
        select SECT_GP 
        from USRYFA.TB_YF_STKCOL 
        WHERE YD_GP     = :V_YD_GP
          AND BAY_GP    = :V_YD_BAY_GP
          AND (SECT_GP IN ('SL','SR','GF','DC','TC')
                OR (  SECT_GP   < '17'
                      AND REGEXP_INSTR(SECT_GP,'[^0-9]') = '0')
              )
        GROUP BY BAY_GP,SECT_GP
        ) A, VW_CM_CODES B
   WHERE B.CD_EN_ID(+) = 'YD_EQP_GP'
     AND B.CD_CAT_ID(+) = 'HS0000'
     AND B.CD_VAL(+) = A.SECT_GP
   ORDER BY CD_VAL
 </pre> */
public final static String getSectList = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSectList";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.stackcolpointchk
SELECT
    YD_STK_COL_GP
FROM
    TB_YF_STKCOL
WHERE 1=1
AND WLOC_CD     = :V_WLOC_CD
AND YD_PNT_CD   = :V_YD_PNT_CD
AND TRN_EQP_CD  IS NULL
AND CAR_NO      IS NULL
AND CARD_NO     IS NULL
AND SUBSTR(YD_STK_COL_GP,3,2) = :V_TRN_EQP_GP
 </pre> */
public final static String stackcolpointchk = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.stackcolpointchk";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStockTransOrdDTWbook
SELECT
    A.STL_NO,
    SUBSTR(B.YD_STK_COL_GP, 2, 1) AS YD_BAY_GP,
    B.YD_STK_COL_GP,
    B.YD_STK_BED_NO,
    B.YD_STK_LYR_NO,
    B.DUMMY_CT
FROM
    USRYFA.TB_YF_STOCK A,
    (
        SELECT
            (NVL2(B.STL_NO, 1, 0) + NVL2(C.STL_NO, 1, 0)) AS DUMMY_CT,
            A.*
        FROM
            USRYFA.TB_YF_STKLYR A,
            USRYFA.TB_YF_STKLYR B,
            USRYFA.TB_YF_STKLYR C
        WHERE 1=1
        AND A.YD_STK_COL_GP = B.YD_STK_COL_GP(+)
        AND LPAD(TO_NUMBER(A.YD_STK_BED_NO) - 1, 2, '0') = B.YD_STK_BED_NO(+)   -- -1ЙшЕх
        AND A.YD_STK_COL_GP = C.YD_STK_COL_GP(+)
        AND A.YD_STK_BED_NO = C.YD_STK_BED_NO(+)
        AND LPAD(TO_NUMBER(A.YD_STK_LYR_NO) + 1, 2, '0') = B.YD_STK_LYR_NO(+)   -- +1Дм
        AND LPAD(TO_NUMBER(A.YD_STK_LYR_NO) + 1, 2, '0') = C.YD_STK_LYR_NO(+)   -- +1Дм
    ) B,
    USRYDA.TB_YD_CARPOINT C
WHERE 1=1
AND A.STL_NO =B.STL_NO
AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DT
AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
AND B.YD_STK_COL_GP LIKE :V_YD_GP || :V_YD_BAY_GP ||'%'
AND C.YD_CARPNT_CD = :V_YD_CARPNT_CD
AND SUBSTR(B.YD_STK_COL_GP, 3, 2) BETWEEN '00' AND '99'
AND SUBSTR(B.YD_STK_COL_GP, 3, 2) BETWEEN C.YD_SPAN_FROM AND C.YD_SPAN_TO
AND B.YD_STK_LYR_STAT IN ('C')
ORDER BY B.DUMMY_CT DESC, B.YD_STK_LYR_NO DESC
 </pre> */
public final static String getYdStockTransOrdDTWbook = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStockTransOrdDTWbook";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR076
SELECT 'YDDMR076'                          AS JMS_TC_CD            --JMSTCФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT   --JMSTCЛ§МКРЯНУ
     , 'YDDMR076'                          AS TC_CODE              --IFБИКаФкЕх
     , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS TC_CREATE_DDTT       --TCЛ§МКРЯНУ
     , CARD_NO		                       AS CARD_NO     
     , CAR_NO		                       AS CAR_NO            
     , SUBSTR(YD_CARUD_STOP_LOC,1,1)       AS YD_GP
     , SUBSTR(NVL(TO_CHAR(C.YD_CARUD_CMPL_DT ,'YYYYMMDDHH24MISS'),:V_WR_DT),1,8)	       AS CARUD_END_DATE
     , SUBSTR(NVL(TO_CHAR(C.YD_CARUD_CMPL_DT ,'YYYYMMDDHH24MISS'),:V_WR_DT),9,6)    	   AS CARUD_END_TIME     
     , TRANS_ORD_DATE                      AS TRANS_WORD_DATE
     , TRANS_ORD_SEQNO                     AS TRANS_WORD_SEQNO   
     , (
            SELECT
                MIN(B.CR_FRTOMOVE_GP) 
            FROM
                TB_YD_CARFTMVMTL A,
                TB_YF_STOCK B
            WHERE 1=1
            AND A.STL_NO = B.STL_NO
            AND A.YD_CAR_SCH_ID = C.YD_CAR_SCH_ID
       )    AS CR_FRTOMOVE_GP
FROM
    TB_YD_CARSCH C
WHERE YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String TcYDDMR076 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDDMR076";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDTSJ010
--МвРчТїЗЎЧЯТїПЯЗс РќЙЎ
SELECT 'YDTSJ010'                          AS JMS_TC_CD          --JMSTCФкЕх
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
      ,TS.TRN_EQP_CD                                             --ПюМлРхКёФкЕх
      ,TS.ARR_WLOC_CD                                            --ТјСіАГМвФкЕх
      ,SC.YD_PNT_CD                        AS ARR_YD_PNT_CD      --ТјСіОпЕхЦїРЮЦЎФкЕх
      ,TO_CHAR(NVL(TS.YD_CARUD_CMPL_DT,SYSDATE),'YYYYMMDDHH24MISS') AS CARUD_CMPL_DT --ЧЯТїПЯЗсРЯНУ
  FROM TB_YF_STKCOL SC
      ,TB_YD_CARSCH TS
 WHERE SC.YD_STK_COL_GP = TS.YD_CARUD_STOP_LOC
   AND TS.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
 </pre> */
public final static String TcYDTSJ010 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.TcYDTSJ010";

 /** <pre> 
--com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarYdCmbnCarldGP
WITH TEMP_TABLE AS
(
    SELECT
        A.TRANS_ORD_DATE,
        A.TRANS_ORD_SEQNO,
        A.YD_GP
    FROM
        (
            SELECT
                B.YD_GP,
                A.STL_NO,
                A.TRANS_ORD_DATE,
                A.TRANS_ORD_SEQNO
            FROM
                USRYDA.TB_YD_STOCK A,
                TB_PT_COILCOMM B
            WHERE 1=1
            AND A.STL_NO = B.COIL_NO 
            AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DATE
            AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
            
            UNION ALL
            
            SELECT
                B.YD_GP,
                A.STOCK_ID,
                A.TRANS_ORD_DATE2,
                A.TRANS_ORD_SEQNO2
            FROM
                USRYMA.TB_YM_STOCK A,
                TB_PT_COILCOMM B
            WHERE 1=1
            AND A.STOCK_ID=B.COIL_NO 
            AND A.TRANS_ORD_DATE2=:V_TRANS_ORD_DATE
            AND A.TRANS_ORD_SEQNO2=:V_TRANS_ORD_SEQNO
            
            UNION ALL
            
            SELECT
                B.YD_GP,
                A.STL_NO,
                A.TRANS_ORD_DATE,
                A.TRANS_ORD_SEQNO
            FROM
                USRYFA.TB_YF_STOCK A,
                TB_PT_COILCOMM B
            WHERE 1=1
            AND A.STL_NO = B.COIL_NO 
            AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DATE
            AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
        ) A
    GROUP BY A.TRANS_ORD_DATE, A.TRANS_ORD_SEQNO, A.YD_GP
)
SELECT
    A.TRANS_ORD_DATE,
    A.TRANS_ORD_SEQNO,
    COUNT(YD_GP) AS CNT,
    (
        SELECT
            B.YD_GP
        FROM
            TEMP_TABLE B
        WHERE 1=1
        AND B.YD_GP <> :V_YD_GP
    ) AS NEXT_YD_GP
FROM
    TEMP_TABLE A
GROUP BY A.TRANS_ORD_DATE ,A.TRANS_ORD_SEQNO
HAVING COUNT(YD_GP) > 1
 </pre> */
public final static String getYdCarYdCmbnCarldGP = "bak.com.inisteel.cim.yf.acoil.dao.AcoilDAO.getYdCarYdCmbnCarldGP";

