 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListAimBay_CCast2
--YDОпЕхРћФЁП­РЧ YD_STKBED_USG_CD ПЁ PALLET СЖШИ Ш­ИщПЁМ­ СіСЄЧб ИёРћЕП СЖШИ
SELECT
    (
        CASE 
        WHEN B.YD_STKBED_USG_CD='D' AND SUBSTR(A.TRN_EQP_CD, 2, 2) ='TR' THEN 'E' 
        ELSE B.YD_STKBED_USG_CD END
    ) AS DEST_BAY,  --ИёРћЕП
    A.TRN_EQP_CD,
    A.YD_CAR_SCH_ID 
FROM
    TB_YD_CARSCH A,
    TB_YD_STKCOL B
WHERE 1=1
AND A.YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
AND A.DEL_YN = 'N'
AND A.YD_CARLD_STOP_LOC = B.YD_STK_COL_GP
AND B.YD_STK_COL_GP LIKE 'A_PT__'
AND B.YD_STKBED_USG_CD IN ('A', 'D', 'E') --A:МіУт, D:УЖМл, E:СжЙЎПм
 </pre> */
public final static String getListAimBay_CCast2 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getListAimBay_CCast2";

 /** <pre> 
-- com.inisteel.cim.yf.acoil.dao.AcoilDAO.acoilYardCarExplainInfo.getYdCoilCarPointBackUp 
-- ТїЗЎЕПАЃРЬРћ 
SELECT YD_STK_COL_GP AS CD_VAL
      ,YD_BAY_GP || 'ЕП (' || YD_STK_COL_GP || ')' AS CD_NM
      ,YD_CARPNT_CD
      ,YD_PNT_CD
      ,WLOC_CD
  FROM TB_YD_CARPOINT
 WHERE YD_GP = :V_YD_GP
  AND YD_CAR_USETYPE_GP = 'MT'
    --AND DEL_YN = 'N'
   AND YD_BAY_GP LIKE :V_YD_BAY_GP || '%'
 ORDER BY YD_STK_COL_GP
 </pre> */
