 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L002
-- РњРхЧАСІПјСЄКИ
SELECT JMS_TC_CD                                     --JMSTCФкЕх
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
      ,JMS_TC_CD                                     --РќЙЎID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')       --Л§МКРЯНУ
     ||RPAD(NVL(MSG_GP                 ,'I'), 1,' ') --РќЙЎБИКа
     ||'0318'                                        --РќЙЎБцРЬ
     ||RPAD(' ',29,' ')                              --РгНУ
     ||RPAD(NVL(YD_INFO_SYNC_CD        ,' '), 1,' ') --ОпЕхСЄКИЕПБтШ­ФкЕх
     ||RPAD(NVL(YD_STL_INFO_SND_SH     ,' '), 3,' ') --ОпЕхРчЗсСЄКИМлНХИХМі
     ||RPAD(NVL(YD_STL_INFO_SND_CNT    ,' '), 3,' ') --ОпЕхРчЗсСЄКИМлНХМјЙј
     ||RPAD(NVL(STL_APPEAR_GP          ,' '), 1,' ') --РчЗсПмЧќБИКа
     ||RPAD(NVL(STL_NO               ,' '),11,' ') --РчЗсЙјШЃ
     ||RPAD(NVL(YD_STR_LOC             ,' '), 8,' ') --ОпЕхРњРхРЇФЁ
     ||RPAD(NVL(YD_STK_LYR_NO         ,' '), 2,' ') --ОпЕхРћФЁДмЙјШЃ
     ||LPAD(NVL(YD_STL_WT              ,'0'), 5,'0') --ОпЕхРчЗсСпЗЎ
     ||LPAD(NVL(YD_STL_T               ,'0'), 6,'0') --ОпЕхРчЗсЕЮВВ
     ||LPAD(NVL(YD_STL_W               ,'0'), 5,'0') --ОпЕхРчЗсЦј
     ||LPAD(NVL(YD_STL_L               ,'0'), 7,'0') --ОпЕхРчЗсБцРЬ
     ||LPAD(NVL(MAT_ODIA               ,'0'), 5,'0') --РчЗсПмАц
     ||LPAD(NVL(MAT_IDIA               ,'0'), 5,'0') --РчЗсГЛАц
     ||RPAD(NVL(STLKIND_CD             ,' '), 3,' ') --А­СО
     ||RPAD(NVL(SPEC_ABBSYM            ,' '),15,' ') --БдАнОрШЃ
     ||RPAD(NVL(YD_IPGO_DD             ,' '),14,' ') --ОпЕхРдАэРЯРк
     ||RPAD(NVL(PLNT_PROC_CD           ,' '), 3,' ') --АјРхАјСЄФкЕх
     ||RPAD(NVL(CURR_PROG_CD           ,' '), 1,' ') --ЧіРчСјЕЕФкЕх
     ||RPAD(NVL(ORD_YEOJAE_GP          ,' '), 1,' ') --СжЙЎПЉРчБИКа
     ||RPAD(NVL(ORD_NO                 ,' '),10,' ') --СжЙЎЙјШЃ
     ||RPAD(NVL(ORD_DTL                ,' '), 3,' ') --СжЙЎЧрЙј
     ||RPAD(NVL(BUY_SLAB_NO            ,' '),30,' ') --БИРдSLABЙјШЃ
     ||RPAD(NVL(SLAB_WO_RT_CD          ,' '), 2,' ') --SLABСіНУЧрМБФкЕх
     ||RPAD(NVL(ORD_HCR_GP             ,' '), 1,' ') --МГАшHCRБИКа
     ||RPAD(NVL(HCR_GP                 ,' '), 1,' ') --HCRБИКа
     ||RPAD(NVL(CC_MC_CD               ,' '), 1,' ') --ПЌСжMachineФкЕх
     ||RPAD(NVL(SCARFING_YN            ,' '), 1,' ') --SCARFINGПЉКЮ
     ||RPAD(NVL(SCARFING_DONE_YN       ,' '), 1,' ') --SCARFINGПЯЗсРЏЙЋ
     ||RPAD(NVL(RPR_MTD                ,' '), 1,' ') --СжЦэМеСњЙцЙ§
     ||RPAD(NVL(SCARFING_DEPTH         ,' '), 2,' ') --SCARFINGБэРЬ
     ||RPAD(NVL(REHEAT_SLAB_GP         ,' '), 1,' ') --РчП­РчБИКа
     ||RPAD(NVL(PTOP_PLNT_GP           ,' '), 2,' ') --СЖОїАјРхБИКа
     ||RPAD(NVL(REFUR_CHG_LOT_NO       ,' '),10,' ') --АЁП­ЗЮРхРдLotЙјШЃ
     ||LPAD(NVL(CT_LOT_SCH_SERNO       ,'0'),22,'0') --Л§ЛъХыСІLotНКФЩСйРЯЗУЙјШЃ
     ||RPAD(NVL(FRTOMOVE_ORD_DATE      ,' '), 8,' ') --РЬМлСіНУРЯРк
     ||RPAD(NVL(FRTOMOVE_PLANT_GP      ,' '), 2,' ') --РЬМлАјРхБИКа
     ||RPAD(NVL(URGENT_FRTOMOVE_WORD_GP,' '), 1,' ') --БфБоРЬМлРлОїСіНУБИКа
     ||RPAD(NVL(HYSCO_TRANS_CLS        ,' '), 1,' ') --HYSCOПюМлБИКа
     ||RPAD(NVL(APPEAR_GRADE           ,' '), 1,' ') --ПмАќСОЧеЦЧСЄЕюБо
     ||RPAD(NVL(COOL_METHOD            ,' '), 1,' ') --БЧУыФкРЯГУАЂЙцЙ§
     ||RPAD(NVL(COOL_DONE_GP           ,' '), 1,' ') --ГУАЂПЯЗсБИКа
     ||RPAD(NVL(CONV_BRANCH_CD         ,' '), 2,' ') --ОпЕхConveyorКаБтФкЕх
     ||RPAD(NVL(CUST_KO_NAME           ,' '),40,' ') --АэАДЛчИэ
     ||RPAD(NVL(DEST_CD                ,' '), 5,' ') --ИёРћСіФкЕх
     ||RPAD(NVL(DLVRDD_RULE_DD         ,' '), 8,' ') --ГГБтБтСиРЯ
     ||RPAD(NVL(ITEMNAME_CD            ,' '), 3,' ') --ЧАИэФкЕх
     ||RPAD(NVL(OVERALL_STATAMP_GRADE  ,' '), 1,' ') --СОЧеЦЧСЄЕюБо
     ||RPAD(NVL(ORD_GP                 ,' '), 1,' ') --МіСжБИКа
     ||RPAD(NVL(YD_STK_LOT_TP          ,' '), 2,' ') --ОпЕхЛъРћLotType
     ||RPAD(NVL(YD_STK_LOT_CD          ,' '),18,' ') --ОпЕхЛъРћLotФкЕх
     ||RPAD(NVL(YD_PLAN_PROC           ,' '),10,' ') --АшШЙАјСЄ
     ||RPAD(NVL(YD_PASS_PROC           ,' '),10,' ') --ХыАњАјСЄ
     ||RPAD(NVL(YD_NEXT_PROC           ,' '), 2,' ') --ДйРНАјСЄ
     ||RPAD(NVL(HRMILL_CMPL_DT         ,' '),14,' ') --П­ПЌОаПЌПЯЗсРЯНУ

       AS JMS_TC_MESSAGE --JMSTCMESSAGE
FROM (

        SELECT   'YFF1L002'                             AS JMS_TC_CD                --РќЙЎID
               , :V_MSG_GP                              AS MSG_GP                   --РќЙЎБИКа
               , :V_YD_INFO_SYNC_CD                     AS YD_INFO_SYNC_CD          --ОпЕхСЄКИЕПБтШ­ФкЕх
               , '001'                                  AS YD_STL_INFO_SND_SH       --ОпЕхРчЗсСЄКИМлНХИХМі
               , '001'                                  AS YD_STL_INFO_SND_CNT      --ОпЕхРчЗсСЄКИМлНХМјЙј
               , CC.STL_APPEAR_GP                       AS STL_APPEAR_GP            --РчЗсПмЧќБИКа
               , ST.STL_NO                              AS STL_NO                 --РчЗсЙјШЃ
               , LY.YD_STK_COL_GP || LY.YD_STK_BED_NO   AS YD_STR_LOC               --ОпЕхРњРхРЇФЁ
               , LY.YD_STK_LYR_NO                       AS YD_STK_LYR_NO           --ОпЕхРћФЁДмЙјШЃ
               , TO_CHAR(CC.COIL_WT    , 'FM00000'  )   AS YD_STL_WT                --ОпЕхРчЗсСпЗЎ
               , TO_CHAR(CC.COIL_T     , 'FM000V000')   AS YD_STL_T                 --ОпЕхРчЗсЕЮВВ
               , TO_CHAR(CC.COIL_W     , 'FM0000V0' )   AS YD_STL_W                 --ОпЕхРчЗсЦј
               , TO_CHAR(CC.COIL_LEN   , 'FM0000000')   AS YD_STL_L                 --ОпЕхРчЗсБцРЬ
               , TO_CHAR(CC.COIL_OUTDIA, 'FM00000'  )   AS MAT_ODIA                 --РчЗсПмАц
               , TO_CHAR(CC.COIL_INDIA , 'FM0000V0' )* 25.4   AS MAT_IDIA                 --РчЗсГЛАц
               , NULL                                   AS STLKIND_CD               --А­СО
               , CC.SPEC_ABBSYM                         AS SPEC_ABBSYM              --БдАнОрШЃ
               , CC.RECEIPT_DATE                        AS YD_IPGO_DD               --ОпЕхРдАэРЯРк
               , CC.PLNT_PROC_CD                        AS PLNT_PROC_CD             --АјРхАјСЄФкЕх
               , CC.CURR_PROG_CD                        AS CURR_PROG_CD             --ЧіРчСјЕЕФкЕх
               , CC.ORD_YEOJAE_GP                       AS ORD_YEOJAE_GP            --СжЙЎПЉРчБИКа
               , CC.ORD_NO                              AS ORD_NO                   --СжЙЎЙјШЃ
               , CC.ORD_DTL                             AS ORD_DTL                  --СжЙЎЧрЙј
               , NULL                                   AS BUY_SLAB_NO              --БИРдSLABЙјШЃ
               , NULL                                   AS SLAB_WO_RT_CD            --SLABСіНУЧрМБФкЕх
               , OC.ORD_HCR_GP                          AS ORD_HCR_GP               --МГАшHCRБИКа
               , CC.HCR_GP                              AS HCR_GP                   --HCRБИКа
               , NULL                                   AS CC_MC_CD                 --ПЌСжMachineФкЕх
               , NULL                                   AS SCARFING_YN              --SCARFINGПЉКЮ
               , NULL                                   AS SCARFING_DONE_YN         --SCARFINGПЯЗсРЏЙЋ
               , NULL                                   AS RPR_MTD                  --СжЦэМеСњЙцЙ§
               , NULL                                   AS SCARFING_DEPTH           --SCARFINGБэРЬ
               , NULL                                   AS REHEAT_SLAB_GP           --РчП­РчБИКа
               , CC.PTOP_PLNT_GP                        AS PTOP_PLNT_GP             --СЖОїАјРхБИКа
               , NULL                                   AS REFUR_CHG_LOT_NO         --АЁП­ЗЮРхРдLotЙјШЃ
               , NULL                                   AS CT_LOT_SCH_SERNO         --Л§ЛъХыСІLotНКФЩСйРЯЗУЙјШЃ
               , CC.FRTOMOVE_ORD_DATE                   AS FRTOMOVE_ORD_DATE         --РЬМлСіНУРЯРк
               , CC.FRTOMOVE_PLANT_GP                   AS FRTOMOVE_PLANT_GP         --РЬМлАјРхБИКа
               , ''                                     AS URGENT_FRTOMOVE_WORD_GP  --БфБоРЬМлРлОїСіНУБИКа
               , CC.HYSCO_TRANS_GP                      AS HYSCO_TRANS_CLS          --HYSCOПюМлБИКа
               , CC.APPEAR_GRADE                        AS APPEAR_GRADE             --ПмАќСОЧеЦЧСЄЕюБо
               , OC.COOL_METHOD                         AS COOL_METHOD              --БЧУыФкРЯГУАЂЙцЙ§
               , CC.COOL_DONE_GP                                   AS COOL_DONE_GP             --ГУАЂПЯЗсБИКа
               , NULL                                   AS CONV_BRANCH_CD           --ОпЕхConveyorКаБтФкЕх
               , (SELECT REPLACE(CUST_KO_NAME,'Ђп','(Сж)')
                    FROM TB_SM_CUSTINFO
                   WHERE CUST_CD = OC.CUST_CD)          AS CUST_KO_NAME             --АэАДЛчИэ
               , OC.DEST_CD                             AS DEST_CD                  --ИёРћСіФкЕх
               , TO_CHAR(OC.ORD_CONS_DATE,'YYYYMMDD')   AS DLVRDD_RULE_DD           --ГГБтБтСиРЯ
               , CC.ITEMNAME_CD                         AS ITEMNAME_CD              --ЧАИэФкЕх
               , CC.OVERALL_STAMP_GRADE                 AS OVERALL_STATAMP_GRADE    --СОЧеЦЧСЄЕюБо
               , OC.ORD_GP                              AS ORD_GP                   --МіСжБИКа
               , NULL                                   AS YD_STK_LOT_TP             --ОпЕхЛъРћLotType
               , NULL                                   AS YD_STK_LOT_CD             --ОпЕхЛъРћLotФкЕх
               , CC.PLAN_PROC1||CC.PLAN_PROC2||CC.PLAN_PROC3||CC.PLAN_PROC4||CC.PLAN_PROC5  AS YD_PLAN_PROC  --АшШЙАјСЄ
               , CC.PASS_PROC1||CC.PASS_PROC2||CC.PASS_PROC3||CC.PASS_PROC4||CC.PASS_PROC5  AS YD_PASS_PROC  --ХыАњАјСЄ
               , CC.NEXT_PROC                           AS YD_NEXT_PROC              --ДйРНАјСЄ
               , TO_CHAR(CC.HRMILL_CMPL_DT,'YYYYMMDDHH24MISS') AS HRMILL_CMPL_DT     --П­ПЌОаПЌПЯЗсРЯНУ

          FROM
                 TB_YF_STOCK ST
               , TB_YF_STKLYR LY
               , TB_PT_COILCOMM CC
               , TB_PT_OSCOMM OC

         WHERE ST.STL_NO = :V_STL_NO
           AND ST.STL_NO = LY.STL_NO(+)
           AND ST.STL_NO = CC.COIL_NO
           AND CC.ORD_NO  = OC.ORD_NO(+)
           AND CC.ORD_DTL = OC.ORD_DTL(+)
           AND LY.YD_STK_LYR_STAT IN ('C','U')
           AND ROWNUM = 1
     )
 </pre> */
public final static String getYFF1L002 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L002";

