 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarYdCmbnCarSch
SELECT
    C.*
FROM
    USRYDA.TB_YD_STOCK A,
    USRYDA.TB_YD_STKLYR B,
    USRYDA.TB_YD_CARPOINT C
WHERE 1=1
AND A.STL_NO = B.STL_NO
AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DATE
AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
AND SUBSTR(B.YD_STK_COL_GP, 3, 2) BETWEEN C.YD_SPAN_FROM AND C.YD_SPAN_TO
AND SUBSTR(B.YD_STK_COL_GP, 1, 1) = C.YD_GP
AND 'J' = :V_YD_GP

UNION ALL

SELECT
	C.*
FROM
	USRYMA.TB_YM_STOCK A,
	USRYMA.TB_YM_STACKLAYER B,
	USRYDA.TB_YD_CARPOINT C
WHERE 1=1
AND A.STOCK_ID=B.STOCK_ID 
AND A.TRANS_ORD_DATE2=:V_TRANS_ORD_DATE
AND A.TRANS_ORD_SEQNO2=:V_TRANS_ORD_SEQNO
AND SUBSTR(B.STACK_COL_GP,3,2) BETWEEN C.YD_SPAN_FROM AND C.YD_SPAN_TO
AND SUBSTR(B.STACK_COL_GP,1,1)=C.YD_GP
AND :V_YD_GP = '3'

UNION ALL

SELECT
    C.*
FROM
    USRYFA.TB_YF_STOCK A,
    USRYFA.TB_YF_STKLYR B,
    USRYDA.TB_YD_CARPOINT C
WHERE 1=1
AND A.STL_NO = B.STL_NO 
AND A.TRANS_ORD_DATE = :V_TRANS_ORD_DATE
AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
AND SUBSTR(B.YD_STK_COL_GP, 3, 2) BETWEEN C.YD_SPAN_FROM AND C.YD_SPAN_TO
AND SUBSTR(B.YD_STK_COL_GP, 1, 1) = C.YD_GP
AND :V_YD_GP = '1'
 </pre> */
public final static String getYdCarYdCmbnCarSch = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdCarYdCmbnCarSch";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStkcolStackColGp
SELECT
    A.YD_STK_COL_GP AS YD_STK_COL_GP,
    A.CAR_NO        AS CAR_NO,
    A.CARD_NO       AS CARD_NO,
    A.WLOC_CD       AS WLOC_CD,
    A.YD_PNT_CD     AS YD_PNT_CD,
    B.YD_CARPNT_CD  AS YD_CARPNT_CD
FROM
    TB_YF_STKCOL A,
    TB_YD_CARPOINT B
WHERE 1=1
AND B.YD_STK_COL_GP = A.YD_STK_COL_GP
AND A.YD_STK_COL_GP = :V_YD_STK_COL_GP
 </pre> */
public final static String getYdStkcolStackColGp = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYdStkcolStackColGp";

 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L001 
WITH PARAM AS (
    SELECT :V_YD_INFO_SYNC_CD   AS V_YD_INFO_SYNC_CD
          ,:V_YD_STK_COL_GP     AS V_YD_STK_COL_GP
          ,:V_YD_STK_BED_NO     AS V_YD_STK_BED_NO
      FROM DUAL
)

SELECT JMS_TC_CD                                  --JMSTCФкЕх
      ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ
      ,JMS_TC_CD                                  --РќЙЎID
     ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS')    --Л§МКРЯНУ
     ||'I'                                        --РќЙЎБИКа
     ||'0090'                                     --РќЙЎБцРЬ
     ||RPAD(' ',29,' ')                           --РгНУ
     ||RPAD(NVL(YD_INFO_SYNC_CD     ,' '), 1,' ') --ОпЕхСЄКИЕПБтШ­ФкЕх
     ||RPAD(NVL(YD_GP               ,' '), 1,' ') --ОпЕхБИКа
     ||RPAD(NVL(BAY_GP              ,' '), 1,' ') --ОпЕхЕПБИКа
     ||RPAD(NVL(SECT_GP             ,' '), 2,' ') --ОпЕхМГКёБИКа
     ||RPAD(NVL(COL_GP              ,' '), 2,' ') --ОпЕхРћФЁП­ЙјШЃ
     ||RPAD(NVL(YD_STK_BED_NO        ,' '), 2,' ') --ОпЕхРћФЁBedЙјШЃ
     ||RPAD(NVL(YD_STK_LYR_NO      ,' '), 2,' ') --ОпЕхРћФЁДмЙјШЃ
     ||RPAD(NVL(YS_STK_BED_L_GP     ,' '), 1,' ') --ОпЕхРћФЁBedБцРЬБИКа
     ||RPAD(NVL(YS_STK_BED_W_GP     ,' '), 1,' ') --ОпЕхРћФЁBedЦјБИКа
     ||RPAD(NVL(YD_STK_BED_DIR_GP   ,' '), 1,' ') --ОпЕхРћФЁBedЙцЧтБИКа
     ||RPAD(NVL(YD_STK_BED_ACTIVE_STAT ,' '), 1,' ') --ОпЕхРћФЁBedШАМКЛѓХТ
     ||RPAD(NVL(YD_STK_BED_WHIO_STAT,' '), 1,' ') --ОпЕхРћФЁBedРдУтАэЛѓХТ
     ||RPAD(NVL(YD_STK_BED_XAXIS    ,' '), 7,' ') --ОпЕхРћФЁBedXУр(СжЧр)
     ||RPAD(NVL(YD_STK_BED_YAXIS    ,' '), 5,' ') --ОпЕхРћФЁBedYУр(СжЧр)
     ||RPAD(NVL(YD_STK_BED_ZAXIS_SYM,' '), 1,' ') --ОпЕхРћФЁBedZУрКЮШЃ
     ||RPAD(NVL(YD_STK_BED_ZAXIS    ,' '), 5,' ') --ОпЕхРћФЁBedZУр(СжЧр)
     ||RPAD(NVL(YD_STK_BED_LYR_MAX  ,' '), 3,' ') --ОпЕхРћФЁBedДмMax
     ||RPAD(NVL(YD_STK_BED_WT_MAX   ,' '), 7,' ') --ОпЕхРћФЁBedСпЗЎMax
     ||RPAD(NVL(YD_STK_BED_H_MAX    ,' '), 5,' ') --ОпЕхРћФЁBedГєРЬMax
     ||RPAD(NVL(YD_STK_BED_L_MAX    ,' '), 5,' ') --ОпЕхРћФЁBedБцРЬMax
     ||RPAD(NVL(YD_STK_BED_W_MAX    ,' '), 5,' ') --ОпЕхРћФЁBedЦјMax
     ||RPAD(NVL(YD_CAR_ARRSTRT_STAT ,' '), 1,' ') --ОпЕхТїЗЎТјЙпЛѓХТ
     ||RPAD(NVL(YD_CAR_USE_GP       ,' '), 1,' ') --ОпЕхТїЗЎЛчПыБИКа
     ||RPAD(NVL(YD_EQP_WRK_STAT     ,' '), 1,' ') --ОпЕхМГКёРлОїЛѓХТ
     ||RPAD(NVL(CAR_NO              ,' '),15,' ') --ТїЗЎЙјШЃ
     ||RPAD(NVL(TRN_EQP_CD          ,' '), 8,' ') --ПюМлРхКёФкЕх
     ||RPAD(NVL(CARD_NO             ,' '), 4,' ') --ФЋЕхЙјШЃ
     ||RPAD(NVL(YD_CAR_AIM_YD_GP    ,' '), 1,' ') --ОпЕхТїЗЎИёЧЅОпЕхБИКа
       AS JMS_TC_MESSAGE --JMSTCMessage
  FROM (
  
        SELECT 'YFF1L001'                                        AS JMS_TC_CD
              ,P.V_YD_INFO_SYNC_CD                               AS YD_INFO_SYNC_CD
              ,SC.YD_GP                                          AS YD_GP
              ,SC.BAY_GP                                         AS BAY_GP
              ,SC.SECT_GP                                        AS SECT_GP
              ,SC.COL_GP                                         AS COL_GP 
              ,SC.YD_STK_COL_GP                                  AS YD_STK_COL_GP
              ,SB.YD_STK_BED_NO                                  AS YD_STK_BED_NO
              ,SL.YD_STK_LYR_NO                                  AS YD_STK_LYR_NO
              ,''                                                AS YS_STK_BED_L_GP
              ,''                                                AS YS_STK_BED_W_GP
              ,SC.ROTATION_ANGLE                                 AS YD_STK_BED_DIR_GP
              ,DECODE(SL.YD_STK_LYR_ACTIVE_STAT,'E','L',SL.YD_STK_LYR_ACTIVE_STAT ) AS YD_STK_BED_ACTIVE_STAT
              ,''                                                AS YD_STK_BED_WHIO_STAT
              ,TO_CHAR(NVL(SL.YD_STK_LYR_X_AXIS,0)  ,'FM0000000') AS YD_STK_BED_XAXIS
              ,TO_CHAR(NVL(SL.YD_STK_LYR_Y_AXIS,0)  ,'FM00000'  ) AS YD_STK_BED_YAXIS
              ,CASE WHEN SL.YD_STK_LYR_Z_AXIS >= 0  THEN '+'
                    ELSE '-' END                                 AS YD_STK_BED_ZAXIS_SYM
              ,TO_CHAR(NVL(ABS(SL.YD_STK_LYR_Z_AXIS),0)  ,'FM00000'  ) AS YD_STK_BED_ZAXIS
              ,TO_CHAR(SB.YD_STK_BED_ABLE_QNTY      ,'FM000'    ) AS YD_STK_BED_LYR_MAX
              ,TO_CHAR(SB.YD_STK_BED_WT_MAX         ,'FM0000000V0' ) AS YD_STK_BED_WT_MAX
              ,TO_CHAR(SB.YD_STK_BED_HIGH_MAX       ,'FM00000V000' ) AS YD_STK_BED_H_MAX
              ,TO_CHAR(SB.YD_STK_BED_LEN_MAX        ,'FM00000V000' ) AS YD_STK_BED_L_MAX
              ,TO_CHAR(SB.YD_STK_BED_W_MAX          ,'FM00000V000' ) AS YD_STK_BED_W_MAX
              ,DECODE(TS.YD_CAR_PROG_STAT,'5','S','E','S','2','A','B','A','A') -- DEFALUT A
                                                                 AS YD_CAR_ARRSTRT_STAT
              ,SC.YD_CAR_USE_GP                                  AS YD_CAR_USE_GP
              ,TS.YD_EQP_WRK_STAT                                AS YD_EQP_WRK_STAT
              ,SC.CAR_NO                                         AS CAR_NO
              ,SC.TRN_EQP_CD                                     AS TRN_EQP_CD
              ,SC.CARD_NO                                        AS CARD_NO
              ,TS.YD_CAR_AIM_YD_GP                               AS YD_CAR_AIM_YD_GP 
          FROM TB_YF_STKBED    SB
             , TB_YF_STKCOL   SC
             , TB_YF_STKLYR SL
             , (SELECT YD_STK_COL_GP
                      ,SUBSTR(YD_CARUD_STOP_LOC,1,1) AS YD_CAR_AIM_YD_GP
                      ,YD_CAR_PROG_STAT
                      ,YD_EQP_WRK_STAT
                  FROM (SELECT SC.YD_STK_COL_GP
                              ,TS.YD_CARUD_STOP_LOC
                              ,TS.YD_CAR_PROG_STAT
                              ,TS.YD_EQP_WRK_STAT
                              ,ROW_NUMBER() OVER (ORDER BY TS.YD_CAR_SCH_ID DESC) AS RN
                          FROM TB_YF_STKCOL SC
                              ,TB_YD_CARSCH TS
                              ,PARAM P
                         WHERE SC.YD_STK_COL_GP = P.V_YD_STK_COL_GP
                           AND SUBSTR(SC.YD_STK_COL_GP,3,2) IN ('TR','PT')
                           AND SC.DEL_YN        = 'N'
                           AND TS.DEL_YN        = 'N'
                           AND ((TS.TRN_EQP_CD    = SC.TRN_EQP_CD
                             AND SC.YD_CAR_USE_GP = 'L')  --БИГЛПюМл
                             OR (TS.CAR_NO        = SC.CAR_NO
                             AND TS.CARD_NO       = SC.CARD_NO
                             AND SC.YD_CAR_USE_GP = 'G')) --УтЧЯТїЗЎ
                         UNION ALL
                        SELECT SC.YD_STK_COL_GP
                              ,TS.YD_CARUD_STOP_LOC
                              ,TS.YD_CAR_PROG_STAT
                              ,TS.YD_EQP_WRK_STAT
                              ,ROW_NUMBER() OVER (ORDER BY TS.YD_TCAR_SCH_ID DESC) AS RN
                          FROM TB_YF_STKCOL  SC
                              ,TB_YF_TCARSCH TS
                              ,PARAM P
                         WHERE SC.YD_STK_COL_GP = P.V_YD_STK_COL_GP
                           AND SC.YD_STK_COL_GP LIKE '__TC%'
                           AND SC.DEL_YN        = 'N'
                           AND TS.YD_EQP_ID     = SUBSTR(SC.YD_STK_COL_GP,1,1)||'X'||SUBSTR(SC.YD_STK_COL_GP,3)
                           AND TS.DEL_YN        = 'N')
                 WHERE RN = 1) TS
              ,PARAM P
         WHERE SC.YD_STK_COL_GP = SB.YD_STK_COL_GP
           AND SB.YD_STK_COL_GP = SL.YD_STK_COL_GP
           AND SB.YD_STK_BED_NO = SL.YD_STK_BED_NO
           AND SC.YD_STK_COL_GP = TS.YD_STK_COL_GP(+)
           AND SB.YD_STK_COL_GP LIKE NVL(P.V_YD_STK_COL_GP,'X')||'%'
           AND SB.YD_STK_BED_NO LIKE (CASE WHEN SUBSTR(SC.YD_STK_COL_GP,3,2) = 'PT' THEN '01' ELSE P.V_YD_STK_BED_NO END) ||'%'
           AND SC.DEL_YN = 'N'
           AND SB.DEL_YN = 'N'
           AND SL.DEL_YN = 'N'
         ORDER BY BAY_GP, SECT_GP, YD_STK_COL_GP, YD_STK_BED_NO, YD_STK_LYR_NO   
       )
 </pre> */
public final static String getYFF1L001 = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L001";

 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L001_CarInfo   
 
 SELECT JMS_TC_CD --JMSTCФкЕх  
 ,TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS JMS_TC_CREATE_DDTT --JMSTCЛ§МКРЯНУ  
 ,JMS_TC_CD --РќЙЎID  
 ||TO_CHAR(SYSDATE,'YYYY-MM-DDHH24:MI:SS') --Л§МКРЯНУ  
 ||'I' --РќЙЎБИКа  
 ||'0090' --РќЙЎБцРЬ  
 ||RPAD(' ',29,' ') --РгНУ  
 ||RPAD(NVL(YD_INFO_SYNC_CD ,' '), 1,' ') --ОпЕхСЄКИЕПБтШ­ФкЕх  
 ||RPAD(NVL(YD_GP ,' '), 1,' ') --ОпЕхБИКа  
 ||RPAD(NVL(BAY_GP ,' '), 1,' ') --ОпЕхЕПБИКа  
 ||RPAD(NVL(SECT_GP ,' '), 2,' ') --ОпЕхМГКёБИКа  
 ||RPAD(NVL(COL_GP ,' '), 2,' ') --ОпЕхРћФЁП­ЙјШЃ  
 ||RPAD(NVL(YD_STK_BED_NO ,' '), 2,' ') --ОпЕхРћФЁBedЙјШЃ  
 ||RPAD(NVL(YD_STK_LYR_GP ,' '), 2,' ') --ОпЕхРћФЁДмЙјШЃ  
 ||RPAD(NVL(YS_STK_BED_L_GP ,' '), 1,' ') --ОпЕхРћФЁBedБцРЬБИКа  
 ||RPAD(NVL(YS_STK_BED_W_GP ,' '), 1,' ') --ОпЕхРћФЁBedЦјБИКа  
 ||RPAD(NVL(YD_STK_BED_DIR_GP ,' '), 1,' ') --ОпЕхРћФЁBedЙцЧтБИКа  
 ||RPAD(NVL(YD_STK_BED_ACT_STAT ,' '), 1,' ') --ОпЕхРћФЁBedШАМКЛѓХТ  
 ||RPAD(NVL(YD_STK_BED_WHIO_STAT,' '), 1,' ') --ОпЕхРћФЁBedРдУтАэЛѓХТ  
 ||LPAD(NVL(YD_STK_BED_XAXIS ,'0'), 7,'0') --ОпЕхРћФЁBedXУр(СжЧр)  
 ||LPAD(NVL(YD_STK_BED_YAXIS ,'0'), 5,'0') --ОпЕхРћФЁBedYУр(СжЧр)  
 ||RPAD(NVL(YD_STK_BED_ZAXIS_SYM,' '), 1,' ') --ОпЕхРћФЁBedZУрКЮШЃ **  
 ||LPAD(NVL(YD_STK_BED_ZAXIS ,'0'), 5,'0') --ОпЕхРћФЁBedZУр(СжЧр)  
 ||LPAD(NVL(YD_STK_BED_LYR_MAX ,'0'), 3,'0') --ОпЕхРћФЁBedДмMax  
 ||LPAD(NVL(YD_STK_BED_WT_MAX ,'0'), 7,'0') --ОпЕхРћФЁBedСпЗЎMax  
 ||LPAD(NVL(YD_STK_BED_H_MAX ,'0'), 5,'0') --ОпЕхРћФЁBedГєРЬMax  
 ||LPAD(NVL(YD_STK_BED_L_MAX ,'0'), 5,'0') --ОпЕхРћФЁBedБцРЬMax  
 ||LPAD(NVL(YD_STK_BED_W_MAX ,'0'), 5,'0') --ОпЕхРћФЁBedЦјMax  
 ||RPAD(NVL(YD_CAR_ARRSTRT_STAT ,' '), 1,' ') --ОпЕхТїЗЎТјЙпЛѓХТ  
 ||RPAD(NVL(YD_CAR_USE_GP ,' '), 1,' ') --ОпЕхТїЗЎЛчПыБИКа  
 ||RPAD(NVL(YD_EQP_WRK_STAT ,' '), 1,' ') --ОпЕхМГКёРлОїЛѓХТ  
 ||RPAD(NVL(NVL(CAR_NO,TRN_EQP_CD),' '),15,' ') --ТїЗЎЙјШЃ  
 ||RPAD(NVL(TRN_EQP_CD ,' '), 8,' ') --ПюМлРхКёФкЕх  
 ||RPAD(NVL(CARD_NO ,' '), 4,' ') --ФЋЕхЙјШЃ  
 ||RPAD(NVL(YD_CAR_AIM_YD_GP ,' '), 1,' ') --ОпЕхТїЗЎИёЧЅОпЕхБИКа  
 AS JMS_TC_MESSAGE --JMSTCMessage  
 FROM (  
 SELECT 'YFF1L001' AS JMS_TC_CD  
 ,:V_YD_INFO_SYNC_CD AS YD_INFO_SYNC_CD  
 ,SC.YD_GP AS YD_GP  
 ,SC.BAY_GP AS BAY_GP  
 ,SC.SECT_GP AS SECT_GP  
 ,SC.COL_GP AS COL_GP  
 ,SC.YD_STK_COL_GP AS YD_STK_COL_GP  
 ,SB.YD_STK_BED_NO AS YD_STK_BED_NO  
 ,SL.YD_STK_LYR_GP AS YD_STK_LYR_GP  
 ,'' AS YS_STK_BED_L_GP  
 ,'' AS YS_STK_BED_W_GP  
 ,'' AS YD_STK_BED_DIR_GP  
 ,CASE WHEN SUBSTR(SC.YD_STK_COL_GP,3,2) = 'PT' THEN  
 (  
 SELECT DECODE(CP.YD_STK_COL_ACT_STAT,'N','C','L') FROM TB_YD_CARPOINT CP WHERE CP.YD_STK_COL_GP = SC.YD_STK_COL_GP  
 )  
 ELSE SB.YD_STK_BED_ACTIVE_STAT  
 END AS YD_STK_BED_ACT_STAT  
 ,'' AS YD_STK_BED_WHIO_STAT  
 ,TO_CHAR(NVL(SB.YD_STK_BED_X_AXIS,0) ,'FM0000000') AS YD_STK_BED_XAXIS  
 ,TO_CHAR(NVL(SB.YD_STK_BED_Y_AXIS,0) ,'FM00000' ) AS YD_STK_BED_YAXIS  
 ,CASE WHEN SC.YD_STK_COL_RULE_Z_AXIS < 0 THEN '-' ELSE '+' END AS YD_STK_BED_ZAXIS_SYM  
 ,TO_CHAR(NVL(SB.YD_STK_BED_Z_AXIS,0) ,'FM00000' ) AS YD_STK_BED_ZAXIS  
 ,TO_CHAR(SB.YD_STK_BED_ABLE_QNTY ,'FM000' ) AS YD_STK_BED_LYR_MAX  
 ,TO_CHAR(SB.YD_STK_BED_WT_MAX ,'FM0000000') AS YD_STK_BED_WT_MAX  
 ,TO_CHAR(SB.YD_STK_BED_HIGH_MAX ,'FM00000' ) AS YD_STK_BED_H_MAX  
 ,TO_CHAR(SB.YD_STK_BED_LEN_MAX ,'FM00000' ) AS YD_STK_BED_L_MAX  
 ,TO_CHAR(SB.YD_STK_BED_W_MAX ,'FM00000' ) AS YD_STK_BED_W_MAX  
 ,NVL(:V_YD_CAR_ARRSTRT_STAT,'') AS YD_CAR_ARRSTRT_STAT  
 ,NVL(:V_YD_CAR_USE_GP,'') AS YD_CAR_USE_GP  
 ,NVL(:V_YD_EQP_WRK_STAT,'') AS YD_EQP_WRK_STAT  
 ,NVL(:V_CAR_NO,'') AS CAR_NO  
 ,NVL(:V_TRN_EQP_CD,'') AS TRN_EQP_CD  
 ,NVL(:V_CARD_NO,'') AS CARD_NO  
 ,'1' AS YD_CAR_AIM_YD_GP  
 FROM TB_YF_STKBED SB  
 , TB_YF_STKCOL SC  
 , (  
 SELECT A.YD_STK_COL_GP  
 ,A.YD_STK_BED_NO  
 ,(SELECT NVL(MAX(B.YD_STK_LYR_NO),'00') FROM TB_YF_STKLYR B WHERE B.YD_STK_COL_GP = A.YD_STK_COL_GP AND B.YD_STK_BED_NO = A.YD_STK_BED_NO AND B.STL_NO IS NOT NULL AND YD_STK_LYR_STAT IN ('C','U')) AS YD_STK_LYR_GP  
 ,MAX(A.DEL_YN) AS DEL_YN  
 FROM TB_YF_STKLYR A  
 WHERE A.YD_STK_COL_GP LIKE '1%'  
 AND A.DEL_YN = 'N'  
 GROUP BY A.YD_STK_COL_GP,A.YD_STK_BED_NO  
 ) SL  
  
 WHERE SC.YD_STK_COL_GP = SB.YD_STK_COL_GP  
 AND SB.YD_STK_COL_GP = SL.YD_STK_COL_GP  
 AND SB.YD_STK_BED_NO = SL.YD_STK_BED_NO  
 AND SB.YD_STK_COL_GP LIKE NVL(:V_YD_STK_COL_GP,'X')||'%'  
 AND SB.YD_STK_BED_NO LIKE :V_YD_STK_BED_NO||'%'  
 AND SC.DEL_YN = 'N'  
 AND SB.DEL_YN = 'N'  
 AND SL.DEL_YN = 'N'  
 ORDER BY BAY_GP, SECT_GP, YD_STK_COL_GP, YD_STK_BED_NO, YD_STK_LYR_GP  
 ) 
 </pre> */
public final static String getYFF1L001_CarInfo = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getYFF1L001_CarInfo";

