 /** <pre> 
-- com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSchLogList 
SELECT --+ ALL_ROWS 
       X.RNUM          AS RNUM                 
     , X.TOTAL         AS TOTALCOUNT           
     , X.SCH_CONTENTS  AS SCH_CONTENTS         
  FROM(SELECT ROWNUM AS RNUM
                    , TOTAL
                    , SCH_CONTENTS
         FROM (SELECT COUNT(*) OVER() AS TOTAL
                    , SCH_CONTENTS  
                FROM TB_YF_SCHLOG
               WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
             )A
        WHERE ROWNUM <= :V_PAGE_NO * :V_PAGE_SIZE) X
 WHERE RNUM >= ((:V_PAGE_NO-1)* :V_PAGE_SIZE)+1
 </pre> */
public final static String getSchLogList = "bak.com.inisteel.cim.yf.acommon.dao.YfCommDAO.getSchLogList";

 /** <pre> 
--com.inisteel.cim.yf.acommon.dao.YfCommDAO.getStockInfoWcrGp
SELECT
    A.STL_NO,
    B.ORD_HCR_GP,
    B.ORD_YEOJAE_GP,
    (
        SELECT
            C.YD_WBOOK_ID
        FROM
            TB_YF_WRKBOOK C,
            TB_YF_WRKBOOKMTL D
        WHERE 1=1
        AND D.STL_NO = A.STL_NO
        AND D.YD_WBOOK_ID = C.YD_WBOOK_ID
        AND D.DEL_YN = 'N'
        AND C.DEL_YN = 'N'
    ) AS YD_WBOOK_ID
FROM
    TB_YF_STOCK A,
    VW_YD_SLABCOMM B
WHERE 1=1
AND A.STL_NO = :V_STL_NO
AND A.STL_NO = B.SLAB_NO(+)
 </pre> */
